/**
 * Lightweight bridge allowing Three.js scene code to trigger sound effects
 * and music without depending on React context. The AudioProvider registers
 * itself as the handler; scenes call `triggerSound` / `triggerMusic` directly.
 */

type SoundHandler = (soundId: string) => void;
type MusicHandler = (soundId: string) => void;
type StopMusicHandler = () => void;

let handler: SoundHandler | null = null;
let musicHandler: MusicHandler | null = null;
let stopMusicHandler: StopMusicHandler | null = null;

/** Registers the sound handler (called by AudioProvider on mount). */
export function registerSoundHandler(fn: SoundHandler): void {
  handler = fn;
}

/** Unregisters the sound handler (called by AudioProvider on unmount). */
export function unregisterSoundHandler(): void {
  handler = null;
}

/** Registers the music handler (called by AudioProvider on mount). */
export function registerMusicHandler(fn: MusicHandler): void {
  musicHandler = fn;
}

/** Unregisters the music handler (called by AudioProvider on unmount). */
export function unregisterMusicHandler(): void {
  musicHandler = null;
}

/** Registers the stop music handler (called by AudioProvider on mount). */
export function registerStopMusicHandler(fn: StopMusicHandler): void {
  stopMusicHandler = fn;
}

/** Unregisters the stop music handler (called by AudioProvider on unmount). */
export function unregisterStopMusicHandler(): void {
  stopMusicHandler = null;
}

/**
 * Triggers a one-shot sound effect from scene code.
 * Safe to call even when audio is not available ΓÇö silently no-ops.
 *
 * @param soundId - The sound identifier from the design inventory.
 */
export function triggerSound(soundId: string): void {
  if (handler) handler(soundId);
}

/**
 * Starts looping music from scene code (e.g. record player interaction).
 * Safe to call even when audio is not available ΓÇö silently no-ops.
 *
 * @param soundId - The music track identifier.
 */
export function triggerMusic(soundId: string): void {
  if (musicHandler) musicHandler(soundId);
}

/**
 * Stops currently playing music from scene code.
 * Safe to call even when audio is not available ΓÇö silently no-ops.
 */
export function triggerStopMusic(): void {
  if (stopMusicHandler) stopMusicHandler();
}

/**
 * Core audio engine managing gain routing, polyphony limits, ducking,
 * and crossfade between music/ambient tracks.
 *
 * Gain chain: source ΓåÆ category gain ΓåÆ master gain ΓåÆ destination
 * Categories: music, ambient, sfx
 */

const MAX_SIMULTANEOUS = 8;
const MAX_SFX = 4;
const DUCK_AMOUNT = 0.35;
const DUCK_ATTACK = 0.08;
const DUCK_RELEASE = 0.4;
const CROSSFADE_DURATION = 1.5;

interface ActiveSound {
  id: string;
  category: 'sfx' | 'music' | 'ambient';
  startTime: number;
  stop: () => void;
}

let ctx: AudioContext | null = null;
let masterGain: GainNode | null = null;
let musicGain: GainNode | null = null;
let ambientGain: GainNode | null = null;
let sfxGain: GainNode | null = null;
let muted = false;
let currentMusicFadeGain: GainNode | null = null;
let currentAmbientFadeGain: GainNode | null = null;
const activeSounds: ActiveSound[] = [];

/** Initializes the audio engine with the given AudioContext. */
export function initEngine(audioContext: AudioContext): void {
  if (ctx === audioContext) return;
  ctx = audioContext;

  masterGain = ctx.createGain();
  masterGain.connect(ctx.destination);

  musicGain = ctx.createGain();
  musicGain.gain.value = 0.25;
  musicGain.connect(masterGain);

  ambientGain = ctx.createGain();
  ambientGain.gain.value = 0.18;
  ambientGain.connect(masterGain);

  sfxGain = ctx.createGain();
  sfxGain.gain.value = 0.5;
  sfxGain.connect(masterGain);
}

/** Returns the underlying AudioContext, or null if not initialized. */
export function getCtx(): AudioContext | null {
  return ctx;
}

/** Returns the master gain node. */
export function getMasterGain(): GainNode | null {
  return masterGain;
}

/** Returns the music gain node. */
export function getMusicGain(): GainNode | null {
  return musicGain;
}

/** Returns the ambient gain node. */
export function getAmbientGain(): GainNode | null {
  return ambientGain;
}

/** Returns the SFX gain node. */
export function getSfxGain(): GainNode | null {
  return sfxGain;
}

/** Sets the global mute state. When muted, master gain drops to 0. */
export function setMuted(value: boolean): void {
  muted = value;
  if (!masterGain || !ctx) return;
  const t = ctx.currentTime;
  masterGain.gain.setTargetAtTime(value ? 0 : 1, t, 0.02);
}

/** Returns true if the engine is currently muted. */
export function isMuted(): boolean {
  return muted;
}

/**
 * Registers an active sound for polyphony tracking.
 * Returns false if the polyphony limit is exceeded and the sound should not play.
 */
export function registerSound(id: string, category: 'sfx' | 'music' | 'ambient', stopFn: () => void): boolean {
  // Clean up finished sounds (rough heuristic: older than 30s for SFX)
  pruneFinished();

  const sfxCount = activeSounds.filter((s) => s.category === 'sfx').length;
  const totalCount = activeSounds.length;

  if (category === 'sfx' && sfxCount >= MAX_SFX) {
    // Drop oldest non-looping SFX
    const oldest = activeSounds.find((s) => s.category === 'sfx');
    if (oldest) {
      oldest.stop();
      activeSounds.splice(activeSounds.indexOf(oldest), 1);
    }
  } else if (totalCount >= MAX_SIMULTANEOUS) {
    const oldest = activeSounds.find((s) => s.category === 'sfx');
    if (oldest) {
      oldest.stop();
      activeSounds.splice(activeSounds.indexOf(oldest), 1);
    }
  }

  activeSounds.push({
    id,
    category,
    startTime: ctx?.currentTime ?? 0,
    stop: stopFn,
  });
  return true;
}

/** Removes a sound from the active tracking list. */
export function unregisterSound(stopFn: () => void): void {
  const idx = activeSounds.findIndex((s) => s.stop === stopFn);
  if (idx !== -1) activeSounds.splice(idx, 1);
}

/** Stops all sounds of a given category. */
export function stopCategory(category: 'sfx' | 'music' | 'ambient'): void {
  const toStop = activeSounds.filter((s) => s.category === category);
  for (const s of toStop) {
    s.stop();
    const idx = activeSounds.indexOf(s);
    if (idx !== -1) activeSounds.splice(idx, 1);
  }
}

/** Ducks music and ambient volumes briefly (for prominent SFX). */
export function duck(): void {
  if (!ctx || !musicGain || !ambientGain) return;
  const t = ctx.currentTime;
  musicGain.gain.setTargetAtTime(0.25 * DUCK_AMOUNT, t, DUCK_ATTACK);
  ambientGain.gain.setTargetAtTime(0.18 * DUCK_AMOUNT, t, DUCK_ATTACK);
  musicGain.gain.setTargetAtTime(0.25, t + DUCK_ATTACK + 0.2, DUCK_RELEASE);
  ambientGain.gain.setTargetAtTime(0.18, t + DUCK_ATTACK + 0.2, DUCK_RELEASE);
}

/**
 * Crossfades from the current music to a new music synthesis function.
 * The old music fades out while the new fades in over CROSSFADE_DURATION.
 */
export function crossfadeMusic(fadeDuration = CROSSFADE_DURATION): GainNode | null {
  if (!ctx || !musicGain) return null;
  const t = ctx.currentTime;

  // Stop all tracked music and disconnect the old fade gain
  stopCategory('music');
  if (currentMusicFadeGain) {
    try {
      currentMusicFadeGain.disconnect();
    } catch {
      /* already disconnected */
    }
    currentMusicFadeGain = null;
  }

  // Create a sub-gain for the new music that fades in
  const fadeIn = ctx.createGain();
  fadeIn.gain.setValueAtTime(0, t);
  fadeIn.gain.linearRampToValueAtTime(1, t + fadeDuration);
  fadeIn.connect(musicGain);
  currentMusicFadeGain = fadeIn;
  return fadeIn;
}

/**
 * Crossfades ambient bed similarly to music crossfade.
 */
export function crossfadeAmbient(fadeDuration = CROSSFADE_DURATION): GainNode | null {
  if (!ctx || !ambientGain) return null;
  const t = ctx.currentTime;

  stopCategory('ambient');
  if (currentAmbientFadeGain) {
    try {
      currentAmbientFadeGain.disconnect();
    } catch {
      /* already disconnected */
    }
    currentAmbientFadeGain = null;
  }

  const fadeIn = ctx.createGain();
  fadeIn.gain.setValueAtTime(0, t);
  fadeIn.gain.linearRampToValueAtTime(1, t + fadeDuration);
  fadeIn.connect(ambientGain);
  currentAmbientFadeGain = fadeIn;
  return fadeIn;
}

/** Cleans up the engine on app teardown. */
export function disposeEngine(): void {
  for (const s of activeSounds) {
    try {
      s.stop();
    } catch {
      /* noop */
    }
  }
  activeSounds.length = 0;
  if (currentMusicFadeGain) {
    try {
      currentMusicFadeGain.disconnect();
    } catch {
      /* noop */
    }
  }
  if (currentAmbientFadeGain) {
    try {
      currentAmbientFadeGain.disconnect();
    } catch {
      /* noop */
    }
  }
  currentMusicFadeGain = null;
  currentAmbientFadeGain = null;
  ctx = null;
  masterGain = null;
  musicGain = null;
  ambientGain = null;
  sfxGain = null;
}

function pruneFinished(): void {
  if (!ctx) return;
  const now = ctx.currentTime;
  // Remove SFX older than 10 seconds (they're short one-shots)
  for (let i = activeSounds.length - 1; i >= 0; i--) {
    if (activeSounds[i].category === 'sfx' && now - activeSounds[i].startTime > 10) {
      activeSounds.splice(i, 1);
    }
  }
}

/**
 * Shared Web Audio synthesis primitives used by all procedural audio modules.
 * Provides envelope shaping, noise generation, oscillator factories, and frequency utilities.
 */

/** Applies an ADSR amplitude envelope to a GainNode. */
export function applyEnvelope(
  _ctx: AudioContext,
  gain: GainNode,
  attack: number,
  decay: number,
  sustain: number,
  release: number,
  startTime: number,
  duration: number,
  peakGain = 1.0,
): void {
  const g = gain.gain;
  g.setValueAtTime(0, startTime);
  g.linearRampToValueAtTime(peakGain, startTime + attack);
  g.linearRampToValueAtTime(peakGain * sustain, startTime + attack + decay);
  g.setValueAtTime(peakGain * sustain, startTime + duration - release);
  g.linearRampToValueAtTime(0, startTime + duration);
}

/** Applies a simple attack-release envelope (no sustain phase). */
export function applyAR(
  _ctx: AudioContext,
  gain: GainNode,
  attack: number,
  release: number,
  startTime: number,
  peakGain = 1.0,
): void {
  const g = gain.gain;
  g.setValueAtTime(0, startTime);
  g.linearRampToValueAtTime(peakGain, startTime + attack);
  g.exponentialRampToValueAtTime(0.001, startTime + attack + release);
}

/** Creates a white noise AudioBuffer of the given duration. */
export function createNoiseBuffer(ctx: AudioContext, duration: number): AudioBuffer {
  const sampleRate = ctx.sampleRate;
  const length = Math.ceil(sampleRate * duration);
  const buffer = ctx.createBuffer(1, length, sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < length; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  return buffer;
}

/** Creates a pink noise AudioBuffer (lower frequencies boosted). */
export function createPinkNoiseBuffer(ctx: AudioContext, duration: number): AudioBuffer {
  const sampleRate = ctx.sampleRate;
  const length = Math.ceil(sampleRate * duration);
  const buffer = ctx.createBuffer(1, length, sampleRate);
  const data = buffer.getChannelData(0);

  let b0 = 0,
    b1 = 0,
    b2 = 0,
    b3 = 0,
    b4 = 0,
    b5 = 0,
    b6 = 0;
  for (let i = 0; i < length; i++) {
    const white = Math.random() * 2 - 1;
    b0 = 0.99886 * b0 + white * 0.0555179;
    b1 = 0.99332 * b1 + white * 0.0750759;
    b2 = 0.969 * b2 + white * 0.153852;
    b3 = 0.8665 * b3 + white * 0.3104856;
    b4 = 0.55 * b4 + white * 0.5329522;
    b5 = -0.7616 * b5 - white * 0.016898;
    data[i] = (b0 + b1 + b2 + b3 + b4 + b5 + b6 + white * 0.5362) * 0.11;
    b6 = white * 0.115926;
  }
  return buffer;
}

/** Plays a noise burst through a bandpass filter with envelope. */
export function playFilteredNoiseBurst(
  ctx: AudioContext,
  destination: AudioNode,
  frequency: number,
  q: number,
  attack: number,
  release: number,
  gain: number,
  startTime?: number,
): void {
  const t = startTime ?? ctx.currentTime;
  const dur = attack + release;
  const source = ctx.createBufferSource();
  source.buffer = createNoiseBuffer(ctx, dur + 0.05);

  const filter = ctx.createBiquadFilter();
  filter.type = 'bandpass';
  filter.frequency.value = frequency;
  filter.Q.value = q;

  const env = ctx.createGain();
  applyAR(ctx, env, attack, release, t, gain);

  source.connect(filter).connect(env).connect(destination);
  source.start(t);
  source.stop(t + dur + 0.05);
}

/** Creates a simple oscillator with envelope, auto-disconnects after playing. */
export function playTone(
  ctx: AudioContext,
  destination: AudioNode,
  type: OscillatorType,
  frequency: number,
  attack: number,
  release: number,
  gain: number,
  startTime?: number,
  detune?: number,
): OscillatorNode {
  const t = startTime ?? ctx.currentTime;
  const dur = attack + release;

  const osc = ctx.createOscillator();
  osc.type = type;
  osc.frequency.value = frequency;
  if (detune) osc.detune.value = detune;

  const env = ctx.createGain();
  applyAR(ctx, env, attack, release, t, gain);

  osc.connect(env).connect(destination);
  osc.start(t);
  osc.stop(t + dur + 0.02);
  return osc;
}

/** Plays a frequency sweep (glissando) from startFreq to endFreq. */
export function playFreqSweep(
  ctx: AudioContext,
  destination: AudioNode,
  type: OscillatorType,
  startFreq: number,
  endFreq: number,
  attack: number,
  release: number,
  gain: number,
  startTime?: number,
): void {
  const t = startTime ?? ctx.currentTime;
  const dur = attack + release;

  const osc = ctx.createOscillator();
  osc.type = type;
  osc.frequency.setValueAtTime(startFreq, t);
  osc.frequency.exponentialRampToValueAtTime(endFreq, t + dur);

  const env = ctx.createGain();
  applyAR(ctx, env, attack, release, t, gain);

  osc.connect(env).connect(destination);
  osc.start(t);
  osc.stop(t + dur + 0.02);
}

/** Converts a MIDI note number to frequency in Hz. */
export function midiToFreq(note: number): number {
  return 440 * Math.pow(2, (note - 69) / 12);
}

/** Returns a musical scale as MIDI note numbers starting from the given root. */
export function majorScale(root: number): number[] {
  const intervals = [0, 2, 4, 5, 7, 9, 11];
  return intervals.map((i) => root + i);
}

/** Returns a pentatonic scale as MIDI note numbers. */
export function pentatonicScale(root: number): number[] {
  const intervals = [0, 2, 4, 7, 9];
  return intervals.map((i) => root + i);
}

/** Picks a random element from an array. */
export function pick<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

/** Returns a random float between min and max. */
export function rand(min: number, max: number): number {
  return min + Math.random() * (max - min);
}

import { Component, type ReactNode, type ErrorInfo } from 'react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
}

/**
 * Catches unhandled errors in the React component tree and renders a child-friendly fallback.
 * Displays an owl icon and a "Try Again" button that reloads the page.
 *
 * @remarks This is a class component because React requires `getDerivedStateFromError` and
 *          `componentDidCatch` lifecycle methods for error boundaries ΓÇö there is no hooks equivalent.
 *          This is the only class component in the codebase; all others are functional.
 */
export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(): State {
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('[ErrorBoundary]', error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            height: '100vh',
            background: '#faf3e8',
            color: '#5a4a3a',
            fontFamily: 'system-ui, sans-serif',
            padding: 32,
            textAlign: 'center',
          }}
        >
          <div style={{ fontSize: 64, marginBottom: 16 }}>&#x1F989;</div>
          <p style={{ fontSize: 20, marginBottom: 24 }}>Oops! Something went wrong.</p>
          <button
            onClick={() => window.location.reload()}
            style={{
              padding: '12px 32px',
              fontSize: 18,
              borderRadius: 28,
              border: 'none',
              background: '#e8a54b',
              color: 'white',
              cursor: 'pointer',
              boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
            }}
          >
            Try Again
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

import { CylinderGeometry, Group, Mesh, SphereGeometry } from 'three';
import {
  COL_CROWN,
  COL_CHEST_BUFF,
  COL_WING_DARK,
  COL_WING_TAWNY,
  COL_TAIL_DARK,
  COL_TALON,
  LEG_HEIGHT,
  WING_REST_ANGLE,
} from './palette';
import { matteFeather, keratin } from './helpers';

/**
 * Creates a sphere mesh with non-uniform scale to simulate Babylon.js
 * CreateSphere with diameterX/Y/Z.
 */
function createScaledSphere(
  name: string,
  diameterX: number,
  diameterY: number,
  diameterZ: number,
  segments: number,
  material: InstanceType<typeof import('three').MeshStandardMaterial>,
): Mesh {
  const mesh = new Mesh(new SphereGeometry(0.5, segments, segments), material);
  mesh.name = name;
  mesh.scale.set(diameterX, diameterY, diameterZ);
  return mesh;
}

/**
 * Builds the owl torso ΓÇö broad chest, compact abdomen, shoulder masses, subtle
 * back slope. The silhouette tapers downward and does not read as an egg
 * or stacked spheres.
 *
 * @returns The core torso mesh (used as the tappable pick target).
 */
export function buildBody(parent: Group): Mesh {
  const bodyMat = matteFeather('owl_bodyMat', COL_CROWN);
  const chestMat = matteFeather('owl_chestMat', COL_CHEST_BUFF);

  // Neck taper ΓÇö narrow cylinder bridging head and torso for separation
  const neck = new Mesh(new CylinderGeometry(0.52 / 2, 0.68 / 2, 0.22, 14), bodyMat);
  neck.name = 'owl_neck';
  parent.add(neck);
  neck.position.set(0, 1.08 + LEG_HEIGHT, 0.02);

  // Core torso ΓÇö broader at chest, compressed front-to-back, tapers at base
  const torso = createScaledSphere('owl_torso', 1.1, 1.2, 0.95, 18, bodyMat);
  parent.add(torso);
  torso.position.set(0, 0.58 + LEG_HEIGHT, 0);

  // Chest front ΓÇö large bright cream panel dominating the front view
  const chest = createScaledSphere('owl_chest', 0.82, 0.95, 0.36, 16, chestMat);
  parent.add(chest);
  chest.position.set(0, 0.52 + LEG_HEIGHT, 0.32);

  // Shoulder masses ΓÇö give hunched silhouette, attach wings visually
  [-1, 1].forEach((side) => {
    const shoulder = createScaledSphere(`owl_shoulder${side > 0 ? 'R' : 'L'}`, 0.32, 0.44, 0.42, 10, bodyMat);
    parent.add(shoulder);
    shoulder.position.set(side * 0.4, 0.92 + LEG_HEIGHT, -0.08);
  });

  // Back slope ΓÇö darker panel between wings
  const back = createScaledSphere('owl_back', 0.66, 0.4, 0.3, 10, bodyMat);
  parent.add(back);
  back.position.set(0, 0.88 + LEG_HEIGHT, -0.36);

  // Lower abdomen taper ΓÇö narrower volume at bottom, breaks egg silhouette
  const abdomen = createScaledSphere('owl_abdomen', 0.62, 0.38, 0.55, 10, chestMat);
  parent.add(abdomen);
  abdomen.position.set(0, 0.18 + LEG_HEIGHT, 0.02);

  // ΓöÇΓöÇ Breast feather streaks ΓÇö layered arcs giving texture to the chest ΓöÇΓöÇ
  const streakMat = matteFeather('owl_streakMat', COL_WING_TAWNY);
  for (let row = 0; row < 5; row++) {
    const rowY = 0.82 + LEG_HEIGHT - row * 0.14;
    const rowWidth = 0.3 + row * 0.04;
    const count = 3 + row; // more streaks per row going down
    for (let c = 0; c < count; c++) {
      const xPos = (c - (count - 1) / 2) * (rowWidth / count);
      const streak = createScaledSphere(`owl_streak_${row}_${c}`, 0.06, 0.04, 0.02, 4, streakMat);
      parent.add(streak);
      streak.position.set(xPos, rowY, 0.46 - row * 0.02);
    }
  }

  return torso;
}

/**
 * Builds a folded wing ΓÇö covert layer over secondaries, individual primary
 * feather shapes tapering past the tail. Attached high at the shoulder and
 * hugging the body.
 *
 * @param parent - The parent group to attach the wing to.
 * @param side - -1 for left wing, +1 for right wing.
 * @returns The wing anchor group for animation.
 */
export function buildWing(parent: Group, side: number): Group {
  const s = side > 0 ? 'R' : 'L';
  const covertMat = matteFeather(`owl_covertMat${s}`, COL_WING_TAWNY);
  const primaryMat = matteFeather(`owl_primaryMat${s}`, COL_WING_DARK);

  const anchor = new Group();
  anchor.name = `owl_wingAnchor${s}`;
  parent.add(anchor);
  anchor.position.set(side * 0.5, 0.88 + LEG_HEIGHT, -0.08);
  anchor.rotation.z = side * WING_REST_ANGLE;

  // Upper coverts ΓÇö broad tawny layer at shoulder, gives wing width
  const covert = createScaledSphere(`owl_covert${s}`, 0.28, 0.6, 0.5, 12, covertMat);
  anchor.add(covert);
  covert.position.set(side * 0.06, -0.02, 0.04);

  // Scalloped covert rows ΓÇö 5 layered arcs for feather barring pattern
  for (let r = 0; r < 5; r++) {
    const scallop = createScaledSphere(
      `owl_scallop${s}_${r}`,
      0.24,
      0.06,
      0.44,
      8,
      r % 2 === 0 ? primaryMat : covertMat,
    );
    anchor.add(scallop);
    scallop.position.set(side * 0.07, 0.16 - r * 0.12, 0.06);
  }

  // Secondaries ΓÇö broad mid-layer below coverts
  const secondary = createScaledSphere(`owl_secondary${s}`, 0.2, 0.76, 0.44, 12, primaryMat);
  anchor.add(secondary);
  secondary.position.set(side * 0.08, -0.18, -0.02);

  // Secondary feather tips ΓÇö individual feather shapes visible at trailing edge
  for (let f = 0; f < 5; f++) {
    const feather = createScaledSphere(
      `owl_secFeather${s}_${f}`,
      0.08,
      0.14,
      0.03,
      6,
      f % 2 === 0 ? primaryMat : covertMat,
    );
    anchor.add(feather);
    feather.position.set(side * (0.1 + f * 0.008), -0.06 - f * 0.12, -0.06);
  }

  // Primaries ΓÇö 6 individual long feather shapes, well-fanned
  for (let p = 0; p < 6; p++) {
    const length = 0.48 + p * 0.06;
    const width = 0.065 - p * 0.004;
    const primary = createScaledSphere(`owl_primary${s}_${p}`, width, length, 0.03, 6, primaryMat);
    anchor.add(primary);
    primary.position.set(side * (0.08 + p * 0.018), -0.4 - p * 0.05, -0.1 - p * 0.025);
    primary.rotation.z = side * p * 0.03;
  }

  return anchor;
}

/**
 * Builds a short tail fan ΓÇö 5 feathers in a compact wedge tucked behind the body.
 *
 * @param parent - The parent group to attach the tail to.
 * @returns The tail anchor group.
 */
export function buildTail(parent: Group): Group {
  const tailMat = matteFeather('owl_tailMat', COL_TAIL_DARK);

  const anchor = new Group();
  anchor.name = 'owl_tailAnchor';
  parent.add(anchor);
  anchor.position.set(0, 0.26 + LEG_HEIGHT, -0.44);
  anchor.rotation.x = 0.22;

  // 5 feathers in a tight fan
  for (let i = -2; i <= 2; i++) {
    const length = 0.3 - Math.abs(i) * 0.03;
    const featherMesh = createScaledSphere(`owl_tailFeather${i}`, 0.06, length, 0.025, 6, tailMat);
    anchor.add(featherMesh);
    featherMesh.position.set(i * 0.04, -length * 0.35, 0);
    featherMesh.rotation.z = i * 0.05;
  }

  return anchor;
}

/**
 * Builds a bird leg ΓÇö thin feathered shank, ankle joint, three forward toes
 * with softened talons, and one rear toe.
 *
 * @param parent - The parent group to attach the leg to.
 * @param side - -1 for left leg, +1 for right leg.
 * @returns The leg anchor group.
 */
export function buildLeg(parent: Group, side: number): Group {
  const s = side > 0 ? 'R' : 'L';
  const shankMat = matteFeather(`owl_shankMat${s}`, COL_CROWN);
  const talonMat = keratin(`owl_talonMat${s}`, COL_TALON);

  const anchor = new Group();
  anchor.name = `owl_legAnchor${s}`;
  parent.add(anchor);
  anchor.position.set(side * 0.16, 0.18, 0.06);

  // Feathered shank ΓÇö thick at top (feather trousers), thinner at ankle
  const shank = new Mesh(new CylinderGeometry(0.14 / 2, 0.06 / 2, 0.26, 10), shankMat);
  shank.name = `owl_shank${s}`;
  anchor.add(shank);
  shank.position.set(0, -0.1, 0);

  // Ankle joint ΓÇö visible bulge
  const ankle = new Mesh(new SphereGeometry(0.07 / 2, 8, 8), talonMat);
  ankle.name = `owl_ankle${s}`;
  anchor.add(ankle);
  ankle.position.set(0, -0.22, 0);

  // Foot base ΓÇö sits at ground level relative to root
  const foot = new Group();
  foot.name = `owl_foot${s}`;
  anchor.add(foot);
  foot.position.set(0, -0.24, 0.02);

  // Three forward toes ΓÇö thick, long, well-splayed
  for (let t = -1; t <= 1; t++) {
    const toe = new Mesh(new CylinderGeometry(0.035 / 2, 0.042 / 2, 0.18, 8), talonMat);
    toe.name = `owl_toe${s}_${t}`;
    foot.add(toe);
    toe.position.set(t * 0.055, 0, 0.06);
    toe.rotation.x = -Math.PI / 2.5;
    toe.rotation.y = t * 0.45;

    // Claw tip ΓÇö visible dark curved nail
    const claw = new Mesh(new CylinderGeometry(0.014 / 2, 0.026 / 2, 0.05, 6), talonMat);
    claw.name = `owl_claw${s}_${t}`;
    toe.add(claw);
    claw.position.set(0, -0.1, 0.01);
    claw.rotation.x = 0.5;
  }

  // Rear toe (hallux)
  const rear = new Mesh(new CylinderGeometry(0.028 / 2, 0.036 / 2, 0.12, 6), talonMat);
  rear.name = `owl_rearToe${s}`;
  foot.add(rear);
  rear.position.set(0, 0, -0.04);
  rear.rotation.x = Math.PI / 3;

  return anchor;
}

import { Group, Mesh, SphereGeometry, TorusGeometry } from 'three';
import {
  COL_CROWN,
  COL_FACIAL_DISC,
  COL_FACE_SHADOW,
  COL_IRIS,
  COL_PUPIL,
  COL_HIGHLIGHT,
  COL_BEAK,
  HEAD_Y,
  LEG_HEIGHT,
} from './palette';
import { matteFeather, glossyEye, keratin } from './helpers';

/**
 * Creates a sphere mesh with non-uniform scale to simulate Babylon.js
 * CreateSphere with diameterX/Y/Z.
 */
function createScaledSphere(
  name: string,
  diameterX: number,
  diameterY: number,
  diameterZ: number,
  segments: number,
  material: InstanceType<typeof import('three').MeshStandardMaterial>,
): Mesh {
  const mesh = new Mesh(new SphereGeometry(0.5, segments, segments), material);
  mesh.name = name;
  mesh.scale.set(diameterX, diameterY, diameterZ);
  return mesh;
}

/**
 * Builds the owl head ΓÇö a broad, flat sphere (wider than tall) with a concave
 * facial disc, subtle brow ridges, cheek feather pads, and small ear tufts.
 * The silhouette reads clearly as a real owl head at thumbnail size.
 */
export function buildHead(parent: Group): Mesh {
  const crownMat = matteFeather('owl_crownMat', COL_CROWN);
  const discMat = matteFeather('owl_discMat', COL_FACIAL_DISC);
  const shadowMat = matteFeather('owl_shadowMat', COL_FACE_SHADOW);

  // Head sphere ΓÇö wider than tall, flattened front-to-back: owl proportions
  const head = createScaledSphere('owl_head', 1.4, 1.1, 1.15, 18, crownMat);
  parent.add(head);
  head.position.set(0, HEAD_Y + LEG_HEIGHT, 0.02);

  // ΓöÇΓöÇ Facial disc ΓÇö lighter dish blending into the crown from the front ΓöÇΓöÇ
  const disc = createScaledSphere('owl_disc', 1.1, 0.94, 0.2, 16, discMat);
  head.add(disc);
  disc.position.set(0, -0.04, 0.28);

  // Disc rim ΓÇö subtle dark shadow border, not a visor
  const rim = new Mesh(new TorusGeometry(0.96 / 2, 0.025 / 2, 16, 32), shadowMat);
  rim.name = 'owl_discRim';
  head.add(rim);
  rim.position.set(0, -0.04, 0.26);

  // ΓöÇΓöÇ Brow ridges ΓÇö soft feathered shelf above each eye (not angry) ΓöÇΓöÇ
  [-1, 1].forEach((side) => {
    const brow = createScaledSphere(`owl_brow${side > 0 ? 'R' : 'L'}`, 0.3, 0.05, 0.1, 8, crownMat);
    head.add(brow);
    brow.position.set(side * 0.26, 0.3, 0.36);
    brow.rotation.z = -side * 0.04;
  });

  // ΓöÇΓöÇ Cheek feather pads ΓÇö volume at lower sides of the disc ΓöÇΓöÇ
  [-1, 1].forEach((side) => {
    const cheek = createScaledSphere(`owl_cheek${side > 0 ? 'R' : 'L'}`, 0.24, 0.2, 0.12, 8, discMat);
    head.add(cheek);
    cheek.position.set(side * 0.36, -0.14, 0.28);
  });

  // ΓöÇΓöÇ Ear tufts ΓÇö tall pointed feather tufts for screech-owl silhouette ΓöÇΓöÇ
  // All tuft parts are siblings on the head (not nested) to avoid scale compression.
  [-1, 1].forEach((side) => {
    const s = side > 0 ? 'R' : 'L';
    const baseX = side * 0.38;
    const baseY = 0.42;
    const baseZ = 0.02;
    const tiltZ = -side * 0.35;

    // Base tuft ΓÇö tall and wider
    const tuft = createScaledSphere(`owl_earTuft${s}`, 0.24, 0.42, 0.1, 8, crownMat);
    head.add(tuft);
    tuft.position.set(baseX, baseY, baseZ);
    tuft.rotation.z = tiltZ;

    // Mid tuft ΓÇö second layer for volume (sibling of head, not child of tuft)
    const mid = createScaledSphere(`owl_earMid${s}`, 0.16, 0.26, 0.07, 6, crownMat);
    head.add(mid);
    mid.position.set(baseX + side * 0.04, baseY + 0.14, baseZ);
    mid.rotation.z = tiltZ;

    // Tip tuft ΓÇö lighter point extending further
    const tip = createScaledSphere(`owl_earTip${s}`, 0.1, 0.16, 0.04, 6, discMat);
    head.add(tip);
    tip.position.set(baseX + side * 0.06, baseY + 0.28, baseZ);
    tip.rotation.z = tiltZ;
  });

  return head;
}

/**
 * Creates an ellipsoid mesh by scaling the geometry vertices directly, NOT the
 * mesh transform. This means child objects' positions are not distorted by the
 * parent's shape ΓÇö critical for nested eye layers.
 */
function createEyeMesh(
  name: string,
  radiusX: number,
  radiusY: number,
  radiusZ: number,
  segments: number,
  material: InstanceType<typeof import('three').MeshStandardMaterial>,
): Mesh {
  const geo = new SphereGeometry(1, segments, segments);
  geo.scale(radiusX, radiusY, radiusZ);
  const mesh = new Mesh(geo, material);
  mesh.name = name;
  return mesh;
}

/**
 * Builds a single realistic owl eye ΓÇö eyeball globe recessed in a dark socket,
 * amber iris disc, dark pupil, glossy corneal dome, catch-light highlights,
 * and separate upper/lower lids for organic blink animation.
 *
 * All eye parts use geometry scaling (not mesh.scale) so nested child positions
 * are not compressed by parent ellipsoid shapes.
 *
 * @param parent - The parent mesh (head) to attach the eye to.
 * @param side - -1 for left eye, +1 for right eye.
 * @returns Object with the eye group mesh and both lid meshes for animation.
 */
export function buildEye(parent: Mesh, side: number): { eyeGroup: Mesh; upperLid: Mesh; lowerLid: Mesh } {
  const s = side > 0 ? 'R' : 'L';
  const xOff = side * 0.28;
  const yOff = 0.02;

  const shadowMat = matteFeather(`owl_socketMat${s}`, COL_FACE_SHADOW);
  const crownMat = matteFeather(`owl_lidMat${s}`, COL_CROWN);
  const scleraMat = glossyEye(`owl_scleraMat${s}`, COL_HIGHLIGHT);
  const irisMat = glossyEye(`owl_irisMat${s}`, COL_IRIS);
  const pupilMat = glossyEye(`owl_pupilMat${s}`, COL_PUPIL);
  const highlightMat = glossyEye(`owl_highlightMat${s}`, COL_HIGHLIGHT);

  // Dark eye socket ΓÇö prominent recess on the facial disc
  const socket = createEyeMesh(`owl_socket${s}`, 0.26, 0.25, 0.07, 14, shadowMat);
  parent.add(socket);
  socket.position.set(xOff, yOff, 0.44);

  // Eyeball globe ΓÇö large white sclera, flattened front-to-back
  const globe = createEyeMesh(`owl_globe${s}`, 0.23, 0.23, 0.13, 16, scleraMat);
  socket.add(globe);
  globe.position.z = 0.02;

  // Iris ΓÇö amber disc flush on the globe front surface (globe z-radius = 0.13)
  const iris = createEyeMesh(`owl_iris${s}`, 0.18, 0.18, 0.015, 16, irisMat);
  irisMat.polygonOffset = true;
  irisMat.polygonOffsetFactor = -1;
  irisMat.polygonOffsetUnits = -1;
  globe.add(iris);
  iris.position.set(0, 0.04, 0.12);

  // Pupil ΓÇö dark disc sitting on the iris surface
  const pupil = createEyeMesh(`owl_pupil${s}`, 0.09, 0.09, 0.01, 14, pupilMat);
  pupilMat.polygonOffset = true;
  pupilMat.polygonOffsetFactor = -2;
  pupilMat.polygonOffsetUnits = -2;
  iris.add(pupil);
  pupil.position.z = 0.015;

  // Corneal dome ΓÇö subtle glossy sheen (transparent, no depth write)
  const corneaMat = glossyEye(`owl_corneaMat${s}`, COL_HIGHLIGHT, 0.08);
  const corneaDome = createEyeMesh(`owl_cornea${s}`, 0.24, 0.24, 0.02, 14, corneaMat);
  globe.add(corneaDome);
  corneaDome.position.z = 0.11;
  corneaDome.renderOrder = 1;

  // Primary catch-light
  const shine = new Mesh(new SphereGeometry(0.035, 8, 8), highlightMat);
  shine.name = `owl_shine${s}`;
  corneaDome.add(shine);
  shine.position.set(0.05, 0.055, 0.035);

  // Secondary catch-light
  const shine2 = new Mesh(new SphereGeometry(0.018, 6, 6), highlightMat);
  shine2.name = `owl_shine2${s}`;
  corneaDome.add(shine2);
  shine2.position.set(-0.03, -0.03, 0.03);

  // Upper eyelid ΓÇö feathered, drops from above (primary blink lid)
  const upperLid = createScaledSphere(`owl_upperLid${s}`, 0.56, 0.3, 0.2, 12, crownMat);
  parent.add(upperLid);
  upperLid.position.set(xOff, yOff + 0.26, 0.5);
  upperLid.scale.y = 0; // hidden when open

  // Lower eyelid ΓÇö smaller, rises from below during blink
  const lowerLid = createScaledSphere(`owl_lowerLid${s}`, 0.48, 0.18, 0.16, 10, crownMat);
  parent.add(lowerLid);
  lowerLid.position.set(xOff, yOff - 0.22, 0.5);
  lowerLid.scale.y = 0; // hidden when open

  return { eyeGroup: socket, upperLid, lowerLid };
}

/**
 * Builds a visible hooked beak centred between the eyes ΓÇö upper mandible with
 * a curved hook tip, lower mandible tucked under. Small and gentle, not aggressive.
 */
export function buildBeak(parent: Mesh): Mesh {
  const beakMat = keratin('owl_beakMat', COL_BEAK);

  // Upper mandible ΓÇö golden hook, pushed well forward and below the eyes
  const upper = createScaledSphere('owl_beakUpper', 0.13, 0.1, 0.16, 12, beakMat);
  parent.add(upper);
  upper.position.set(0, -0.18, 0.58);
  upper.rotation.x = 0.4;

  // Hook tip ΓÇö protrudes downward from mandible
  const hook = createScaledSphere('owl_beakHook', 0.06, 0.05, 0.06, 8, beakMat);
  upper.add(hook);
  hook.position.set(0, -0.05, 0.06);

  // Lower mandible ΓÇö tucked under, slightly recessed
  const lower = createScaledSphere('owl_beakLower', 0.09, 0.04, 0.07, 8, beakMat);
  parent.add(lower);
  lower.position.set(0, -0.24, 0.55);

  return upper;
}

import { Color, DoubleSide, MeshStandardMaterial } from 'three';

// ΓöÇΓöÇ Generic helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Tiny random offset for natural organic variation. */
export function jitter(base: number, range: number): number {
  return base + (Math.random() - 0.5) * range;
}

/** Returns a random duration between minMs and maxMs. */
export function randomInterval(minMs: number, maxMs: number): number {
  return minMs + Math.random() * (maxMs - minMs);
}

// ΓöÇΓöÇ Material wrappers ΓÇö three surface families ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Matte feather surface ΓÇö high roughness, zero metallic.
 * Used for all plumage: body, head, wings, tail, lids.
 */
export function matteFeather(name: string, color: Color): MeshStandardMaterial {
  const mat = new MeshStandardMaterial({
    color,
    metalness: 0.0,
    roughness: 0.82,
  });
  mat.name = name;
  return mat;
}

/**
 * Glossy eye surface ΓÇö very low roughness for wet-look eyeballs, iris, cornea.
 */
export function glossyEye(name: string, color: Color, alpha = 1.0): MeshStandardMaterial {
  const mat = new MeshStandardMaterial({
    color,
    metalness: 0.02,
    roughness: 0.08,
    opacity: alpha,
    transparent: alpha < 1,
    depthWrite: alpha >= 1,
  });
  mat.name = name;
  return mat;
}

/**
 * Keratin surface ΓÇö moderate roughness, slightly waxy. Beak and talons.
 */
export function keratin(name: string, color: Color): MeshStandardMaterial {
  const mat = new MeshStandardMaterial({
    color,
    metalness: 0.0,
    roughness: 0.55,
    side: DoubleSide,
  });
  mat.name = name;
  return mat;
}

import { Raycaster, Vector2, type Scene, type PerspectiveCamera } from 'three';
import type { MiniGameTapEvent, MiniGameDragEvent, MiniGameDragEndEvent, PickResult } from './types';

/** Return type for createInputDispatcher. */
export interface InputDispatcher {
  /** Registers the tap event handler. */
  onTap: (handler: (e: MiniGameTapEvent) => void) => void;
  /** Registers the drag event handler. */
  onDrag: (handler: (e: MiniGameDragEvent) => void) => void;
  /** Registers the drag-end event handler. */
  onDragEnd: (handler: (e: MiniGameDragEndEvent) => void) => void;
  /**
   * Pauses or resumes event delivery.
   * @param paused - Whether to suppress all input events.
   */
  setPaused: (paused: boolean) => void;
  /** Removes all pointer listeners from the canvas. */
  dispose: () => void;
}

/** Manifest subset used by the input dispatcher for mode filtering. */
interface InputManifest {
  inputModes: Array<'tap' | 'drag'>;
}

/** Minimum distance in pixels before a pointer gesture is classified as a drag. */
const DRAG_THRESHOLD = 10;

/** Minimum milliseconds between taps at the same position. */
const TAP_COOLDOWN_MS = 120;

/** Maximum pixel distance for two taps to be considered "same position". */
const TAP_PROXIMITY = 8;

/**
 * Creates an input dispatcher that translates pointer events into game-level tap and drag events.
 * Performs Three.js raycasting to provide pick results with hit mesh and world position.
 * @param canvas - The HTML canvas element to listen on.
 * @param scene - The Three.js scene for raycasting.
 * @param manifest - The mini-game manifest entry describing supported input modes.
 * @param camera - Optional camera override. If not provided, uses the scene default.
 * @returns An InputDispatcher with handler registration, pause control, and disposal.
 */
export function createInputDispatcher(
  canvas: HTMLCanvasElement,
  scene: unknown,
  manifest: InputManifest,
  camera?: PerspectiveCamera,
): InputDispatcher {
  let paused = false;
  let tapHandler: ((e: MiniGameTapEvent) => void) | null = null;
  let dragHandler: ((e: MiniGameDragEvent) => void) | null = null;
  let dragEndHandler: ((e: MiniGameDragEndEvent) => void) | null = null;

  // Raycaster for pick results
  const raycaster = new Raycaster();
  const ndcCoord = new Vector2();

  // Pointer tracking state
  let isDown = false;
  let lastX = 0;
  let lastY = 0;
  let totalDistance = 0;
  let isDragging = false;

  // Tap cooldown state
  let lastTapX = -9999;
  let lastTapY = -9999;
  let lastTapTime = 0;

  const supportsTap = manifest.inputModes.includes('tap');
  const supportsDrag = manifest.inputModes.includes('drag');

  /** Performs a raycast from screen coordinates and returns a PickResult. */
  function performPick(screenX: number, screenY: number): PickResult {
    if (!camera || !scene || !(scene as Scene).children) {
      return { hit: false };
    }

    const rect = canvas.getBoundingClientRect();
    ndcCoord.x = ((screenX - rect.left) / rect.width) * 2 - 1;
    ndcCoord.y = -((screenY - rect.top) / rect.height) * 2 + 1;

    raycaster.setFromCamera(ndcCoord, camera);
    const intersections = raycaster.intersectObjects((scene as Scene).children, true);

    if (intersections.length > 0) {
      const hit = intersections[0];
      return {
        hit: true,
        pickedMesh: hit.object,
        pickedPoint: { x: hit.point.x, y: hit.point.y, z: hit.point.z },
        point: { x: hit.point.x, y: hit.point.y, z: hit.point.z },
      };
    }

    return { hit: false };
  }

  // Checks whether a tap at the given position is within the cooldown window.
  function isTapOnCooldown(x: number, y: number): boolean {
    const now = Date.now();
    const dx = x - lastTapX;
    const dy = y - lastTapY;
    const dist = Math.sqrt(dx * dx + dy * dy);
    return dist < TAP_PROXIMITY && now - lastTapTime < TAP_COOLDOWN_MS;
  }

  function handlePointerDown(e: PointerEvent): void {
    if (paused) return;
    isDown = true;
    lastX = e.clientX;
    lastY = e.clientY;
    totalDistance = 0;
    isDragging = false;
  }

  function handlePointerMove(e: PointerEvent): void {
    if (paused || !isDown) return;

    const dx = e.clientX - lastX;
    const dy = e.clientY - lastY;
    const segmentDist = Math.sqrt(dx * dx + dy * dy);
    totalDistance += segmentDist;
    lastX = e.clientX;
    lastY = e.clientY;

    if (totalDistance >= DRAG_THRESHOLD) {
      isDragging = true;

      if (supportsDrag && dragHandler) {
        dragHandler({
          screenX: e.clientX,
          screenY: e.clientY,
          deltaX: dx,
          deltaY: dy,
          totalDistance,
          pickResult: performPick(e.clientX, e.clientY),
        });
      }
    }
  }

  function handlePointerUp(e: PointerEvent): void {
    if (paused || !isDown) {
      isDown = false;
      return;
    }

    isDown = false;

    if (isDragging) {
      // End of drag
      if (supportsDrag && dragEndHandler) {
        dragEndHandler({
          screenX: e.clientX,
          screenY: e.clientY,
          totalDistance,
        });
      }
    } else {
      // Tap
      if (supportsTap && tapHandler && !isTapOnCooldown(e.clientX, e.clientY)) {
        lastTapX = e.clientX;
        lastTapY = e.clientY;
        lastTapTime = Date.now();

        tapHandler({
          screenX: e.clientX,
          screenY: e.clientY,
          pickResult: performPick(e.clientX, e.clientY),
        });
      }
    }

    isDragging = false;
    totalDistance = 0;
  }

  canvas.addEventListener('pointerdown', handlePointerDown);
  canvas.addEventListener('pointermove', handlePointerMove);
  canvas.addEventListener('pointerup', handlePointerUp);

  return {
    onTap(handler: (e: MiniGameTapEvent) => void): void {
      tapHandler = handler;
    },

    onDrag(handler: (e: MiniGameDragEvent) => void): void {
      dragHandler = handler;
    },

    onDragEnd(handler: (e: MiniGameDragEndEvent) => void): void {
      dragEndHandler = handler;
    },

    setPaused(p: boolean): void {
      paused = p;
      if (p) {
        // Reset tracking state when pausing to avoid stuck gestures
        isDown = false;
        isDragging = false;
        totalDistance = 0;
      }
    },

    dispose(): void {
      canvas.removeEventListener('pointerdown', handlePointerDown);
      canvas.removeEventListener('pointermove', handlePointerMove);
      canvas.removeEventListener('pointerup', handlePointerUp);
      tapHandler = null;
      dragHandler = null;
      dragEndHandler = null;
    },
  };
}

import { Scene, Mesh, Group, Color, Vector3, PlaneGeometry, CylinderGeometry, BoxGeometry } from 'three';
import { createFeltMaterial, createWoodMaterial } from '@app/minigames/shared/materials';
import { buildSkyGradient, buildDetailedCloud } from '@app/minigames/shared/meshBuilders';
import type { MeshStandardMaterial } from 'three';

/**
 * Low-level mesh constructors for the balloon race environment.
 * Pure constructors ΓÇö take a Scene and return positioned meshes.
 */

/**
 * Creates the ground plane with a PBR felt material.
 * @param scene - The Three.js scene.
 * @returns The ground mesh.
 */
export function buildGround(scene: Scene): Mesh {
  const geo = new PlaneGeometry(16, 10);
  geo.rotateX(-Math.PI / 2);
  const mat = createFeltMaterial('groundMat', new Color(0.3, 0.7, 0.2)) as MeshStandardMaterial;
  mat.emissive = new Color(0.03, 0.07, 0.02);
  const ground = new Mesh(geo, mat);
  ground.name = 'ground';
  scene.add(ground);
  return ground;
}

/**
 * Creates fluffy detailed clouds that balloons fly past.
 * @param scene - The Three.js scene.
 * @returns Array of cloud meshes.
 */
export function buildClouds(_scene: Scene): Group[] {
  const clouds: Group[] = [];
  const cloudConfigs = [
    { pos: new Vector3(-4, 9, -2), scale: 1.8 },
    { pos: new Vector3(3, 10, -3), scale: 1.5 },
    { pos: new Vector3(0, 8.5, -1), scale: 1.2 },
    { pos: new Vector3(5, 9.5, -4), scale: 1.6 },
  ];

  for (const cfg of cloudConfigs) {
    clouds.push(buildDetailedCloud(cfg.pos, cfg.scale));
  }

  return clouds;
}

/**
 * Creates bunting decorations with PBR wood poles and felt banners.
 * @param scene - The Three.js scene.
 * @returns Array of pole and banner meshes.
 */
export function buildBunting(scene: Scene): Mesh[] {
  const meshes: Mesh[] = [];
  const poleMat = createWoodMaterial('poleMat', new Color(0.6, 0.4, 0.2));
  const buntingMat = createFeltMaterial('buntingMat', new Color(0.9, 0.2, 0.3)) as MeshStandardMaterial;
  buntingMat.emissive = new Color(0.09, 0.02, 0.03);

  const poleXPositions = [-5, 0, 5];
  const poles: Mesh[] = [];
  for (const px of poleXPositions) {
    const poleGeo = new CylinderGeometry(0.05, 0.05, 4);
    const pole = new Mesh(poleGeo, poleMat);
    pole.name = 'pole';
    pole.position.set(px, 2, -3);
    scene.add(pole);
    meshes.push(pole);
    poles.push(pole);
  }

  // Horizontal bunting between consecutive poles
  for (let i = 0; i < poles.length - 1; i++) {
    const start = poles[i].position;
    const end = poles[i + 1].position;
    const midX = (start.x + end.x) / 2;
    const midZ = (start.z + end.z) / 2;
    const length = start.distanceTo(end);
    const buntingGeo = new BoxGeometry(length, 0.05, 0.3);
    const bunting = new Mesh(buntingGeo, buntingMat);
    bunting.name = 'bunting';
    bunting.position.set(midX, 3.8, midZ);
    scene.add(bunting);
    meshes.push(bunting);
  }

  return meshes;
}

/**
 * Builds the sky gradient backdrop behind the play area.
 * @param scene - The Three.js scene.
 * @returns The sky mesh.
 */
export function buildSky(scene: Scene): Group {
  const sky = buildSkyGradient(new Color(0.25, 0.55, 0.95), new Color(0.6, 0.85, 1.0), 30);
  sky.position.set(0, 5, 8);
  scene.add(sky);
  return sky;
}

import { Scene, Color, type Mesh } from 'three';
import { createConfettiBurst, createSparkleBurst } from '@app/minigames/shared/particleFx';
import type {
  IMiniGame,
  MiniGameContext,
  MiniGameTapEvent,
  MiniGameDragEvent,
  MiniGameDragEndEvent,
  ViewportInfo,
} from '../../framework/types';
import type { BalloonData } from './types';
import {
  GOLD_COLOR,
  MAX_ACTIVE,
  REMOVAL_HEIGHT,
  MIN_LAUNCH_STRETCH,
  ROUND_PAUSE,
  BALLOON_POINTS,
  STRETCH_BONUS,
  STRETCH_BONUS_THRESHOLD,
  BASE_LAUNCH_VELOCITY,
  STRETCH_VELOCITY_MULTIPLIER,
  STRETCH_DRAG_SENSITIVITY,
  SELECTED_EMISSIVE_FACTOR,
  SCORE_MILESTONE_INTERVAL,
  SPAWN_INTERVAL,
  SPAWN_JITTER,
} from './types';
import { balloonsForRound, roundHasGolden } from './helpers';
import {
  spawnBalloon,
  disposeBalloon,
  updateIdleSway,
  updateFlyingMotion,
  applyStretchVisual,
  resetStretchVisual,
  restoreIdleEmissive,
} from './balloons';
import { setupScene, teardownScene, type SceneEnvironment } from './environment';

/**
 * Creates the Balloon Race mini-game.
 * Players select balloons, stretch them upward, and release to launch.
 * Features round-based progression with golden bonus balloons.
 * @param context - Shell-provided context with shared systems.
 * @returns An IMiniGame implementation for balloon launching gameplay.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  // ΓöÇΓöÇ Scene environment ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let env: SceneEnvironment | null = null;

  // ΓöÇΓöÇ Game state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let balloons: BalloonData[] = [];
  let selectedBalloonIdx = -1;
  let currentRound = 1;
  let roundBalloons = 6;
  let launchedThisRound = 0;
  let paused = false;
  let roundPauseCountdown = -1;

  // ΓöÇΓöÇ Framework subscriptions ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let unsubScore: (() => void) | null = null;

  // ΓöÇΓöÇ Orchestration helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /** Fills the active balloon array up to MAX_ACTIVE from the round budget. */
  function fillBalloons(): void {
    const remaining = roundBalloons - launchedThisRound - balloons.length;
    const toSpawn = Math.min(remaining, MAX_ACTIVE - balloons.length);
    const needsGolden = roundHasGolden(currentRound) && !balloons.some((b) => b.kind === 'golden');

    for (let i = 0; i < toSpawn; i++) {
      const kind = i === 0 && needsGolden ? 'golden' : 'standard';
      balloons.push(spawnBalloon(scene, kind));
    }
  }

  /** Starts a new round. */
  function startRound(): void {
    roundBalloons = balloonsForRound(currentRound);
    launchedThisRound = 0;
    fillBalloons();
  }

  /** Checks if the round is complete and starts the inter-round countdown. */
  function checkRoundComplete(): void {
    if (launchedThisRound >= roundBalloons && balloons.length === 0) {
      context.celebration.milestone(context.viewport.width / 2, context.viewport.height / 2, 'large');
      context.celebration.celebrationSound('fanfare');
      roundPauseCountdown = ROUND_PAUSE;
    }
  }

  /** Finds the balloon index whose mesh matches a pick result. */
  function findBalloonAtPick(pickResult: unknown): number {
    const pick = pickResult as { pickedMesh?: Mesh | null } | null;
    if (!pick?.pickedMesh) return -1;
    const pickedMesh = pick.pickedMesh;
    return balloons.findIndex(
      (b) =>
        b.mesh === pickedMesh ||
        b.knotSphere === pickedMesh ||
        b.knotCylinder === pickedMesh ||
        (pickedMesh.parent && pickedMesh.parent === b.mesh),
    );
  }

  // ΓöÇΓöÇ IMiniGame implementation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const game: IMiniGame = {
    id: 'balloon-race' as const,

    async setup(): Promise<void> {
      env = setupScene(scene);
    },

    start(): void {
      currentRound = 1;
      launchedThisRound = 0;
      selectedBalloonIdx = -1;
      paused = false;
      roundPauseCountdown = -1;

      // Reset framework systems
      context.score.reset();
      context.combo.reset();

      // Register respawn loop with SpawnScheduler
      context.spawner.register({
        spawn: () => {
          const remaining = roundBalloons - launchedThisRound - balloons.length;
          if (remaining > 0) {
            const needsGolden = roundHasGolden(currentRound) && !balloons.some((b) => b.kind === 'golden');
            balloons.push(spawnBalloon(scene, needsGolden && remaining === 1 ? 'golden' : 'standard'));
          }
        },
        intervalSeconds: SPAWN_INTERVAL,
        jitterSeconds: SPAWN_JITTER,
        maxCount: MAX_ACTIVE,
        activeCount: () => balloons.length,
      });

      // Subscribe to score milestones
      let lastMilestone = 0;
      unsubScore = context.score.onScoreChanged((newScore: number) => {
        const milestone = Math.floor(newScore / SCORE_MILESTONE_INTERVAL);
        if (milestone > lastMilestone) {
          lastMilestone = milestone;
          context.celebration.milestone(0, 0, 'medium');
        }
      });

      // Start background music
      context.audio.playMusic('carnival-theme');

      startRound();
    },

    update(deltaTime: number): void {
      if (paused) return;

      // Round pause countdown (replaces window.setTimeout)
      if (roundPauseCountdown > 0) {
        roundPauseCountdown -= deltaTime;
        if (roundPauseCountdown <= 0) {
          roundPauseCountdown = -1;
          currentRound++;
          startRound();
        }
        return;
      }

      for (let i = balloons.length - 1; i >= 0; i--) {
        const b = balloons[i];

        if (b.state === 'idle') {
          updateIdleSway(b, deltaTime);
        }

        if (b.state === 'launched' || b.state === 'flying') {
          updateFlyingMotion(b, deltaTime);

          // Remove once above threshold ΓÇö celebrate with particles
          if (b.mesh.position.y > REMOVAL_HEIGHT) {
            const burstPos = b.mesh.position.clone();
            createConfettiBurst(scene, burstPos, b.color, new Color(1, 1, 1), 30);
            if (b.kind === 'golden') {
              createSparkleBurst(scene, burstPos, GOLD_COLOR, 25);
            }
            disposeBalloon(b);
            balloons.splice(i, 1);
            if (i <= selectedBalloonIdx) {
              selectedBalloonIdx = -1;
            }
            checkRoundComplete();
            continue;
          }
        }
      }
    },

    pause(): void {
      paused = true;
      context.spawner.pauseAll();
    },

    resume(): void {
      paused = false;
      context.spawner.resumeAll();
    },

    teardown(): void {
      // Unsubscribe from score changes
      unsubScore?.();
      unsubScore = null;

      // Clear all spawn timers
      context.spawner.clearAll();

      // Stop background music
      context.audio.stopMusic();

      // Dispose balloons
      for (const b of balloons) {
        disposeBalloon(b);
      }
      balloons = [];

      // Dispose environment
      if (env) {
        teardownScene(env);
        env = null;
      }
    },

    onResize(_viewport: ViewportInfo): void {
      if (!env) return;
      // Camera resize handled by camera system
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused) return;

      const idx = findBalloonAtPick(event.pickResult);
      if (idx === -1) {
        // Deselect
        if (selectedBalloonIdx >= 0 && selectedBalloonIdx < balloons.length) {
          restoreIdleEmissive(balloons[selectedBalloonIdx]);
        }
        selectedBalloonIdx = -1;
        return;
      }

      const balloon = balloons[idx];
      if (balloon.state !== 'idle') return;

      // Deselect previous
      if (selectedBalloonIdx >= 0 && selectedBalloonIdx < balloons.length) {
        restoreIdleEmissive(balloons[selectedBalloonIdx]);
      }

      // Select new balloon ΓÇö stronger emissive glow for selection feedback
      selectedBalloonIdx = idx;
      balloon.material.emissive = balloon.color.clone().multiplyScalar(SELECTED_EMISSIVE_FACTOR);
    },

    onDrag(event: MiniGameDragEvent): void {
      if (paused) return;
      if (selectedBalloonIdx < 0 || selectedBalloonIdx >= balloons.length) return;

      const balloon = balloons[selectedBalloonIdx];
      if (balloon.state !== 'idle' && balloon.state !== 'stretching') return;

      // Only respond to upward drags (negative deltaY in screen space)
      if (event.deltaY >= 0) return;

      balloon.state = 'stretching';
      const stretchIncrement = Math.abs(event.deltaY) / context.viewport.height;
      balloon.stretchAmount = Math.min(1.0, balloon.stretchAmount + stretchIncrement * STRETCH_DRAG_SENSITIVITY);

      applyStretchVisual(balloon);
    },

    onDragEnd(event: MiniGameDragEndEvent): void {
      if (paused) return;
      if (selectedBalloonIdx < 0 || selectedBalloonIdx >= balloons.length) return;

      const balloon = balloons[selectedBalloonIdx];
      if (balloon.state !== 'stretching') {
        selectedBalloonIdx = -1;
        return;
      }

      if (balloon.stretchAmount < MIN_LAUNCH_STRETCH) {
        // Snap back ΓÇö not enough stretch
        balloon.state = 'idle';
        balloon.stretchAmount = 0;
        resetStretchVisual(balloon);
        selectedBalloonIdx = -1;
        return;
      }

      // Launch the balloon
      balloon.state = 'launched';
      balloon.velocity = BASE_LAUNCH_VELOCITY + balloon.stretchAmount * STRETCH_VELOCITY_MULTIPLIER;
      balloon.mesh.scale.set(1, 1, 1);

      // Score via framework
      const basePoints = BALLOON_POINTS[balloon.kind];
      const stretchBonus = balloon.stretchAmount > STRETCH_BONUS_THRESHOLD ? STRETCH_BONUS[balloon.kind] : 0;
      context.score.addPoints(basePoints + stretchBonus);
      context.combo.registerHit();
      context.celebration.confetti(event.screenX, event.screenY, balloon.kind === 'golden' ? 'large' : 'medium');
      context.celebration.celebrationSound('whoosh');

      // Sparkle burst on golden bonus stretch
      if (balloon.kind === 'golden' && stretchBonus > 0) {
        createSparkleBurst(scene, balloon.mesh.position.clone(), GOLD_COLOR, 15);
      }

      // Clear selection
      restoreIdleEmissive(balloon);
      selectedBalloonIdx = -1;

      launchedThisRound++;
    },
  };

  return game;
}

import { Vector3 } from 'three';

/**
 * State for a single scalar damped harmonic oscillator.
 * Use `createSpring` to create and `tickSpring` to advance.
 */
export interface SpringState {
  /** Current value. */
  value: number;
  /** Current velocity. */
  velocity: number;
  /** Target value the spring pulls toward. */
  target: number;
  /** Angular frequency ΓÇö controls speed of oscillation. Higher = snappier. */
  omega: number;
  /** Damping ratio. 1.0 = critically damped, <1 = bouncy, >1 = overdamped. */
  zeta: number;
}

/**
 * Creates a new scalar spring in resting state.
 * @param value - Initial resting value.
 * @param omega - Angular frequency (stiffness). Default 12.
 * @param zeta - Damping ratio. Default 0.7 (slightly underdamped / bouncy).
 * @returns A SpringState struct.
 */
export function createSpring(value: number, omega = 12, zeta = 0.7): SpringState {
  return { value, velocity: 0, target: value, omega, zeta };
}

/**
 * Advances a scalar spring by dt seconds using semi-implicit Euler integration.
 * Mutates the spring state in-place. Returns the current value for convenience.
 * @param s - The spring to advance.
 * @param dt - Time step in seconds.
 * @returns The updated value.
 */
export function tickSpring(s: SpringState, dt: number): number {
  const diff = s.value - s.target;
  const accel = -s.omega * s.omega * diff - 2 * s.zeta * s.omega * s.velocity;
  s.velocity += accel * dt;
  s.value += s.velocity * dt;
  return s.value;
}

/**
 * Returns true if the spring is close enough to its target to be considered at rest.
 * @param s - The spring to check.
 * @param threshold - Position threshold. Default 0.001.
 * @param velThreshold - Velocity threshold. Default 0.01.
 */
export function isSpringAtRest(s: SpringState, threshold = 0.001, velThreshold = 0.01): boolean {
  return Math.abs(s.value - s.target) < threshold && Math.abs(s.velocity) < velThreshold;
}

/**
 * Snaps a spring to its target, zeroing velocity.
 * @param s - The spring to snap.
 */
export function snapSpring(s: SpringState): void {
  s.value = s.target;
  s.velocity = 0;
}

/**
 * State for a 3D spring (three independent scalar springs).
 */
export interface Spring3State {
  x: SpringState;
  y: SpringState;
  z: SpringState;
}

/**
 * Creates a 3D spring from a Vector3 initial value.
 * @param v - Initial position.
 * @param omega - Angular frequency. Default 12.
 * @param zeta - Damping ratio. Default 0.7.
 */
export function createSpring3(v: Vector3, omega = 12, zeta = 0.7): Spring3State {
  return {
    x: createSpring(v.x, omega, zeta),
    y: createSpring(v.y, omega, zeta),
    z: createSpring(v.z, omega, zeta),
  };
}

/**
 * Advances a 3D spring and writes the result into a Vector3 (no allocation).
 * @param s - The 3D spring to advance.
 * @param dt - Time step in seconds.
 * @param out - Vector3 to write the result into.
 */
export function tickSpring3(s: Spring3State, dt: number, out: Vector3): void {
  out.x = tickSpring(s.x, dt);
  out.y = tickSpring(s.y, dt);
  out.z = tickSpring(s.z, dt);
}

/**
 * Sets the target of a 3D spring from a Vector3.
 * @param s - The 3D spring.
 * @param target - New target position.
 */
export function setSpring3Target(s: Spring3State, target: Vector3): void {
  s.x.target = target.x;
  s.y.target = target.y;
  s.z.target = target.z;
}

import { Scene, Mesh, MeshStandardMaterial, Color, Vector3, SphereGeometry, type Material } from 'three';
import { createBubbleMaterial } from '@app/minigames/shared/materials';
import type { BubbleState, BubbleKind } from '../types';
import type { EntityPool } from '../../../framework/types';
import {
  BUBBLE_COLORS,
  GOLDEN_COLOR,
  RAINBOW_COLOR,
  SIZE_VARIANTS,
  GOLDEN_BURST_COUNT,
  MAX_BUBBLES,
  MIN_FLOAT_SPEED,
  MAX_FLOAT_SPEED,
  SPAWN_X_MIN,
  SPAWN_X_MAX,
  SPAWN_Y_BOTTOM,
  SPAWN_X_LEFT_EDGE,
  SPAWN_X_RIGHT_EDGE,
  SPAWN_SIDE_Y_MIN,
  SPAWN_SIDE_Y_MAX,
  SPAWN_BOTTOM_CHANCE,
  WOBBLE_SPEED_MIN,
  WOBBLE_SPEED_MAX,
} from '../types';
import { randomRange } from '../helpers';

/**
 * Bubble entity lifecycle ΓÇö creation, material assignment, spawn placement,
 * pool reset, disposal, and spawn patterns.
 */

/** Shared PBR material for the white specular shine highlight on each bubble. */
let shineMat: MeshStandardMaterial | null = null;

/** Counter for unique bubble mesh naming. */
let bubbleIndex = 0;

/**
 * Assigns a PBR iridescent soap-bubble material to a bubble mesh.
 * Disposes any existing material on the mesh before applying.
 * @param scene - The Three.js scene.
 * @param mesh - The bubble mesh to style.
 * @param kind - The bubble kind (determines color).
 * @returns The base color and color index assigned.
 */
export function applyBubbleMaterial(
  _scene: Scene,
  mesh: Mesh,
  kind: BubbleKind,
): { baseColor: Color; colorIndex: number } {
  if (mesh.material && mesh.material !== shineMat) {
    (mesh.material as Material).dispose();
  }

  let baseColor: Color;
  let colorIndex: number;

  if (kind === 'golden') {
    baseColor = GOLDEN_COLOR;
    colorIndex = 0;
  } else if (kind === 'rainbow') {
    baseColor = RAINBOW_COLOR;
    colorIndex = 0;
  } else {
    colorIndex = Math.floor(Math.random() * BUBBLE_COLORS.length);
    baseColor = BUBBLE_COLORS[colorIndex];
  }

  const alpha = kind === 'giant' ? 0.6 : 0.5;
  const mat = createBubbleMaterial(`bubbleMat_${mesh.name}`, baseColor, alpha);
  mesh.material = mat;

  return { baseColor, colorIndex };
}

/**
 * Positions a bubble at an off-screen edge ΓÇö bottom (70%) or left/right side (30%).
 * Starts at zero scale with spawning=true for the entrance animation.
 * @param bubble - The bubble state to reposition.
 */
export function positionBubbleAtSpawn(bubble: BubbleState): void {
  if (Math.random() < SPAWN_BOTTOM_CHANCE) {
    // Spawn from bottom edge
    bubble.mesh.position.x = randomRange(SPAWN_X_MIN, SPAWN_X_MAX);
    bubble.mesh.position.y = SPAWN_Y_BOTTOM + randomRange(-0.5, 0);
  } else {
    // Spawn from a side edge
    const fromLeft = Math.random() < 0.5;
    bubble.mesh.position.x = fromLeft ? SPAWN_X_LEFT_EDGE : SPAWN_X_RIGHT_EDGE;
    bubble.mesh.position.y = randomRange(SPAWN_SIDE_Y_MIN, SPAWN_SIDE_Y_MAX);
  }
  bubble.mesh.position.z = randomRange(-1, 1.5);
  bubble.speed = randomRange(MIN_FLOAT_SPEED, MAX_FLOAT_SPEED);
  bubble.phase = Math.random() * Math.PI * 2;
  bubble.wobblePhase = Math.random() * Math.PI * 2;
  bubble.wobbleSpeed = randomRange(WOBBLE_SPEED_MIN, WOBBLE_SPEED_MAX);
  bubble.active = true;
  bubble.age = 0;
  bubble.spawning = true;
  bubble.mesh.visible = true;
  bubble.mesh.scale.setScalar(0);
}

/**
 * Creates a new bubble entity for the pool.
 * @param scene - The Three.js scene.
 * @returns A fresh BubbleState ready for pooling.
 */
export function createBubble(scene: Scene): BubbleState {
  const sizeVariant = Math.floor(Math.random() * SIZE_VARIANTS.length);
  const name = `bubble_${bubbleIndex++}`;
  const geo = new SphereGeometry(0.5, 32, 32);
  const mesh = new Mesh(geo);
  mesh.name = name;
  scene.add(mesh);

  const { baseColor, colorIndex } = applyBubbleMaterial(scene, mesh, 'normal');

  // Shine mesh removed ΓÇö the custom bubble shader handles specular highlights via Fresnel.
  // We still create a dummy mesh ref so BubbleState.shineMesh stays valid for existing code.
  const shine = new Mesh();
  shine.visible = false;

  return {
    mesh,
    shineMesh: shine,
    speed: randomRange(MIN_FLOAT_SPEED, MAX_FLOAT_SPEED),
    phase: Math.random() * Math.PI * 2,
    sizeVariant,
    active: false,
    baseColor,
    colorIndex,
    kind: 'normal',
    tapsRemaining: 0,
    wobblePhase: Math.random() * Math.PI * 2,
    wobbleSpeed: randomRange(WOBBLE_SPEED_MIN, WOBBLE_SPEED_MAX),
    age: 0,
    spawning: false,
  };
}

/**
 * Resets a bubble entity when it is returned to the pool.
 * @param _scene - The Three.js scene (unused in Three.js version).
 * @param bubble - The bubble to reset.
 */
export function resetBubble(_scene: Scene, bubble: BubbleState): void {
  bubble.active = false;
  bubble.spawning = false;
  bubble.mesh.visible = false;
  bubble.mesh.position.set(0, -10, 0);
  bubble.mesh.scale.setScalar(1);
  bubble.kind = 'normal';
  bubble.tapsRemaining = 0;
  bubble.age = 0;
}

/**
 * Spawns a burst of small bubbles radiating outward from a position.
 * @param scene - The Three.js scene.
 * @param pool - The bubble entity pool.
 * @param activeBubbles - The mutable array of active bubbles.
 * @param pos - World position to radiate from.
 */
export function spawnGoldenBurst(
  scene: Scene,
  pool: EntityPool<BubbleState>,
  activeBubbles: BubbleState[],
  pos: Vector3,
): void {
  for (let i = 0; i < GOLDEN_BURST_COUNT; i++) {
    if (activeBubbles.length >= MAX_BUBBLES) break;

    const bubble = pool.acquire();
    bubble.kind = 'normal';
    bubble.sizeVariant = 0;
    bubble.tapsRemaining = 1;

    const { baseColor, colorIndex } = applyBubbleMaterial(scene, bubble.mesh, 'normal');
    bubble.baseColor = baseColor;
    bubble.colorIndex = colorIndex;

    const angle = (i / GOLDEN_BURST_COUNT) * Math.PI * 2;
    const dist = 0.5 + Math.random() * 0.8;
    bubble.mesh.position.set(
      pos.x + Math.cos(angle) * dist,
      pos.y + Math.sin(angle) * dist * 0.5 + randomRange(-0.3, 0.3),
      pos.z + randomRange(-0.3, 0.3),
    );
    bubble.speed = randomRange(0.4, 0.9);
    bubble.phase = Math.random() * Math.PI * 2;
    bubble.wobblePhase = Math.random() * Math.PI * 2;
    bubble.wobbleSpeed = randomRange(3.0, 5.0);
    bubble.active = true;
    bubble.age = 0;
    bubble.spawning = true;
    bubble.mesh.visible = true;
    bubble.mesh.scale.setScalar(0);

    activeBubbles.push(bubble);
  }
}

/**
 * Disposes a bubble entity permanently (mesh + shine + material).
 * @param bubble - The bubble to dispose.
 */
export function disposeBubble(bubble: BubbleState): void {
  bubble.shineMesh.geometry?.dispose();
  bubble.shineMesh.removeFromParent();
  if (bubble.mesh.material && bubble.mesh.material !== shineMat) {
    (bubble.mesh.material as Material).dispose();
  }
  bubble.mesh.geometry?.dispose();
  bubble.mesh.removeFromParent();
}

/**
 * Disposes the shared shine material. Call during teardown.
 */
export function disposeSharedShineMat(): void {
  if (shineMat) {
    shineMat.dispose();
    shineMat = null;
  }
}

/**
 * Resets the bubble index counter.
 */
export function resetBubbleIndex(): void {
  bubbleIndex = 0;
}

import { Scene, Color, Vector3, type Object3D } from 'three';
import { createGameCamera, createGameLighting } from '@app/minigames/shared/sceneSetup';
import type { GameCamera, GameLights } from '@app/minigames/shared/sceneSetup';
import { buildSkyGradient } from '@app/minigames/shared/meshBuilders';
import type { EnvironmentObjects, StarMesh } from '../types';
import { buildMoon, buildStar } from './scenery';
import type { MeshStandardMaterial } from 'three';

/**
 * Scene-level setup: camera + lighting rig and night sky assembly.
 */

/** Lighting rig returned by setupSceneLighting for teardown disposal. */
export interface SceneLightingRig {
  camera: GameCamera;
  lights: GameLights;
}

/**
 * Creates the twilight camera and lighting rig for the bubble-pop scene.
 * @param scene - The Three.js scene.
 * @returns The camera and light objects for later disposal.
 */
export function setupSceneLighting(_scene: Scene): SceneLightingRig {
  const camera = createGameCamera({
    name: 'bubblePop',
    radius: 10.0,
    beta: 1.4,
    fov: 0.9,
    target: new Vector3(0, 2, 0),
  });

  const lights = createGameLighting({
    name: 'bubblePop',
    direction: new Vector3(0.3, -1, -0.3).normalize(),
    directionalIntensity: 0.25,
    hemisphericIntensity: 0.35,
  });

  return { camera, lights };
}

/**
 * Assembles the night sky dreamscape: twilight gradient, crescent moon,
 * and twinkling stars.
 * @param scene - The Three.js scene.
 * @returns Environment objects for per-frame update and disposal.
 */
export function buildEnvironment(scene: Scene): EnvironmentObjects {
  const meshes: Object3D[] = [];
  const stars: StarMesh[] = [];

  // Twilight sky gradient ΓÇö disable raycasting so it doesn't intercept bubble taps
  const sky = buildSkyGradient(new Color(0.04, 0.06, 0.12), new Color(0.12, 0.06, 0.18), 28);
  scene.add(sky);
  sky.position.z = 10;
  sky.raycast = () => {};
  meshes.push(sky);

  // Crescent moon ΓÇö disable raycasting on moon and its children
  const moon = buildMoon(scene);
  moon.position.set(4.5, 7.5, 8);
  moon.traverse((child) => { child.raycast = () => {}; });
  meshes.push(moon);

  // Get the moon material from the first child
  let moonMat: MeshStandardMaterial | null = null;
  moon.traverse((child) => {
    if (child.name === 'moonFull' && (child as import('three').Mesh).material) {
      moonMat = (child as import('three').Mesh).material as MeshStandardMaterial;
    }
  });

  // Stars ΓÇö disable raycasting so they don't intercept bubble taps
  for (let i = 0; i < 20; i++) {
    const star = buildStar(scene, i);
    star.mesh.position.set(-7 + Math.random() * 14, 3 + Math.random() * 8, 7 + Math.random() * 3);
    if (star.mesh.position.x > 3 && star.mesh.position.y > 6) {
      star.mesh.position.x -= 4;
    }
    star.mesh.raycast = () => {};
    meshes.push(star.mesh);
    stars.push(star);
  }

  return { meshes, stars, moon, moonMat };
}

import { Scene, Vector3, type Mesh } from 'three';
import type { IMiniGame, MiniGameContext, MiniGameTapEvent, ViewportInfo, EntityPool } from '../../framework/types';
import type { BubbleState, BubbleKind, EnvironmentObjects } from './types';
import {
  MAX_BUBBLES,
  RECYCLE_Y,
  MOON_PULSE_INTERVAL,
  BUBBLE_POINTS,
  SPAWN_JITTER,
  POOL_BUFFER,
  SCREEN_PROJECTION_SCALE,
  POP_SOUNDS,
  SIZE_VARIANTS,
  FALLBACK_X_EXTENT,
  FALLBACK_Y_EXTENT,
  FALLBACK_Y_OFFSET,
} from './types';
import { randomRange } from './helpers';
import {
  applyBubbleMaterial,
  positionBubbleAtSpawn,
  createBubble,
  resetBubble,
  disposeBubble,
  spawnGoldenBurst,
  disposeSharedShineMat,
  resetBubbleIndex,
  updateBubbleMotion,
  updateBubbleWobble,
  updateIridescence,
  popBubbleEffect,
  tickPopAnimations,
  clearPopAnimations,
  createTapFallbackSparkle,
  disposePopTexture,
  triggerChainPop,
  triggerWobbleChain,
  tapGiantBubble,
} from './bubbles';
import {
  setupSceneLighting,
  buildEnvironment,
  updateEnvironment,
  pulseNearbyStars,
  decayStarPulses,
  pulseMoon,
  decayMoonPulse,
  type SceneLightingRig,
} from './environment';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';
import { tmpVec3 } from './tempPool';
import { createSpatialHash, applySoftBodyRepulsion, applyPopPressureWave } from './physics';
import type { SpatialHash } from './physics';
import {
  createPlayerProfile,
  recordTap,
  updatePlayerProfile,
  computeEffectiveDifficulty,
  createPhaseState,
  recordPopForEnergy,
  updatePhaseEnergy,
  WARMUP_DURATION,
  COOLDOWN_IDLE_THRESHOLD,
  type SessionAct,
} from './adaptive';
import {
  targetBubbleCount,
  spawnInterval,
  bubbleSpeedRange,
  giantTapsRequired,
  showerInterval,
  showerCount,
  showerSpawnStagger,
  pickBubbleKindBalanced,
  nextMilestoneScore,
} from './balance';
import { disposeGameRig } from '@app/minigames/shared/sceneSetup';

/**
 * Factory function for the Bubble Pop mini-game.
 * @param context - Shell-provided context with shared systems.
 * @returns An IMiniGame object literal whose methods the framework calls through the game lifecycle.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  let lighting: SceneLightingRig | null = null;
  let pool: EntityPool<BubbleState> | null = null;
  const activeBubbles: BubbleState[] = [];

  let env: EnvironmentObjects | null = null;

  // Spatial hash for soft-body repulsion
  const spatialHash: SpatialHash<BubbleState> = createSpatialHash<BubbleState>(2.0);

  let paused = false;
  let elapsedTime = 0;
  let popCount = 0;

  const chainPopQueue: { bubble: BubbleState; delay: number }[] = [];
  const wobbleQueue: { bubble: BubbleState; timer: number }[] = [];

  // Adaptive systems
  const playerProfile = createPlayerProfile();
  const phaseState = createPhaseState();
  let effectiveDifficulty = 0;
  let sessionAct: SessionAct = 'warmup';
  let lastTapTime = 0;
  let milestoneIndex = 0;
  let lastMilestoneScore = 0;

  let showerSpawnerId: string | null = null;
  let unsubScore: (() => void) | null = null;

  function worldToApproxScreen(pos: Vector3): { screenX: number; screenY: number } {
    const halfW = context.viewport.width / 2;
    const halfH = context.viewport.height / 2;
    return { screenX: pos.x * SCREEN_PROJECTION_SCALE + halfW, screenY: -pos.y * SCREEN_PROJECTION_SCALE + halfH };
  }

  function spawnBubble(forceKind?: BubbleKind): void {
    if (!pool) return;
    const maxCount = targetBubbleCount(effectiveDifficulty);
    if (activeBubbles.length >= maxCount) return;

    const bubble = pool.acquire();
    const phase = phaseState.current;

    // During warm-up, only normal bubbles
    const kind = sessionAct === 'warmup' ? 'normal' : (forceKind ?? pickBubbleKindBalanced(effectiveDifficulty, phase));
    bubble.kind = kind;
    bubble.sizeVariant = Math.floor(Math.random() * SIZE_VARIANTS.length);
    bubble.tapsRemaining = kind === 'giant' ? giantTapsRequired(playerProfile.value) : 1;

    // Phase-aware speed range
    const [minSpeed, maxSpeed] = bubbleSpeedRange(effectiveDifficulty, phase);
    bubble.speed = randomRange(minSpeed, maxSpeed);

    // During calm, bias toward larger bubbles
    if (phase === 'calm' && kind === 'normal') {
      bubble.sizeVariant = Math.min(SIZE_VARIANTS.length - 1, bubble.sizeVariant + 1);
    }

    const { baseColor, colorIndex } = applyBubbleMaterial(scene, bubble.mesh, kind);
    bubble.baseColor = baseColor;
    bubble.colorIndex = colorIndex;
    positionBubbleAtSpawn(bubble);
    activeBubbles.push(bubble);

    context.audio.playSound('sfx_bubble_pop_appear');
  }

  function spawnShower(): void {
    if (showerSpawnerId) {
      context.spawner.cancel(showerSpawnerId);
    }
    const target = targetBubbleCount(effectiveDifficulty);
    let remaining = showerCount(effectiveDifficulty, activeBubbles.length, target);
    if (remaining <= 0) return;

    showerSpawnerId = context.spawner.register({
      spawn: () => {
        spawnBubble('normal');
        remaining--;
        if (remaining <= 0 && showerSpawnerId) {
          context.spawner.cancel(showerSpawnerId);
          showerSpawnerId = null;
        }
      },
      intervalSeconds: showerSpawnStagger(effectiveDifficulty),
      maxCount: MAX_BUBBLES,
      activeCount: () => activeBubbles.length,
    });
  }

  /** Removes a bubble from activeBubbles using swap-remove (O(1), no splice). */
  function recycleBubble(index: number): void {
    const bubble = activeBubbles[index];
    const last = activeBubbles.length - 1;
    if (index !== last) {
      activeBubbles[index] = activeBubbles[last];
    }
    activeBubbles.pop();
    if (pool) pool.release(bubble);
  }

  function popBubble(bubble: BubbleState, screenX: number, screenY: number): void {
    bubble.active = false;
    popCount++;

    // Track pop for energy-based phase transitions
    recordPopForEnergy(phaseState);

    context.combo.registerHit();
    const basePoints = BUBBLE_POINTS[bubble.kind] ?? BUBBLE_POINTS.normal;
    context.score.addPoints(basePoints);

    // Use tmpVec3 to avoid per-pop allocation
    const popPos = tmpVec3(3).copy(bubble.mesh.position);

    if (bubble.kind === 'golden' && pool) {
      spawnGoldenBurst(scene, pool, activeBubbles, popPos);
      context.celebration.celebrationSound('whoosh');
    } else if (bubble.kind === 'rainbow') {
      triggerChainPop(bubble, activeBubbles, chainPopQueue);
      context.celebration.celebrationSound('chime');
    }

    triggerWobbleChain(bubble, activeBubbles, wobbleQueue);

    // Push nearby bubbles away from the pop (pressure wave)
    applyPopPressureWave(activeBubbles, popPos.x, popPos.y, 1 / 60);

    popBubbleEffect(scene, bubble, () => {
      const idx = activeBubbles.indexOf(bubble);
      if (idx !== -1) {
        recycleBubble(idx);
      } else if (pool) {
        pool.release(bubble);
      }
    });

    context.audio.playSound(POP_SOUNDS[bubble.sizeVariant] ?? POP_SOUNDS[1]);

    if (env) {
      pulseNearbyStars(env, popPos);
      if (popCount % MOON_PULSE_INTERVAL === 0) {
        pulseMoon(env);
      }
      const showerTrigger = showerInterval(effectiveDifficulty);
      if (popCount % showerTrigger === 0 && popCount > 0) {
        spawnShower();
      }
    }

    context.celebration.confetti(screenX, screenY);
    context.celebration.celebrationSound('pop');
  }

  /** Initial bubble count for warm-up (starts low, ramps up). */
  const WARMUP_INITIAL = 3;

  const game: IMiniGame = {
    id: 'bubble-pop',

    async setup(): Promise<void> {
      lighting = setupSceneLighting(scene);

      pool = context.createPool<BubbleState>({
        create: () => createBubble(scene),
        reset: (bubble) => resetBubble(scene, bubble),
        dispose: disposeBubble,
        maxPoolSize: MAX_BUBBLES + POOL_BUFFER,
      });
      pool.prewarm(MAX_BUBBLES);

      env = buildEnvironment(scene);
    },

    start(): void {
      paused = false;
      elapsedTime = 0;
      popCount = 0;
      chainPopQueue.length = 0;
      wobbleQueue.length = 0;
      clearPopAnimations();
      milestoneIndex = 0;
      lastMilestoneScore = 0;
      lastTapTime = 0;
      sessionAct = 'warmup';

      // Reset adaptive systems
      Object.assign(playerProfile, createPlayerProfile());
      Object.assign(phaseState, createPhaseState());
      effectiveDifficulty = 0;

      context.score.reset();
      context.combo.reset();

      // Warm-up: start with fewer bubbles
      for (let i = 0; i < WARMUP_INITIAL; i++) {
        spawnBubble('normal');
      }

      // Register main spawn loop with dynamic interval
      context.spawner.register({
        spawn: () => spawnBubble(),
        intervalSeconds: spawnInterval(effectiveDifficulty),
        jitterSeconds: SPAWN_JITTER,
        maxCount: MAX_BUBBLES,
        activeCount: () => activeBubbles.length,
      });

      // Escalating milestone schedule
      unsubScore = context.score.onScoreChanged((newScore) => {
        const nextThreshold = nextMilestoneScore(milestoneIndex, lastMilestoneScore);
        if (newScore >= nextThreshold) {
          lastMilestoneScore = nextThreshold;
          milestoneIndex++;
          const halfW = context.viewport.width / 2;
          const halfH = context.viewport.height / 2;
          context.celebration.milestone(halfW, halfH, 'large');
        }
      });

      context.audio.playMusic('mus_bubble_pop_background');
    },

    update(deltaTime: number): void {
      if (paused) return;

      elapsedTime += deltaTime;

      // Update adaptive systems
      updatePlayerProfile(playerProfile, elapsedTime);
      effectiveDifficulty = computeEffectiveDifficulty(context.difficulty.level, playerProfile.value);
      updatePhaseEnergy(phaseState, deltaTime, effectiveDifficulty);

      // Session act transitions
      if (sessionAct === 'warmup' && elapsedTime > WARMUP_DURATION) {
        sessionAct = 'engagement';
      }
      if (sessionAct === 'engagement' && lastTapTime > 0 && elapsedTime - lastTapTime > COOLDOWN_IDLE_THRESHOLD) {
        sessionAct = 'cooldown';
      }

      const phase = phaseState.current;

      // Iridescence update
      updateIridescence(activeBubbles);

      // Tick pop animations inside the game loop
      tickPopAnimations(deltaTime);

      // Process chain pop queue (swap-remove pattern)
      for (let i = chainPopQueue.length - 1; i >= 0; i--) {
        chainPopQueue[i].delay -= deltaTime;
        if (chainPopQueue[i].delay <= 0) {
          const { bubble } = chainPopQueue[i];
          chainPopQueue[i] = chainPopQueue[chainPopQueue.length - 1];
          chainPopQueue.pop();
          if (bubble.active) {
            context.audio.playSound('sfx_bubble_pop_chain_pop');
            const { screenX, screenY } = worldToApproxScreen(bubble.mesh.position);
            popBubble(bubble, screenX, screenY);
          }
        }
      }

      // Process wobble auto-pop queue (swap-remove pattern)
      for (let i = wobbleQueue.length - 1; i >= 0; i--) {
        wobbleQueue[i].timer -= deltaTime;
        if (wobbleQueue[i].timer <= 0) {
          const { bubble } = wobbleQueue[i];
          wobbleQueue[i] = wobbleQueue[wobbleQueue.length - 1];
          wobbleQueue.pop();
          if (bubble.active) {
            const { screenX, screenY } = worldToApproxScreen(bubble.mesh.position);
            popBubble(bubble, screenX, screenY);
          }
        }
      }

      // Populate spatial hash for soft-body repulsion
      spatialHash.clear();
      for (let i = 0; i < activeBubbles.length; i++) {
        const b = activeBubbles[i];
        if (b.active && !b.spawning) {
          spatialHash.insert(b, b.mesh.position.x, b.mesh.position.y);
        }
      }

      for (let i = activeBubbles.length - 1; i >= 0; i--) {
        const bubble = activeBubbles[i];
        if (!bubble.active && !bubble.spawning) continue;

        updateBubbleMotion(bubble, elapsedTime, deltaTime);
        updateBubbleWobble(bubble, elapsedTime, deltaTime);

        if (bubble.mesh.position.y > RECYCLE_Y && !bubble.spawning) {
          recycleBubble(i);
        }
      }

      // Soft-body repulsion ΓÇö prevents bubble overlap
      applySoftBodyRepulsion(activeBubbles, spatialHash, deltaTime);

      if (env) {
        updateEnvironment(env, elapsedTime);
        decayStarPulses(env, deltaTime);
        decayMoonPulse(env, deltaTime);
      }

      // Crescendo events
      if (phase === 'crescendo') {
        spawnShower();
        if (env) pulseMoon(env);
      }
    },

    pause(): void {
      paused = true;
      context.spawner.pauseAll();
    },

    resume(): void {
      paused = false;
      context.spawner.resumeAll();
    },

    teardown(): void {
      unsubScore?.();
      unsubScore = null;

      context.spawner.clearAll();
      showerSpawnerId = null;

      activeBubbles.length = 0;
      chainPopQueue.length = 0;
      wobbleQueue.length = 0;
      clearPopAnimations();

      if (pool) {
        pool.dispose();
        pool = null;
      }
      disposeSharedShineMat();
      disposePopTexture();
      resetBubbleIndex();

      if (env) {
        for (const mesh of env.meshes) {
          disposeMeshDeep(mesh);
        }
        env = null;
      }

      if (lighting) {
        disposeGameRig(lighting.camera, lighting.lights);
        lighting = null;
      }

      context.audio.stopMusic();
    },

    onResize(_viewport: ViewportInfo): void {
      if (!lighting) return;
      // Camera resize handled by camera system
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused) return;

      lastTapTime = elapsedTime;

      // If in cool-down, snap back to engagement with a return burst
      if (sessionAct === 'cooldown') {
        sessionAct = 'engagement';
        // Spawn a few welcoming bubbles near the tap
        for (let i = 0; i < 3; i++) {
          spawnBubble('normal');
        }
      }

      const pickResult = event.pickResult;
      let hitBubble = false;

      if (pickResult?.hit && pickResult.pickedMesh) {
        const pickedMesh = pickResult.pickedMesh as Mesh;
        for (let i = 0; i < activeBubbles.length; i++) {
          const bubble = activeBubbles[i];
          if (
            bubble.active &&
            !bubble.spawning &&
            (bubble.mesh === pickedMesh || pickedMesh.parent === bubble.mesh)
          ) {
            hitBubble = true;
            if (bubble.kind === 'giant' && bubble.tapsRemaining > 1) {
              tapGiantBubble(bubble);
              context.audio.playSound('sfx_bubble_pop_pop_large');
            } else {
              popBubble(bubble, event.screenX, event.screenY);
            }
            break;
          }
        }
      }

      // Record tap for player profiling
      recordTap(playerProfile, elapsedTime, hitBubble);

      if (hitBubble) return;

      // First-tap fallback ΓÇö reuse tmpVec3 to avoid per-tap allocation
      if (pickResult?.hit && pickResult.pickedPoint) {
        const pos = tmpVec3(4).set(pickResult.pickedPoint.x, pickResult.pickedPoint.y, pickResult.pickedPoint.z);
        createTapFallbackSparkle(scene, pos);
      } else {
        const pos = tmpVec3(4).set(
          (event.screenX / context.viewport.width - 0.5) * FALLBACK_X_EXTENT,
          (0.5 - event.screenY / context.viewport.height) * FALLBACK_Y_EXTENT + FALLBACK_Y_OFFSET,
          0,
        );
        createTapFallbackSparkle(scene, pos);
      }
      context.audio.playSound('sfx_bubble_pop_twinkle');
    },
  };

  return game;
}

import type { BubbleState } from '../types';
import { SIZE_VARIANTS, GIANT_SCALE } from '../types';
import type { SpatialHash } from './spatialHash';

/**
 * Soft-body repulsion ΓÇö keeps bubbles from overlapping.
 * Applies gentle push-apart forces when bubbles are closer than the sum
 * of their radii. Also applies pop pressure wave impulses.
 */

/** Repulsion tuning constants. */
const REPULSION_STRENGTH = 2.0;
const REPULSION_DAMPING = 0.8;
const PRESSURE_WAVE_STRENGTH = 3.0;
const PRESSURE_WAVE_RADIUS = 3.0;

/** Returns the effective world-space radius of a bubble. */
function bubbleRadius(bubble: BubbleState): number {
  const baseRadius = (SIZE_VARIANTS[bubble.sizeVariant] ?? 0.55) / 2;
  return baseRadius * (bubble.kind === 'giant' ? GIANT_SCALE : 1);
}

/**
 * Applies soft-body repulsion forces between all active bubbles.
 * Uses the spatial hash for O(n) neighbor lookups.
 * @param activeBubbles - The current active bubbles.
 * @param hash - Spatial hash populated with current bubble positions.
 * @param deltaTime - Frame delta time in seconds.
 */
export function applySoftBodyRepulsion(
  activeBubbles: readonly BubbleState[],
  hash: SpatialHash<BubbleState>,
  deltaTime: number,
): void {
  const maxRadius = 0.8 * GIANT_SCALE; // largest possible bubble radius
  const queryRadius = maxRadius * 2.5; // generous to catch all potential overlaps

  for (let i = 0; i < activeBubbles.length; i++) {
    const a = activeBubbles[i];
    if (!a.active || a.spawning) continue;

    const ax = a.mesh.position.x;
    const ay = a.mesh.position.y;
    const ra = bubbleRadius(a);

    const neighbors = hash.queryRadius(ax, ay, queryRadius);
    for (let j = 0; j < neighbors.length; j++) {
      const entry = neighbors[j];
      const b = entry.item;
      if (b === a || !b.active || b.spawning) continue;

      const dx = ax - entry.x;
      const dy = ay - entry.y;
      const distSq = dx * dx + dy * dy;
      const rb = bubbleRadius(b);
      const minDist = ra + rb;
      const minDistSq = minDist * minDist;

      if (distSq < minDistSq && distSq > 0.0001) {
        const dist = Math.sqrt(distSq);
        const overlap = minDist - dist;
        const nx = dx / dist;
        const ny = dy / dist;
        // Push apart proportional to overlap
        const force = overlap * REPULSION_STRENGTH * REPULSION_DAMPING * deltaTime;
        // Split evenly between both bubbles
        const half = force * 0.5;
        a.mesh.position.x += nx * half;
        a.mesh.position.y += ny * half;
        b.mesh.position.x -= nx * half;
        b.mesh.position.y -= ny * half;
      }
    }
  }
}

/**
 * Applies a pressure wave impulse from a pop position, pushing nearby bubbles outward.
 * @param activeBubbles - The current active bubbles.
 * @param popX - Pop world X.
 * @param popY - Pop world Y.
 * @param deltaTime - Frame delta time.
 */
export function applyPopPressureWave(
  activeBubbles: readonly BubbleState[],
  popX: number,
  popY: number,
  deltaTime: number,
): void {
  for (let i = 0; i < activeBubbles.length; i++) {
    const b = activeBubbles[i];
    if (!b.active || b.spawning) continue;

    const dx = b.mesh.position.x - popX;
    const dy = b.mesh.position.y - popY;
    const distSq = dx * dx + dy * dy;

    if (distSq < PRESSURE_WAVE_RADIUS * PRESSURE_WAVE_RADIUS && distSq > 0.01) {
      const dist = Math.sqrt(distSq);
      const falloff = 1 - dist / PRESSURE_WAVE_RADIUS;
      const impulse = falloff * PRESSURE_WAVE_STRENGTH * deltaTime;
      b.mesh.position.x += (dx / dist) * impulse;
      b.mesh.position.y += (dy / dist) * impulse;
    }
  }
}

import { Color, Vector3 } from 'three';

/**
 * Pre-allocated temporary objects for per-frame operations.
 * Avoids GC pressure from `new Vector3()` / `new Color()` in hot loops.
 * Each slot is overwritten every time it's used ΓÇö do NOT hold references
 * across frames.
 */

const _v3: Vector3[] = [];
const _color: Color[] = [];

for (let i = 0; i < 8; i++) _v3.push(new Vector3());
for (let i = 0; i < 4; i++) _color.push(new Color());

/** Returns a pre-allocated Vector3 scratch object. Index 0ΓÇô7 available. */
export function tmpVec3(index: number): Vector3 {
  return _v3[index];
}

/** Returns a pre-allocated Color scratch object. Index 0ΓÇô3 available. */
export function tmpColor(index: number): Color {
  return _color[index];
}

import { Mesh, Group, MeshStandardMaterial, PlaneGeometry, CanvasTexture, Color, DoubleSide } from 'three';
import { createWoodMaterial, createFeltMaterial } from '@app/minigames/shared/materials';
import { buildSkyGradient } from '@app/minigames/shared/meshBuilders';
import { SURFACE_SIZE, TEXTURE_SIZE, BRUSH_RADIUS_TEX, MUD_COLORS } from '../types';
import { worldToTexCoords } from '../helpers';

/**
 * Low-level mesh/texture constructors for the scrub-to-reveal environment.
 * Creates the cleaning surface with a CanvasTexture mess overlay,
 * a background rug on a wooden floor, and scrub interaction support.
 */

/** Handles for the cleaning surface and its CanvasTexture. */
export interface CleaningSurface {
  plane: Mesh;
  canvas: HTMLCanvasElement;
  texture: CanvasTexture;
  material: MeshStandardMaterial;
}

/**
 * Creates the mess overlay cleaning surface ΓÇö a horizontal ground plane
 * with a CanvasTexture that starts fully opaque (mud) and becomes
 * transparent as the player scrubs.
 * @returns The cleaning surface handles.
 */
export function buildCleaningSurface(): CleaningSurface {
  const canvas = document.createElement('canvas');
  canvas.width = TEXTURE_SIZE;
  canvas.height = TEXTURE_SIZE;

  const texture = new CanvasTexture(canvas);

  const material = new MeshStandardMaterial({
    map: texture,
    alphaMap: texture,
    transparent: true,
    side: DoubleSide,
    depthWrite: false,
    roughness: 1,
    metalness: 0,
  });

  const geo = new PlaneGeometry(SURFACE_SIZE, SURFACE_SIZE);
  geo.rotateX(-Math.PI / 2);
  const plane = new Mesh(geo, material);
  plane.position.y = 0.35;
  plane.renderOrder = 1;

  return { plane, canvas, texture, material };
}

/**
 * Paints the initial mud/mess overlay onto the canvas texture.
 * Creates organic-looking splotchy mud with texture variation,
 * similar to a child's dirty play surface.
 * @param canvas - The HTMLCanvasElement to paint on.
 * @param texture - The CanvasTexture to mark for update.
 */
export function createMudOverlay(canvas: HTMLCanvasElement, texture: CanvasTexture): void {
  const ctx = canvas.getContext('2d')!;
  const size = TEXTURE_SIZE;

  // Base mud color
  ctx.fillStyle = '#6B4F3A';
  ctx.fillRect(0, 0, size, size);

  // Large splotchy layers for organic look
  for (let j = 0; j < 40; j++) {
    const sx = Math.random() * size;
    const sy = Math.random() * size;
    const sr = size * 0.04 + Math.random() * size * 0.12;
    ctx.beginPath();
    ctx.arc(sx, sy, sr, 0, Math.PI * 2);
    ctx.fillStyle = MUD_COLORS[Math.floor(Math.random() * MUD_COLORS.length)];
    ctx.globalAlpha = 0.2 + Math.random() * 0.35;
    ctx.fill();
  }

  // Smaller splotches for texture detail
  for (let j = 0; j < 60; j++) {
    const sx = Math.random() * size;
    const sy = Math.random() * size;
    const sr = size * 0.01 + Math.random() * size * 0.05;
    ctx.beginPath();
    ctx.arc(sx, sy, sr, 0, Math.PI * 2);
    ctx.fillStyle = MUD_COLORS[Math.floor(Math.random() * MUD_COLORS.length)];
    ctx.globalAlpha = 0.15 + Math.random() * 0.3;
    ctx.fill();
  }

  // Scratchy texture lines
  ctx.globalAlpha = 0.06;
  ctx.strokeStyle = '#3a2810';
  ctx.lineWidth = 1;
  for (let j = 0; j < 30; j++) {
    ctx.beginPath();
    ctx.moveTo(Math.random() * size, Math.random() * size);
    ctx.lineTo(Math.random() * size, Math.random() * size);
    ctx.stroke();
  }

  // Small specks
  ctx.globalAlpha = 0.12;
  ctx.fillStyle = '#3a2810';
  for (let j = 0; j < 80; j++) {
    ctx.beginPath();
    ctx.arc(Math.random() * size, Math.random() * size, 1 + Math.random() * 3, 0, Math.PI * 2);
    ctx.fill();
  }

  // Lighter puddle highlights
  ctx.globalAlpha = 0.08;
  ctx.fillStyle = '#C0A87A';
  for (let j = 0; j < 12; j++) {
    ctx.beginPath();
    ctx.ellipse(
      Math.random() * size,
      Math.random() * size,
      size * 0.04 + Math.random() * size * 0.08,
      size * 0.02 + Math.random() * size * 0.04,
      Math.random() * Math.PI,
      0,
      Math.PI * 2,
    );
    ctx.fill();
  }

  ctx.globalAlpha = 1;
  texture.needsUpdate = true;
}

/**
 * Erases a circle from the mess canvas at the given world position.
 * Uses destination-out compositing for smooth brush-like clearing with
 * soft edges ΓÇö feels like scrubbing with a sponge.
 * @param canvas - The mess canvas element.
 * @param texture - The CanvasTexture to mark for update.
 * @param worldX - World X coordinate of the scrub center.
 * @param worldZ - World Z coordinate of the scrub center.
 */
export function scrubAt(canvas: HTMLCanvasElement, _texture: CanvasTexture, worldX: number, worldZ: number): void {
  const ctx = canvas.getContext('2d')!;
  const { texX, texY } = worldToTexCoords(worldX, worldZ);

  ctx.globalCompositeOperation = 'destination-out';
  const grad = ctx.createRadialGradient(texX, texY, BRUSH_RADIUS_TEX * 0.3, texX, texY, BRUSH_RADIUS_TEX);
  grad.addColorStop(0, 'rgba(0,0,0,1)');
  grad.addColorStop(0.7, 'rgba(0,0,0,0.8)');
  grad.addColorStop(1, 'rgba(0,0,0,0)');

  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(texX, texY, BRUSH_RADIUS_TEX, 0, Math.PI * 2);
  ctx.fill();

  ctx.globalCompositeOperation = 'source-over';
}

/**
 * Force-clears the mess in a circle around a shape after full reveal.
 * Makes the area fully transparent so the revealed toy is unobstructed.
 * @param canvas - The mess canvas element.
 * @param texture - The CanvasTexture to mark for update.
 * @param worldX - Shape world X.
 * @param worldZ - Shape world Z.
 * @param clearRadius - Radius in texture pixels to clear.
 */
export function clearAreaAroundShape(
  canvas: HTMLCanvasElement,
  _texture: CanvasTexture,
  worldX: number,
  worldZ: number,
  clearRadius: number,
): void {
  const ctx = canvas.getContext('2d')!;
  const { texX, texY } = worldToTexCoords(worldX, worldZ);

  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = 'rgba(0,0,0,1)';
  ctx.beginPath();
  ctx.arc(texX, texY, clearRadius, 0, Math.PI * 2);
  ctx.fill();
  ctx.globalCompositeOperation = 'source-over';
}

/**
 * Creates the wooden floor underneath everything.
 * @returns The floor mesh.
 */
export function buildFloor(): Mesh {
  const geo = new PlaneGeometry(14, 12);
  geo.rotateX(-Math.PI / 2);
  const floor = new Mesh(geo, createWoodMaterial('ctm_floorMat', new Color('#B5874B')));
  floor.position.y = -0.01;
  return floor;
}

/**
 * Creates a decorative rug underneath the cleaning area.
 * @returns Array of rug meshes (ground plane).
 */
export function buildRug(): Mesh[] {
  const meshes: Mesh[] = [];

  const geo = new PlaneGeometry(SURFACE_SIZE + 1, SURFACE_SIZE + 1);
  geo.rotateX(-Math.PI / 2);
  const rug = new Mesh(geo, createFeltMaterial('ctm_rugMat', new Color('#E8C8A0')));
  rug.position.y = 0.005;
  meshes.push(rug);

  return meshes;
}

/**
 * Builds the sky gradient backdrop.
 * @returns The sky mesh.
 */
export function buildSky(): Group {
  return buildSkyGradient(new Color('#87CEEB'), new Color('#FFF8F0'), 20);
}

import { Scene, Color, Vector3 } from 'three';
import { createConfettiBurst, createSparkleBurst } from '@app/minigames/shared/particleFx';
import type {
  IMiniGame,
  MiniGameContext,
  MiniGameTapEvent,
  MiniGameDragEvent,
  MiniGameDragEndEvent,
  ViewportInfo,
} from '../../framework/types';
import type { HiddenShape } from './types';
import {
  TOY_TYPES,
  CELEBRATION_PAUSE,
  REVEAL_POINTS,
  HALF_REVEAL_THRESHOLD,
  FULL_REVEAL_THRESHOLD,
  MESS_PLANE_Y,
  MESH_Y_HIDDEN,
  SHAPE_SCALE,
  TEXTURE_SIZE,
  SURFACE_SIZE,
} from './types';
import { shuffle, randomSurfacePosition, itemCountForRound, checkRevealProgress } from './helpers';
import {
  createToyMesh,
  disposeToy,
  updateRevealAnimation,
  updateIdleBob,
  startReveal,
  hideShapeMesh,
  updateCelebrationBounce,
} from './toys';
import {
  setupScene,
  teardownScene,
  refreshMudOverlay,
  updateAmbientLighting,
  scrubAt,
  clearAreaAroundShape,
  type SceneEnvironment,
} from './environment';

/**
 * Creates the Clean The Mess mini-game instance.
 * Players scrub a dirty surface to reveal hidden toy shapes underneath.
 * Features round-based progression with escalating celebration,
 * combo tracking, and ambient atmosphere.
 * @param context - The shell-provided context with shared systems.
 * @returns An IMiniGame implementation for the scrub-to-reveal game.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  // -- Scene environment --
  let env: SceneEnvironment | null = null;

  // -- Game state --
  let shapes: HiddenShape[] = [];
  let currentRound = 0;
  let revealedCount = 0;
  let totalShapes = 0;
  let paused = false;
  let celebrationTimer = 0;
  let celebrating = false;
  let allClean = false;
  let time = 0;
  let started = false;
  let textureDirty = false;

  // Combo unsub
  let unsubCombo: (() => void) | null = null;

  // -- Orchestration helpers --

  /**
   * Converts a tap/drag event to a world position on the mess plane.
   * Uses the pickResult from the shell's raycaster if available,
   * otherwise falls back to a simple projection.
   * @param event - The tap or drag event with pickResult.
   * @returns World position on the mess plane, or null if no hit.
   */
  function eventToMessPlane(event: {
    pickResult?: { hit: boolean; point?: { x: number; y: number; z: number } };
  }): Vector3 | null {
    if (event.pickResult?.hit && event.pickResult.point) {
      const p = event.pickResult.point;
      return new Vector3(p.x, p.y, p.z);
    }
    return null;
  }

  /** Spawns hidden shapes for the current round. */
  function spawnRoundShapes(): void {
    // Dispose old shapes
    for (const shape of shapes) {
      disposeToy(shape.mesh);
    }
    shapes = [];
    revealedCount = 0;
    allClean = false;

    const count = itemCountForRound(currentRound);
    totalShapes = count;

    // Pick random toy types
    const allIndices = [...Array(TOY_TYPES.length).keys()];
    const shuffled = shuffle(allIndices);
    const indices = count <= TOY_TYPES.length ? shuffled.slice(0, count) : shuffled;

    const placedPositions: Vector3[] = [];
    for (let i = 0; i < count; i++) {
      const typeIdx = indices[i % indices.length];
      const toyType = TOY_TYPES[typeIdx];
      const pos = randomSurfacePosition(placedPositions);
      placedPositions.push(pos);

      const mesh = createToyMesh(scene, toyType, 'toy_' + currentRound + '_' + i);
      mesh.scale.setScalar(SHAPE_SCALE);
      mesh.position.set(pos.x, MESH_Y_HIDDEN, pos.z);
      scene.add(mesh);

      const shape: HiddenShape = {
        typeIdx,
        mesh,
        state: 'hidden',
        surfaceX: pos.x,
        surfaceZ: pos.z,
        progress: 0,
        halfCelebrated: false,
        revealTime: 0,
        revealScale: SHAPE_SCALE,
        popProgress: 1,
      };

      hideShapeMesh(shape);
      shapes.push(shape);
    }

    // Refresh the mud overlay
    if (env) {
      refreshMudOverlay(env);
    }

    context.score.reset();
  }

  /**
   * Performs a scrub at the given world position: erases from the texture,
   * checks reveal progress for all hidden shapes, and triggers celebrations.
   */
  function performScrub(worldX: number, worldZ: number, screenX: number, screenY: number): void {
    if (!env) return;

    // Clamp to surface bounds
    const halfSize = SURFACE_SIZE / 2;
    if (Math.abs(worldX) > halfSize || Math.abs(worldZ) > halfSize) return;

    // Erase from the texture
    scrubAt(env.cleaningSurface.canvas, env.cleaningSurface.texture, worldX, worldZ);
    textureDirty = true;

    // Scrub sparkles
    createSparkleBurst(scene, new Vector3(worldX, MESS_PLANE_Y + 0.1, worldZ), new Color(1, 1, 1), 4);

    // Check each hidden shape for reveal progress
    const texCtx = env.cleaningSurface.canvas.getContext('2d')!;
    for (const shape of shapes) {
      if (shape.state === 'revealed' || shape.state === 'celebrating') continue;

      const progress = checkRevealProgress(shape, texCtx);
      shape.progress = progress;

      // Half-reveal celebration ΓÇö sparkle hint, shape is already visible through cleaned mud
      if (progress > HALF_REVEAL_THRESHOLD && !shape.halfCelebrated) {
        shape.halfCelebrated = true;
        shape.state = 'peeking';
        context.celebration.celebrationSound('chime');
        createSparkleBurst(scene, new Vector3(shape.surfaceX, 0.3, shape.surfaceZ), new Color('#54a0ff'), 8);
      }

      // Full reveal
      if (progress > FULL_REVEAL_THRESHOLD) {
        handleFullReveal(shape, screenX, screenY);
      }
    }
  }

  /** Handles full reveal of a shape with celebration effects. */
  function handleFullReveal(shape: HiddenShape, screenX: number, screenY: number): void {
    if (!env) return;

    // Clear mud around the shape completely
    const clearRadius = Math.floor((TEXTURE_SIZE / SURFACE_SIZE) * 1.2);
    clearAreaAroundShape(
      env.cleaningSurface.canvas,
      env.cleaningSurface.texture,
      shape.surfaceX,
      shape.surfaceZ,
      clearRadius,
    );
    textureDirty = true;

    // Start reveal animation
    startReveal(shape, time);

    // Score and celebrate
    revealedCount++;
    context.score.addPoints(REVEAL_POINTS);
    context.combo.registerHit();

    // Celebration effects with escalation
    const toyType = TOY_TYPES[shape.typeIdx];
    const sparkleCount = revealedCount >= 4 ? 25 : revealedCount >= 2 ? 15 : 10;
    const intensity = revealedCount >= 4 ? 'large' : revealedCount >= 2 ? 'medium' : 'small';

    createSparkleBurst(scene, new Vector3(shape.surfaceX, 0.5, shape.surfaceZ), toyType.color, sparkleCount);
    context.celebration.celebrationSound('pop');
    context.celebration.confetti(screenX, screenY, intensity);

    // Check if all shapes revealed
    if (revealedCount >= totalShapes) {
      handleAllClean();
    }
  }

  /** Handles the All Clean state with big celebration. */
  function handleAllClean(): void {
    allClean = true;
    celebrating = true;
    celebrationTimer = CELEBRATION_PAUSE;

    // Mark all shapes as celebrating
    for (const shape of shapes) {
      if (shape.state === 'revealed') {
        shape.state = 'celebrating';
      }
    }

    // Big celebration effects
    const cx = context.viewport.width / 2;
    const cy = context.viewport.height / 2;
    context.celebration.milestone(cx, cy, 'large');
    context.celebration.celebrationSound('fanfare');

    // Multi-position confetti bursts
    createConfettiBurst(scene, new Vector3(-2, 1.5, -1), new Color(1, 1, 0), new Color('#FF00FF'), 40);
    createConfettiBurst(scene, new Vector3(2, 1.5, 1), new Color('#64B5F6'), new Color(0, 1, 0), 40);
    createConfettiBurst(scene, new Vector3(0, 2, 0), new Color('#FFB74D'), new Color(1, 0, 0), 50);
  }

  // -- IMiniGame implementation --

  const game: IMiniGame = {
    id: 'clean-the-mess',

    async setup(): Promise<void> {
      env = setupScene(scene);
    },

    start(): void {
      currentRound = 1;
      celebrating = false;
      celebrationTimer = 0;
      allClean = false;
      time = 0;
      started = true;

      context.score.reset();
      context.combo.reset();

      // Combo streak celebration
      unsubCombo = context.combo.onComboChanged((streak: number) => {
        if (streak >= 3 && streak % 2 === 0) {
          createSparkleBurst(scene, new Vector3(0, 1.5, 0), new Color(1, 1, 0), 12);
          context.celebration.celebrationSound('chime');
        }
      });

      context.audio.playMusic('playroom-theme');
      spawnRoundShapes();
    },

    update(deltaTime: number): void {
      if (paused || !started) return;

      time += deltaTime;

      // Push texture changes to GPU if dirty
      if (textureDirty && env) {
        env.cleaningSurface.texture.needsUpdate = true;
        textureDirty = false;
      }

      // Handle celebration between rounds
      if (celebrating) {
        celebrationTimer -= deltaTime;

        // Celebrating shapes bounce happily
        for (const shape of shapes) {
          if (shape.state === 'celebrating') {
            updateCelebrationBounce(shape, time);
          }
        }

        if (celebrationTimer <= 0) {
          celebrating = false;
          currentRound++;
          spawnRoundShapes();
        }

        // Still update ambient lighting
        if (env) {
          updateAmbientLighting(env.lights, time, revealedCount, totalShapes);
        }
        return;
      }

      // Animate shapes
      for (const shape of shapes) {
        if (shape.state === 'revealed') {
          const done = updateRevealAnimation(shape, deltaTime);
          if (done) {
            updateIdleBob(shape, time);
          }
        } else if (shape.state === 'celebrating') {
          updateCelebrationBounce(shape, time);
        }
      }

      // Ambient effects
      if (env) {
        updateAmbientLighting(env.lights, time, revealedCount, totalShapes);
      }
    },

    pause(): void {
      paused = true;
    },

    resume(): void {
      paused = false;
    },

    teardown(): void {
      if (unsubCombo) {
        unsubCombo();
        unsubCombo = null;
      }
      context.audio.stopMusic();

      for (const shape of shapes) {
        disposeToy(shape.mesh);
      }
      shapes = [];

      if (env) {
        teardownScene(env);
        env = null;
      }

      started = false;
    },

    onResize(_viewport: ViewportInfo): void {
      // Camera resize handled by camera system
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused || !started) return;

      // During All Clean celebration, tap to advance to next round
      if (allClean && !celebrating) {
        celebrating = true;
        celebrationTimer = 0.1;
        return;
      }

      if (celebrating) return;

      // Scrub at tap point
      const worldPos = eventToMessPlane(event);
      if (worldPos) {
        performScrub(worldPos.x, worldPos.z, event.screenX, event.screenY);
      } else {
        // First-tap fallback: sparkle even if no hit
        const fallbackPos = new Vector3(
          (event.screenX / context.viewport.width - 0.5) * 8,
          0.5,
          (0.5 - event.screenY / context.viewport.height) * 6,
        );
        createSparkleBurst(scene, fallbackPos, new Color(1, 1, 1), 6);
        context.celebration.celebrationSound('pop');
      }
    },

    onDrag(event: MiniGameDragEvent): void {
      if (paused || celebrating || !started) return;

      // Continuous scrubbing on drag
      const worldPos = eventToMessPlane(event);
      if (worldPos) {
        performScrub(worldPos.x, worldPos.z, event.screenX, event.screenY);
      }
    },

    onDragEnd(_event: MiniGameDragEndEvent): void {
      // Nothing needed ΓÇö scrubbing is per-move, not per-drag-complete
    },
  };

  return game;
}

import {
  Scene,
  Mesh,
  Group,
  SphereGeometry,
  BoxGeometry,
  CylinderGeometry,
  TorusGeometry,
  type MeshStandardMaterial,
} from 'three';
import {
  createWoodMaterial,
  createFeltMaterial,
  createGlossyPaintMaterial,
  createPlasticMaterial,
  createRubberMaterial,
  createPaperMaterial,
} from '@app/minigames/shared/materials';
import type { ToyType } from '../types';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';

/**
 * Toy entity lifecycle ΓÇö creation, material assignment, and disposal.
 * Each toy is built from compositional primitives to be visually
 * recognizable, not a generic shape.
 */

/**
 * Returns a PBR material for the given toy using the appropriate factory.
 * @param toyType - The toy type with material kind and color.
 * @param name - Unique material name prefix.
 * @returns A MeshStandardMaterial configured for the toy.
 */
export function createToyPBRMaterial(toyType: ToyType, name: string): MeshStandardMaterial {
  const matName = `${name}_mat`;
  switch (toyType.materialKind) {
    case 'glossyPaint':
      return createGlossyPaintMaterial(matName, toyType.color) as MeshStandardMaterial;
    case 'wood':
      return createWoodMaterial(matName, toyType.color) as MeshStandardMaterial;
    case 'felt':
      return createFeltMaterial(matName, toyType.color) as MeshStandardMaterial;
    case 'rubber':
      return createRubberMaterial(matName, toyType.color) as MeshStandardMaterial;
    case 'paper':
      return createPaperMaterial(matName, toyType.color) as MeshStandardMaterial;
    case 'plastic':
    default:
      return createPlasticMaterial(matName, toyType.color) as MeshStandardMaterial;
  }
}

// ΓöÇΓöÇ Individual toy builders ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Builds a ball mesh ΓÇö sphere with two stripe rings. */
function buildBall(scene: Scene, name: string, mat: MeshStandardMaterial): Mesh {
  const root = new Mesh(new SphereGeometry(0.2, 12, 12), mat);
  root.name = `${name}_body`;
