/** Builds a block mesh ΓÇö box with a star decal on one face. */
function buildBlock(scene: Scene, name: string, mat: MeshStandardMaterial): Mesh {
  const root = new Mesh(new BoxGeometry(0.35, 0.35, 0.35), mat);
  root.name = `${name}_body`;
  scene.add(root);

  const star = buildStarShape(scene, `${name}_decal`, 0.12);
  const decalMat = createPlasticMaterial(
    `${name}_decal_mat`,
    mat.color.clone().multiplyScalar(1.3),
  ) as MeshStandardMaterial;
  star.traverse((child) => {
    if ((child as Mesh).isMesh) (child as Mesh).material = decalMat;
  });
  star.position.z = -0.18;
  root.add(star);

  return root;
