/** Builds a star shape from 5 elongated boxes rotated 72 deg apart. */
function buildStarShape(_scene: Scene, name: string, radius: number): Group {
  const root = new Group();
  root.name = `${name}_root`;
  for (let i = 0; i < 5; i++) {
    const ray = new Mesh(new BoxGeometry(radius * 0.3, radius * 2, radius * 0.15));
    ray.name = `${name}_r${i}`;
    ray.rotation.z = (i * Math.PI * 2) / 5;
    root.add(ray);
  }
  return root;
}

/** Builds a star toy mesh ΓÇö star shape with plastic material. */
function buildStar(scene: Scene, name: string, mat: MeshStandardMaterial): Mesh {
  const star = buildStarShape(scene, name, 0.15);
  star.traverse((child) => {
    if ((child as Mesh).isMesh) {
      (child as Mesh).material = mat;
    }
  });
  scene.add(star);
  return star as unknown as Mesh;
}

/** Builds a train mesh ΓÇö long body + smokestack + wheels + cabin. */
function buildTrain(scene: Scene, name: string, mat: MeshStandardMaterial): Mesh {
  const root = new Group();
  root.name = `${name}_root`;
  scene.add(root);

  const body = new Mesh(new BoxGeometry(0.5, 0.15, 0.18), mat);
  body.name = `${name}_body`;
  root.add(body);

  const cabin = new Mesh(new BoxGeometry(0.15, 0.12, 0.16), mat);
  cabin.name = `${name}_cabin`;
  cabin.position.set(-0.17, 0.135, 0);
  root.add(cabin);

  const stackMat = createPlasticMaterial(
    `${name}_stack_mat`,
    mat.color.clone().multiplyScalar(0.3),
  ) as MeshStandardMaterial;
  const stack = new Mesh(new CylinderGeometry(0.03, 0.03, 0.12, 8), stackMat);
  stack.name = `${name}_stack`;
  stack.position.set(0.15, 0.135, 0);
  root.add(stack);

  const wheelMat = createRubberMaterial(
    `${name}_wheel_mat`,
    mat.color.clone().multiplyScalar(0.2),
  ) as MeshStandardMaterial;
  const wheelXs = [-0.17, -0.05, 0.07, 0.19];
  for (let i = 0; i < wheelXs.length; i++) {
    for (let side = 0; side < 2; side++) {
      const w = new Mesh(new CylinderGeometry(0.04, 0.04, 0.03, 8), wheelMat);
      w.name = `${name}_w${i}_${side}`;
      w.rotation.x = Math.PI / 2;
      w.position.set(wheelXs[i], -0.07, side === 0 ? 0.1 : -0.1);
      root.add(w);
    }
  }

  return root as unknown as Mesh;
}

/** Map toy IDs to their builder functions. */
const TOY_BUILDERS: Record<string, (scene: Scene, name: string, mat: MeshStandardMaterial) => Mesh> = {
  ball: buildBall,
  block: buildBlock,
  car: buildCar,
  doll: buildDoll,
  plane: buildPlane,
  boat: buildBoat,
  bear: buildBear,
  duck: buildDuck,
  robot: buildRobot,
  dinosaur: buildDinosaur,
  star: buildStar,
  train: buildTrain,
};

/**
 * Creates a compositional toy mesh for the given toy type with PBR materials.
 * @param scene - The Three.js scene.
 * @param toyType - The type definition with ID, color, and material kind.
 * @param name - The mesh name.
 * @returns The created Mesh.
 */
export function createToyMesh(scene: Scene, toyType: ToyType, name: string): Mesh {
  const mat = createToyPBRMaterial(toyType, name);
  const builder = TOY_BUILDERS[toyType.id];
  if (builder) {
    return builder(scene, name, mat);
  }
  // Fallback: simple sphere
  const mesh = new Mesh(new SphereGeometry(0.2, 12, 12), mat);
  mesh.name = name;
  scene.add(mesh);
  return mesh;
}

/**
 * Disposes a toy mesh, its children, and all associated materials.
 * @param mesh - The toy mesh to dispose.
 */
export function disposeToy(mesh: Mesh): void {
  disposeMeshDeep(mesh);
}

import { Scene, Color, Vector3, type Mesh, type MeshStandardMaterial } from 'three';
import type { IMiniGame, MiniGameContext, MiniGameTapEvent, ViewportInfo } from '../../framework/types';
import { createSparkleBurst, createConfettiBurst } from '@app/minigames/shared/particleFx';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';
import {
  COLORS,
  EASEL_BG_COLOR,
  NEXT_PROMPT_DELAY,
  ROUND_PAUSE_DURATION,
  MATCH_POINTS,
  DIMMED_ALPHA,
  RECENT_TARGET_LIMIT,
} from './types';
import { randomInt, shuffle, getRoundConfig } from './helpers';
import {
  createTargetSwatch,
  createChoiceSwatches,
  updateFlipAnimation,
  updateShakeAnimation,
  updateBloomAnimation,
  type FlipState,
  type ShakeState,
  type BloomState,
} from './swatches';
import { setupScene, teardownScene, type SceneEnvironment } from './environment';

/**
 * Creates the Color Match mini-game.
 * Players tap swatches on a craft table to match the target color shown on an easel.
 * Features combo tracking, scoring, round progression, and increasing difficulty.
 * @param context - Shell-provided context with shared systems.
 * @returns An IMiniGame implementation for the color-match game.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  // ΓöÇΓöÇ Scene environment ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let env: SceneEnvironment | null = null;

  // ΓöÇΓöÇ Target swatch on easel ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let targetSwatch: Mesh | null = null;
  let targetMaterial: MeshStandardMaterial | null = null;

  // ΓöÇΓöÇ Choice swatches on craft table ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let choiceSwatches: Mesh[] = [];
  let choiceMaterials: MeshStandardMaterial[] = [];

  // ΓöÇΓöÇ Game state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let paused = false;
  let currentRound = 1;
  let matchesThisRound = 0;
  let matchesNeeded = 8;
  let targetColorIdx = -1;
  let choiceColorIndices: number[] = [];
  const dimmedChoices = new Set<number>();
  const recentTargets: number[] = [];

  // ΓöÇΓöÇ Animation state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  let flipState: FlipState | null = null;
  let shakeState: ShakeState | null = null;
  let bloomState: BloomState | null = null;
  let nextPromptTimer = -1;
  let roundPauseTimer = -1;
  let waitingForNextPrompt = false;
  let waitingForRoundPause = false;

  // ΓöÇΓöÇ Orchestration helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /** Picks a target color index that avoids recent repeats. */
  function pickTargetColor(poolSize: number): number {
    const available: number[] = [];
    for (let i = 0; i < poolSize; i++) {
      if (!recentTargets.includes(i)) {
        available.push(i);
      }
    }
    if (available.length === 0) {
      return randomInt(poolSize);
    }
    return available[randomInt(available.length)];
  }

  /** Sets up a new match prompt: picks target, assigns choice colors, starts flip. */
  function showNextPrompt(): void {
    waitingForNextPrompt = false;
    dimmedChoices.clear();

    const config = getRoundConfig(currentRound);

    targetColorIdx = pickTargetColor(config.poolSize);
    recentTargets.push(targetColorIdx);
    if (recentTargets.length > RECENT_TARGET_LIMIT) {
      recentTargets.shift();
    }

    // Build choice indices: must include the target
    const pool: number[] = [];
    for (let i = 0; i < config.poolSize; i++) {
      if (i !== targetColorIdx) pool.push(i);
    }
    shuffle(pool);

    choiceColorIndices = [targetColorIdx, ...pool.slice(0, config.choiceCount - 1)];
    shuffle(choiceColorIndices);

    // Ensure we have the right number of swatches
    if (choiceSwatches.length !== config.choiceCount) {
      const result = createChoiceSwatches(scene, config.choiceCount, choiceSwatches, choiceMaterials);
      choiceSwatches = result.choiceSwatches;
      choiceMaterials = result.choiceMaterials;
    }

    // Apply colors to choices
    for (let i = 0; i < choiceColorIndices.length; i++) {
      choiceMaterials[i].color.copy(COLORS[choiceColorIndices[i]].color);
      choiceMaterials[i].opacity = 1;
      choiceMaterials[i].transparent = false;
    }

    // Set target color (revealed by flip)
    if (targetMaterial) {
      targetMaterial.color.copy(COLORS[targetColorIdx].color);
    }

    // Reset easel background
    if (env) {
      env.easelBackgroundMat.color.copy(EASEL_BG_COLOR);
      env.easelBackgroundMat.emissive.set(0, 0, 0);
    }

    // Start flip animation
    flipState = { timer: 0 };
    if (targetSwatch) {
      targetSwatch.rotation.y = Math.PI;
    }
  }

  /** Advances to the next round with celebration. */
  function advanceRound(): void {
    currentRound++;
    matchesThisRound = 0;
    matchesNeeded = getRoundConfig(currentRound).matchesNeeded;

    waitingForRoundPause = true;
    roundPauseTimer = 0;

    createConfettiBurst(scene, new Vector3(0, 2.8, -1.93), new Color(1, 0.85, 0.2), new Color(0.27, 0.53, 1), 60);
    context.celebration.milestone((context.viewport.width ?? 400) / 2, (context.viewport.height ?? 400) / 2, 'large');
  }

  /** Handles a correct color match: score, effects, and state transition. */
  function handleCorrectMatch(swatchIdx: number, screenX: number, screenY: number): void {
    context.combo.registerHit();
    context.score.addPoints(MATCH_POINTS);

    context.celebration.confetti(screenX, screenY, 'medium');
    context.celebration.celebrationSound('chime');

    createSparkleBurst(scene, choiceSwatches[swatchIdx].position.clone(), COLORS[choiceColorIndices[swatchIdx]].color);

    // Start bloom animation
    bloomState = { timer: 0, targetColor: COLORS[choiceColorIndices[swatchIdx]].color.clone() };

    matchesThisRound++;
    waitingForNextPrompt = true;
    nextPromptTimer = 0;
  }

  /** Handles a wrong color match: shake and dim. */
  function handleWrongMatch(swatchIdx: number): void {
    context.combo.breakCombo();

    shakeState = { timer: 0, swatchIdx, originalX: choiceSwatches[swatchIdx].position.x };

    dimmedChoices.add(swatchIdx);
    choiceMaterials[swatchIdx].opacity = DIMMED_ALPHA;
    choiceMaterials[swatchIdx].transparent = true;
  }

  // ΓöÇΓöÇ IMiniGame implementation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const game: IMiniGame = {
    id: 'color-match',

    async setup(): Promise<void> {
      env = setupScene(scene);

      const targetResult = createTargetSwatch(scene);
      targetSwatch = targetResult.targetSwatch;
      targetMaterial = targetResult.targetMaterial;
    },

    start(): void {
      paused = false;
      currentRound = 1;
      matchesThisRound = 0;
      matchesNeeded = 8;
      dimmedChoices.clear();
      recentTargets.length = 0;
      waitingForNextPrompt = false;
      waitingForRoundPause = false;
      flipState = null;
      shakeState = null;
      bloomState = null;
      nextPromptTimer = -1;
      roundPauseTimer = -1;

      // Reset framework systems
      context.score.reset();
      context.combo.reset();

      // Start background music
      context.audio.playMusic('art-studio-theme');

      const config = getRoundConfig(currentRound);
      const result = createChoiceSwatches(scene, config.choiceCount, choiceSwatches, choiceMaterials);
      choiceSwatches = result.choiceSwatches;
      choiceMaterials = result.choiceMaterials;
      showNextPrompt();
    },

    update(deltaTime: number): void {
      if (paused) return;

      // Round pause countdown
      if (waitingForRoundPause) {
        roundPauseTimer += deltaTime;
        if (roundPauseTimer >= ROUND_PAUSE_DURATION) {
          waitingForRoundPause = false;
          roundPauseTimer = -1;
          const config = getRoundConfig(currentRound);
          const result = createChoiceSwatches(scene, config.choiceCount, choiceSwatches, choiceMaterials);
          choiceSwatches = result.choiceSwatches;
          choiceMaterials = result.choiceMaterials;
          showNextPrompt();
        }
        return;
      }

      // Next prompt countdown
      if (waitingForNextPrompt) {
        nextPromptTimer += deltaTime;
        if (nextPromptTimer >= NEXT_PROMPT_DELAY) {
          nextPromptTimer = -1;
          if (matchesThisRound >= matchesNeeded) {
            advanceRound();
          } else {
            showNextPrompt();
          }
        }
      }

      // Flip animation
      if (flipState && targetSwatch) {
        if (updateFlipAnimation(flipState, targetSwatch, deltaTime)) {
          flipState = null;
        }
      }

      // Shake animation
      if (shakeState && shakeState.swatchIdx < choiceSwatches.length) {
        if (updateShakeAnimation(shakeState, choiceSwatches, deltaTime)) {
          shakeState = null;
        }
      }

      // Bloom animation
      if (bloomState && env) {
        if (updateBloomAnimation(bloomState, env.easelBackgroundMat, deltaTime)) {
          bloomState = null;
        }
      }
    },

    pause(): void {
      paused = true;
    },

    resume(): void {
      paused = false;
    },

    teardown(): void {
      // Stop background music
      context.audio.stopMusic();

      // Dispose choice swatches
      for (const mesh of choiceSwatches) disposeMeshDeep(mesh);
      for (const mat of choiceMaterials) mat.dispose();
      choiceSwatches.length = 0;
      choiceMaterials.length = 0;
      choiceColorIndices.length = 0;
      dimmedChoices.clear();
      recentTargets.length = 0;

      // Dispose target swatch
      if (targetSwatch) {
        disposeMeshDeep(targetSwatch);
        targetSwatch = null;
      }
      if (targetMaterial) {
        targetMaterial.dispose();
        targetMaterial = null;
      }

      // Dispose environment
      if (env) {
        teardownScene(env);
        env = null;
      }
    },

    onResize(_viewport: ViewportInfo): void {
      // Camera resize handled by camera system
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused || waitingForNextPrompt || waitingForRoundPause) return;
      if (flipState) return; // Don't accept taps during flip

      const pickResult = event.pickResult;
      if (!pickResult?.hit || !pickResult.pickedMesh) return;

      const pickedMesh = pickResult.pickedMesh as Mesh;

      for (let i = 0; i < choiceSwatches.length; i++) {
        if (choiceSwatches[i] === pickedMesh) {
          if (dimmedChoices.has(i)) return;

          if (choiceColorIndices[i] === targetColorIdx) {
            handleCorrectMatch(i, event.screenX, event.screenY);
          } else {
            handleWrongMatch(i);
          }
          return;
        }
      }
    },
  };

  return game;
}

import { Scene, Vector3, type Mesh } from 'three';
import type { MiniGameContext, MiniGameTapEvent, MiniGameDragEvent } from '../../framework/types';
import type { FloatingToy } from './types';
import { DRAG_SPLASH_INTERVAL } from './types';
import type { ElephantParts } from './elephant';
import { aimTrunkAt, elephantWiggle, isElephantMesh } from './elephant';
import { bounceToy, findToyByMesh } from './toys';
import { createSplashEffect, type SplashDeps } from './splashEffects';

/** Dependencies injected from the game closure for interaction handling. */
export interface InteractionDeps {
  scene: Scene;
  context: MiniGameContext;
  elephantParts: ElephantParts | null;
  waterPlane: Mesh | null;
  toys: FloatingToy[];
  splashDeps: SplashDeps;
}

/** Mutable drag state tracked across drag events. */
export interface DragState {
  lastDragPos: Vector3 | null;
}

/**
 * Creates initial drag state.
 * @returns Fresh DragState.
 */
export function createDragState(): DragState {
  return { lastDragPos: null };
}

/** Converts a PickResult point ({x,y,z}) to a Three.js Vector3. */
function toVec3(p: { x: number; y: number; z: number }): Vector3 {
  return new Vector3(p.x, p.y, p.z);
}

/**
 * Handles a tap event: elephant tap, toy tap, or water tap.
 * @param deps - Interaction dependencies.
 * @param event - The tap event.
 */
export function handleTap(deps: InteractionDeps, event: MiniGameTapEvent): void {
  const { context, elephantParts, waterPlane, toys, splashDeps } = deps;

  const pickResult = event.pickResult;
  if (!pickResult?.hit || !pickResult.pickedMesh) return;

  const pickedMesh = pickResult.pickedMesh as Mesh;
  const pickedPoint = pickResult.point ? toVec3(pickResult.point) : null;

  // Tap on elephant
  if (elephantParts && isElephantMesh(pickedMesh, elephantParts.elephantRoot)) {
    elephantWiggle(elephantParts);
    context.celebration.celebrationSound('splash');
    return;
  }

  // Tap on a floating toy directly
  const toy = findToyByMesh(pickedMesh, toys);
  if (toy) {
    if (elephantParts) aimTrunkAt(elephantParts.trunkParent, toy.mesh.position);
    bounceToy(toy, true);
    context.audio.playSound('sfx_shared_reward_star');
    if (pickedPoint) {
      createSplashEffect(splashDeps, pickedPoint, true);
    }
    return;
  }

  // Tap on water ΓÇö foot stomp radial splash
  if (pickedMesh === waterPlane && pickedPoint) {
    if (elephantParts) aimTrunkAt(elephantParts.trunkParent, pickedPoint);
    createSplashEffect(splashDeps, pickedPoint, false);
    context.celebration.celebrationSound('splash');
  }
}

/**
 * Handles a drag event: aim trunk and create trailing splashes.
 * @param deps - Interaction dependencies.
 * @param dragState - Mutable drag state.
 * @param event - The drag event.
 */
export function handleDrag(deps: InteractionDeps, dragState: DragState, event: MiniGameDragEvent): void {
  const { elephantParts, splashDeps } = deps;

  const pickResult = event.pickResult;
  if (!pickResult?.hit || !pickResult.point) return;

  const worldPos = toVec3(pickResult.point);
  if (elephantParts) aimTrunkAt(elephantParts.trunkParent, worldPos);

  if (dragState.lastDragPos) {
    const dist = dragState.lastDragPos.distanceTo(worldPos);
    if (dist >= DRAG_SPLASH_INTERVAL) {
      createSplashEffect(splashDeps, worldPos, false);
      dragState.lastDragPos = worldPos.clone();
    }
  } else {
    dragState.lastDragPos = worldPos.clone();
    createSplashEffect(splashDeps, worldPos, false);
  }
}

