/**
 * Builds a realistic apple mesh with a glossy red body and a small green stem.
 * @param scene - The Three.js scene.
 * @param name - Unique mesh name prefix.
 * @returns A parent Group representing the apple.
 */
export function buildApple(scene: Scene, name: string): Mesh {
  const root = new Group() as unknown as Mesh;
  root.name = `${name}_root`;

  const bodyGeo = new SphereGeometry(0.3 / 2, 12, 12);
  const body = new Mesh(bodyGeo, createGlossyPaintMaterial(`${name}_mat`, new Color(0.9, 0.12, 0.1)));
  body.name = name;
  root.add(body);

  // Small brown stem on top
  const stemGeo = new CylinderGeometry(0.01 / 2, 0.02 / 2, 0.08);
  const stem = new Mesh(stemGeo, createWoodMaterial(`${name}_stemMat`, new Color(0.4, 0.25, 0.1)));
  stem.name = `${name}_stem`;
  stem.position.set(0, 0.16, 0);
  root.add(stem);

  // Tiny green leaf at stem
  const leafGeo = new SphereGeometry(0.05 / 2, 6, 6);
  const leaf = new Mesh(leafGeo, createLeafMaterial(`${name}_leafMat`, new Color(0.2, 0.6, 0.15)));
  leaf.name = `${name}_leaf`;
  leaf.scale.set(0.5, 0.3, 1.2);
  leaf.position.set(0.02, 0.17, 0.02);
  root.add(leaf);

  scene.add(root);
  return root;
}

/**
 * Builds a realistic carrot mesh ΓÇö orange tapered body with green leafy top.
 * @param scene - The Three.js scene.
 * @param name - Unique mesh name prefix.
 * @returns A parent Group representing the carrot.
 */
export function buildCarrot(scene: Scene, name: string): Mesh {
  const root = new Group() as unknown as Mesh;
  root.name = `${name}_root`;

  const bodyGeo = new CylinderGeometry(0.04 / 2, 0.18 / 2, 0.45);
  const body = new Mesh(bodyGeo, createGlossyPaintMaterial(`${name}_mat`, new Color(1.0, 0.5, 0.08)));
  body.name = name;
  root.add(body);

  // Green leafy top ΓÇö three small tapered cylinders fanning out
  for (let i = 0; i < 3; i++) {
    const topLeafGeo = new CylinderGeometry(0.005 / 2, 0.025 / 2, 0.15);
    const topLeaf = new Mesh(topLeafGeo, createLeafMaterial(`${name}_topMat_${i}`, new Color(0.15, 0.6, 0.1)));
    topLeaf.name = `${name}_top_${i}`;
    const angle = ((i - 1) * Math.PI) / 6;
    topLeaf.position.set(Math.sin(angle) * 0.015, 0.28, Math.cos(angle) * 0.015);
    topLeaf.rotation.z = angle * 0.5;
    root.add(topLeaf);
  }

  scene.add(root);
  return root;
}

/**
 * Builds a glossy berry mesh with a small crown of tiny bumps.
 * @param scene - The Three.js scene.
 * @param name - Unique mesh name prefix.
 * @returns A parent Group representing the berry.
 */
export function buildBerry(scene: Scene, name: string): Mesh {
  const root = new Group() as unknown as Mesh;
  root.name = `${name}_root`;

  const bodyGeo = new SphereGeometry(0.18 / 2, 10, 10);
  const mat = createGlossyPaintMaterial(`${name}_mat`, new Color(0.5, 0.1, 0.55));
  mat.emissive = new Color(0.08, 0.01, 0.09);
  const body = new Mesh(bodyGeo, mat);
  body.name = name;
  root.add(body);

  // Small crown bumps at the top
  for (let i = 0; i < 4; i++) {
    const bumpGeo = new SphereGeometry(0.03 / 2, 6, 6);
