/**
 * Builds a watermelon slice mesh ΓÇö green rind with red interior and dark seed dots.
 * @param scene - The Three.js scene.
 * @param name - Unique mesh name prefix.
 * @returns A parent Group representing the watermelon slice.
 */
export function buildWatermelon(scene: Scene, name: string): Mesh {
  const root = new Group() as unknown as Mesh;
  root.name = `${name}_root`;

  // Outer rind ΓÇö green sphere
  const rindGeo = new SphereGeometry(0.32 / 2, 12, 12);
