  // Inner flesh ΓÇö slightly smaller red sphere peeking through
  const fleshGeo = new SphereGeometry(0.26 / 2, 10, 10);
  const fleshMat = createGlossyPaintMaterial(`${name}_fleshMat`, new Color(0.9, 0.15, 0.15));
  fleshMat.emissive = new Color(0.1, 0.01, 0.01);
  const flesh = new Mesh(fleshGeo, fleshMat);
  flesh.name = `${name}_flesh`;
  flesh.position.set(0, 0.04, 0);
