  // Dark stripe ring
  const stripeGeo = new TorusGeometry(0.32 / 2, 0.03 / 2, 16, 16);
  const stripe = new Mesh(stripeGeo, createGlossyPaintMaterial(`${name}_stripeMat`, new Color(0.08, 0.35, 0.1)));
  stripe.name = `${name}_stripe`;
