    seed.name = `${name}_seed_${i}`;
    const a = ((i - 1) * Math.PI) / 4;
    seed.position.set(Math.cos(a) * 0.06, 0.12, Math.sin(a) * 0.06);
    root.add(seed);
  }

  scene.add(root);
  return root;
}

/** Food definitions with detailed builder functions. */
export const FOODS: readonly FoodDef[] = [
  { name: 'apple', build: buildApple },
  { name: 'carrot', build: buildCarrot },
  { name: 'berry', build: buildBerry },
  { name: 'banana', build: buildBanana },
  { name: 'leaf', build: buildLeafFood },
  { name: 'cookie', build: buildCookie },
  { name: 'acorn', build: buildAcorn },
  { name: 'watermelon', build: buildWatermelon },
];

/**
 * Creates a detailed food mesh using the food definition's builder function.
 * @param foodDef - The food type definition.
 * @returns A Mesh for the food item.
 */
export function buildFoodMesh(scene: Scene, foodDef: FoodDef, foodIdCounter: { value: number }): Mesh {
  const id = foodIdCounter.value++;
  const meshName = `feedAnimal_food_${foodDef.name}_${id}`;
  const mesh = foodDef.build(scene, meshName);
  return mesh;
}

/**
 * Removes and disposes a food item by index.
 * @param idx - Index in the foods array.
 */
export function removeFood(foods: FoodItem[], idx: number): void {
  const item = foods[idx];
  // Dispose child meshes
  item.mesh.traverse((child) => {
    if (child instanceof Mesh) {
      child.geometry?.dispose();
      if (child.material) {
        if (Array.isArray(child.material)) {
          child.material.forEach((m) => m.dispose());
        } else {
          child.material.dispose();
        }
      }
    }
  });
  item.mesh.removeFromParent();
  foods.splice(idx, 1);
}

/**
 * Shows the animal at the given index and hides all others.
 * @param idx - Animal index to show.
 */
export function showAnimal(animalRoots: Mesh[], idx: number): void {
  for (let i = 0; i < animalRoots.length; i++) {
    animalRoots[i].visible = i === idx;
    animalRoots[i].position.copy(ANIMAL_POS);
  }
}

/** Begins the walk-off / walk-in animal swap sequence. */
export function startAnimalTransition(
  currentAnimalIdx: number,
  state: {
    isTransitioning: boolean;
    transitionTimer: number;
    transitionPhase: 'walk-off' | 'walk-in';
    nextAnimalIdx: number;
  },
): void {
  state.isTransitioning = true;
  state.transitionTimer = 0;
  state.transitionPhase = 'walk-off';
  state.nextAnimalIdx = (currentAnimalIdx + 1) % ANIMAL_COUNT;
}

import { type Scene, Mesh, Group, PlaneGeometry, BoxGeometry, Color, Vector3 } from 'three';
import { createFeltMaterial } from '@app/minigames/shared/materials';
