} from '@app/minigames/shared/meshBuilders';
import { BLANKET_CENTER, BLANKET_HALF_W, BLANKET_HALF_D } from './types';

/** Builds the garden ground plane with a felt-like grass material. */
export function buildGround(scene: Scene): Mesh {
  const geo = new PlaneGeometry(20, 20);
  geo.rotateX(-Math.PI / 2);
  const groundMesh = new Mesh(geo, createFeltMaterial('feedAnimal_groundMat', new Color(0.3, 0.65, 0.25)));
  groundMesh.name = 'feedAnimal_ground';
  scene.add(groundMesh);
  return groundMesh;
}

/** Builds the picnic blanket mesh with a felt material. */
export function buildBlanket(scene: Scene, decorMeshes: (Mesh | Group)[]): Mesh {
  const geo = new BoxGeometry(BLANKET_HALF_W * 2, 0.06, BLANKET_HALF_D * 2);
  const blanketMesh = new Mesh(geo, createFeltMaterial('feedAnimal_blanketMat', new Color(0.85, 0.25, 0.25)));
  blanketMesh.name = 'feedAnimal_blanket';
  blanketMesh.position.copy(BLANKET_CENTER);
  scene.add(blanketMesh);

  // White stripe accents on blanket
  for (let i = -1; i <= 1; i += 2) {
    const stripeGeo = new BoxGeometry(0.15, 0.065, BLANKET_HALF_D * 2);
    const stripe = new Mesh(stripeGeo, createFeltMaterial(`feedAnimal_stripeMat_${i}`, new Color(0.95, 0.95, 0.92)));
    stripe.name = `feedAnimal_stripe_${i}`;
    stripe.position.set(BLANKET_CENTER.x + i * 0.8, BLANKET_CENTER.y + 0.005, BLANKET_CENTER.z);
    scene.add(stripe);
    decorMeshes.push(stripe);
  }

  return blanketMesh;
}

/** Builds the background fence using the shared detailed fence builder. */
export function buildFence(scene: Scene, decorMeshes: (Mesh | Group)[]): void {
  const fenceZ = -4.5;
  // Build 3 fence sections spanning the background
  for (let i = 0; i < 3; i++) {
    const xPos = (i - 1) * 3.8;
    const fence = buildDetailedFence(new Vector3(xPos, 0, fenceZ), 3.5);
    scene.add(fence);
    decorMeshes.push(fence);
  }
}

/** Builds decorative flowers and grass tufts using shared mesh builders. */
export function buildFlowersAndGrass(scene: Scene, decorMeshes: (Mesh | Group)[]): void {
  const flowerPositions = [
    new Vector3(-4, 0, -3),
    new Vector3(-3.5, 0, -3.8),
    new Vector3(3.5, 0, -3.2),
    new Vector3(4.2, 0, -3.6),
    new Vector3(-4.5, 0, 1),
    new Vector3(4.8, 0, 0.5),
  ];
  const flowerColors = [
    new Color(1, 0.4, 0.5),
    new Color(1, 0.85, 0.2),
    new Color(0.6, 0.4, 1),
    new Color(1, 0.6, 0.8),
    new Color(0.4, 0.7, 1),
    new Color(1, 0.5, 0.2),
  ];
  for (let i = 0; i < flowerPositions.length; i++) {
    const flower = buildDetailedFlower(flowerPositions[i], flowerColors[i], 0.5);
    scene.add(flower);
    decorMeshes.push(flower);
  }

  // Scatter grass tufts around the scene edges
  const grassPositions = [
    new Vector3(-3, 0, -2),
    new Vector3(-2.5, 0, 0.5),
    new Vector3(3.2, 0, -1.5),
    new Vector3(2.8, 0, 1.2),
    new Vector3(-4.2, 0, -1),
    new Vector3(4.5, 0, -0.5),
    new Vector3(-1.5, 0, -3.5),
    new Vector3(1.8, 0, -3.8),
  ];
  for (const pos of grassPositions) {
    const tuft = buildGrassTuft(pos);
    scene.add(tuft);
    decorMeshes.push(tuft);
  }
}

/** Builds a storybook sky gradient backdrop behind the scene. */
export function buildSky(scene: Scene): Group {
  const skyMesh = buildSkyGradient(new Color(0.45, 0.7, 0.95), new Color(0.75, 0.9, 0.98), 22);
  skyMesh.position.set(0, 3, 0);
  scene.add(skyMesh);
  return skyMesh;
}

/** Creates an invisible pick plane for projecting drag coordinates. */
export function buildPickPlane(scene: Scene): Mesh {
  const geo = new PlaneGeometry(30, 30);
  geo.rotateX(-Math.PI / 2);
  const pickPlane = new Mesh(geo);
  pickPlane.name = 'feedAnimal_pickPlane';
  pickPlane.position.y = 0.5;
  pickPlane.visible = false;
  scene.add(pickPlane);
  return pickPlane;
}

/**
 * Procedural audio for the Fireflies mini-game.
 *
 * - Pentatonic catch chimes (each catch plays a note; combos build chords)
 * - Ambient nighttime soundscape (crickets, wind) that layers with illumination tiers
 * - Tier transition ascending chimes
 * - Tap-empty-space sparkle sound
 *
 * All synthesis uses Web Audio API directly. Sounds route through the shared
 * audio engine when available, or create a standalone AudioContext.
 */

import { getCtx, getSfxGain } from '@app/assets/audio/utils/audioEngine';
import {
  playTone,
  playFilteredNoiseBurst,
  playFreqSweep,
  pentatonicScale,
  midiToFreq,
  rand,
  createPinkNoiseBuffer,
} from '@app/assets/audio/utils/synthHelpers';

// ΓöÇΓöÇ Pentatonic scale: C5 root for bright, bell-like chimes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** MIDI notes for C5 pentatonic: C5(72), D5(74), E5(76), G5(79), A5(81). */
const PENTATONIC = pentatonicScale(72);

/** Frequencies pre-computed for the 5 pentatonic notes. */
const CHIME_FREQS = PENTATONIC.map(midiToFreq);

/** Perfect fifth interval (7 semitones up) for golden firefly. */
const GOLDEN_INTERVAL = 7;

// ΓöÇΓöÇ Ambient state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Target ambient volume per illumination tier (0-5). */
const AMBIENT_TIER_VOLUME = [0.0, 0.0, 0.02, 0.04, 0.06, 0.08];

/** Cricket chirp rate per tier (chirps per second). */
const CRICKET_RATE = [0, 0, 2, 4, 6, 8];

export interface FirefliesAudio {
  /** Play a catch chime ΓÇö picks a random pentatonic note. */
  playCatchChime(): void;
  /** Play the golden firefly catch (root + fifth). */
  playGoldenCatch(): void;
  /** Play a soft sparkle for tapping empty space. */
  playTapSparkle(): void;
  /** Play ascending chime when illumination tier changes. */
  playTierTransition(newTier: number): void;
  /** Update ambient soundscape for current tier (call each frame). */
  updateAmbient(tier: number, deltaTime: number): void;
  /** Start the ambient soundscape loops. */
  start(): void;
  /** Stop and dispose all audio resources. */
  dispose(): void;
}

/**
 * Creates the fireflies audio system.
 *
 * @param isMuted - Function returning true when audio should be suppressed.
 * @returns A FirefliesAudio controller.
 */
export function createFirefliesAudio(isMuted: () => boolean): FirefliesAudio {
  let disposed = false;
  let ambientGain: GainNode | null = null;
  let windSource: AudioBufferSourceNode | null = null;
  let cricketTimer = 0;
  let currentAmbientVolume = 0;
  let lastTier = -1;

  /** Gets the shared AudioContext, or null if unavailable. */
  function ctx(): AudioContext | null {
    return getCtx();
  }

  /** Gets the SFX destination gain node. */
  function dest(): AudioNode | null {
    return getSfxGain();
  }

  /**
   * Plays a bell-like chime at the given frequency.
   * Uses fundamental + 2nd and 3rd harmonics for richness.
   */
  function playBellChime(frequency: number, volume: number, time?: number): void {
    const c = ctx();
    const d = dest();
    if (!c || !d || isMuted()) return;

    const t = time ?? c.currentTime;
    // Fundamental
    playTone(c, d, 'sine', frequency, 0.008, 0.6, volume, t);
    // 2nd harmonic (octave above, softer)
    playTone(c, d, 'sine', frequency * 2, 0.008, 0.4, volume * 0.3, t);
    // 3rd harmonic (very subtle)
    playTone(c, d, 'sine', frequency * 3, 0.005, 0.25, volume * 0.1, t);
  }

  /** Plays a single cricket chirp (short filtered noise burst at high frequency). */
  function playCricketChirp(): void {
    const c = ctx();
    if (!c || !ambientGain || isMuted()) return;

    const freq = rand(4000, 6500);
    const t = c.currentTime + rand(0, 0.05);
    // Two rapid bursts = cricket chirp pattern
    playFilteredNoiseBurst(c, ambientGain, freq, 8, 0.003, 0.025, 0.06, t);
    playFilteredNoiseBurst(c, ambientGain, freq * 1.02, 8, 0.003, 0.025, 0.04, t + 0.04);
  }

  /** Starts the continuous low wind sound. */
  function startWind(): void {
    const c = ctx();
    if (!c || !ambientGain) return;

    const buffer = createPinkNoiseBuffer(c, 4.0);
    const source = c.createBufferSource();
    source.buffer = buffer;
    source.loop = true;

    const filter = c.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 250;
    filter.Q.value = 0.5;

    const windGain = c.createGain();
    windGain.gain.value = 0.015;

    source.connect(filter).connect(windGain).connect(ambientGain);
    source.start();
    windSource = source;
  }

  return {
    playCatchChime(): void {
      if (isMuted()) return;
      const noteIdx = Math.floor(Math.random() * CHIME_FREQS.length);
      playBellChime(CHIME_FREQS[noteIdx], 0.12);
    },

    playGoldenCatch(): void {
      if (isMuted()) return;
      const c = ctx();
      if (!c) return;
      const t = c.currentTime;
      // Root note
      playBellChime(CHIME_FREQS[0], 0.15, t);
      // Perfect fifth, slightly delayed for shimmer
      const fifthFreq = midiToFreq(PENTATONIC[0] + GOLDEN_INTERVAL);
      playBellChime(fifthFreq, 0.12, t + 0.06);
    },

    playTapSparkle(): void {
      const c = ctx();
      const d = dest();
      if (!c || !d || isMuted()) return;

      const t = c.currentTime;
      // Soft crystalline tink ΓÇö high sine with very short decay
      playTone(c, d, 'sine', rand(2800, 3500), 0.005, 0.12, 0.06, t);
      playTone(c, d, 'sine', rand(3500, 4200), 0.005, 0.08, 0.03, t + 0.02);
    },

    playTierTransition(newTier: number): void {
      const c = ctx();
      const d = dest();
      if (!c || !d || isMuted() || newTier <= 0) return;

      const t = c.currentTime;
      // Ascending arpeggio ΓÇö play notes up to the tier number
      const notesToPlay = Math.min(newTier, CHIME_FREQS.length);
      for (let i = 0; i < notesToPlay; i++) {
        playBellChime(CHIME_FREQS[i], 0.08, t + i * 0.12);
      }
      // Final shimmer sweep
      playFreqSweep(c, d, 'sine', CHIME_FREQS[0], CHIME_FREQS[notesToPlay - 1] * 2, 0.01, 0.4, 0.04, t + notesToPlay * 0.12);
    },

    updateAmbient(tier: number, deltaTime: number): void {
      if (disposed || !ambientGain) return;

      // Smoothly interpolate ambient volume toward target
      const targetVol = isMuted() ? 0 : AMBIENT_TIER_VOLUME[Math.min(tier, 5)];
      currentAmbientVolume += (targetVol - currentAmbientVolume) * (1 - Math.exp(-deltaTime * 1.5));
      ambientGain.gain.value = currentAmbientVolume;

      // Play tier transition sound on tier change
      if (tier !== lastTier && lastTier >= 0 && tier > lastTier) {
        this.playTierTransition(tier);
      }
      lastTier = tier;

      // Cricket chirps ΓÇö random timing based on tier rate
      const rate = CRICKET_RATE[Math.min(tier, 5)];
      if (rate > 0) {
        cricketTimer += deltaTime;
        const interval = 1.0 / rate + rand(-0.1, 0.1);
        if (cricketTimer >= interval) {
          cricketTimer = 0;
          playCricketChirp();
        }
      }
    },

    start(): void {
      const c = ctx();
      if (!c || disposed) return;

      // Create ambient gain node routed to SFX output
      const d = dest();
      if (!d) return;
      ambientGain = c.createGain();
      ambientGain.gain.value = 0;
      ambientGain.connect(d);

      startWind();
    },

    dispose(): void {
      disposed = true;
      if (windSource) {
        try { windSource.stop(); } catch { /* already stopped */ }
        windSource.disconnect();
        windSource = null;
      }
      if (ambientGain) {
        ambientGain.disconnect();
        ambientGain = null;
      }
    },
  };
}

import {
  type Scene,
  SpriteMaterial,
  Sprite,
  PointLight,
  Vector3,
  AdditiveBlending,
  CanvasTexture,
} from 'three';
import { createFireflyGlow } from '@app/minigames/shared/particleFx';
import type { FireflyData } from './types';
import { FIREFLY_COLOR, GOLDEN_COLOR } from './types';
import { randomRange } from '@app/minigames/shared/mathUtils';
import { randomSpawnPos, randomBehavior } from './helpers';

// ΓöÇΓöÇ Cached glow dot texture ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

let glowDotTexture: CanvasTexture | null = null;

/**
 * Returns a cached 64x64 soft radial glow texture.
 * Bright center fading smoothly to transparent ΓÇö looks like a point of light.
 */
function getGlowDotTexture(): CanvasTexture {
  if (glowDotTexture) return glowDotTexture;
  const size = 64;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d')!;
  const half = size / 2;
  const gradient = ctx.createRadialGradient(half, half, 0, half, half, half);
  gradient.addColorStop(0, 'rgba(255, 255, 255, 1)');
  gradient.addColorStop(0.1, 'rgba(255, 255, 255, 0.9)');
  gradient.addColorStop(0.3, 'rgba(255, 255, 255, 0.4)');
  gradient.addColorStop(0.6, 'rgba(255, 255, 255, 0.08)');
  gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, size, size);
  glowDotTexture = new CanvasTexture(canvas);
  return glowDotTexture;
}

/**
 * Creates a firefly entity as a soft glowing sprite with a point light
 * and particle trail. No 3D mesh ΓÇö fireflies are points of light.
 *
 * @param scene - The Three.js scene.
 * @param index - Index for unique naming.
 * @param isGolden - Whether this is the golden variant.
 * @returns A FireflyData object ready for activation.
 */
export function createFirefly(
  scene: Scene,
  index: number,
  isGolden: boolean,
): FireflyData {
  const baseColor = isGolden ? GOLDEN_COLOR : FIREFLY_COLOR;

  // ΓöÇΓöÇ Sprite: the firefly IS a soft glowing dot ΓöÇΓöÇ
  const spriteSize = isGolden ? 0.45 : 0.3;
  const spriteMaterial = new SpriteMaterial({
    map: getGlowDotTexture(),
    color: baseColor.clone(),
    transparent: true,
    opacity: 0.85,
    blending: AdditiveBlending,
    depthWrite: false,
  });
  const sprite = new Sprite(spriteMaterial);
  sprite.scale.setScalar(spriteSize);
  sprite.name = `nature_firefly_${isGolden ? 'golden' : 'standard'}_${index}`;
  sprite.raycast = () => {}; // hit detection is screen-space, not raycaster
  scene.add(sprite);

  // ΓöÇΓöÇ Point light for local glow illumination ΓöÇΓöÇ
  const light = new PointLight(baseColor.clone(), isGolden ? 0.6 : 0.35, isGolden ? 3.5 : 2.5);
  light.name = `nature_firefly_light_${index}`;
  scene.add(light);

  // ΓöÇΓöÇ Position ΓöÇΓöÇ
  const pos = randomSpawnPos();
  sprite.position.copy(pos);
  light.position.copy(pos);

  // ΓöÇΓöÇ Continuous glow particle trail ΓöÇΓöÇ
  const glowTrail = createFireflyGlow(scene, sprite, baseColor);

  const behavior = randomBehavior();
  const behaviorCenter = randomSpawnPos();
  const behaviorRadius = randomRange(0.8, 1.5);
  const zigzagDir = new Vector3(
    randomRange(-1, 1),
    randomRange(-0.5, 0.5),
    randomRange(-0.5, 0.5),
  ).normalize();

  return {
    sprite,
    spriteMaterial,
    light,
    glowTrail,
    speed: randomRange(0.25, 0.55),
    glowPhase: Math.random() * Math.PI * 2,
    driftOffsetX: Math.random() * Math.PI * 2,
    driftOffsetY: Math.random() * Math.PI * 2,
    driftOffsetZ: Math.random() * Math.PI * 2,
    time: Math.random() * 100,
    isGolden,
    catching: false,
    catchProgress: 0,
    catchStartPos: new Vector3(0, 0, 0),
    flashing: false,
    flashTimer: 0,
    active: true,
    respawnTimer: 0,
    behavior,
    behaviorCenter,
    behaviorAngle: Math.random() * Math.PI * 2,
    behaviorRadius,
    zigzagTimer: randomRange(1.0, 2.0),
    zigzagDir,
  };
}

/**
 * Resets a firefly to a new random position with new drift parameters.
 *
 * @param fd - The firefly data to reset.
 * @param scene - The Three.js scene (needed to re-start the glow trail).
 */
export function resetFirefly(fd: FireflyData, scene: Scene): void {
  const pos = randomSpawnPos();
  fd.sprite.position.copy(pos);
  fd.light.position.copy(pos);
  fd.speed = randomRange(0.25, 0.55);
  fd.glowPhase = Math.random() * Math.PI * 2;
  fd.driftOffsetX = Math.random() * Math.PI * 2;
  fd.driftOffsetY = Math.random() * Math.PI * 2;
  fd.driftOffsetZ = Math.random() * Math.PI * 2;
  fd.time = Math.random() * 100;
  fd.catching = false;
  fd.catchProgress = 0;
  fd.flashing = false;
  fd.flashTimer = 0;
  fd.active = true;
  fd.respawnTimer = 0;
  fd.behavior = randomBehavior();
  fd.behaviorCenter = randomSpawnPos();
  fd.behaviorAngle = Math.random() * Math.PI * 2;
  fd.behaviorRadius = randomRange(0.8, 1.5);
  fd.zigzagTimer = randomRange(1.0, 2.0);
  fd.zigzagDir = new Vector3(
    randomRange(-1, 1),
    randomRange(-0.5, 0.5),
    randomRange(-0.5, 0.5),
  ).normalize();
  fd.sprite.visible = true;
  fd.light.visible = true;
  fd.spriteMaterial.opacity = 0.85;
  fd.glowTrail.start(scene);
}

import {
  type Scene,
  Mesh,
  type Object3D,
  SphereGeometry,
  CylinderGeometry,
  LatheGeometry,
  ShapeGeometry,
  Shape,
  Group,
  RingGeometry,
  MeshStandardMaterial,
  Color,
  Vector2,
  Vector3,
  DoubleSide,
  BufferGeometry,
  Float32BufferAttribute,
  Points,
  PointsMaterial,
  AdditiveBlending,
  CanvasTexture,
} from 'three';
import { createLeafMaterial, createWoodMaterial } from '@app/minigames/shared/materials';
import {
  buildSkyGradient,
  buildDetailedTree,
  buildGrassTuft,
  buildDetailedFlower,
} from '@app/minigames/shared/meshBuilders';
import { JAR_POS, JAR_SCALE } from './types';

export interface EnvironmentResult {
  skyMesh: Object3D;
  groundMesh: Mesh;
  groundMaterial: MeshStandardMaterial;
  jarBody: Mesh;
  jarCap: Mesh;
  jarMaterial: MeshStandardMaterial;
  moonMesh: Mesh;
  moonMaterial: MeshStandardMaterial;
  /** Star field points for twinkling animation. */
  starField: Points;
  starSizes: Float32Array;
  starPhases: Float32Array;
  /** Flower root meshes for traversal by illumination controller. */
  flowerMeshes: Object3D[];
  environmentMeshes: Object3D[];
  allMaterials: MeshStandardMaterial[];
}

/**
 * Creates the environment: sky gradient, ground, jar, trees, grass, flowers, and moon.
 */
export function createEnvironment(scene: Scene): EnvironmentResult {
  const environmentMeshes: Object3D[] = [];
  const allMaterials: MeshStandardMaterial[] = [];

  // Night sky gradient backdrop
  const skyMesh = buildSkyGradient(new Color(0.02, 0.02, 0.08), new Color(0.08, 0.12, 0.2), 30);
  scene.add(skyMesh);
  skyMesh.position.set(0, 4, -10);

  // Ground plane with rounded back corners
  const groundShape = new Shape();
  const gw = 10; // half-width
  const gd = 6;  // half-depth
  const cr = 3;  // corner radius for back corners
  // All four corners rounded, clockwise (in XZ, mapped to XY for shape)
  groundShape.moveTo(-gw + cr, gd);     // front edge start
  groundShape.lineTo(gw - cr, gd);      // front edge
  groundShape.quadraticCurveTo(gw, gd, gw, gd - cr);   // front-right rounded
  groundShape.lineTo(gw, -gd + cr);     // right edge
  groundShape.quadraticCurveTo(gw, -gd, gw - cr, -gd); // back-right rounded
  groundShape.lineTo(-gw + cr, -gd);    // back edge
  groundShape.quadraticCurveTo(-gw, -gd, -gw, -gd + cr); // back-left rounded
  groundShape.lineTo(-gw, gd - cr);     // left edge
  groundShape.quadraticCurveTo(-gw, gd, -gw + cr, gd);   // front-left rounded
  const groundGeo = new ShapeGeometry(groundShape, 8);
  groundGeo.rotateX(-Math.PI / 2);
  const groundMat = createLeafMaterial('meadow_floor_mat', new Color(0.15, 0.25, 0.08));
  groundMat.emissive = new Color(0.05, 0.08, 0.03); // Tier 0: visible ground
  const groundMesh = new Mesh(groundGeo, groundMat);
  groundMesh.name = 'meadow_floor';
  scene.add(groundMesh);
  allMaterials.push(groundMat);

  // Mason jar body ΓÇö LatheGeometry with a proper jar silhouette
  const jarProfile = [
    new Vector2(0.0, 0.0),     // center bottom
    new Vector2(0.5, 0.0),     // base edge
    new Vector2(0.55, 0.08),   // base curve
    new Vector2(0.55, 1.1),    // body wall
    new Vector2(0.52, 1.25),   // shoulder curve inward
    new Vector2(0.42, 1.4),    // shoulder to neck
    new Vector2(0.32, 1.55),   // neck
    new Vector2(0.32, 1.7),    // neck top
    new Vector2(0.38, 1.72),   // lip flare out
    new Vector2(0.38, 1.78),   // lip top outer
    new Vector2(0.30, 1.78),   // lip top inner
    new Vector2(0.30, 1.72),   // lip inner edge
    new Vector2(0.0, 1.72),    // close inner top
  ];
  const jarBodyGeo = new LatheGeometry(jarProfile, 24);
  const jarMaterial = new MeshStandardMaterial({
    name: 'nature_jar_mat',
    color: new Color(0.7, 0.85, 0.9),
    metalness: 0.1,
    roughness: 0.05,
    transparent: true,
    opacity: 0.65,
    side: DoubleSide,
    emissive: new Color(0.16, 0.22, 0.28),
  });
  const jarBody = new Mesh(jarBodyGeo, jarMaterial);
  jarBody.name = 'nature_jar_body';
  jarBody.position.set(JAR_POS.x, JAR_POS.y, JAR_POS.z);
  jarBody.scale.setScalar(JAR_SCALE);
  scene.add(jarBody);
  allMaterials.push(jarMaterial);

  // Cork lid ΓÇö squat cylinder sitting on the jar lip, scaled to match jar
  const jarCapGeo = new CylinderGeometry(0.34, 0.36, 0.2, 16);
  const capMat = createWoodMaterial('nature_jar_cap_mat', new Color(0.55, 0.42, 0.28));
  const jarCap = new Mesh(jarCapGeo, capMat);
  jarCap.name = 'nature_jar_cap';
  jarCap.position.set(JAR_POS.x, JAR_POS.y + 1.88 * JAR_SCALE, JAR_POS.z);
  jarCap.scale.setScalar(JAR_SCALE);
  scene.add(jarCap);
  allMaterials.push(capMat);

  // Detailed storybook trees as backdrop (dark canopies for nighttime)
  const treePositions = [new Vector3(4, 0, -4), new Vector3(6, 0, -3), new Vector3(-5, 0, -5)];
  for (const treePos of treePositions) {
    const tree = buildDetailedTree(treePos, 3.0, new Color(0.25, 0.4, 0.18));
    scene.add(tree);
    environmentMeshes.push(tree);
  }

  // Grass tufts scattered across the meadow
  const grassPositions = [
    new Vector3(-1, 0, 1),
    new Vector3(2, 0, -1),
    new Vector3(-4, 0, 0.5),
    new Vector3(3, 0, 2),
    new Vector3(0, 0, -1.5),
    new Vector3(-2, 0, -0.5),
    new Vector3(5, 0, 0),
    new Vector3(-6, 0, -1),
  ];
  for (const gp of grassPositions) {
    const tuft = buildGrassTuft(gp, new Color(0.3, 0.6, 0.2));
    scene.add(tuft);
    environmentMeshes.push(tuft);
  }

  // Wildflowers dotted among the grass
  const flowerConfigs = [
    { pos: new Vector3(-1.5, 0, 0.8), color: new Color(0.9, 0.3, 0.5) },
    { pos: new Vector3(1.5, 0, -0.5), color: new Color(0.6, 0.4, 0.9) },
    { pos: new Vector3(3.5, 0, 1.5), color: new Color(0.95, 0.75, 0.2) },
    { pos: new Vector3(-3.5, 0, -1.2), color: new Color(0.4, 0.6, 0.95) },
  ];
  for (const fc of flowerConfigs) {
    const flower = buildDetailedFlower(fc.pos, fc.color, 0.35);
    scene.add(flower);
    environmentMeshes.push(flower);
  }

  // Star field ΓÇö scattered across the sky backdrop
  const starCount = 120;
  const starPositions = new Float32Array(starCount * 3);
  const starSizes = new Float32Array(starCount);
  const starPhases = new Float32Array(starCount);
  for (let i = 0; i < starCount; i++) {
    starPositions[i * 3] = (Math.random() - 0.5) * 24;       // x: spread across sky
    starPositions[i * 3 + 1] = 2 + Math.random() * 10;       // y: above ground
    starPositions[i * 3 + 2] = -8 - Math.random() * 4;       // z: behind scene
    starSizes[i] = 0.03 + Math.random() * 0.06;
    starPhases[i] = Math.random() * Math.PI * 2;
  }
  const starGeo = new BufferGeometry();
  starGeo.setAttribute('position', new Float32BufferAttribute(starPositions, 3));

  // Soft dot texture for stars
  const starTexCanvas = document.createElement('canvas');
  starTexCanvas.width = 32;
  starTexCanvas.height = 32;
  const starCtx = starTexCanvas.getContext('2d')!;
  const starGrad = starCtx.createRadialGradient(16, 16, 0, 16, 16, 16);
  starGrad.addColorStop(0, 'rgba(255, 255, 255, 1)');
  starGrad.addColorStop(0.3, 'rgba(255, 255, 255, 0.5)');
  starGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');
  starCtx.fillStyle = starGrad;
  starCtx.fillRect(0, 0, 32, 32);
  const starTexture = new CanvasTexture(starTexCanvas);

  const starMat = new PointsMaterial({
    map: starTexture,
    size: 0.12,
    transparent: true,
    opacity: 0.6,
    blending: AdditiveBlending,
    depthWrite: false,
    color: new Color(0.6, 0.7, 1.0),
    sizeAttenuation: true,
  });
  const starField = new Points(starGeo, starMat);
  starField.name = 'nature_starfield';
  scene.add(starField);

  // Moon ΓÇö starts very dim (Tier 0), illumination controller will brighten it
  const moonGeo = new SphereGeometry(0.8, 16, 16);
  const moonMat = new MeshStandardMaterial({
    color: new Color(1.0, 0.95, 0.75),
    emissive: new Color(0.4, 0.38, 0.2), // Visible moon glow
    metalness: 0.0,
    roughness: 0.6,
  });
  moonMat.name = 'nature_moon_mat';
  const moonMesh = new Mesh(moonGeo, moonMat);
  moonMesh.name = 'nature_moon';
  moonMesh.position.set(3, 4, -9);
  scene.add(moonMesh);
  allMaterials.push(moonMat);

  // Saturn ΓÇö above and offset from the front-left tree (-5, 0, -5)
  {
    const saturn = new Group();
    saturn.name = 'nature_saturn';

    // Planet body ΓÇö muted golden, not too bright
    const planetGeo = new SphereGeometry(0.3, 16, 16);
    const planetMat = new MeshStandardMaterial({
      color: new Color(0.75, 0.65, 0.4),
      emissive: new Color(0.2, 0.18, 0.1),
      metalness: 0.0,
      roughness: 0.8,
    });
    const planetMesh = new Mesh(planetGeo, planetMat);
    saturn.add(planetMesh);
    allMaterials.push(planetMat);

    // Ring ΓÇö flat disc tilted to read as Saturn's ring
    const ringGeo = new RingGeometry(0.42, 0.65, 48);
    const ringMat = new MeshStandardMaterial({
      color: new Color(0.7, 0.6, 0.4),
      emissive: new Color(0.15, 0.12, 0.08),
      side: DoubleSide,
      transparent: true,
      opacity: 0.6,
      metalness: 0.0,
      roughness: 0.6,
    });
    const ringMesh = new Mesh(ringGeo, ringMat);
    ringMesh.rotation.x = -Math.PI * 0.35;
    ringMesh.rotation.z = 0.15;
    saturn.add(ringMesh);
    allMaterials.push(ringMat);

    // Place in the gap between the left tree (-5) and right trees (4,6), above treeline
    saturn.position.set(-10.5, 3.2, -9);
    scene.add(saturn);
    environmentMeshes.push(saturn);
  }

  // Collect flower meshes separately for illumination control.
  // Flowers are the last N entries added to environmentMeshes.
  const flowerMeshes: Object3D[] = [];
  const flowerCount = flowerConfigs.length;
  const flowerStart = environmentMeshes.length - flowerCount;
  for (let i = flowerStart; i < environmentMeshes.length; i++) {
    flowerMeshes.push(environmentMeshes[i]);
  }

  return {
    skyMesh,
    groundMesh,
    groundMaterial: groundMat,
    jarBody,
    jarCap,
    jarMaterial,
    moonMesh,
    moonMaterial: moonMat,
    starField,
    starSizes,
    starPhases,
    flowerMeshes,
    environmentMeshes,
    allMaterials,
  };
}

import {
  type Scene,
  Vector3,
  Sprite,
  SpriteMaterial,
  AdditiveBlending,
  CanvasTexture,
  Color,
} from 'three';
import { createSparkleBurst } from '@app/minigames/shared/particleFx';

// ΓöÇΓöÇ Shooting Star ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface ShootingStar {
  sprite: Sprite;
  material: SpriteMaterial;
  startPos: Vector3;
  endPos: Vector3;
  progress: number;
  duration: number;
  active: boolean;
}

// ΓöÇΓöÇ Surprise Event Controller ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export interface SurpriseEventController {
  update(deltaTime: number, tier: number): void;
  dispose(): void;
}

/** Cached star streak texture. */
let streakTexture: CanvasTexture | null = null;

function getStreakTexture(): CanvasTexture {
  if (streakTexture) return streakTexture;
  const w = 64, h = 16;
  const canvas = document.createElement('canvas');
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext('2d')!;
  const grad = ctx.createLinearGradient(0, h / 2, w, h / 2);
  grad.addColorStop(0, 'rgba(255, 255, 255, 0)');
  grad.addColorStop(0.3, 'rgba(255, 255, 255, 0.6)');
  grad.addColorStop(0.7, 'rgba(255, 255, 255, 1)');
  grad.addColorStop(1, 'rgba(255, 255, 255, 0.8)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, w, h);
  streakTexture = new CanvasTexture(canvas);
  return streakTexture;
}

/**
 * Creates a surprise event controller that triggers occasional visual events:
 * - Shooting stars streak across the sky (tier >= 2)
 */
export function createSurpriseEvents(scene: Scene): SurpriseEventController {
  let disposed = false;

  // Shooting star pool (reuse up to 2)
  const stars: ShootingStar[] = [];
  let shootingStarTimer = 3 + Math.random() * 5; // first one after 3-8s

  function getOrCreateStar(): ShootingStar {
    const existing = stars.find(s => !s.active);
    if (existing) return existing;

    const mat = new SpriteMaterial({
      map: getStreakTexture(),
      color: new Color(0.95, 0.95, 1.0),
      transparent: true,
      opacity: 0,
      blending: AdditiveBlending,
      depthWrite: false,
    });
    const sprite = new Sprite(mat);
    sprite.scale.set(2.5, 0.15, 1);
    sprite.visible = false;
    scene.add(sprite);

    const star: ShootingStar = {
      sprite,
      material: mat,
      startPos: new Vector3(),
      endPos: new Vector3(),
      progress: 0,
      duration: 0.6,
      active: false,
    };
    stars.push(star);
    return star;
  }

  function launchShootingStar(): void {
    const star = getOrCreateStar();

    // Start from upper-right area, streak down-left
    const startX = 2 + Math.random() * 6;
    const startY = 7 + Math.random() * 4;
    star.startPos.set(startX, startY, -7 - Math.random() * 2);
    star.endPos.set(startX - 6 - Math.random() * 4, startY - 3 - Math.random() * 2, star.startPos.z);
    star.progress = 0;
    star.duration = 0.5 + Math.random() * 0.4;
    star.active = true;
    star.sprite.visible = true;

    // Orient sprite along travel direction
    const dir = star.endPos.clone().sub(star.startPos).normalize();
    const angle = Math.atan2(dir.y, dir.x);
    star.sprite.material.rotation = angle;
  }

  return {
    update(deltaTime: number, tier: number): void {
      if (disposed) return;

      // Shooting stars from the start, more frequent at higher tiers
      shootingStarTimer -= deltaTime;
      if (shootingStarTimer <= 0) {
        launchShootingStar();
        const baseInterval = Math.max(6, 18 - tier * 2);
        shootingStarTimer = baseInterval + Math.random() * 8;
      }

      // Animate active shooting stars
      for (const star of stars) {
        if (!star.active) continue;

        star.progress += deltaTime / star.duration;
        if (star.progress >= 1.0) {
          star.active = false;
          star.sprite.visible = false;
          // Sparkle burst at the end point
          createSparkleBurst(scene, star.endPos.clone(), new Color(0.8, 0.85, 1.0), 8);
          continue;
        }

        const t = star.progress;
        // Ease-in: starts slow, accelerates
        const eased = t * t;
        const pos = star.startPos.clone().lerp(star.endPos, eased);
        star.sprite.position.copy(pos);

        // Fade: bright in middle, fade at start and end
        const fade = t < 0.15 ? t / 0.15 : t > 0.7 ? (1 - t) / 0.3 : 1.0;
        star.material.opacity = 0.9 * fade;

        // Scale: stretch as it speeds up
        const stretch = 2.0 + eased * 2.0;
        star.sprite.scale.set(stretch, 0.12, 1);
      }
    },

    dispose(): void {
      disposed = true;
      for (const star of stars) {
        star.sprite.removeFromParent();
        star.material.dispose();
      }
      stars.length = 0;
    },
  };
}

import { Vector3 } from 'three';
import { randomRange } from '@app/minigames/shared/mathUtils';
import type { DifficultyTier, FireflyBehavior, FireflyData } from './types';
import { SPAWN, FOREGROUND_Z } from './types';

export { randomRange };

/** Returns the difficulty tier for a given score. */
export function getDifficultyTier(score: number): DifficultyTier {
  if (score > 50) return { maxFireflies: 14, speedMultiplier: 1.2 };
  if (score > 35) return { maxFireflies: 12, speedMultiplier: 1.15 };
  if (score > 20) return { maxFireflies: 10, speedMultiplier: 1.1 };
  if (score > 10) return { maxFireflies: 8, speedMultiplier: 1.05 };
  return { maxFireflies: 7, speedMultiplier: 1.0 };
}

/**
 * Creates a random spawn position within the play area.
 * @returns A Vector3 within spawn bounds.
 */
export function randomSpawnPos(): Vector3 {
  return new Vector3(
    randomRange(SPAWN.xMin, SPAWN.xMax),
    randomRange(SPAWN.yMin, SPAWN.yMax),
    randomRange(SPAWN.zMin, SPAWN.zMax),
  );
}

/**
 * Creates a spawn position guaranteed to be in the foreground (close to camera).
 * Uses lower Y range so they're easy to tap for young children.
 * @returns A Vector3 in the foreground area.
 */
export function foregroundSpawnPos(): Vector3 {
  return new Vector3(
    randomRange(-3, 3),
    randomRange(0.5, 2.5),
    randomRange(FOREGROUND_Z, SPAWN.zMax + 1),
  );
}

/**
 * Picks a random behavior type with weighted distribution:
 * drift 50%, circle 30%, zigzag 20%.
 */
export function randomBehavior(): FireflyBehavior {
  const r = Math.random();
  if (r < 0.5) return 'drift';
  if (r < 0.8) return 'circle';
  return 'zigzag';
}

/** Scratch vector to avoid per-frame allocations. */
const _tmpDir = new Vector3();

/**
 * Picks a random normalized direction for zigzag movement.
 */
function randomZigzagDir(): Vector3 {
  return new Vector3(
    randomRange(-1, 1),
    randomRange(-0.5, 0.5),
    randomRange(-0.5, 0.5),
  ).normalize();
}

/**
 * Updates a firefly's position based on its behavior type.
 * @param fd - The firefly data to update.
 * @param deltaTime - Frame delta in seconds.
 * @param speedMult - Difficulty speed multiplier.
 */
export function updateFireflyBehavior(
  fd: FireflyData,
  deltaTime: number,
  speedMult: number,
): void {
  fd.time += deltaTime * fd.speed * speedMult;
  const t = fd.time;

  switch (fd.behavior) {
    case 'drift': {
      fd.sprite.position.x += Math.sin(t * 0.7 + fd.driftOffsetX) * 0.008 * fd.speed * speedMult;
      fd.sprite.position.y += Math.cos(t * 0.5 + fd.driftOffsetY) * 0.006 * fd.speed * speedMult;
      fd.sprite.position.z += Math.sin(t * 0.3 + fd.driftOffsetZ) * 0.004 * fd.speed * speedMult;
      break;
    }

    case 'circle': {
      // Orbit around behaviorCenter at behaviorRadius with a gentle vertical bob
      const angularSpeed = 0.4 * fd.speed * speedMult;
      fd.behaviorAngle += angularSpeed * deltaTime;

      const cx = fd.behaviorCenter.x + Math.cos(fd.behaviorAngle) * fd.behaviorRadius;
      const cz = fd.behaviorCenter.z + Math.sin(fd.behaviorAngle) * fd.behaviorRadius;
      const cy = fd.behaviorCenter.y + Math.sin(t * 0.6) * 0.3;

      fd.sprite.position.x = cx;
      fd.sprite.position.y = cy;
      fd.sprite.position.z = cz;
      break;
    }

    case 'zigzag': {
      // Move in current direction, smoothly lerp toward a new direction periodically
      fd.zigzagTimer -= deltaTime;
      if (fd.zigzagTimer <= 0) {
        // Pick a new target direction
        _tmpDir.copy(randomZigzagDir());
        fd.zigzagDir.copy(_tmpDir);
        fd.zigzagTimer = randomRange(1.0, 2.0);
      }

      // Smooth movement ΓÇö lerp current position toward zigzag direction
      const moveSpeed = 0.012 * fd.speed * speedMult;
      fd.sprite.position.x += fd.zigzagDir.x * moveSpeed;
      fd.sprite.position.y += fd.zigzagDir.y * moveSpeed;
      fd.sprite.position.z += fd.zigzagDir.z * moveSpeed;

      // Add a gentle wobble so it doesn't look perfectly straight
      fd.sprite.position.y += Math.sin(t * 1.2) * 0.002 * fd.speed * speedMult;
      break;
    }
  }
}

import {
  Color,
  PointLight,
  type Scene,
  Mesh,
  MeshStandardMaterial,
  type Object3D,
} from 'three';
import type { GameLightingRig } from '@app/minigames/shared/sceneSetup';

/** Target values for a single illumination tier. */
interface TierValues {
  directionalIntensity: number;
  ambientIntensity: number;
  /** Multiplier applied to the base moon emissive color. */
  moonEmissive: number;
  /** Multiplier applied to the base ground emissive color. */
  groundEmissive: number;
  /** Emissive intensity for flower materials. */
  flowerEmissive: number;
  /** Jar interior point light intensity. */
  jarLightIntensity: number;
  /** Jar material emissive multiplier. */
  jarEmissive: number;
  /** Directional light color (shifts from cold blue to warm white). */
  dirColor: [number, number, number];
}

/** Illumination tier definition with collected-count threshold. */
interface IlluminationTierDef {
  threshold: number;
  values: TierValues;
}

/**
 * The six illumination tiers that define how the garden transforms
 * as the player catches more fireflies.
 *
 * Tier 0 ΓÇö Dark:       Near-black. Silhouettes only.
 * Tier 1 ΓÇö Dim:        Moon brightens. Tree outlines visible.
 * Tier 2 ΓÇö Awakening:  Flowers begin faint bioluminescent pulse.
 * Tier 3 ΓÇö Glowing:    Jar projects warm light. Trees get rim lighting.
 * Tier 4 ΓÇö Radiant:    Full moonlight. Garden alive with color.
 * Tier 5 ΓÇö Enchanted:  Everything glows. The jar is a beacon.
 */
const TIERS: IlluminationTierDef[] = [
  {
    threshold: 0,
    values: {
      directionalIntensity: 0.18,
      ambientIntensity: 0.12,
      moonEmissive: 0.6,
      groundEmissive: 0.05,
      flowerEmissive: 0.0,
      jarLightIntensity: 0.25,
      jarEmissive: 0.35,
      dirColor: [0.55, 0.6, 0.85],
    },
  },
  {
    threshold: 3,
    values: {
      directionalIntensity: 0.08,
      ambientIntensity: 0.04,
      moonEmissive: 0.25,
      groundEmissive: 0.01,
      flowerEmissive: 0.0,
      jarLightIntensity: 0.0,
      jarEmissive: 0.05,
      dirColor: [0.6, 0.65, 0.85],
    },
  },
  {
    threshold: 8,
    values: {
      directionalIntensity: 0.14,
      ambientIntensity: 0.07,
      moonEmissive: 0.45,
      groundEmissive: 0.02,
      flowerEmissive: 0.06,
      jarLightIntensity: 0.1,
      jarEmissive: 0.15,
      dirColor: [0.7, 0.7, 0.85],
    },
  },
  {
    threshold: 15,
    values: {
      directionalIntensity: 0.22,
      ambientIntensity: 0.12,
      moonEmissive: 0.70,
      groundEmissive: 0.04,
      flowerEmissive: 0.14,
      jarLightIntensity: 0.4,
      jarEmissive: 0.35,
      dirColor: [0.8, 0.78, 0.82],
    },
  },
  {
    threshold: 25,
    values: {
      directionalIntensity: 0.32,
      ambientIntensity: 0.18,
      moonEmissive: 0.90,
      groundEmissive: 0.07,
      flowerEmissive: 0.22,
      jarLightIntensity: 0.8,
      jarEmissive: 0.55,
      dirColor: [0.9, 0.85, 0.8],
    },
  },
  {
    threshold: 40,
    values: {
      directionalIntensity: 0.40,
      ambientIntensity: 0.25,
      moonEmissive: 1.1,
      groundEmissive: 0.10,
      flowerEmissive: 0.30,
      jarLightIntensity: 1.2,
      jarEmissive: 0.75,
      dirColor: [0.95, 0.9, 0.82],
    },
  },
];

/** Exponential lerp rate ΓÇö controls how fast transitions feel. ~80% in 1s. */
const TRANSITION_SPEED = 2.0;

/** Warm amber color for the jar interior point light. */
const JAR_LIGHT_COLOR = new Color(1.0, 0.85, 0.5);

/** Base moon emissive color (warm yellow-white). */
const MOON_BASE_COLOR = new Color(0.95, 0.9, 0.6);

/** Base ground emissive color (warm green). */
const GROUND_BASE_COLOR = new Color(0.3, 0.5, 0.15);

/** Base jar emissive color (warm amber-green). */
const JAR_BASE_COLOR = new Color(0.6, 0.8, 0.3);

/** Scene element references needed by the illumination controller. */
export interface IlluminationRefs {
  lights: GameLightingRig;
  moonMaterial: MeshStandardMaterial;
  groundMaterial: MeshStandardMaterial;
  jarMaterial: MeshStandardMaterial;
  flowerMaterials: MeshStandardMaterial[];
}

/** Mutable interpolation state for smooth tier transitions. */
interface LerpState {
  directionalIntensity: number;
  ambientIntensity: number;
  moonEmissive: number;
  groundEmissive: number;
  flowerEmissive: number;
  jarLightIntensity: number;
  jarEmissive: number;
  dirColorR: number;
  dirColorG: number;
  dirColorB: number;
}

export interface IlluminationController {
  /** Call each frame with current collected count and delta time. */
  update(collectedCount: number, deltaTime: number): void;
  /** Returns the current tier index (0-5). */
  getCurrentTier(): number;
  /** Dispose the jar interior light. */
  dispose(): void;
}

/**
 * Collects all MeshStandardMaterial instances from an Object3D hierarchy.
 * Used to find flower petal/stem materials for emissive control.
 */
export function collectMaterials(objects: Object3D[]): MeshStandardMaterial[] {
  const mats: MeshStandardMaterial[] = [];
  for (const obj of objects) {
    obj.traverse((child) => {
      if (child instanceof Mesh && child.material instanceof MeshStandardMaterial) {
        if (!mats.includes(child.material)) {
          mats.push(child.material);
        }
      }
    });
  }
  return mats;
}

/**
 * Determines the target tier for a given collected count.
 * Returns the highest tier whose threshold has been met.
 */
function getTargetTier(collectedCount: number): number {
  for (let i = TIERS.length - 1; i >= 0; i--) {
    if (collectedCount >= TIERS[i].threshold) return i;
  }
  return 0;
}

/**
 * Creates the illumination controller that drives progressive scene transformation.
 * The controller smoothly interpolates all scene lighting and material properties
 * between illumination tiers as the player catches fireflies.
 *
 * @param scene - The Three.js scene (jar light is added here).
 * @param refs - References to scene elements the controller will modify.
 * @param jarPosition - World position of the jar (for interior light placement).
 * @returns An IlluminationController with update and dispose methods.
 */
export function createIlluminationController(
  scene: Scene,
  refs: IlluminationRefs,
  jarPosition: { x: number; y: number; z: number },
): IlluminationController {
  // Create jar interior point light (centered within the scaled-down jar)
  const jarLight = new PointLight(JAR_LIGHT_COLOR, 0, 6.0);
  jarLight.name = 'fireflies_jar_interior_light';
  jarLight.position.set(jarPosition.x, jarPosition.y + 0.6, jarPosition.z);
  scene.add(jarLight);

  // Ensure main lights are in the scene
  if (!refs.lights.directionalLight.parent) scene.add(refs.lights.directionalLight);
  if (!refs.lights.ambientLight.parent) scene.add(refs.lights.ambientLight);
  if (!refs.lights.pointLight.parent) scene.add(refs.lights.pointLight);

  // Initialize lerp state to Tier 0 values
  const t0 = TIERS[0].values;
  const state: LerpState = {
    directionalIntensity: t0.directionalIntensity,
    ambientIntensity: t0.ambientIntensity,
    moonEmissive: t0.moonEmissive,
    groundEmissive: t0.groundEmissive,
    flowerEmissive: t0.flowerEmissive,
    jarLightIntensity: t0.jarLightIntensity,
    jarEmissive: t0.jarEmissive,
    dirColorR: t0.dirColor[0],
    dirColorG: t0.dirColor[1],
    dirColorB: t0.dirColor[2],
  };

  // Apply Tier 0 values immediately so scene starts dark
  applyState(state, refs, jarLight);

  let currentTierIndex = 0;

  function applyState(s: LerpState, r: IlluminationRefs, jl: PointLight): void {
    // Lighting rig
    r.lights.directionalLight.intensity = s.directionalIntensity;
    r.lights.directionalLight.color.setRGB(s.dirColorR, s.dirColorG, s.dirColorB);
    r.lights.ambientLight.intensity = s.ambientIntensity;

    // Moon emissive
    r.moonMaterial.emissive.copy(MOON_BASE_COLOR).multiplyScalar(s.moonEmissive);

    // Ground emissive
    r.groundMaterial.emissive.copy(GROUND_BASE_COLOR).multiplyScalar(s.groundEmissive);

    // Jar material emissive
    r.jarMaterial.emissive.copy(JAR_BASE_COLOR).multiplyScalar(s.jarEmissive);

    // Jar interior light
    jl.intensity = s.jarLightIntensity;

    // Flower emissive ΓÇö apply to all flower materials
    for (const mat of r.flowerMaterials) {
      // Preserve the flower's base color hue but scale emissive intensity
      mat.emissive.copy(mat.color).multiplyScalar(s.flowerEmissive);
    }
  }

  return {
    update(collectedCount: number, deltaTime: number): void {
      const targetIdx = getTargetTier(collectedCount);
      currentTierIndex = targetIdx;
      const target = TIERS[targetIdx].values;

      // Exponential interpolation toward target values
      const alpha = 1 - Math.exp(-deltaTime * TRANSITION_SPEED);

      state.directionalIntensity += (target.directionalIntensity - state.directionalIntensity) * alpha;
      state.ambientIntensity += (target.ambientIntensity - state.ambientIntensity) * alpha;
      state.moonEmissive += (target.moonEmissive - state.moonEmissive) * alpha;
      state.groundEmissive += (target.groundEmissive - state.groundEmissive) * alpha;
      state.flowerEmissive += (target.flowerEmissive - state.flowerEmissive) * alpha;
      state.jarLightIntensity += (target.jarLightIntensity - state.jarLightIntensity) * alpha;
      state.jarEmissive += (target.jarEmissive - state.jarEmissive) * alpha;
      state.dirColorR += (target.dirColor[0] - state.dirColorR) * alpha;
      state.dirColorG += (target.dirColor[1] - state.dirColorG) * alpha;
      state.dirColorB += (target.dirColor[2] - state.dirColorB) * alpha;

      applyState(state, refs, jarLight);
    },

    getCurrentTier(): number {
      return currentTierIndex;
    },

    dispose(): void {
      jarLight.removeFromParent();
    },
  };
}

import {
  Scene,
  PerspectiveCamera,
  MeshStandardMaterial,
  Vector3,
  type Mesh,
  type Object3D,
  SpriteMaterial,
  Sprite,
  PointLight,
  AdditiveBlending,
  CanvasTexture,
  Color,
} from 'three';
import type { IMiniGame, MiniGameContext, MiniGameTapEvent } from '../../framework/types';
import {
  createGameCamera,
  createGameLighting,
  disposeGameRig,
  type GameLightingRig,
} from '@app/minigames/shared/sceneSetup';
import { createSparkleBurst, createStarCollect } from '@app/minigames/shared/particleFx';
import type { FireflyData } from './types';
import {
  JAR_POS,
  JAR_SCALE,
  JAR_BODY_HEIGHT,
  BOUNDS,
  FOREGROUND_Z,
  HIT_RADIUS_PX,
  RESPAWN_DELAY,
  GOLDEN_UNLOCK_SCORE,
  GOLDEN_SPAWN_INTERVAL,
  FLASH_DURATION,
  ARC_DURATION,
  MILESTONE_COUNT,
  FIREFLY_COLOR,
  GOLDEN_COLOR,
} from './types';
import { getDifficultyTier, randomSpawnPos, foregroundSpawnPos, updateFireflyBehavior } from './helpers';
import { createEnvironment } from './environment';
import { createFirefly, resetFirefly } from './entities';
import {
  createIlluminationController,
  collectMaterials,
  type IlluminationController,
} from './illumination';
import { createFirefliesAudio, type FirefliesAudio } from './audio';
import { createSurpriseEvents, type SurpriseEventController } from './events';
import { createTapHint, type TapHint } from './tapHint';
import type { Points } from 'three';

// ΓöÇΓöÇ Jar orbit firefly system ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** State for a captured firefly orbiting the jar. */
interface JarOrbitFirefly {
  sprite: Sprite;
  material: SpriteMaterial;
  light: PointLight;
  angle: number;
  height: number;
  orbitRadius: number;
  speed: number;
  bobPhase: number;
}

/** Cached glow texture for orbit sprites. */
let orbitGlowTex: CanvasTexture | null = null;

/** Returns a cached 32x32 soft glow texture for jar orbit sprites. */
function getOrbitGlowTexture(): CanvasTexture {
  if (orbitGlowTex) return orbitGlowTex;
  const s = 32;
  const c = document.createElement('canvas');
  c.width = s;
  c.height = s;
  const ctx = c.getContext('2d')!;
  const g = ctx.createRadialGradient(16, 16, 0, 16, 16, 16);
  g.addColorStop(0, 'rgba(255, 255, 255, 1)');
  g.addColorStop(0.3, 'rgba(255, 255, 255, 0.5)');
  g.addColorStop(1, 'rgba(255, 255, 255, 0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, s, s);
  orbitGlowTex = new CanvasTexture(c);
  return orbitGlowTex;
}

/** Scaled jar dimensions for orbit placement (inside the jar). */
const JAR_SCALED_HEIGHT = JAR_BODY_HEIGHT * JAR_SCALE;
const JAR_SCALED_RADIUS = 0.55 * JAR_SCALE; // jar body max radius, scaled
const JAR_ORBIT_RADIUS_MIN = 0.08;
const JAR_ORBIT_RADIUS_MAX = JAR_SCALED_RADIUS * 0.75;

/**
 * Creates a small glowing sprite that orbits the jar permanently.
 * @param scene - The Three.js scene.
 * @param color - The firefly color to use.
 * @returns A JarOrbitFirefly ready for animation.
 */
function createJarOrbitFirefly(scene: Scene, color: Color): JarOrbitFirefly {
  const mat = new SpriteMaterial({
    map: getOrbitGlowTexture(),
    color: color.clone(),
    transparent: true,
    opacity: 0.8,
    blending: AdditiveBlending,
    depthWrite: false,
  });
  const sprite = new Sprite(mat);
  sprite.scale.setScalar(0.12);
  sprite.name = 'jar_orbit_firefly';
  scene.add(sprite);

  const light = new PointLight(color.clone(), 0.15, 1.5);
  light.name = 'jar_orbit_light';
  scene.add(light);

  const angle = Math.random() * Math.PI * 2;
  // Keep inside jar body: from just above base to shoulder
  const height = JAR_POS.y + 0.1 * JAR_SCALE + Math.random() * (JAR_SCALED_HEIGHT * 0.6);
  const orbitRadius = JAR_ORBIT_RADIUS_MIN + Math.random() * (JAR_ORBIT_RADIUS_MAX - JAR_ORBIT_RADIUS_MIN);
  const speed = 0.8 + Math.random() * 1.2;
  const bobPhase = Math.random() * Math.PI * 2;

  // Set initial position
  sprite.position.set(JAR_POS.x + Math.cos(angle) * orbitRadius, height, JAR_POS.z + Math.sin(angle) * orbitRadius);
  light.position.copy(sprite.position);

  return { sprite, material: mat, light, angle, height, orbitRadius, speed, bobPhase };
}

/**
 * Creates the Fireflies mini-game instance.
 * Players tap glowing fireflies to catch them and fill a jar.
 * @param context - Shell-provided mini-game context with shared systems.
 * @returns An IMiniGame implementation for the fireflies game.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  let paused = false;
  let collectedCount = 0;
  let milestoneTriggered = false;
  let goldenTimer = 0;
  let goldenActive = false;
  let elapsedTime = 0;

  const fireflies: FireflyData[] = [];
  let camera: ReturnType<typeof createGameCamera> | null = null;
  let lights: GameLightingRig | null = null;
  let groundMesh: Mesh | null = null;
  let jarBody: Mesh | null = null;
  let jarCap: Mesh | null = null;
  let moonMesh: Mesh | null = null;
  let skyMesh: Object3D | null = null;
  let illumination: IlluminationController | null = null;
  let audio: FirefliesAudio | null = null;
  let surpriseEvents: SurpriseEventController | null = null;
  let starField: Points | null = null;
  let starSizes: Float32Array | null = null;
  let starPhases: Float32Array | null = null;
  let tapHint: TapHint | null = null;
  let firstCatchDone = false;
  const jarOrbitFireflies: JarOrbitFirefly[] = [];
  const environmentMeshes: Object3D[] = [];
  const allMaterials: MeshStandardMaterial[] = [];
  const flowerRoots: Object3D[] = [];

  /**
   * Ensures the correct number of fireflies exist for the current difficulty tier.
   */
  function ensureFireflyCount(): void {
    const tier = getDifficultyTier(context.score.score);
    const targetCount = tier.maxFireflies;

    while (fireflies.length < targetCount) {
      const fd = createFirefly(scene, fireflies.length, false);
      fireflies.push(fd);
    }
  }

  /**
   * Attempts to spawn the golden firefly if conditions are met.
   */
  function trySpawnGolden(): void {
    if (context.score.score < GOLDEN_UNLOCK_SCORE) return;
    if (goldenActive) return;

    let goldenFd = fireflies.find((fd) => fd.isGolden && !fd.active);
    if (!goldenFd) {
      goldenFd = createFirefly(scene, fireflies.length, true);
      fireflies.push(goldenFd);
    }

    resetFirefly(goldenFd, scene);
    goldenFd.isGolden = true;
    goldenFd.spriteMaterial.color.copy(GOLDEN_COLOR);
    goldenFd.light.color.copy(GOLDEN_COLOR);
    goldenFd.light.intensity = 0.6;
    goldenActive = true;
  }

  const game: IMiniGame = {
    id: 'fireflies',

    async setup(): Promise<void> {
      // Camera & lights ΓÇö intensities set to Tier 0 (dark); illumination controller will drive them
      camera = createGameCamera({
        name: 'fireflies',
        beta: 1.3,
        radius: 9.0,
        target: new Vector3(0, 1.5, 0),
        fov: 0.9,
      });
      lights = createGameLighting({
        name: 'fireflies',
        direction: new Vector3(-0.5, -1, 0.5),
        directionalIntensity: 0.04,
        hemisphericIntensity: 0.02,
        pointPosition: new Vector3(0, 4, 0),
        pointIntensity: 0.4,
      });

      // Environment
      const env = createEnvironment(scene);
      skyMesh = env.skyMesh;
      groundMesh = env.groundMesh;
      jarBody = env.jarBody;
      jarCap = env.jarCap;
      moonMesh = env.moonMesh;
      starField = env.starField;
      starSizes = env.starSizes;
      starPhases = env.starPhases;
      environmentMeshes.push(...env.environmentMeshes);
      allMaterials.push(...env.allMaterials);

      // Store flower refs for proximity interaction
      flowerRoots.push(...env.flowerMeshes);

      // Progressive illumination controller
      const flowerMaterials = collectMaterials(env.flowerMeshes);
      illumination = createIlluminationController(scene, {
        lights,
        moonMaterial: env.moonMaterial,
        groundMaterial: env.groundMaterial,
        jarMaterial: env.jarMaterial,
        flowerMaterials,
      }, JAR_POS);

      // Procedural audio
      audio = createFirefliesAudio(() => context.audio.isMuted);

      // Surprise events (shooting stars, etc.)
      surpriseEvents = createSurpriseEvents(scene);

      // Onboarding tap hint
      tapHint = createTapHint(scene);

      // Initial fireflies
      for (let i = 0; i < 5; i++) {
        fireflies.push(createFirefly(scene, fireflies.length, false));
      }
    },

    start(): void {
      paused = false;
      collectedCount = 0;
      milestoneTriggered = false;
      goldenTimer = 0;
      goldenActive = false;
      elapsedTime = 0;
      context.score.reset();
      context.combo.reset();
      audio?.start();
      firstCatchDone = false;
    },

    update(deltaTime: number): void {
      if (paused) return;

      elapsedTime += deltaTime;
      const tier = getDifficultyTier(context.score.score);

      // Drive progressive scene illumination and ambient audio
      illumination?.update(collectedCount, deltaTime);
      const currentTier = illumination?.getCurrentTier() ?? 0;
      audio?.updateAmbient(currentTier, deltaTime);
      surpriseEvents?.update(deltaTime, currentTier);

      // Star twinkling
      if (starField && starSizes && starPhases) {
        const geo = starField.geometry;
        const posAttr = geo.getAttribute('position');
        const count = starSizes.length;
        for (let i = 0; i < count; i++) {
          // Each star twinkles at its own phase and rate
          // Modulate the Y position very slightly for a shimmer effect
          const baseY = 2 + (starPhases[i] / (Math.PI * 2)) * 10;
          posAttr.setY(i, baseY + Math.sin(elapsedTime * 0.8 + starPhases[i]) * 0.02);
        }
        posAttr.needsUpdate = true;
        // Modulate overall opacity based on twinkling
        (starField.material as { opacity: number }).opacity = 0.5 + 0.2 * Math.sin(elapsedTime * 0.3);
      }

      const speedMult = tier.speedMultiplier;

      // Tap hint: track the nearest active firefly as a visual guide
      if (tapHint && !firstCatchDone) {
        const hintTarget = fireflies.find(fd => fd.active && !fd.catching) ?? null;
        tapHint.update(deltaTime, hintTarget?.sprite ?? null);
      }

      // Animate captured fireflies orbiting inside the jar
      for (const orb of jarOrbitFireflies) {
        orb.angle += orb.speed * deltaTime;
        const bob = Math.sin(elapsedTime * 1.5 + orb.bobPhase) * 0.03;
        orb.sprite.position.set(
          JAR_POS.x + Math.cos(orb.angle) * orb.orbitRadius,
          orb.height + bob,
          JAR_POS.z + Math.sin(orb.angle) * orb.orbitRadius,
        );
        orb.light.position.copy(orb.sprite.position);
        // Gentle pulse
        orb.material.opacity = 0.6 + 0.3 * Math.sin(elapsedTime * 2 + orb.bobPhase);
      }

      // Golden firefly spawn timer
      if (context.score.score >= GOLDEN_UNLOCK_SCORE) {
        goldenTimer += deltaTime;
        if (goldenTimer >= GOLDEN_SPAWN_INTERVAL) {
          goldenTimer = 0;
          trySpawnGolden();
        }
      }

      ensureFireflyCount();

      // Maintain minimum 5 active fireflies on screen at all times
      let activeCount = 0;
      for (const fd of fireflies) {
        if (fd.active && !fd.catching) activeCount++;
      }
      if (activeCount < 5) {
        for (const fd of fireflies) {
          if (!fd.active && !fd.isGolden) {
            fd.respawnTimer = 0;
            resetFirefly(fd, scene);
            activeCount++;
            if (activeCount >= 5) break;
          }
        }
      }

      // Ensure at least 2 fireflies are in the foreground (close to camera, easy to tap)
      let foregroundCount = 0;
      for (const fd of fireflies) {
        if (fd.active && !fd.catching && fd.sprite.position.z >= FOREGROUND_Z) foregroundCount++;
      }
      if (foregroundCount < 2) {
        for (const fd of fireflies) {
          if (fd.active && !fd.catching && fd.sprite.position.z < FOREGROUND_Z) {
            const pos = foregroundSpawnPos();
            fd.sprite.position.copy(pos);
            fd.light.position.copy(pos);
            fd.behaviorCenter.copy(pos);
            foregroundCount++;
            if (foregroundCount >= 2) break;
          }
        }
      }

      for (const fd of fireflies) {
        // Handle respawn timers
        if (!fd.active && !fd.catching) {
          if (fd.respawnTimer > 0) {
            fd.respawnTimer -= deltaTime;
            if (fd.respawnTimer <= 0) {
              resetFirefly(fd, scene);
            }
          }
          continue;
        }

        // Handle catch animation
        if (fd.catching) {
          const baseScale = fd.isGolden ? 0.45 : 0.3;

          if (fd.flashing) {
            fd.flashTimer -= deltaTime;
            if (fd.flashTimer <= 0) {
              fd.flashing = false;
              fd.catchProgress = 0;
              // Snap scale back to base when flash ends
              fd.sprite.scale.setScalar(baseScale);
            } else {
              // Scale pop: lerp up to 1.8x base during flash
              const flashT = 1.0 - fd.flashTimer / FLASH_DURATION;
              const popScale = baseScale * (1.0 + 0.8 * Math.sin(flashT * Math.PI));
              fd.sprite.scale.setScalar(popScale);

              // Color pulse from warm white to gold
              const gold = 0.85 + 0.15 * Math.sin(flashT * Math.PI * 2);
              fd.spriteMaterial.color.setRGB(1, 0.95 * gold, 0.7 * gold);
            }
            // Warm flash ΓÇö brighten sprite and light
            fd.spriteMaterial.opacity = 1.0;
            fd.light.intensity = 1.5;
            continue;
          }

          // Boost glow trail during arc for a comet-like effect
          fd.glowTrail.configure({ emitRate: 20 });

          // Arc to jar animation
          fd.catchProgress += deltaTime / ARC_DURATION;
          if (fd.catchProgress >= 1.0) {
            // Sparkle burst at jar mouth on arrival
            const jarMouth = JAR_POS.clone().add(new Vector3(0, JAR_SCALED_HEIGHT, 0));
            createStarCollect(scene, jarMouth);

            // Spawn a permanent orbiting firefly around the jar
            const orbColor = fd.isGolden ? GOLDEN_COLOR : FIREFLY_COLOR;
            jarOrbitFireflies.push(createJarOrbitFirefly(scene, orbColor));

            fd.sprite.visible = false;
            fd.light.visible = false;
            fd.glowTrail.configure({ emitRate: 4 }); // restore normal rate
            fd.glowTrail.stop();
            fd.active = false;
            fd.catching = false;
            fd.sprite.scale.setScalar(baseScale);

            if (fd.isGolden) {
              goldenActive = false;
            }

            fd.respawnTimer = RESPAWN_DELAY;
            collectedCount++;

            if (collectedCount >= MILESTONE_COUNT && !milestoneTriggered) {
              milestoneTriggered = true;
              context.celebration.milestone(context.viewport.width / 2, context.viewport.height / 2, 'large');
            }
            continue;
          }

          // Compute arc position with easeOutCubic
          const rawT = fd.catchProgress;
          const t = 1 - (1 - rawT) * (1 - rawT) * (1 - rawT); // easeOutCubic
          const arcHeight = 2.0 * Math.sin(t * Math.PI);
          const jarTarget = JAR_POS.clone().add(new Vector3(0, JAR_SCALED_HEIGHT * 0.6, 0));
          const lerpPos = fd.catchStartPos.clone().lerp(jarTarget, t);
          lerpPos.y += arcHeight;

          // Spiral wobble that decreases as it approaches the jar
          const wobble = (1 - t) * 0.3;
          lerpPos.x += Math.sin(t * Math.PI * 3) * wobble;
          lerpPos.z += Math.cos(t * Math.PI * 3) * wobble;

          fd.sprite.position.copy(lerpPos);
          fd.light.position.copy(lerpPos);

          // Shrink from 1.0x to 0.3x base scale during arc
          const arcScale = baseScale * (1.0 - rawT * 0.7);
          fd.sprite.scale.setScalar(arcScale);

          // Fade during arc
          const fade = 1.0 - rawT * 0.7;
          fd.spriteMaterial.opacity = 0.85 * fade;
          // Light intensity with slight pulse
          const baseLightIntensity = (fd.isGolden ? 0.6 : 0.35) * fade;
          fd.light.intensity = baseLightIntensity + Math.sin(rawT * Math.PI * 4) * 0.1;
          continue;
        }

        // Behavior-driven movement (drift / circle / zigzag)
        updateFireflyBehavior(fd, deltaTime, speedMult);

        // Keep point light in sync
        fd.light.position.copy(fd.sprite.position);

        // Glow pulse animation
        let pulseVal: number;
        if (fd.isGolden) {
          // Golden: double-pulse heartbeat pattern (lub-dub)
          const pulsePeriod = 1.6;
          const pulseT = ((elapsedTime + fd.glowPhase) % pulsePeriod) / pulsePeriod;
          if (pulseT < 0.12) {
            pulseVal = pulseT / 0.12; // first beat rise
          } else if (pulseT < 0.24) {
            pulseVal = 1.0 - (pulseT - 0.12) / 0.12; // first beat fall
          } else if (pulseT < 0.32) {
            pulseVal = (pulseT - 0.24) / 0.08 * 0.7; // second beat rise (shorter)
          } else if (pulseT < 0.48) {
            pulseVal = 0.7 * (1.0 - (pulseT - 0.32) / 0.16); // second beat fall
          } else {
            pulseVal = 0; // rest
          }
        } else {
          // Standard: asymmetric single pulse ΓÇö quick brighten, slow fade
          const pulsePeriod = 2.0;
          const pulseT = ((elapsedTime + fd.glowPhase) % pulsePeriod) / pulsePeriod;
          const risePhase = 0.2;
          if (pulseT < risePhase) {
            pulseVal = pulseT / risePhase;
          } else {
            pulseVal = 1.0 - (pulseT - risePhase) / (1.0 - risePhase);
          }
        }

        const baseColor = fd.isGolden ? GOLDEN_COLOR : FIREFLY_COLOR;
        fd.spriteMaterial.opacity = fd.isGolden ? (0.4 + 0.6 * pulseVal) : (0.25 + 0.65 * pulseVal);
        fd.spriteMaterial.color.copy(baseColor);
        fd.light.intensity = (fd.isGolden ? 0.8 : 0.35) * (0.15 + 0.85 * pulseVal);

        // Out-of-bounds check
        const pos = fd.sprite.position;
        if (pos.x < BOUNDS.xMin || pos.x > BOUNDS.xMax || pos.y < BOUNDS.yMin || pos.y > BOUNDS.yMax) {
          const newPos = randomSpawnPos();
          fd.sprite.position.copy(newPos);
          fd.light.position.copy(newPos);
          fd.time = Math.random() * 100;
        }
      }

      // Flower proximity glow: flowers brighten when a firefly is nearby
      const PROXIMITY_RADIUS = 2.5;
      const PROXIMITY_SQ = PROXIMITY_RADIUS * PROXIMITY_RADIUS;
      for (let fi = 0; fi < flowerRoots.length; fi++) {
        const flower = flowerRoots[fi];
        let closestDistSq = Infinity;
        for (const fd of fireflies) {
          if (!fd.active || fd.catching) continue;
          const dx = fd.sprite.position.x - flower.position.x;
          const dy = fd.sprite.position.y - flower.position.y;
          const dz = fd.sprite.position.z - flower.position.z;
          const distSq = dx * dx + dy * dy + dz * dz;
          if (distSq < closestDistSq) closestDistSq = distSq;
        }
        // Proximity factor: 1.0 when firefly is right on top, 0.0 when beyond radius
        const proximity = closestDistSq < PROXIMITY_SQ
          ? 1.0 - Math.sqrt(closestDistSq) / PROXIMITY_RADIUS
          : 0;
        // Gently sway the flower when a firefly is near
        flower.rotation.z = Math.sin(elapsedTime * 2 + fi) * 0.05 * proximity;
      }
    },

    pause(): void {
      paused = true;
    },

    resume(): void {
      paused = false;
    },

    teardown(): void {
      // Dispose firefly sprites, lights, and particle trails
      for (const fd of fireflies) {
        fd.glowTrail.stop();
        fd.glowTrail.dispose();
        fd.light.removeFromParent();
        fd.spriteMaterial.dispose();
        fd.sprite.removeFromParent();
      }
      fireflies.length = 0;

      for (const m of environmentMeshes) {
        m.removeFromParent();
      }
      environmentMeshes.length = 0;

      skyMesh?.removeFromParent();
      groundMesh?.removeFromParent();
      jarBody?.removeFromParent();
      jarCap?.removeFromParent();
      moonMesh?.removeFromParent();

      for (const mat of allMaterials) {
        mat.dispose();
      }
      allMaterials.length = 0;

      illumination?.dispose();
      illumination = null;

      audio?.dispose();
      audio = null;

      surpriseEvents?.dispose();
      surpriseEvents = null;

      starField?.removeFromParent();
      starField = null;
      starSizes = null;
      starPhases = null;

      tapHint?.dispose();
      tapHint = null;

      // Dispose orbiting jar fireflies
      for (const orb of jarOrbitFireflies) {
        orb.sprite.removeFromParent();
        orb.material.dispose();
        orb.light.removeFromParent();
      }
      jarOrbitFireflies.length = 0;

      disposeGameRig(camera, lights);
      camera = null;
      lights = null;
      groundMesh = null;
      jarBody = null;
      jarCap = null;
      moonMesh = null;
      skyMesh = null;
    },

    onResize(): void {
      // Camera FOV and positioning are fixed; no resize adjustments needed
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused) return;

      // Screen-space hit detection
      const cam = context.camera as PerspectiveCamera;
      const rect = context.canvas.getBoundingClientRect();

      let nearestFd: FireflyData | null = null;
      let nearestDist = HIT_RADIUS_PX;

      for (const fd of fireflies) {
        if (!fd.active || fd.catching) continue;

        const projected = fd.sprite.position.clone().project(cam);
        if (projected.z > 1) continue;
        const sx = (projected.x * 0.5 + 0.5) * rect.width + rect.left;
        const sy = (-projected.y * 0.5 + 0.5) * rect.height + rect.top;

        const dx = sx - event.screenX;
        const dy = sy - event.screenY;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < nearestDist) {
          nearestDist = dist;
          nearestFd = fd;
        }
      }

      if (!nearestFd) {
        audio?.playTapSparkle();
        return;
      }

      const catchColor = nearestFd.isGolden ? GOLDEN_COLOR : FIREFLY_COLOR;
      createSparkleBurst(scene, nearestFd.sprite.position.clone(), catchColor, 15);

      if (nearestFd.isGolden) {
        audio?.playGoldenCatch();
      } else {
        audio?.playCatchChime();
      }

      // Dismiss tap hint on first successful catch
      if (!firstCatchDone) {
        firstCatchDone = true;
        tapHint?.dismiss();
      }

      nearestFd.catching = true;
      nearestFd.flashing = true;
      nearestFd.flashTimer = FLASH_DURATION;
      nearestFd.catchStartPos = nearestFd.sprite.position.clone();

      const points = nearestFd.isGolden ? 5 : 1;
      context.score.addPoints(points);
      context.combo.registerHit();

      context.celebration.confetti(event.screenX, event.screenY, 'small');
      context.celebration.celebrationSound('chime');
    },
  };

  return game;
}

import {
  type Scene,
  Points,
  PointsMaterial,
  BufferGeometry,
  Float32BufferAttribute,
  AdditiveBlending,
  CanvasTexture,
  Color,
  Vector3,
} from 'three';

export interface JarFillIndicator {
  /** Update the displayed count (call when collectedCount changes). */
  setCount(count: number): void;
  /** Animate each frame. */
  update(deltaTime: number): void;
  dispose(): void;
}

const MAX_JAR_DOTS = 30;

/** Cached small glow texture for jar dots. */
let dotTexture: CanvasTexture | null = null;

function getDotTexture(): CanvasTexture {
  if (dotTexture) return dotTexture;
  const size = 32;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d')!;
  const grad = ctx.createRadialGradient(16, 16, 0, 16, 16, 16);
  grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
  grad.addColorStop(0.4, 'rgba(255, 255, 255, 0.4)');
  grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, size, size);
  dotTexture = new CanvasTexture(canvas);
  return dotTexture;
}

/**
 * Creates a jar fill indicator that shows collected fireflies
 * as small glowing dots floating inside the jar.
 *
 * @param scene - The Three.js scene.
 * @param jarPos - The jar base position.
 */
export function createJarFill(scene: Scene, jarPos: Vector3): JarFillIndicator {
  // Pre-generate random positions inside the jar volume
  // Jar body is roughly a cylinder from y=0.1 to y=1.4, radius ~0.4
  const positions = new Float32Array(MAX_JAR_DOTS * 3);
  const phases = new Float32Array(MAX_JAR_DOTS);
  for (let i = 0; i < MAX_JAR_DOTS; i++) {
    const angle = Math.random() * Math.PI * 2;
    const r = Math.random() * 0.35;
    positions[i * 3] = jarPos.x + Math.cos(angle) * r;
    positions[i * 3 + 1] = jarPos.y + 0.15 + Math.random() * 1.15;
    positions[i * 3 + 2] = jarPos.z + Math.sin(angle) * r;
    phases[i] = Math.random() * Math.PI * 2;
  }

  const geometry = new BufferGeometry();
  geometry.setAttribute('position', new Float32BufferAttribute(positions, 3));
  // Start with 0 visible dots
  geometry.setDrawRange(0, 0);

  const material = new PointsMaterial({
    map: getDotTexture(),
    size: 0.08,
    transparent: true,
    opacity: 0.8,
    blending: AdditiveBlending,
    depthWrite: false,
    color: new Color('#FFB347'),
    sizeAttenuation: true,
  });

  const points = new Points(geometry, material);
  points.name = 'jar_fill_dots';
  scene.add(points);

  let currentCount = 0;
  let elapsed = 0;

  return {
    setCount(count: number): void {
      currentCount = Math.min(count, MAX_JAR_DOTS);
      geometry.setDrawRange(0, currentCount);
    },

    update(deltaTime: number): void {
      if (currentCount === 0) return;
      elapsed += deltaTime;

      // Gently bob the dots up and down inside the jar
      const posAttr = geometry.getAttribute('position');
      for (let i = 0; i < currentCount; i++) {
        const baseY = 0.15 + (phases[i] / (Math.PI * 2)) * 1.15;
        posAttr.setY(i, jarPos.y + baseY + Math.sin(elapsed * 1.5 + phases[i]) * 0.04);
      }
      posAttr.needsUpdate = true;

      // Pulse opacity gently
      material.opacity = 0.6 + 0.2 * Math.sin(elapsed * 2);
    },

    dispose(): void {
      points.removeFromParent();
      geometry.dispose();
      material.dispose();
    },
  };
}

import {
  type Scene,
  Sprite,
  SpriteMaterial,
  AdditiveBlending,
  CanvasTexture,
  Color,
  type Object3D,
} from 'three';

export interface TapHint {
  /** Call each frame. Tracks a target and animates. */
  update(deltaTime: number, target: Object3D | null): void;
  /** Call when the player catches their first firefly. */
  dismiss(): void;
  dispose(): void;
}

/** Cached concentric-ring "tap here" texture. */
let tapTexture: CanvasTexture | null = null;

function getTapTexture(): CanvasTexture {
  if (tapTexture) return tapTexture;
  const size = 128;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d')!;
  const cx = size / 2;

  // Outer ring
  ctx.beginPath();
  ctx.arc(cx, cx, 50, 0, Math.PI * 2);
  ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
  ctx.lineWidth = 3;
  ctx.stroke();

  // Inner ring
  ctx.beginPath();
  ctx.arc(cx, cx, 30, 0, Math.PI * 2);
  ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
  ctx.lineWidth = 2;
  ctx.stroke();

  // Center dot
  const grad = ctx.createRadialGradient(cx, cx, 0, cx, cx, 12);
  grad.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
  grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(cx, cx, 12, 0, Math.PI * 2);
  ctx.fill();

  tapTexture = new CanvasTexture(canvas);
  return tapTexture;
}

/**
 * Creates a pulsing "tap here" indicator that follows a firefly.
 * Appears at game start, dismissed after first catch.
 */
export function createTapHint(scene: Scene): TapHint {
  const material = new SpriteMaterial({
    map: getTapTexture(),
    color: new Color(1, 0.9, 0.5),
    transparent: true,
    opacity: 0,
    blending: AdditiveBlending,
    depthWrite: false,
  });
  const sprite = new Sprite(material);
  sprite.scale.setScalar(1.2);
  sprite.name = 'tap_hint';
  scene.add(sprite);

  let elapsed = 0;
  let dismissed = false;
  let fadeOut = false;
  let appearDelay = 1.5; // wait 1.5s before showing

  return {
    update(deltaTime: number, target: Object3D | null): void {
      if (dismissed && material.opacity <= 0) return;

      elapsed += deltaTime;

      // Delay before appearing
      if (appearDelay > 0) {
        appearDelay -= deltaTime;
        return;
      }

      if (fadeOut) {
        material.opacity = Math.max(0, material.opacity - deltaTime * 2);
        if (material.opacity <= 0) {
          sprite.visible = false;
          dismissed = true;
        }
        return;
      }

      // Fade in
      if (material.opacity < 0.7) {
        material.opacity = Math.min(0.7, material.opacity + deltaTime * 0.8);
      }

      // Pulse scale
      const pulse = 1.0 + 0.2 * Math.sin(elapsed * 3);
      sprite.scale.setScalar(1.2 * pulse);

      // Track target position (offset slightly above)
      if (target) {
        sprite.position.copy(target.position);
        sprite.position.y += 0.6;
      }
    },

    dismiss(): void {
      fadeOut = true;
    },

    dispose(): void {
      sprite.removeFromParent();
      material.dispose();
      dismissed = true;
    },
  };
}

import { type Scene, Vector3, type Object3D } from 'three';
import { buildBunny, buildKitten, buildBear, buildFrog } from '@app/minigames/shared/animalBuilder';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';
import type { AnimalType, SpotRuntime } from './types';
import { COOLDOWN_MIN, COOLDOWN_MAX } from './types';
import {
  randomRange,
  pickAnimalType,
  getMaxSimultaneous,
  getActivePeekerCount,
  getAvailableSpotIndices,
} from './helpers';

/**
 * Creates a detailed peek mesh using shared animal builders.
 * Builds a full PBR animal model scaled to peek size.
 * @param animalType - The type of animal to create.
 * @param scene - The Three.js scene.
 * @param spotName - Name of the parent spot for unique naming.
 * @returns The root mesh of the animal peek composite.
 */
export function createPeekMesh(animalType: AnimalType, scene: Scene, spotName: string): Object3D {
  const peekName = `peek_${spotName}_${animalType}`;
  const origin = new Vector3(0, 0, 0);
  let root: Object3D;

  switch (animalType) {
    case 'bunny':
      root = buildBunny(peekName, origin);
      break;
    case 'cat':
      root = buildKitten(peekName, origin);
      break;
    case 'bear':
      root = buildBear(peekName, origin);
      break;
    case 'frog':
      root = buildFrog(peekName, origin);
      break;
  }

  scene.add(root);

  // Scale animals down to peek size
  root.scale.set(0.45, 0.45, 0.45);
  root.visible = false;

  return root;
}

/**
 * Disposes a peek mesh and all its child meshes and materials.
 * @param mesh - The root peek mesh to dispose.
 */
export function disposePeekMesh(mesh: Object3D): void {
  disposeMeshDeep(mesh);
}

/**
 * Spawns an animal peek at a specific spot.
 * @param spotIndex - The index of the spot to occupy.
 */
export function occupySpot(spots: SpotRuntime[], scene: Scene, spotIndex: number): void {
  const spot = spots[spotIndex];
  if (spot.state !== 'empty') return;

  const animalType = pickAnimalType(spots, spotIndex);
  spot.animalType = animalType;
  spot.state = 'occupied';
  spot.peekTimer = 0;

  // Create and position peek mesh above the spot
  const peekMesh = createPeekMesh(animalType, scene, spot.name);
  peekMesh.position.copy(spot.pos);
  peekMesh.position.y = spot.pos.y + 0.6;
  peekMesh.visible = true;
  spot.peekMesh = peekMesh;
}

/**
 * Hides the animal at a spot and starts cooldown.
 * @param spotIndex - The index of the spot to hide.
 */
export function hideAnimal(spots: SpotRuntime[], spotIndex: number): void {
  const spot = spots[spotIndex];
  if (spot.peekMesh) {
    disposePeekMesh(spot.peekMesh);
    spot.peekMesh = null;
  }
  spot.state = 'cooldown';
  spot.cooldownTimer = 0;
  spot.cooldownDuration = randomRange(COOLDOWN_MIN, COOLDOWN_MAX);
  spot.animalType = null;
  spot.peekTimer = 0;
  spot.revealTimer = 0;
}

/**
 * Spawns new peekers to ensure the minimum active count is maintained.
 */
export function ensureMinimumPeekers(spots: SpotRuntime[], scene: Scene, findCount: number): void {
  const maxSim = getMaxSimultaneous(findCount);
  const currentActive = getActivePeekerCount(spots);

  if (currentActive >= maxSim) return;

  const available = getAvailableSpotIndices(spots);
  if (available.length === 0) return;

  const needed = Math.min(maxSim - currentActive, available.length);
  for (let i = 0; i < needed; i++) {
    const randIdx = Math.floor(Math.random() * available.length);
    const spotIdx = available[randIdx];
    available.splice(randIdx, 1);
    occupySpot(spots, scene, spotIdx);
  }
}

/**
 * Applies a gentle scale pulse to a spot mesh for the rustle effect.
 * @param spot - The spot to rustle.
 */
export function rustleSpot(spot: SpotRuntime): void {
  if (!spot.spotMesh) return;
  const original = spot.spotMesh.scale.clone();
  const pulsed = original.clone().multiplyScalar(1.1);

  spot.spotMesh.scale.copy(pulsed);
  setTimeout(() => {
    if (spot.spotMesh) {
      spot.spotMesh.scale.copy(original);
    }
  }, 150);
}

