/**
 * Creates the forest floor ground plane with felt material.
 */
export function createForestFloor(scene: Scene, environmentMeshes: Object3D[]): void {
  const geo = new PlaneGeometry(12, 10);
  geo.rotateX(-Math.PI / 2);
  const ground = new Mesh(geo, createFeltMaterial('forest_floor_mat', new Color(0.35, 0.3, 0.15)));
  ground.name = 'forest_floor';
  scene.add(ground);
  environmentMeshes.push(ground);
}

/**
 * Creates the tree canopy effect as a large semi-transparent green sphere with leaf material.
 */
export function createCanopy(scene: Scene, environmentMeshes: Object3D[]): void {
  const geo = new SphereGeometry(14 / 2, 12, 12);
  const canopyMat = createLeafMaterial('canopy_mat', new Color(0.2, 0.5, 0.15));
  canopyMat.opacity = 0.25;
  canopyMat.transparent = true;
  canopyMat.side = DoubleSide;
  const canopy = new Mesh(geo, canopyMat);
  canopy.name = 'canopy';
  canopy.position.set(0, 7, 0);
  scene.add(canopy);
  environmentMeshes.push(canopy);
}

/**
 * Creates decorative mushrooms scattered on the forest floor using PBR materials.
 */
export function createMushrooms(scene: Scene, environmentMeshes: Object3D[]): void {
  const mushroomPositions = [
    new Vector3(-1.5, 0, -0.5),
    new Vector3(0.5, 0, 1.5),
    new Vector3(3.5, 0, -0.5),
    new Vector3(-3.5, 0, 1),
  ];

  const capMat = createFurMaterial('mushroom_cap_mat', new Color(0.8, 0.2, 0.15));
  const stemMat = createWoodMaterial('mushroom_stem_mat', new Color(0.9, 0.85, 0.7));

  mushroomPositions.forEach((pos, i) => {
    const stemGeo = new CylinderGeometry(0.08 / 2, 0.08 / 2, 0.15);
    const stem = new Mesh(stemGeo, stemMat);
    stem.name = `mushroom_stem_${i}`;
    stem.position.set(pos.x, 0.075, pos.z);
    scene.add(stem);
    environmentMeshes.push(stem);

    const capGeo = new SphereGeometry(0.2 / 2, 6, 6);
    const cap = new Mesh(capGeo, capMat);
    cap.name = `mushroom_cap_${i}`;
    cap.position.set(pos.x, 0.18, pos.z);
    cap.scale.set(1, 0.5, 1);
    scene.add(cap);
    environmentMeshes.push(cap);
  });
}

/**
 * Creates a hiding spot mesh using detailed shared mesh builders.
 * @param def - The spot definition describing shape and position.
 * @returns The created hiding spot mesh.
 */
export function createSpotMesh(scene: Scene, def: SpotDef): Object3D {
  let obj: Object3D;

  if (def.name.includes('bush')) {
    obj = buildDetailedBush(def.pos.clone(), 1.4, new Color(0.25, 0.5, 0.2));
    scene.add(obj);
  } else if (def.name === 'tree') {
    obj = buildDetailedTree(def.pos.clone(), 1.5, new Color(0.3, 0.55, 0.18));
    scene.add(obj);
  } else if (def.name === 'rock') {
    obj = buildDetailedRock(def.pos.clone(), 1.6, new Color(0.5, 0.48, 0.45));
    scene.add(obj);
  } else if (def.name === 'log') {
    const geo = new BoxGeometry(1.8, 0.6, 0.8);
    obj = new Mesh(geo, createWoodMaterial(`spot_${def.name}_mat`, new Color(0.4, 0.28, 0.15)));
    obj.name = `spot_${def.name}`;
    obj.position.copy(def.pos);
    scene.add(obj);
  } else if (def.name === 'flowers') {
    obj = buildDetailedBush(def.pos.clone(), 1.0, new Color(0.2, 0.55, 0.25));
    scene.add(obj);
  } else {
    obj = buildDetailedBush(def.pos.clone(), 1.2, new Color(0.3, 0.45, 0.2));
    scene.add(obj);
  }

  return obj;
}

/**
 * Creates decorative grass tufts and flowers scattered across the forest floor.
 */
export function createForestDecorations(scene: Scene, environmentMeshes: Object3D[]): void {
  // Scatter grass tufts
  const grassPositions = [
    new Vector3(-4, 0, 0),
    new Vector3(-2.5, 0, 2),
    new Vector3(0, 0, -3),
    new Vector3(1.5, 0, 3),
    new Vector3(4, 0, 1),
    new Vector3(-1, 0, -2.5),
    new Vector3(3, 0, -2.5),
  ];
  for (const gp of grassPositions) {
    const tuft = buildGrassTuft(gp);
    scene.add(tuft);
    environmentMeshes.push(tuft);
  }

  // Scatter small flowers
  const flowerData: { pos: Vector3; color: Color }[] = [
    { pos: new Vector3(-3.5, 0, -2), color: new Color(0.9, 0.4, 0.5) },
    { pos: new Vector3(2.5, 0, -3), color: new Color(0.95, 0.85, 0.3) },
    { pos: new Vector3(0.5, 0, 2.5), color: new Color(0.6, 0.4, 0.9) },
    { pos: new Vector3(-2, 0, 1.5), color: new Color(0.95, 0.6, 0.2) },
    { pos: new Vector3(4.5, 0, -1), color: new Color(0.85, 0.3, 0.4) },
  ];
  for (const fd of flowerData) {
    const flower = buildDetailedFlower(fd.pos, fd.color, 0.3);
    scene.add(flower);
    environmentMeshes.push(flower);
  }
}

/**
 * Creates a sky gradient backdrop behind the scene.
 */
export function createSky(scene: Scene, environmentMeshes: Object3D[]): void {
  const sky = buildSkyGradient(new Color(0.4, 0.7, 0.95), new Color(0.7, 0.88, 0.55), 18);
  sky.position.set(0, 5, -8);
  scene.add(sky);
  environmentMeshes.push(sky);
}

import { randomRange, randomPick } from '@app/minigames/shared/mathUtils';
import type { AnimalType, SpotRuntime } from './types';
import { ANIMAL_TYPES, PEEK_DURATION_MAX, PEEK_DURATION_MIN } from './types';

export { randomRange, randomPick };

/**
 * Determines the maximum number of simultaneous peekers based on find count.
 * @param findCount - Total animals found so far.
 * @returns Maximum number of spots that should be occupied at once.
 */
export function getMaxSimultaneous(findCount: number): number {
  if (findCount <= 5) return 1;
  if (findCount <= 12) return 2;
  if (findCount <= 20) return 2;
  return 3;
}

/**
 * Computes peek duration based on difficulty level.
 * @param difficultyLevel - Normalized difficulty from 0 to 1.
 * @returns Peek duration in seconds.
 */
export function getPeekDuration(difficultyLevel: number): number {
  return PEEK_DURATION_MAX - (PEEK_DURATION_MAX - PEEK_DURATION_MIN) * difficultyLevel;
}

/**
 * Returns the count of spots currently in occupied or revealed state.
 * @returns Number of active peekers.
 */
export function getActivePeekerCount(spots: SpotRuntime[]): number {
  return spots.filter((s) => s.state === 'occupied' || s.state === 'revealed').length;
}

/**
 * Returns indices of spots that are empty and available for occupation.
 * @returns Array of spot indices.
 */
export function getAvailableSpotIndices(spots: SpotRuntime[]): number[] {
  return spots.map((s, i) => (s.state === 'empty' ? i : -1)).filter((i) => i !== -1);
}

/**
 * Selects a random animal type, avoiding the same type at adjacent spots.
 * @param spotIndex - The index of the spot being occupied.
 * @returns A randomly selected animal type.
 */
export function pickAnimalType(spots: SpotRuntime[], spotIndex: number): AnimalType {
  const adjacentTypes: AnimalType[] = [];
  if (spotIndex > 0 && spots[spotIndex - 1].animalType) {
    adjacentTypes.push(spots[spotIndex - 1].animalType!);
  }
  if (spotIndex < spots.length - 1 && spots[spotIndex + 1].animalType) {
    adjacentTypes.push(spots[spotIndex + 1].animalType!);
  }

  const candidates = ANIMAL_TYPES.filter((t) => !adjacentTypes.includes(t));
  return candidates.length > 0 ? randomPick(candidates) : randomPick(ANIMAL_TYPES);
}

import {
  Color,
  Vector3,
  SphereGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  Mesh,
  type Scene,
  type Object3D,
} from 'three';

// ---------------------------------------------------------------------------
// Return type interfaces
// ---------------------------------------------------------------------------

/** Handle for a bubble trail effect that drifts and self-disposes. */
export interface BubbleTrail {
  /** Advance the trail by `dt` seconds. Returns false when all bubbles have expired. */
  update(dt: number): boolean;
  /** Immediately remove all bubble meshes from the scene. */
  dispose(): void;
}

/** Handle for a persistent golden shimmer aura around a mesh. */
export interface GoldenShimmer {
  /** Advance the shimmer animation by `dt` seconds. */
  update(dt: number): void;
  /** Immediately remove all shimmer meshes from the scene. */
  dispose(): void;
}

/** Handle for a caustic light ray that fades in and out. */
export interface CausticRay {
  /** Advance the ray animation by `dt` seconds. Returns false when fully faded out. */
  update(dt: number): boolean;
  /** Immediately remove the ray mesh from the scene. */
  dispose(): void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Returns a random float between min (inclusive) and max (exclusive). */
function randRange(min: number, max: number): number {
  return min + Math.random() * (max - min);
}

/** Returns a small random offset vector for variance. */
function randomOffset(spread: number): Vector3 {
  return new Vector3((Math.random() - 0.5) * spread, (Math.random() - 0.5) * spread, (Math.random() - 0.5) * spread);
}

// Shared geometries (created once, reused across all effects)
let _bubbleGeo: SphereGeometry | null = null;
let _sparkleGeo: SphereGeometry | null = null;
let _causticGeo: CylinderGeometry | null = null;

function getBubbleGeometry(): SphereGeometry {
  if (!_bubbleGeo) _bubbleGeo = new SphereGeometry(1, 8, 6);
  return _bubbleGeo;
}

function getSparkleGeometry(): SphereGeometry {
  if (!_sparkleGeo) _sparkleGeo = new SphereGeometry(1, 6, 4);
  return _sparkleGeo;
}

function getCausticGeometry(): CylinderGeometry {
  if (!_causticGeo) _causticGeo = new CylinderGeometry(1, 1, 1, 8, 1, true);
  return _causticGeo;
}

// ---------------------------------------------------------------------------
// 1. Bubble trail
// ---------------------------------------------------------------------------

interface BubbleParticle {
  mesh: Mesh;
  velocity: Vector3;
  wobblePhase: number;
  wobbleSpeed: number;
  age: number;
  lifespan: number;
  baseScale: number;
  alive: boolean;
}

/**
 * Creates a trail of translucent bubbles that drift in a direction, wobble, grow, and pop.
 *
 * Spawns 8-12 small sphere meshes at `startPos` that drift along `direction` with random
 * offsets. Each bubble rises, wobbles side to side, slowly grows, then self-removes.
 *
 * @param scene - The Three.js scene to add bubbles to.
 * @param startPos - World-space starting position for the trail.
 * @param direction - Primary drift direction for the bubbles.
 * @param color - Optional tint color; defaults to translucent white-blue.
 * @returns A BubbleTrail handle with `update(dt)` and `dispose()` methods.
 */
export function createBubbleTrail(scene: Scene, startPos: Vector3, direction: Vector3, color?: Color): BubbleTrail {
  const bubbleColor = color ?? new Color(0.8, 0.9, 1.0);
  const count = Math.floor(randRange(8, 13));
  const geo = getBubbleGeometry();
  const bubbles: BubbleParticle[] = [];

  for (let i = 0; i < count; i++) {
    const radius = randRange(0.02, 0.06);
    const mat = new MeshStandardMaterial({
      color: bubbleColor,
      transparent: true,
      opacity: 0.6,
      depthWrite: false,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(startPos).add(randomOffset(0.05));
    mesh.scale.setScalar(radius);

    const vel = direction.clone().normalize().multiplyScalar(randRange(0.3, 0.8));
    vel.add(randomOffset(0.2));
    // Ensure bubbles rise
    vel.y = Math.abs(vel.y) + randRange(0.2, 0.5);

    scene.add(mesh);

    bubbles.push({
      mesh,
      velocity: vel,
      wobblePhase: Math.random() * Math.PI * 2,
      wobbleSpeed: randRange(3, 6),
      age: 0,
      lifespan: randRange(1.0, 2.0),
      baseScale: radius,
      alive: true,
    });
  }

  let disposed = false;

  function disposeBubble(b: BubbleParticle): void {
    b.alive = false;
    scene.remove(b.mesh);
    (b.mesh.material as MeshStandardMaterial).dispose();
  }

  return {
    update(dt: number): boolean {
      if (disposed) return false;

      let anyAlive = false;
      for (const b of bubbles) {
        if (!b.alive) continue;

        b.age += dt;
        if (b.age >= b.lifespan) {
          disposeBubble(b);
          continue;
        }

        anyAlive = true;
        const t = b.age / b.lifespan;

        // Move along velocity
        b.mesh.position.addScaledVector(b.velocity, dt);

        // Wobble side to side
        const wobble = Math.sin(b.wobblePhase + b.age * b.wobbleSpeed) * 0.02;
        b.mesh.position.x += wobble;

        // Grow then shrink near end (pop)
        const growCurve = t < 0.7 ? 1.0 + t * 0.5 : 1.35 * (1.0 - (t - 0.7) / 0.3);
        b.mesh.scale.setScalar(b.baseScale * Math.max(growCurve, 0));

        // Fade out near end
        (b.mesh.material as MeshStandardMaterial).opacity = 0.6 * (1.0 - t * t);
      }

      if (!anyAlive) {
        disposed = true;
      }

      return anyAlive;
    },

    dispose(): void {
      if (disposed) return;
      disposed = true;
      for (const b of bubbles) {
        if (b.alive) disposeBubble(b);
      }
    },
  };
}

// ---------------------------------------------------------------------------
// 2. Catch explosion
// ---------------------------------------------------------------------------

interface ExplosionParticle {
  mesh: Mesh;
  velocity: Vector3;
  age: number;
  lifespan: number;
  isBubble: boolean;
  alive: boolean;
}

/**
 * Creates a burst of particles when a fish is caught, scaling with combo level.
 *
 * Emits a mix of color-matched sparkles (70%) and white rising bubbles (30%).
 * More particles spawn at higher combo levels. Self-cleans after all particles expire.
 *
 * @param scene - The Three.js scene to add particles to.
 * @param pos - World-space position of the catch.
 * @param fishColor - Color of the caught fish, used for sparkle tinting.
 * @param comboLevel - Current combo multiplier; increases particle count.
 */
export function createCatchExplosion(scene: Scene, pos: Vector3, fishColor: Color, comboLevel: number): void {
  const baseCount = 15;
  const count = Math.min(baseCount + comboLevel * 5, 40);
  const bubbleCount = Math.floor(count * 0.3);
  const sparkleCount = count - bubbleCount;
  const geo = getSparkleGeometry();
  const particles: ExplosionParticle[] = [];
  const gravity = new Vector3(0, -2.0, 0);
  const drag = 0.97;

  // Sparkle particles (70%)
  for (let i = 0; i < sparkleCount; i++) {
    const mat = new MeshStandardMaterial({
      color: fishColor,
      emissive: fishColor,
      emissiveIntensity: 0.5,
      transparent: true,
      opacity: 1.0,
      depthWrite: false,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(pos);
    const scale = randRange(0.01, 0.03);
    mesh.scale.setScalar(scale);

    const vel = new Vector3((Math.random() - 0.5) * 4, randRange(1, 4), (Math.random() - 0.5) * 4);

    scene.add(mesh);
    particles.push({
      mesh,
      velocity: vel,
      age: 0,
      lifespan: randRange(0.5, 1.0),
      isBubble: false,
      alive: true,
    });
  }

  // Bubble particles (30%)
  for (let i = 0; i < bubbleCount; i++) {
    const mat = new MeshStandardMaterial({
      color: new Color(0.9, 0.95, 1.0),
      transparent: true,
      opacity: 0.7,
      depthWrite: false,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(pos);
    const scale = randRange(0.015, 0.035);
    mesh.scale.setScalar(scale);

    const vel = new Vector3((Math.random() - 0.5) * 1.5, randRange(1.5, 3.5), (Math.random() - 0.5) * 1.5);

    scene.add(mesh);
    particles.push({
      mesh,
      velocity: vel,
      age: 0,
      lifespan: randRange(0.5, 1.0),
      isBubble: true,
      alive: true,
    });
  }

  // Self-updating animation via requestAnimationFrame
  let lastTime = performance.now();

  function tick(): void {
    const now = performance.now();
    const dt = (now - lastTime) / 1000;
    lastTime = now;

    let anyAlive = false;

    for (const p of particles) {
      if (!p.alive) continue;

      p.age += dt;
      if (p.age >= p.lifespan) {
        p.alive = false;
        scene.remove(p.mesh);
        (p.mesh.material as MeshStandardMaterial).dispose();
        continue;
      }

      anyAlive = true;
      const t = p.age / p.lifespan;

      // Apply gravity to sparkles, slight upward bias for bubbles
      if (!p.isBubble) {
        p.velocity.addScaledVector(gravity, dt);
      }
      p.velocity.multiplyScalar(drag);
      p.mesh.position.addScaledVector(p.velocity, dt);

      // Fade out
      (p.mesh.material as MeshStandardMaterial).opacity = (1.0 - t) * (p.isBubble ? 0.7 : 1.0);
    }

    if (anyAlive) {
      requestAnimationFrame(tick);
    }
  }

  requestAnimationFrame(tick);
}

// ---------------------------------------------------------------------------
// 3. Golden shimmer
// ---------------------------------------------------------------------------

/**
 * Creates a persistent golden sparkle aura that orbits around a target mesh.
 *
 * Six tiny emissive gold spheres orbit the target in a ring with gentle scale pulsing.
 * The effect persists until `dispose()` is called.
 *
 * @param scene - The Three.js scene to add shimmer meshes to.
 * @param targetRoot - The Object3D to surround with the shimmer aura.
 * @returns A GoldenShimmer handle with `update(dt)` and `dispose()` methods.
 */
export function createGoldenShimmer(scene: Scene, targetRoot: Object3D): GoldenShimmer {
  const orbitCount = 6;
  const orbitRadius = 0.25;
  const baseScale = 0.015;
  const geo = getSparkleGeometry();
  const goldColor = new Color(1.0, 0.85, 0.2);

  const orbiters: { mesh: Mesh; phaseOffset: number }[] = [];
  let elapsed = 0;
  let disposed = false;

  for (let i = 0; i < orbitCount; i++) {
    const mat = new MeshStandardMaterial({
      color: goldColor,
      emissive: goldColor,
      emissiveIntensity: 0.8,
      transparent: true,
      opacity: 0.9,
      depthWrite: false,
    });
    const mesh = new Mesh(geo, mat);
    mesh.scale.setScalar(baseScale);
    scene.add(mesh);

    orbiters.push({
      mesh,
      phaseOffset: (i / orbitCount) * Math.PI * 2,
    });
  }

  return {
    update(dt: number): void {
      if (disposed) return;

      elapsed += dt;
      const rotSpeed = 1.2; // radians per second
      const targetPos = targetRoot.position;

      for (const orb of orbiters) {
        const angle = elapsed * rotSpeed + orb.phaseOffset;
        orb.mesh.position.set(
          targetPos.x + Math.cos(angle) * orbitRadius,
          targetPos.y + Math.sin(elapsed * 2.0 + orb.phaseOffset) * 0.05,
          targetPos.z + Math.sin(angle) * orbitRadius,
        );

        // Gentle scale pulsing
        const pulse = 1.0 + Math.sin(elapsed * 3.0 + orb.phaseOffset) * 0.3;
        orb.mesh.scale.setScalar(baseScale * pulse);
      }
    },

    dispose(): void {
      if (disposed) return;
      disposed = true;
      for (const orb of orbiters) {
        scene.remove(orb.mesh);
        (orb.mesh.material as MeshStandardMaterial).dispose();
      }
    },
  };
}

// ---------------------------------------------------------------------------
// 4. Caustic ray
// ---------------------------------------------------------------------------

/**
 * Creates a vertical light shaft simulating sunlight filtering through water.
 *
 * A tall translucent cylinder fades in over 1s, holds for 1s, then fades out over 1s
 * (3s total). Gently sways side to side. Self-disposes when the animation completes.
 *
 * @param scene - The Three.js scene to add the ray to.
 * @param x - World-space X position for the ray.
 * @param z - World-space Z position for the ray.
 * @returns A CausticRay handle with `update(dt)` and `dispose()` methods.
 */
export function createCausticRay(scene: Scene, x: number, z: number): CausticRay {
  const height = 4.0;
  const radius = 0.08;
  const totalLife = 3.0;
  const fadeInEnd = 1.0;
  const fadeOutStart = 2.0;
  const maxOpacity = 0.15;

  const geo = getCausticGeometry();
  const mat = new MeshStandardMaterial({
    color: new Color(0.85, 0.92, 1.0),
    emissive: new Color(0.85, 0.92, 1.0),
    emissiveIntensity: 0.4,
    transparent: true,
    opacity: 0.0,
    depthWrite: false,
    side: 2, // DoubleSide
  });

  const mesh = new Mesh(geo, mat);
  mesh.scale.set(radius, height, radius);
  mesh.position.set(x, height * 0.5, z);
  scene.add(mesh);

  let elapsed = 0;
  let disposed = false;
  const swayPhase = Math.random() * Math.PI * 2;

  return {
    update(dt: number): boolean {
      if (disposed) return false;

      elapsed += dt;
      if (elapsed >= totalLife) {
        this.dispose();
        return false;
      }

      // Opacity envelope: fade in, hold, fade out
      let opacity: number;
      if (elapsed < fadeInEnd) {
        opacity = (elapsed / fadeInEnd) * maxOpacity;
      } else if (elapsed < fadeOutStart) {
        opacity = maxOpacity;
      } else {
        opacity = maxOpacity * (1.0 - (elapsed - fadeOutStart) / (totalLife - fadeOutStart));
      }
      mat.opacity = Math.max(opacity, 0);

      // Gentle sway
      const sway = Math.sin(swayPhase + elapsed * 1.5) * 0.04;
      mesh.position.x = x + sway;

      return true;
    },

    dispose(): void {
      if (disposed) return;
      disposed = true;
      scene.remove(mesh);
      mat.dispose();
    },
  };
}

import type { FishState } from '../types';
import {
  BOUNDS,
  FISH_DESPAWN_SCALE_DURATION,
  GOLDEN_SCALE,
  EAT_ANIM_DURATION,
  SHARK_BODY_SCALE_X,
  GOLDEN_DODGE_DISTANCE,
  GOLDEN_DODGE_COOLDOWN,
  GOLDEN_MAX_DODGES,
  GOLDEN_TIRED_SPEED_MULTIPLIER,
} from '../types';
import { clamp } from '../helpers';

/**
 * Per-frame animation for fish entities ΓÇö drift movement, dodge behavior,
 * and despawn scaling. Concerned only with how fish LOOK and MOVE, not
 * what they ARE (lifecycle.ts) or how game rules decide what happens (orchestrator).
 */

/**
 * Updates a fish's drift movement using sine/cosine phase oscillation.
 * Includes gentle startle when shark is nearby.
 * @param fish - The fish to animate.
 * @param dt - Frame delta time (already time-scaled).
 * @param speedMultiplier - Difficulty-driven speed multiplier.
 * @param sharkPosX - Shark X position for startle check.
 * @param sharkPosZ - Shark Z position for startle check.
 */
export function updateFishDrift(
  fish: FishState,
  dt: number,
  speedMultiplier: number,
  sharkPosX?: number,
  sharkPosZ?: number,
): void {
  // Tired golden fish drifts slower
  let effectiveMultiplier = speedMultiplier;
  if (fish.kind === 'golden' && fish.dodgeCount >= GOLDEN_MAX_DODGES) {
    effectiveMultiplier *= GOLDEN_TIRED_SPEED_MULTIPLIER;
  }

  fish.driftPhaseX += dt * fish.driftSpeed * effectiveMultiplier * 0.3;
  fish.driftPhaseZ += dt * fish.driftSpeed * effectiveMultiplier * 0.25;

  const targetX = fish.driftCenterX + Math.sin(fish.driftPhaseX) * 2.0;
  const targetZ = fish.driftCenterZ + Math.cos(fish.driftPhaseZ) * 2.0;

  // Gentle startle: speed up drift slightly when shark is near
  let effectiveSpeed = fish.driftSpeed * effectiveMultiplier;
  if (sharkPosX !== undefined && sharkPosZ !== undefined) {
    const sdx = fish.root.position.x - sharkPosX;
    const sdz = fish.root.position.z - sharkPosZ;
    const sharkDist = Math.sqrt(sdx * sdx + sdz * sdz);
    if (sharkDist < 1.5) {
      effectiveSpeed *= 1.3;
      if (sharkDist < 1.0) {
        fish.driftPhaseX += (Math.random() - 0.5) * 0.3;
        fish.driftPhaseZ += (Math.random() - 0.5) * 0.3;
      }
    }
  }

  return applyMovement(fish, targetX, targetZ, effectiveSpeed * dt);
}

/**
 * Updates golden fish dodge behavior. The golden fish darts sideways
 * when the shark gets close, up to GOLDEN_MAX_DODGES times.
 * @param fish - The golden fish state.
 * @param sharkPosX - Shark X position.
 * @param sharkPosZ - Shark Z position.
 * @param dt - Frame delta time.
 */
export function updateGoldenDodge(fish: FishState, sharkPosX: number, sharkPosZ: number, dt: number): void {
  if (!fish.active || fish.kind !== 'golden') return;

  if (fish.dodgeCooldown > 0) {
    fish.dodgeCooldown -= dt;
    return;
  }

  if (fish.dodgeCount >= GOLDEN_MAX_DODGES) return;

  const dx = fish.root.position.x - sharkPosX;
  const dz = fish.root.position.z - sharkPosZ;
  const dist = Math.sqrt(dx * dx + dz * dz);

  if (dist < 2.0 && dist > 0.01 && !fish.isTargeted) {
    // Dodge perpendicular to approach vector
    const perpX = -dz / dist;
    const perpZ = dx / dist;
    const side = Math.random() > 0.5 ? 1 : -1;

    fish.root.position.x += perpX * side * GOLDEN_DODGE_DISTANCE;
    fish.root.position.z += perpZ * side * GOLDEN_DODGE_DISTANCE;

    fish.root.position.x = clamp(fish.root.position.x, -BOUNDS, BOUNDS);
    fish.root.position.z = clamp(fish.root.position.z, -BOUNDS, BOUNDS);

    fish.dodgeCount++;
    fish.dodgeCooldown = GOLDEN_DODGE_COOLDOWN;

    fish.driftCenterX = fish.root.position.x;
    fish.driftCenterZ = fish.root.position.z;
  }
}

/**
 * Animates a fish's despawn: scale-to-zero over FISH_DESPAWN_SCALE_DURATION.
 * @param fish - The fish despawning.
 * @param dt - Frame delta time (already time-scaled).
 * @returns True when the despawn animation is complete and the fish can be disposed.
 */
export function updateDespawnAnimation(fish: FishState, dt: number): boolean {
  fish.despawnTimer -= dt;
  const s = clamp(fish.despawnTimer / FISH_DESPAWN_SCALE_DURATION, 0, 1);
  const baseScale = fish.kind === 'golden' ? GOLDEN_SCALE * 0.6 : 0.55;
  fish.root.scale.setScalar(s * baseScale);

  if (fish.despawnTimer <= 0) {
    fish.root.scale.setScalar(0);
    return true;
  }
  return false;
}

/**
 * Updates the shark's jaw-snap eat animation (body X scale pulse).
 * @param sharkBody - The shark body mesh.
 * @param eatAnimTimer - Current timer value.
 * @param dt - Frame delta time (already time-scaled).
 * @returns Updated eatAnimTimer value.
 */
export function updateEatAnimation(sharkBody: { scale: { x: number } }, eatAnimTimer: number, dt: number): number {
  eatAnimTimer -= dt;
  const t = clamp(eatAnimTimer / EAT_ANIM_DURATION, 0, 1);
  sharkBody.scale.x = SHARK_BODY_SCALE_X + 0.2 * Math.sin(t * Math.PI);

  if (eatAnimTimer <= 0) {
    sharkBody.scale.x = SHARK_BODY_SCALE_X;
    return -1;
  }
  return eatAnimTimer;
}

// ΓöÇΓöÇ Internal helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

// Lerp fish position toward target and rotate to face movement direction
function applyMovement(fish: FishState, targetX: number, targetZ: number, moveSpeed: number): void {
  const fmx = targetX - fish.root.position.x;
  const fmz = targetZ - fish.root.position.z;
  const fmDist = Math.sqrt(fmx * fmx + fmz * fmz);

  if (fmDist > 0.01) {
    const fStep = Math.min(moveSpeed, fmDist);
    fish.root.position.x += (fmx / fmDist) * fStep;
    fish.root.position.z += (fmz / fmDist) * fStep;

    // Rotate to face movement
    fish.root.rotation.y = Math.atan2(fmz, fmx);
  }

  // Keep in bounds
  fish.root.position.x = clamp(fish.root.position.x, -BOUNDS, BOUNDS);
  fish.root.position.z = clamp(fish.root.position.z, -BOUNDS, BOUNDS);

  // Wrap drift center if fish drifts far
  if (Math.abs(fish.root.position.x - fish.driftCenterX) > 4) {
    fish.driftCenterX = fish.root.position.x;
  }
  if (Math.abs(fish.root.position.z - fish.driftCenterZ) > 4) {
    fish.driftCenterZ = fish.root.position.z;
  }
}

import {
  Group,
  Mesh,
  Color,
  SphereGeometry,
  CylinderGeometry,
  BoxGeometry,
  ConeGeometry,
  MeshStandardMaterial,
} from 'three';
import type { FishSpeciesId } from './species';

// ---------------------------------------------------------------------------
// Material helpers
// ---------------------------------------------------------------------------

/** Create a standard body material for a fish species. */
function bodyMaterial(prefix: string, color: Color): MeshStandardMaterial {
  return new MeshStandardMaterial({
    name: `${prefix}_bodyMat`,
    color,
    roughness: 0.6,
    metalness: 0.1,
  });
}

/** Create a fin material ΓÇö slightly lighter tint of the body color. */
function finMaterial(prefix: string, color: Color): MeshStandardMaterial {
  const lighter = color.clone().lerp(new Color(1, 1, 1), 0.2);
  return new MeshStandardMaterial({
    name: `${prefix}_finMat`,
    color: lighter,
    roughness: 0.7,
    metalness: 0.1,
  });
}

/** Create a white eye sclera material. */
function eyeWhiteMaterial(prefix: string): MeshStandardMaterial {
  return new MeshStandardMaterial({
    name: `${prefix}_eyeWhiteMat`,
    color: new Color(1, 1, 1),
    roughness: 0.3,
    metalness: 0,
  });
}

/** Create a black pupil material. */
function pupilMaterial(prefix: string): MeshStandardMaterial {
  return new MeshStandardMaterial({
    name: `${prefix}_pupilMat`,
    color: new Color(0.02, 0.02, 0.02),
    roughness: 0.3,
    metalness: 0,
  });
}

// ---------------------------------------------------------------------------
// Shared eye builder
// ---------------------------------------------------------------------------

/**
 * Build a pair of eyes (sclera + pupil) and add them to the parent group.
 *
 * @param group - Parent group to attach eyes to.
 * @param prefix - Naming prefix for mesh names.
 * @param yOffset - Vertical offset from center.
 * @param zOffset - Forward offset from center.
 * @param xSpread - Horizontal spread between the two eyes.
 * @param scleraRadius - Radius of the white eye sphere.
 * @param pupilRadius - Radius of the black pupil sphere.
 */
function addEyes(
  group: Group,
  prefix: string,
  yOffset: number,
  zOffset: number,
  xSpread: number,
  scleraRadius: number,
  pupilRadius: number,
): void {
  const eyeWhite = eyeWhiteMaterial(prefix);
  const pupil = pupilMaterial(prefix);

  for (const side of [-1, 1] as const) {
    const sclera = new Mesh(new SphereGeometry(scleraRadius, 12, 8), eyeWhite);
    sclera.name = `${prefix}_eye_${side === -1 ? 'L' : 'R'}`;
    sclera.position.set(side * xSpread, yOffset, zOffset);
    group.add(sclera);

    const pupilMesh = new Mesh(new SphereGeometry(pupilRadius, 8, 6), pupil);
    pupilMesh.name = `${prefix}_pupil_${side === -1 ? 'L' : 'R'}`;
    pupilMesh.position.set(side * xSpread, yOffset, zOffset + scleraRadius * 0.6);
    group.add(pupilMesh);
  }
}

// ---------------------------------------------------------------------------
// Species builders
// ---------------------------------------------------------------------------

/**
 * Build a clownfish mesh ΓÇö orange/white striped body with a cone tail and dorsal fins.
 *
 * @param color - Base body color.
 * @returns A Group containing all child meshes for the clownfish.
 */
export function buildClownfish(color: Color): Group {
  const prefix = 'fish_clownfish';
  const group = new Group();
  group.name = `${prefix}_root`;

  // Body ΓÇö slightly elongated sphere
  const body = new Mesh(new SphereGeometry(0.25, 16, 12), bodyMaterial(prefix, color));
  body.name = `${prefix}_body`;
  body.scale.set(1, 1, 1.3);
  group.add(body);

  // White stripes ΓÇö thin cylinder rings
  const stripeMat = new MeshStandardMaterial({
    name: `${prefix}_stripeMat`,
    color: new Color(1, 1, 1),
    roughness: 0.6,
    metalness: 0.1,
  });

  for (let i = 0; i < 2; i++) {
    const stripe = new Mesh(new CylinderGeometry(0.26, 0.26, 0.02, 16), stripeMat);
    stripe.name = `${prefix}_stripe_${i}`;
    stripe.rotation.x = Math.PI / 2;
    stripe.position.z = -0.08 + i * 0.16;
    group.add(stripe);
  }

  // Tail ΓÇö flattened cone
  const finMat = finMaterial(prefix, color);
  const tail = new Mesh(new ConeGeometry(0.12, 0.2, 8), finMat);
  tail.name = `${prefix}_tail`;
  tail.rotation.x = Math.PI / 2;
  tail.scale.set(1, 0.4, 1);
  tail.position.z = -0.38;
  group.add(tail);

  // Dorsal fins ΓÇö small boxes on top
  for (let i = 0; i < 2; i++) {
    const fin = new Mesh(new BoxGeometry(0.02, 0.08, 0.06), finMat);
    fin.name = `${prefix}_dorsalFin_${i}`;
    fin.position.set(0, 0.22, -0.05 + i * 0.1);
    group.add(fin);
  }

  // Eyes
  addEyes(group, prefix, 0.06, 0.22, 0.12, 0.045, 0.025);

  return group;
}

/**
 * Build a blue tang mesh ΓÇö sleek tropical fish with a prominent dorsal fin and forked tail.
 *
 * @param color - Base body color.
 * @returns A Group containing all child meshes for the blue tang.
 */
export function buildBlueTang(color: Color): Group {
  const prefix = 'fish_blueTang';
  const group = new Group();
  group.name = `${prefix}_root`;

  // Body ΓÇö elongated and slightly compressed vertically
  const body = new Mesh(new SphereGeometry(0.25, 16, 12), bodyMaterial(prefix, color));
  body.name = `${prefix}_body`;
  body.scale.set(1, 0.8, 1.5);
  group.add(body);

  // Prominent dorsal fin ΓÇö rotated cone on top
  const finMat = finMaterial(prefix, color);
  const dorsal = new Mesh(new ConeGeometry(0.08, 0.22, 6), finMat);
  dorsal.name = `${prefix}_dorsalFin`;
  dorsal.position.set(0, 0.24, -0.04);
  group.add(dorsal);

  // Forked tail ΓÇö two thin cones angled apart
  for (let i = 0; i < 2; i++) {
    const fork = new Mesh(new ConeGeometry(0.04, 0.18, 6), finMat);
    fork.name = `${prefix}_tailFork_${i}`;
    fork.rotation.x = Math.PI / 2;
    fork.rotation.z = (i === 0 ? 1 : -1) * 0.4;
    fork.position.set(0, i === 0 ? 0.06 : -0.06, -0.4);
    group.add(fork);
  }

  // Eyes
  addEyes(group, prefix, 0.04, 0.28, 0.13, 0.04, 0.022);

  return group;
}

/**
 * Build a pufferfish mesh ΓÇö round spiky body with big cute eyes.
 *
 * @param color - Base body color.
 * @returns A Group containing all child meshes for the pufferfish.
 */
export function buildPufferfish(color: Color): Group {
  const prefix = 'fish_pufferfish';
  const group = new Group();
  group.name = `${prefix}_root`;

  // Body ΓÇö round sphere
  const body = new Mesh(new SphereGeometry(0.28, 16, 12), bodyMaterial(prefix, color));
  body.name = `${prefix}_body`;
  group.add(body);

  // Spike bumps ΓÇö 12 small cones distributed on the surface
  const spikeMat = finMaterial(prefix, color);
  const goldenAngle = Math.PI * (3 - Math.sqrt(5));
  for (let i = 0; i < 12; i++) {
    const theta = goldenAngle * i;
    const phi = Math.acos(1 - (2 * (i + 0.5)) / 12);
    const r = 0.28;
    const x = r * Math.sin(phi) * Math.cos(theta);
    const y = r * Math.sin(phi) * Math.sin(theta);
    const z = r * Math.cos(phi);

    const spike = new Mesh(new ConeGeometry(0.025, 0.07, 5), spikeMat);
    spike.name = `${prefix}_spike_${i}`;
    spike.position.set(x, y, z);
    spike.lookAt(x * 2, y * 2, z * 2);
    group.add(spike);
  }

  // Small side fins
  const finMat = finMaterial(prefix, color);
  for (const side of [-1, 1] as const) {
    const fin = new Mesh(new BoxGeometry(0.04, 0.06, 0.08), finMat);
    fin.name = `${prefix}_sideFin_${side === -1 ? 'L' : 'R'}`;
    fin.position.set(side * 0.28, 0, 0.05);
    group.add(fin);
  }

  // Big cute eyes ΓÇö larger than other species
  addEyes(group, prefix, 0.1, 0.22, 0.14, 0.065, 0.04);

  // Mouth ΓÇö tiny sphere
  const mouthMat = new MeshStandardMaterial({
    name: `${prefix}_mouthMat`,
    color: new Color(0.8, 0.3, 0.3),
    roughness: 0.5,
    metalness: 0,
  });
  const mouth = new Mesh(new SphereGeometry(0.025, 8, 6), mouthMat);
  mouth.name = `${prefix}_mouth`;
  mouth.position.set(0, -0.06, 0.27);
  group.add(mouth);

  return group;
}

/**
 * Build a seahorse mesh ΓÇö curved upright body made of stacked spheres with a curled tail.
 *
 * @param color - Base body color.
 * @returns A Group containing all child meshes for the seahorse.
 */
export function buildSeahorse(color: Color): Group {
  const prefix = 'fish_seahorse';
  const group = new Group();
  group.name = `${prefix}_root`;

  const bMat = bodyMaterial(prefix, color);

  // Body ΓÇö stack of 5 small spheres along an S-curve
  const curvePoints: [number, number, number][] = [
    [0, 0.24, 0.04],
    [0, 0.12, 0.08],
    [0, 0.0, 0.04],
    [0, -0.12, -0.02],
    [0, -0.24, -0.06],
  ];

  for (let i = 0; i < curvePoints.length; i++) {
    const radius = 0.07 - i * 0.006;
    const seg = new Mesh(new SphereGeometry(radius, 10, 8), bMat);
    seg.name = `${prefix}_bodySegment_${i}`;
    seg.position.set(curvePoints[i][0], curvePoints[i][1], curvePoints[i][2]);
    group.add(seg);
  }

  // Curled tail ΓÇö 3 tiny spheres curling inward at bottom
  const tailPoints: [number, number, number][] = [
    [0, -0.33, -0.04],
    [0, -0.38, 0.01],
    [0, -0.4, 0.06],
  ];

  for (let i = 0; i < tailPoints.length; i++) {
    const radius = 0.03 - i * 0.005;
    const seg = new Mesh(new SphereGeometry(radius, 8, 6), bMat);
    seg.name = `${prefix}_tail_${i}`;
    seg.position.set(tailPoints[i][0], tailPoints[i][1], tailPoints[i][2]);
    group.add(seg);
  }

  // Tiny dorsal fin on back
  const finMat = finMaterial(prefix, color);
  const dorsalFin = new Mesh(new BoxGeometry(0.015, 0.1, 0.04), finMat);
  dorsalFin.name = `${prefix}_dorsalFin`;
  dorsalFin.position.set(0, 0.06, -0.06);
  group.add(dorsalFin);

  // Snout ΓÇö elongated cone pointing forward
  const snout = new Mesh(new ConeGeometry(0.025, 0.12, 6), bMat);
  snout.name = `${prefix}_snout`;
  snout.rotation.x = -Math.PI / 2;
  snout.position.set(0, 0.2, 0.12);
  group.add(snout);

  // Crown bumps on head
  for (let i = 0; i < 3; i++) {
    const bump = new Mesh(new SphereGeometry(0.018, 6, 4), bMat);
    bump.name = `${prefix}_crown_${i}`;
    bump.position.set(-0.025 + i * 0.025, 0.32, 0.03);
    group.add(bump);
  }

  // Eyes
  addEyes(group, prefix, 0.24, 0.08, 0.06, 0.03, 0.016);

  return group;
}

/**
 * Build a golden angelfish mesh ΓÇö flat diamond-shaped body with trailing fins and emissive glow.
 *
 * @param color - Base body color.
 * @returns A Group containing all child meshes for the golden angelfish.
 */
export function buildGoldenAngelfish(color: Color): Group {
  const prefix = 'fish_goldenAngelfish';
  const group = new Group();
  group.name = `${prefix}_root`;

  // Body ΓÇö sphere scaled flat into a diamond shape
  const bMat = bodyMaterial(prefix, color);
  bMat.emissive = new Color(0.3, 0.25, 0.05);
  bMat.emissiveIntensity = 0.4;

  const body = new Mesh(new SphereGeometry(0.3, 16, 12), bMat);
  body.name = `${prefix}_body`;
  body.scale.set(0.4, 1.0, 1.2);
  group.add(body);

  // Trailing fins ΓÇö long thin cones, top and bottom, extended backward
  const finMat = finMaterial(prefix, color);
  finMat.emissive = new Color(0.2, 0.16, 0.03);
  finMat.emissiveIntensity = 0.3;

  const topFin = new Mesh(new ConeGeometry(0.03, 0.3, 6), finMat);
  topFin.name = `${prefix}_trailingFin_top`;
  topFin.rotation.x = Math.PI * 0.6;
  topFin.position.set(0, 0.2, -0.2);
  group.add(topFin);

  const bottomFin = new Mesh(new ConeGeometry(0.03, 0.3, 6), finMat);
  bottomFin.name = `${prefix}_trailingFin_bottom`;
  bottomFin.rotation.x = -Math.PI * 0.6;
  bottomFin.position.set(0, -0.2, -0.2);
  group.add(bottomFin);

  // Eyes
  addEyes(group, prefix, 0.04, 0.28, 0.1, 0.04, 0.022);

  return group;
}

