/** Checks if a mesh is a descendant of (or is) a root object. */
function isDescendantOf(child: Object3D, root: Object3D): boolean {
  let current: Object3D | null = child;
  while (current) {
    if (current === root) return true;
    current = current.parent;
  }
  return false;
}

/**
 * Creates the Little Shark mini-game.
 * @param context - Shell-provided context with shared systems.
 * @returns An IMiniGame implementation for the little-shark game.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;
  const shellCam = context.camera as PerspectiveCamera;
  let env: SceneEnvironment | null = null;
  let ambientCreatures: AmbientCreatures | null = null;
  let sharkRoot: Mesh | null = null;
  let sharkBody: Object3D | null = null;
  let sharkGlowTrail: ReturnType<typeof createGlowTrail> | null = null;
  let tailMeshes: Object3D[] = [];
  let eyeMeshes: Object3D[] = [];
  let sharkAnim: SharkAnimState = createSharkAnimState();
  let sharkMove: SharkMoveState = createSharkMoveState();
  const sharkPos = new Vector3(0, 0, 0);
  let paused = false;
  let elapsedTime = 0;
  let eatAnimTimer = -1;
  let firstCatchDone = false;
  const fishArray: FishState[] = [];
  let goldenFish: FishState | null = null;
  let spawnState: ProximitySpawnState | null = null;
  let surpriseState: SurpriseState | null = null;
  let unsubScore: (() => void) | null = null;
  const celebrations = createCelebrationQueue();
  let interactionState: InteractionState = createInteractionState();

  // Phase 3 ΓÇö Hunt FSM, Expressions
  let huntState: HuntFSMState = createHuntFSMState();
  let expressionState: ExpressionState = createExpressionState();

  // Phase 6 ΓÇö Camera, VFX, Screen effects
  let cameraState: CameraState | null = null;
  let vignetteState: VignetteState | null = null;
  let speedLineState: SpeedLineState | null = null;
  let colorFlashState: ColorFlashState | null = null;
  const activeBubbleTrails: BubbleTrail[] = [];

  function eatFishAction(fish: FishState): void {
    fish.active = false;
    fish.despawnTimer = FISH_DESPAWN_SCALE_DURATION;
    context.score.addPoints(FISH_POINTS[fish.kind]);
    context.combo.registerHit();
    celebrations.playEatCelebration({
      scene,
      fishPos: fish.root.position.clone(),
      fishColor: fish.kind === 'golden' ? GOLDEN_COLOR : FISH_COLORS[0],
      fishKind: fish.kind,
      sharkBody,
      sharkRoot,
      sharkAnim,
      comboStreak: context.combo.streak,
      isFirstCatch: !firstCatchDone,
      context,
    });
    if (!firstCatchDone) firstCatchDone = true;
    eatAnimTimer = EAT_ANIM_DURATION;

    // Camera catch zoom + screen shake
    if (cameraState) {
      triggerCatchZoom(cameraState, fish.kind === 'golden' ? 5.0 : 3.0);
      triggerScreenShake(cameraState, 0.12, fish.kind === 'golden' ? 0.06 : 0.03);
    }

    // Catch explosion VFX scaled by combo
    createCatchExplosion(
      scene,
      fish.root.position.clone(),
      fish.kind === 'golden' ? GOLDEN_COLOR : FISH_COLORS[0],
      context.combo.streak,
    );

    // Golden catch: vignette + color flash
    if (fish.kind === 'golden') {
      if (vignetteState) triggerVignette(vignetteState, 0.4, 0.2);
      if (colorFlashState) triggerColorFlash(colorFlashState, new Color(1.0, 0.85, 0.2), 0.3, 0.12);
    }

    // Cancel hunt if we ate the hunted fish
    if (huntState.targetFishRoot === fish.root) {
      cancelHunt(huntState);
    }

    // Notify proximity spawner to queue replacements
    if (spawnState) notifyFishEaten(spawnState, fish.kind === 'golden');
  }

  // ΓöÇΓöÇ Entity pool helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Acquires a fish from the pool or creates a new one.
   * Reuses inactive fish of matching kind before allocating.
   * @param kind - The fish kind to acquire.
   * @returns A ready-to-use FishState.
   */
  function acquireFish(kind: FishKind): FishState {
    const pooled = fishArray.find((f) => !f.active && f.despawnTimer <= 0 && f.kind === kind);
    if (pooled) {
      resetFishForSpawn(pooled, sharkPos);
      return pooled;
    }
    const fish = createFish(scene, sharkPos, kind);
    fishArray.push(fish);
    return fish;
  }

  // ΓöÇΓöÇ Update subsystems ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /** Updates shark movement, rotation, hunt FSM, and applies to mesh. */
  let _dbgTimer = 0;
  function updateSharkMovement(dt: number): void {
    const huntPhase = getHuntPhase(huntState);
    _dbgTimer += dt;
    if (_dbgTimer > 1.0) {
      _dbgTimer = 0;
      console.log(
        '[SHARK-DBG] movement tick: huntPhase=',
        huntPhase,
        '| swimPhase=',
        sharkMove.swimPhase,
        '| pos=',
        { x: sharkMove.posX.toFixed(2), z: sharkMove.posZ.toFixed(2) },
        '| dest=',
        { x: sharkMove.swimDestX.toFixed(2), z: sharkMove.swimDestZ.toFixed(2) },
        '| dragging=',
        sharkMove.isBeingDragged,
      );
    }

    // Hunt FSM drives movement when not idle
    if (huntPhase !== 'idle') {
      updateHuntFSM(huntState, sharkMove, dt, {
        onStrike: () => {
          // Speed lines on strike
          if (speedLineState) triggerSpeedLines(speedLineState, 0.25);
        },
        onCelebrate: () => {
          triggerBarrelRoll(sharkAnim);
        },
      });
      // Face the direction of travel during hunt ΓÇö fast rotation
      if (Math.abs(sharkMove.velX) > 0.01 || Math.abs(sharkMove.velZ) > 0.01) {
        sharkMove.rotY = Math.atan2(-sharkMove.velZ, sharkMove.velX);
      }
      // Apply position from hunt FSM
      if (sharkRoot) applyToMesh(sharkMove, sharkRoot);
      sharkPos.x = sharkMove.posX;
      sharkPos.z = sharkMove.posZ;
    } else {
      // Normal movement when not hunting
      const wasLunging = sharkMove.isLunging;
      if (sharkMove.swimPhase !== 'idle') {
        updateSwim(sharkMove, dt);
      } else if (!sharkMove.isBeingDragged) {
        updateIdleDrift(sharkMove, dt);
      } else {
        updateSpringFollow(sharkMove, dt);
      }
      updateRotation(sharkMove, dt);
      if (sharkRoot) applyToMesh(sharkMove, sharkRoot);
      sharkPos.x = sharkMove.posX;
      sharkPos.z = sharkMove.posZ;

      if (!sharkMove.isLunging && wasLunging) {
        const near = fishArray.some(
          (f) => f.active && Math.hypot(sharkMove.posX - f.root.position.x, sharkMove.posZ - f.root.position.z) < 2.0,
        );
        if (!near) triggerHeadLook(sharkAnim);
      }
    }

    // Update expression mood based on hunt phase
    const targetMood = getMoodForPhase(huntPhase);
    setMood(expressionState, targetMood);
    updateExpressions(expressionState, dt);
  }

  /** Updates all shark animations driven by mood and speed. */
  function updateSharkAnimations(dt: number): void {
    const speed = getSpeed(sharkMove);
    const mood = getMoodParams(expressionState);

    // Tail wag modulated by mood
    if (tailMeshes.length > 0) {
      // Temporarily scale animation params by mood multipliers
      const origTailPhase = sharkAnim.tailPhase;
      updateTailWag(tailMeshes, sharkAnim, speed * mood.tailFreqMult, dt);
      // Apply amplitude modulation by scaling the result
      for (const tail of tailMeshes) {
        tail.rotation.y *= mood.tailAmpMult;
      }
      void origTailPhase; // used for type-checking only
    }

    if (sharkBody) {
      updateBodyWobble(sharkBody, elapsedTime, speed * mood.bodyWobbleMult);
      updateBreathing(sharkBody, elapsedTime);
    }

    // Eye scale driven by mood
    if (eyeMeshes.length > 0) {
      updateEyeBlink(eyeMeshes, sharkAnim, dt);
      for (const eye of eyeMeshes) {
        eye.scale.y *= mood.eyeScaleY;
      }
    }

    if (sharkRoot) {
      updateBarrelRoll(sharkRoot, sharkAnim, dt);
      updateHeadLook(sharkRoot, sharkAnim, dt);
    }
  }

  /** Updates proximity-based spawning and culls distant fish. */
  function updateSpawning(dt: number): void {
    if (!spawnState) return;

    updateProximitySpawning(spawnState, dt, sharkPos.x, sharkPos.z, {
      spawnFish: (edgeX: number, edgeZ: number, targetX: number, targetZ: number) => {
        const fish = acquireFish('standard');
        fish.root.position.set(edgeX, 0, edgeZ);
        fish.spawning = true;
        fish.spawnTimer = 1.5;
        fish.spawnEdgeX = edgeX;
        fish.spawnEdgeZ = edgeZ;
        fish.driftCenterX = targetX;
        fish.driftCenterZ = targetZ;
      },
      spawnGoldenFish: () => {
        if (!goldenFish) goldenFish = createFish(scene, sharkPos, 'golden');
      },
      countNearbyFish: () => {
        let count = 0;
        for (const f of fishArray) {
          if (!f.active || f.spawning) continue;
          const dx = f.root.position.x - sharkPos.x;
          const dz = f.root.position.z - sharkPos.z;
          if (dx * dx + dz * dz < CAMERA_VIEW_RADIUS * CAMERA_VIEW_RADIUS) count++;
        }
        return count;
      },
    });

    // Silently cull fish that have drifted far from the shark
    for (const fish of fishArray) {
      if (!fish.active || fish.spawning) continue;
      const dx = fish.root.position.x - sharkPos.x;
      const dz = fish.root.position.z - sharkPos.z;
      if (dx * dx + dz * dz > CULL_DISTANCE * CULL_DISTANCE) {
        deactivateFish(fish);
      }
    }
  }

  /** Updates all environment systems (caustics, sway, reactions, ambient, surprises). */
  function updateEnvironmentSystems(dt: number): void {
    if (env) {
      updateCausticLights(env.causticLights, elapsedTime);
      updateSeaweedSway(env.seaweeds, elapsedTime);
      updateAnemoneSway(env.anemones, elapsedTime);
      updateEnvironmentReactions(sharkPos.x, sharkPos.z, env, dt, elapsedTime);
      env.waterSurface.position.y = 2.5 + Math.sin(elapsedTime * 0.15) * 0.03;
    }
    if (ambientCreatures) updateAmbientCreatures(ambientCreatures, dt, elapsedTime, sharkPos.x, sharkPos.z);
    if (surpriseState && env) updateSurprises(surpriseState, elapsedTime, dt, env, scene);
  }

  /** Updates all fish (drift, dodge, spawn, despawn) and checks collisions. */
  function updateFishAndCollisions(dt: number, speedMultiplier: number): void {
    const allFish: FishState[] = [...fishArray];
    if (goldenFish) allFish.push(goldenFish);
    for (const fish of allFish) {
      if (!fish.active) {
        if (fish.despawnTimer > 0) {
          const done = updateDespawnAnimation(fish, dt);
          if (done) {
            if (fish === goldenFish) {
              disposeFish(fish);
              goldenFish = null;
            } else {
              deactivateFish(fish);
            }
          }
        }
        continue;
      }
      if (fish.spawning) {
        fish.spawnTimer -= dt;
        const t = clamp(1.0 - fish.spawnTimer / 1.5, 0, 1);
        const eased = t * t * (3 - 2 * t);
        fish.root.position.x = fish.spawnEdgeX + (fish.driftCenterX - fish.spawnEdgeX) * eased;
        fish.root.position.z = fish.spawnEdgeZ + (fish.driftCenterZ - fish.spawnEdgeZ) * eased;
        if (fish.spawnTimer <= 0) fish.spawning = false;
        continue;
      }
      updateFishDrift(fish, dt, speedMultiplier, sharkPos.x, sharkPos.z);
      if (fish.kind === 'golden') updateGoldenDodge(fish, sharkPos.x, sharkPos.z, dt);
    }

    // Collision detection ΓÇö standard fish
    for (let i = fishArray.length - 1; i >= 0; i--) {
      const fish = fishArray[i];
      if (!fish.active || fish.spawning) continue;
      const ex = sharkPos.x - fish.root.position.x;
      const ez = sharkPos.z - fish.root.position.z;
      if (Math.sqrt(ex * ex + ez * ez) < FISH_HIT_RADIUS) eatFishAction(fish);
    }
    // Collision detection ΓÇö golden fish
    if (goldenFish && goldenFish.active && !goldenFish.spawning) {
      const gx = sharkPos.x - goldenFish.root.position.x;
      const gz = sharkPos.z - goldenFish.root.position.z;
      if (Math.sqrt(gx * gx + gz * gz) < GOLDEN_HIT_RADIUS) {
        eatFishAction(goldenFish);
        context.celebration.milestone(0, 0, 'large');
      }
    }
  }

  /** Updates camera follow, VFX, and screen effects. */
  function updateCameraAndEffects(dt: number): void {
    // Follow camera
    if (cameraState) {
      updateFollowCamera(cameraState, shellCam, sharkPos.x, sharkPos.z, dt);
    }

    // Screen effects
    if (vignetteState) updateVignette(vignetteState, dt);
    if (speedLineState) updateSpeedLines(speedLineState, dt);
    if (colorFlashState) updateColorFlash(colorFlashState, dt);

    // Bubble trails ΓÇö tick active trails, remove expired
    for (let i = activeBubbleTrails.length - 1; i >= 0; i--) {
      const alive = activeBubbleTrails[i].update(dt);
      if (!alive) {
        activeBubbleTrails[i].dispose();
        activeBubbleTrails.splice(i, 1);
      }
    }

    // Spawn bubble trail behind swimming shark periodically
    if (getSpeed(sharkMove) > 1.0 && sharkRoot && Math.random() < dt * 3.0) {
      const dir = new Vector3(-Math.sin(sharkMove.rotY) * 0.5, 0.3, -Math.cos(sharkMove.rotY) * 0.5);
      const trail = createBubbleTrail(scene, sharkRoot.position.clone(), dir);
      activeBubbleTrails.push(trail);
    }
  }

  // ΓöÇΓöÇ Game implementation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const game: IMiniGame = {
    id: 'little-shark',

    async setup(): Promise<void> {
      env = setupScene(scene);

      // Copy game camera settings onto the shell's camera so rendering and raycasting align
      if (env.camera && context.camera) {
        shellCam.position.copy(env.camera.position);
        shellCam.rotation.copy(env.camera.rotation);
        shellCam.fov = env.camera.fov;
        shellCam.near = env.camera.near;
        shellCam.far = env.camera.far;
        shellCam.updateProjectionMatrix();
      }

      // Add lights to scene
      if (env.lights) {
        scene.add(env.lights.directionalLight);
        scene.add(env.lights.ambientLight);
        scene.add(env.lights.pointLight);
      }

      ambientCreatures = createAmbientCreatures(scene);
      const sharkResult = buildSharkEntity(scene, sharkPos);
      sharkRoot = sharkResult.sharkRoot;
      sharkBody = sharkResult.sharkBody;
      sharkGlowTrail = sharkResult.sharkGlowTrail;
      tailMeshes = sharkResult.tailFins;
      eyeMeshes = sharkResult.eyes;

      // Initialize camera system
      cameraState = createCameraState(shellCam);

      // Initialize screen effects (parented to camera)
      vignetteState = createVignette(shellCam);
      speedLineState = createSpeedLines(shellCam);
      colorFlashState = createColorFlash(shellCam);
    },

    start(): void {
      paused = false;
      elapsedTime = 0;
      eatAnimTimer = -1;
      firstCatchDone = false;
      sharkAnim = createSharkAnimState();
      sharkMove = createSharkMoveState();
      sharkPos.set(0, 0, 0);
      context.score.reset();
      context.combo.reset();
      for (const f of fishArray) disposeFish(f);
      fishArray.length = 0;
      if (goldenFish) {
        disposeFish(goldenFish);
        goldenFish = null;
      }
      spawnState = createProximitySpawnState();
      surpriseState = createSurpriseState();
      celebrations.clear();
      interactionState.clear();
      interactionState = createInteractionState();

      // Reset Phase 3 systems
      huntState = createHuntFSMState();
      expressionState = createExpressionState();

      // Reset camera
      if (cameraState) resetCamera(cameraState, shellCam);

      let lastMilestoneScore = 0;
      const maxScheduled = MILESTONE_SCHEDULE.length > 0 ? MILESTONE_SCHEDULE[MILESTONE_SCHEDULE.length - 1].score : 0;
      unsubScore = context.score.onScoreChanged((newScore: number) => {
        for (const ms of MILESTONE_SCHEDULE) {
          if (newScore >= ms.score && lastMilestoneScore < ms.score) {
            context.celebration.milestone(0, 0, ms.size);
            lastMilestoneScore = ms.score;
          }
        }
        if (newScore > maxScheduled) {
          const rm =
            maxScheduled +
            Math.floor((newScore - maxScheduled) / MILESTONE_REPEAT_INTERVAL) * MILESTONE_REPEAT_INTERVAL;
          if (rm > lastMilestoneScore) {
            context.celebration.milestone(0, 0, 'medium');
            lastMilestoneScore = rm;
          }
        }
      });
      context.audio.playMusic('ocean-ambient');
    },

    update(deltaTime: number): void {
      if (paused) return;
      const dt = deltaTime;
      elapsedTime += dt;
      const speedMultiplier = getSpeedMultiplier(context.difficulty.level);

      if (eatAnimTimer > 0 && sharkBody) eatAnimTimer = updateEatAnimation(sharkBody, eatAnimTimer, dt);

      updateSharkMovement(dt);
      updateSharkAnimations(dt);
      updateSpawning(dt);
      updateEnvironmentSystems(dt);
      updateFishAndCollisions(dt, speedMultiplier * 0.5);
      celebrations.update(dt);
      interactionState.update(dt);
      updateCameraAndEffects(dt);
    },

    pause(): void {
      paused = true;
    },

    resume(): void {
      paused = false;
    },

    teardown(): void {
      unsubScore?.();
      unsubScore = null;
      celebrations.clear();
      interactionState.clear();
      context.audio.stopMusic();

      // Dispose bubble trails
      for (const trail of activeBubbleTrails) trail.dispose();
      activeBubbleTrails.length = 0;

      // Dispose screen effects
      if (vignetteState && speedLineState && colorFlashState) {
        disposeScreenFx(vignetteState, speedLineState, colorFlashState);
        vignetteState = null;
        speedLineState = null;
        colorFlashState = null;
      }

      cameraState = null;

      if (sharkGlowTrail) {
        sharkGlowTrail.dispose();
        sharkGlowTrail = null;
      }
      for (const f of fishArray) disposeFish(f);
      fishArray.length = 0;
      if (goldenFish) {
        disposeFish(goldenFish);
        goldenFish = null;
      }
      if (sharkRoot) {
        disposeMeshDeep(sharkRoot);
        sharkRoot = null;
        sharkBody = null;
        tailMeshes = [];
        eyeMeshes = [];
      }
      if (ambientCreatures) {
        disposeAmbientCreatures(ambientCreatures);
        ambientCreatures = null;
      }
      if (env) {
        teardownScene(env);
        env = null;
      }
      spawnState = null;
      surpriseState = null;
      huntState = createHuntFSMState();
      expressionState = createExpressionState();
      resetMeshIndex();
    },

    onResize(_viewport: ViewportInfo): void {
      if (!env) return;
    },

    onTap(event: MiniGameTapEvent): void {
      if (paused) return;
      const pick = event.pickResult;
      console.log('[SHARK-DBG] onTap pick:', {
        hit: pick?.hit,
        meshName: (pick?.pickedMesh as Object3D)?.name,
        pickedPoint: pick?.pickedPoint,
        screenX: event.screenX,
        screenY: event.screenY,
      });
      if (!pick || !pick.hit || !pick.pickedMesh) {
        console.log('[SHARK-DBG] onTap: no pick, bailing');
        return;
      }
      const pickedMesh = pick.pickedMesh as Object3D;
      const kind = classifyPickedMesh(pickedMesh.name);
      console.log('[SHARK-DBG] classified as:', kind, '| mesh:', pickedMesh.name);
      switch (kind) {
        case 'fish': {
          const fish = fishArray.find((f) => f.active && !f.spawning && isDescendantOf(pickedMesh, f.root));
          if (fish) {
            fish.isTargeted = true;
            // Use hunt FSM instead of direct lunge
            if (getHuntPhase(huntState) === 'idle') {
              triggerHunt(huntState, fish.root);
              setMood(expressionState, 'curious');
            } else {
              // Fallback to direct lunge if already hunting
              startLunge(sharkMove, fish.root.position.x, fish.root.position.z, 6.0);
            }
          }
          break;
        }
        case 'golden': {
          if (goldenFish && goldenFish.active && !goldenFish.spawning) {
            if (isDescendantOf(pickedMesh, goldenFish.root)) {
              goldenFish.isTargeted = true;
              if (getHuntPhase(huntState) === 'idle') {
                triggerHunt(huntState, goldenFish.root);
                setMood(expressionState, 'excited');
              } else {
                startLunge(sharkMove, goldenFish.root.position.x, goldenFish.root.position.z, 6.0);
              }
            }
          }
          break;
        }
        case 'shark': {
          if (sharkRoot) {
            handleSharkTap(sharkAnim, scene, sharkRoot, context.audio);
            setMood(expressionState, 'playful');
          }
          break;
        }
        case 'coral': {
          interactionState.handleCoralTap(pickedMesh, scene, context.audio);
          break;
        }
        case 'seaweed': {
          interactionState.handleSeaweedTap(pickedMesh, context.audio);
          break;
        }
        case 'treasure': {
          interactionState.handleTreasureChestTap(pickedMesh, scene, context.audio);
          break;
        }
        case 'rock': {
          handleRockTap(pickedMesh, scene, context.audio);
          break;
        }
        case 'water':
        default: {
          const wp = pick.pickedPoint;
          console.log('[SHARK-DBG] water tap: pickedPoint=', wp, '| sharkPos=', { x: sharkPos.x, z: sharkPos.z });
          if (wp) {
            // Cancel any active hunt so the shark goes where you tap
            if (getHuntPhase(huntState) !== 'idle') {
              cancelHunt(huntState);
              sharkMove.velX = 0;
              sharkMove.velZ = 0;
            }
            const cx = clamp(wp.x, -BOUNDS, BOUNDS);
            const cz = clamp(wp.z, -BOUNDS, BOUNDS);
            console.log('[SHARK-DBG] startLunge to:', { cx, cz }, '| BOUNDS:', BOUNDS);
            startLunge(sharkMove, cx, cz, BOUNDS * 3);
            console.log('[SHARK-DBG] after startLunge: swimPhase=', sharkMove.swimPhase, '| dest=', {
              x: sharkMove.swimDestX,
              z: sharkMove.swimDestZ,
            });
            handleWaterTap(scene, new Vector3(cx, 0, cz), context.audio);
          }
          break;
        }
      }
    },

    onDrag(event: MiniGameDragEvent): void {
      if (paused) return;
      // Cancel hunt when player drags ΓÇö they want manual control
      if (getHuntPhase(huntState) !== 'idle') {
        cancelHunt(huntState);
        sharkMove.velX = 0;
        sharkMove.velZ = 0;
      }
      sharkMove.isBeingDragged = true;
      const pick = event.pickResult;
      if (pick && pick.hit && pick.pickedPoint) {
        sharkMove.targetX = clamp(pick.pickedPoint.x, -BOUNDS, BOUNDS);
        sharkMove.targetZ = clamp(pick.pickedPoint.z, -BOUNDS, BOUNDS);
      }
    },

    onDragEnd(_event: MiniGameDragEndEvent): void {
      sharkMove.isBeingDragged = false;
    },
  };

  return game;
}

// ΓöÇΓöÇ Shark emotional expression system ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Possible emotional states for the shark. */
export type SharkMood = 'neutral' | 'curious' | 'excited' | 'satisfied' | 'playful';

/** Interpolatable visual parameters driven by mood. */
export interface MoodParams {
  /** Vertical eye scale (1.0 = normal, <1 = squint, >1 = wide). */
  eyeScaleY: number;
  /** Average blinks per second. */
  blinkRate: number;
  /** Multiplier applied to tail wag frequency. */
  tailFreqMult: number;
  /** Multiplier applied to tail wag amplitude. */
  tailAmpMult: number;
  /** Multiplier applied to body wobble intensity. */
  bodyWobbleMult: number;
  /** Warm colour shift amount (0 = none, higher = warmer). */
  colorWarmth: number;
}

/** Mutable state tracking mood transitions and interpolated parameters. */
export interface ExpressionState {
  /** The mood we are blending from. */
  currentMood: SharkMood;
  /** The mood we are blending toward. */
  targetMood: SharkMood;
  /** Transition progress from 0 (current) to 1 (target). */
  blendT: number;
  /** Duration of the current blend in seconds. */
  blendDuration: number;
  /** Interpolated mood parameters for the current frame. */
  current: MoodParams;
}

// ΓöÇΓöÇ Mood lookup table ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Canonical mood parameter presets keyed by mood name. */
const MOOD_TABLE: Readonly<Record<SharkMood, Readonly<MoodParams>>> = {
  neutral: {
    eyeScaleY: 1.0,
    blinkRate: 5.0,
    tailFreqMult: 1.0,
    tailAmpMult: 1.0,
    bodyWobbleMult: 1.0,
    colorWarmth: 0.0,
  },
  curious: {
    eyeScaleY: 1.2,
    blinkRate: 7.0,
    tailFreqMult: 1.3,
    tailAmpMult: 0.8,
    bodyWobbleMult: 0.5,
    colorWarmth: 0.1,
  },
  excited: {
    eyeScaleY: 0.8,
    blinkRate: 3.0,
    tailFreqMult: 2.0,
    tailAmpMult: 1.5,
    bodyWobbleMult: 1.5,
    colorWarmth: 0.3,
  },
  satisfied: {
    eyeScaleY: 0.6,
    blinkRate: 8.0,
    tailFreqMult: 0.7,
    tailAmpMult: 0.6,
    bodyWobbleMult: 0.3,
    colorWarmth: 0.2,
  },
  playful: {
    eyeScaleY: 1.1,
    blinkRate: 4.0,
    tailFreqMult: 1.8,
    tailAmpMult: 1.3,
    bodyWobbleMult: 2.0,
    colorWarmth: 0.15,
  },
};

// ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Linearly interpolate between two values. */
function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

/** Ease-in-out cubic curve for smooth mood transitions. */
function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - (-2 * t + 2) ** 3 / 2;
}

/** Interpolate every field of two MoodParams using a 0ΓåÆ1 factor. */
function lerpParams(a: Readonly<MoodParams>, b: Readonly<MoodParams>, t: number): MoodParams {
  return {
    eyeScaleY: lerp(a.eyeScaleY, b.eyeScaleY, t),
    blinkRate: lerp(a.blinkRate, b.blinkRate, t),
    tailFreqMult: lerp(a.tailFreqMult, b.tailFreqMult, t),
    tailAmpMult: lerp(a.tailAmpMult, b.tailAmpMult, t),
    bodyWobbleMult: lerp(a.bodyWobbleMult, b.bodyWobbleMult, t),
    colorWarmth: lerp(a.colorWarmth, b.colorWarmth, t),
  };
}

// ΓöÇΓöÇ Public API ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Creates a fresh expression state initialised to the neutral mood.
 * @returns A new ExpressionState ready for per-frame updates.
 */
export function createExpressionState(): ExpressionState {
  return {
    currentMood: 'neutral',
    targetMood: 'neutral',
    blendT: 1,
    blendDuration: 0.3,
    current: { ...MOOD_TABLE.neutral },
  };
}

/**
 * Initiates a smooth transition to a new mood.
 *
 * If the shark is already at (or transitioning to) the requested mood this is a no-op.
 * @param state - The expression state to mutate.
 * @param mood - The target mood to blend toward.
 * @param blendDuration - Transition time in seconds (default 0.3).
 */
export function setMood(state: ExpressionState, mood: SharkMood, blendDuration = 0.3): void {
  if (state.targetMood === mood) return;

  // Snapshot whatever the shark looks like right now as the blend source
  state.currentMood = state.targetMood;
  state.targetMood = mood;
  state.blendT = 0;
  state.blendDuration = blendDuration;
}

/**
 * Advances the mood blend timer and recalculates interpolated parameters.
 *
 * Call once per frame. When a transition completes, blendT clamps at 1.
 * @param state - The expression state to advance.
 * @param dt - Frame delta time in seconds.
 */
export function updateExpressions(state: ExpressionState, dt: number): void {
  if (state.blendT < 1) {
    state.blendT = Math.min(state.blendT + dt / state.blendDuration, 1);
  }

  const eased = easeInOutCubic(state.blendT);
  const from = MOOD_TABLE[state.currentMood];
  const to = MOOD_TABLE[state.targetMood];
  state.current = lerpParams(from, to, eased);
}

/**
 * Returns the current interpolated mood parameters.
 * @param state - The expression state to read.
 * @returns The interpolated MoodParams for this frame.
 */
export function getMoodParams(state: ExpressionState): MoodParams {
  return state.current;
}

/**
 * Maps a hunt-FSM phase name to the appropriate shark mood.
 * @param phase - The current phase identifier from the hunt state machine.
 * @returns The SharkMood corresponding to the given phase.
 */
export function getMoodForPhase(phase: string): SharkMood {
  switch (phase) {
    case 'idle':
      return 'neutral';
    case 'notice':
      return 'curious';
    case 'pursuit':
    case 'strike':
      return 'excited';
    case 'celebrate':
    case 'recovery':
      return 'satisfied';
    default:
      return 'neutral';
  }
}

import {
  Scene,
  Color,
  Vector3,
  Mesh,
  PlaneGeometry,
  MeshBasicMaterial,
  SphereGeometry,
  DoubleSide,
  type Object3D,
  type MeshStandardMaterial,
} from 'three';
import { createBubblePopEffect, createSparkleBurst } from '@app/minigames/shared/particleFx';
import type { SceneEnvironment } from './environment';

/** Finds the first MeshStandardMaterial with an emissive property on an Object3D or its children. */
function findEmissiveMaterial(obj: Object3D): MeshStandardMaterial | null {
  if (obj instanceof Mesh && obj.material && 'emissive' in obj.material) {
    return obj.material as MeshStandardMaterial;
  }
  for (const child of obj.children) {
    const mat = findEmissiveMaterial(child);
    if (mat) return mat;
  }
  return null;
}

/** All available surprise types. */
type SurpriseType = 'bubbleColumn' | 'colorShift' | 'whaleShadow' | 'treasureSparkle' | 'fishParade';

/** All surprise type values for random selection. */
const ALL_SURPRISE_TYPES: SurpriseType[] = [
  'bubbleColumn',
  'colorShift',
  'whaleShadow',
  'treasureSparkle',
  'fishParade',
];

/** Mutable state for the surprise system. */
export interface SurpriseState {
  /** Seconds until next surprise. */
  nextSurpriseTime: number;
  /** Currently active surprise type, or null. */
  activeSurprise: SurpriseType | null;
  /** Timer for active surprise animation. */
  surpriseTimer: number;
  /** Saved original coral emissive colors for color shift surprise. */
  originalEmissives: Color[];
  /** Whale shadow mesh reference for cleanup. */
  whaleShadowMesh: Mesh | null;
  /** Fish parade mesh references for cleanup. */
  paradeFish: Mesh[];
  /** Elapsed time when the surprise started (for animation). */
  surpriseStartTime: number;
  /** Scheduled sparkle burst times remaining for treasureSparkle. */
  sparkleBurstTimes: number[];
}

/**
 * Creates initial surprise state.
 *
 * @returns Fresh SurpriseState.
 */
export function createSurpriseState(): SurpriseState {
  return {
    nextSurpriseTime: 25 + Math.random() * 15,
    activeSurprise: null,
    surpriseTimer: 0,
    originalEmissives: [],
    whaleShadowMesh: null,
    paradeFish: [],
    surpriseStartTime: 0,
    sparkleBurstTimes: [],
  };
}

/**
 * Cleans up whale shadow mesh from the scene.
 *
 * @param state - Surprise state.
 * @param scene - The Three.js scene.
 */
function cleanupWhaleShadow(state: SurpriseState, scene: Scene): void {
  if (state.whaleShadowMesh) {
    scene.remove(state.whaleShadowMesh);
    state.whaleShadowMesh.geometry.dispose();
    if (Array.isArray(state.whaleShadowMesh.material)) {
      state.whaleShadowMesh.material.forEach((m) => m.dispose());
    } else {
      state.whaleShadowMesh.material.dispose();
    }
    state.whaleShadowMesh = null;
  }
}

/**
 * Cleans up fish parade meshes from the scene.
 *
 * @param state - Surprise state.
 * @param scene - The Three.js scene.
 */
function cleanupParadeFish(state: SurpriseState, scene: Scene): void {
  for (const fish of state.paradeFish) {
    scene.remove(fish);
    fish.geometry.dispose();
    if (Array.isArray(fish.material)) {
      fish.material.forEach((m) => m.dispose());
    } else {
      fish.material.dispose();
    }
  }
  state.paradeFish = [];
}

/**
 * Starts the whale shadow surprise: a large dark ellipse sliding across the floor.
 *
 * @param state - Surprise state.
 * @param scene - The Three.js scene.
 * @param elapsedTime - Current elapsed game time.
 */
function startWhaleShadow(state: SurpriseState, scene: Scene, elapsedTime: number): void {
  const geometry = new PlaneGeometry(3.0, 1.5);
  const material = new MeshBasicMaterial({
    color: new Color(0.05, 0.05, 0.1),
    transparent: true,
    opacity: 0.3,
    side: DoubleSide,
    depthWrite: false,
  });
  const shadow = new Mesh(geometry, material);
  shadow.rotation.x = -Math.PI / 2;
  shadow.position.set(-8, -0.4, 0);
  scene.add(shadow);
  state.whaleShadowMesh = shadow;
  state.activeSurprise = 'whaleShadow';
  state.surpriseTimer = 4.0;
  state.surpriseStartTime = elapsedTime;
}

/**
 * Starts the treasure sparkle surprise: golden sparkles burst from the treasure chest.
 *
 * @param state - Surprise state.
 * @param scene - The Three.js scene.
 * @param env - Scene environment containing the treasure chest.
 */
function startTreasureSparkle(state: SurpriseState, scene: Scene, env: SceneEnvironment): void {
  const chestPos = env.treasureChest.position.clone();
  // First burst immediately
  createSparkleBurst(scene, chestPos, new Color(1.0, 0.85, 0.2), 15);
  state.activeSurprise = 'treasureSparkle';
  state.surpriseTimer = 2.0;
  // Schedule remaining bursts at 0.7s and 1.4s from now
  state.sparkleBurstTimes = [0.7, 1.4];
}

/**
 * Starts the fish parade surprise: 8 tiny decorative fish swim across the scene.
 *
 * @param state - Surprise state.
 * @param scene - The Three.js scene.
 * @param elapsedTime - Current elapsed game time.
 */
function startFishParade(state: SurpriseState, scene: Scene, elapsedTime: number): void {
  const fishColors = [
    new Color(1.0, 0.5, 0.15),
    new Color(0.3, 0.5, 1.0),
    new Color(0.2, 0.8, 0.3),
    new Color(1.0, 0.9, 0.2),
    new Color(1.0, 0.5, 0.7),
    new Color(0.5, 0.8, 1.0),
    new Color(0.8, 0.4, 0.9),
    new Color(0.9, 0.6, 0.2),
  ];

  const geometry = new SphereGeometry(0.12, 8, 6);

  for (let i = 0; i < 8; i++) {
    const material = new MeshBasicMaterial({
      color: fishColors[i % fishColors.length],
      transparent: true,
      opacity: 0.85,
    });
    const fish = new Mesh(geometry.clone(), material);
    // Start off-screen left, spread vertically
    const yOffset = -1 + (i / 7) * 2;
    fish.position.set(-9, yOffset, -2 + i * 0.3);
    fish.scale.set(1.0, 0.6, 0.5);
    scene.add(fish);
    state.paradeFish.push(fish);
  }

  state.activeSurprise = 'fishParade';
  state.surpriseTimer = 5.0;
  state.surpriseStartTime = elapsedTime;
}

/**
 * Updates the surprise system, triggering serendipitous moments.
 *
 * @param state - Surprise state.
 * @param elapsedTime - Total elapsed game time.
 * @param dt - Frame delta time.
 * @param env - Scene environment.
 * @param scene - The Three.js scene.
 */
export function updateSurprises(
  state: SurpriseState,
  elapsedTime: number,
  dt: number,
  env: SceneEnvironment,
  scene: Scene,
): void {
  // Handle active surprise
  if (state.activeSurprise) {
    state.surpriseTimer -= dt;

    if (state.activeSurprise === 'colorShift') {
      // Cycle coral colors through a rainbow
      const hueShift = (elapsedTime * 2) % 1;
      for (let i = 0; i < env.corals.length; i++) {
        const mat = findEmissiveMaterial(env.corals[i]);
        if (mat) {
          const h = (hueShift + i * 0.1) % 1;
          mat.emissive = new Color().setHSL(h, 0.6, 0.3);
        }
      }
    }

    if (state.activeSurprise === 'whaleShadow' && state.whaleShadowMesh) {
      // Move shadow from left to right over 4 seconds
      const progress = 1 - state.surpriseTimer / 4.0;
      state.whaleShadowMesh.position.x = -8 + progress * 16;
    }

    if (state.activeSurprise === 'treasureSparkle') {
      // Fire scheduled sparkle bursts
      const elapsed = 2.0 - state.surpriseTimer;
      const remaining: number[] = [];
      for (const burstTime of state.sparkleBurstTimes) {
        if (elapsed >= burstTime) {
          const chestPos = env.treasureChest.position.clone();
          createSparkleBurst(scene, chestPos, new Color(1.0, 0.85, 0.2), 15);
        } else {
          remaining.push(burstTime);
        }
      }
      state.sparkleBurstTimes = remaining;
    }

    if (state.activeSurprise === 'fishParade') {
      // Move fish from left to right with sine undulation over 5 seconds
      const progress = 1 - state.surpriseTimer / 5.0;
      const localTime = elapsedTime - state.surpriseStartTime;
      for (let i = 0; i < state.paradeFish.length; i++) {
        const fish = state.paradeFish[i];
        const xBase = -9 + progress * 18;
        // Stagger each fish slightly
        const stagger = i * 0.6;
        fish.position.x = xBase + stagger;
        // Sine wave undulation unique per fish
        fish.position.y += Math.sin(localTime * 3 + i * 0.8) * 0.005;
      }
    }

    if (state.surpriseTimer <= 0) {
      // Restore coral colors
      if (state.activeSurprise === 'colorShift') {
        for (let i = 0; i < env.corals.length && i < state.originalEmissives.length; i++) {
          const mat = findEmissiveMaterial(env.corals[i]);
          if (mat) {
            mat.emissive = state.originalEmissives[i];
          }
        }
        state.originalEmissives = [];
      }

      // Clean up whale shadow
      if (state.activeSurprise === 'whaleShadow') {
        cleanupWhaleShadow(state, scene);
      }

      // Clean up fish parade
      if (state.activeSurprise === 'fishParade') {
        cleanupParadeFish(state, scene);
      }

      state.activeSurprise = null;
      state.nextSurpriseTime = 30 + Math.random() * 15;
    }
    return;
  }

  // Count down to next surprise
  state.nextSurpriseTime -= dt;
  if (state.nextSurpriseTime > 0) return;

  // Trigger a random surprise from all 5 types
  const kind = ALL_SURPRISE_TYPES[Math.floor(Math.random() * ALL_SURPRISE_TYPES.length)];

  if (kind === 'bubbleColumn') {
    // Burst of bubbles from center
    createBubblePopEffect(scene, new Vector3(0, 0, 0), new Color(0.5, 0.8, 1.0), 25);
    state.activeSurprise = 'bubbleColumn';
    state.surpriseTimer = 3.0;
  } else if (kind === 'colorShift') {
    // Save original emissives
    state.originalEmissives = env.corals.map((coral) => {
      const mat = findEmissiveMaterial(coral);
      if (mat) return mat.emissive.clone();
      return new Color(0, 0, 0);
    });
    state.activeSurprise = 'colorShift';
    state.surpriseTimer = 3.0;
  } else if (kind === 'whaleShadow') {
    startWhaleShadow(state, scene, elapsedTime);
  } else if (kind === 'treasureSparkle') {
    startTreasureSparkle(state, scene, env);
  } else {
    startFishParade(state, scene, elapsedTime);
  }
}

import {
  type Scene,
  Group,
  Mesh,
  SphereGeometry,
  CylinderGeometry,
  BoxGeometry,
  TorusGeometry,
  PlaneGeometry,
  type MeshStandardMaterial,
  Color,
  Vector3,
} from 'three';
import {
  createGlossyPaintMaterial,
  createToyMetalMaterial,
  createRubberMaterial,
  createFeltMaterial,
  createSandMaterial,
  createGlassMaterial,
  createMetalMaterial,
  createPlasticMaterial,
  createCartoonEyeWhiteMaterial,
  createCartoonPupilMaterial,
} from '@app/minigames/shared/materials';
import { buildDetailedTree } from '@app/minigames/shared/meshBuilders';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';
import type { StarData, ObstacleData, RampData, SegmentData } from './types';
import { SEGMENT_WIDTH } from './types';
import { segmentStartX, pickTemplate } from './helpers';
import { createMountain, createCloud } from './environment';

export interface TruckMeshes {
  body: Mesh;
  wheels: Mesh[];
  eyes: Mesh[];
}

export interface GameMaterials {
  groundMat1: MeshStandardMaterial;
  groundMat2: MeshStandardMaterial;
  starMat: MeshStandardMaterial;
  crateMat: MeshStandardMaterial;
  coneMat: MeshStandardMaterial;
  rampMat: MeshStandardMaterial;
}

/** Creates a star mesh at the given position. */
export function createStar(scene: Scene, x: number, y: number, starMat: MeshStandardMaterial | null): StarData {
  const geo = new SphereGeometry(0.4 / 2, 8, 8);
  const mesh = new Mesh(geo, starMat ?? undefined);
  mesh.name = 'star';
  mesh.position.set(x, y, 0);
  scene.add(mesh);
  return { mesh, collected: false, worldX: x, worldY: y };
}

/** Creates an obstacle mesh at the given position. */
export function createObstacle(
  scene: Scene,
  x: number,
  type: 'crate' | 'cone',
  crateMat: MeshStandardMaterial | null,
  coneMat: MeshStandardMaterial | null,
): ObstacleData {
  let mesh: Mesh;
  if (type === 'crate') {
    const geo = new BoxGeometry(0.6, 0.6, 0.6);
    mesh = new Mesh(geo, crateMat ?? undefined);
    mesh.name = 'crate';
    mesh.position.set(x, 0.3, 0);
  } else {
    const geo = new CylinderGeometry(0, 0.4 / 2, 0.7, 8);
    mesh = new Mesh(geo, coneMat ?? undefined);
    mesh.name = 'cone';
    mesh.position.set(x, 0.35, 0);
  }
  scene.add(mesh);
  return { mesh, crushed: false, worldX: x, type };
}

/** Creates a ramp mesh at the given position. */
export function createRamp(scene: Scene, x: number, rampMat: MeshStandardMaterial | null): RampData {
  const width = 2.0;
  const geo = new BoxGeometry(width, 0.6, 1.2);
  const mesh = new Mesh(geo, rampMat ?? undefined);
  mesh.name = 'ramp';
  mesh.position.set(x, 0.3, 0);
  mesh.rotation.z = -0.3; // angled upward
  scene.add(mesh);
  return { mesh, worldX: x, width };
}

/** Populates a segment with content based on a template. */
export function populateSegment(
  scene: Scene,
  seg: SegmentData,
  materials: {
    starMat: MeshStandardMaterial | null;
    crateMat: MeshStandardMaterial | null;
    coneMat: MeshStandardMaterial | null;
    rampMat: MeshStandardMaterial | null;
  },
): void {
  const baseX = segmentStartX(seg.index);
  const template = pickTemplate();

  // Always add a ramp if template includes one
  const hasRamp = template === 'ramp' || template === 'mixed';
  const hasObstacle = template === 'obstacle' || template === 'mixed';

  if (hasRamp) {
    const rampX = baseX + 5 + Math.random() * 5;
    seg.ramps.push(createRamp(scene, rampX, materials.rampMat));

    // Stars above the ramp
    for (let i = 0; i < 3; i++) {
      seg.stars.push(createStar(scene, rampX + (i - 1) * 0.8, 2.5 + Math.random() * 1.0, materials.starMat));
    }
  }

  if (hasObstacle) {
    const obstacleCount = 1 + Math.floor(Math.random() * 2);
    for (let i = 0; i < obstacleCount; i++) {
      const ox = baseX + 12 + i * 3 + Math.random() * 2;
      const type = Math.random() > 0.5 ? 'crate' : 'cone';
      seg.obstacles.push(createObstacle(scene, ox, type, materials.crateMat, materials.coneMat));
    }

    // Stars between obstacles
    for (let i = 0; i < 2; i++) {
      seg.stars.push(createStar(scene, baseX + 13 + i * 2, 1.5 + Math.random() * 0.5, materials.starMat));
    }
  }

  if (template === 'flat') {
    // Line of stars
    for (let i = 0; i < 5; i++) {
      seg.stars.push(createStar(scene, baseX + 3 + i * 3, 1.5, materials.starMat));
    }
    // Still guarantee at least one ramp
    const rampX = baseX + 10 + Math.random() * 5;
    seg.ramps.push(createRamp(scene, rampX, materials.rampMat));
  }

  // Background scenery
  const mountainCount = 1 + Math.floor(Math.random() * 2);
  for (let i = 0; i < mountainCount; i++) {
    seg.mountains.push(createMountain(scene, baseX + Math.random() * SEGMENT_WIDTH));
  }

  if (Math.random() > 0.3) {
    seg.clouds.push(createCloud(scene, baseX + Math.random() * SEGMENT_WIDTH));
  }

  // Roadside trees on both sides of the track
  const treeCount = 1 + Math.floor(Math.random() * 2);
  for (let i = 0; i < treeCount; i++) {
    const treeX = baseX + Math.random() * SEGMENT_WIDTH;
    const side = Math.random() > 0.5 ? 3.0 : -3.0;
    const height = 1.5 + Math.random() * 1.5;
    const tree = buildDetailedTree(new Vector3(treeX, 0, side), height);
    scene.add(tree);
    seg.trees.push(tree);
  }
}

/** Creates a new ground segment at the given index. */
export function createSegment(
  scene: Scene,
  index: number,
  groundMat1: MeshStandardMaterial | null,
  groundMat2: MeshStandardMaterial | null,
  materials: {
    starMat: MeshStandardMaterial | null;
    crateMat: MeshStandardMaterial | null;
    coneMat: MeshStandardMaterial | null;
    rampMat: MeshStandardMaterial | null;
  },
): SegmentData {
  const baseX = segmentStartX(index);
  const centerX = baseX + SEGMENT_WIDTH / 2;

  const geo = new BoxGeometry(SEGMENT_WIDTH, 0.2, 4);
  const ground = new Mesh(geo, (index % 2 === 0 ? groundMat1 : groundMat2) ?? undefined);
  ground.name = 'ground';
  ground.position.set(centerX, -0.1, 0);
  scene.add(ground);

  const seg: SegmentData = {
    index,
    ground,
    stars: [],
    obstacles: [],
    ramps: [],
    mountains: [],
    clouds: [],
    trees: [],
  };

  // Don't populate the first segment so the player has a clean start
  if (index > 0) {
    populateSegment(scene, seg, materials);
  }

  return seg;
}

/** Disposes all meshes within a segment. */
export function disposeSegment(seg: SegmentData): void {
  seg.ground.geometry?.dispose();
  seg.ground.removeFromParent();
  for (const s of seg.stars) {
    s.mesh.geometry?.dispose();
    s.mesh.removeFromParent();
  }
  for (const o of seg.obstacles) {
    o.mesh.geometry?.dispose();
    o.mesh.removeFromParent();
  }
  for (const r of seg.ramps) {
    r.mesh.geometry?.dispose();
    r.mesh.removeFromParent();
  }
  for (const m of seg.mountains) disposeMeshDeep(m);
  for (const c of seg.clouds) disposeMeshDeep(c);
  for (const t of seg.trees) disposeMeshDeep(t);
}

/**
 * Builds a single rubber tire with torus-segment tread detail.
 * @param name - Mesh name prefix.
 * @param tireMat - Rubber material for the tire surface.
 * @returns A parent group containing the tire cylinder and tread torus segments.
 */
export function buildWheel(scene: Scene, name: string, tireMat: MeshStandardMaterial): Mesh {
  const wheelParent = new Group() as unknown as Mesh;
  wheelParent.name = `${name}_parent`;

  // Main tire cylinder
  const tireGeo = new CylinderGeometry(0.8 / 2, 0.8 / 2, 0.22, 20);
  const tire = new Mesh(tireGeo, tireMat);
  tire.name = `${name}_tire`;
  tire.rotation.x = Math.PI / 2;
  wheelParent.add(tire);

  // Tread detail: small torus segments around the outer rim
  const treadCount = 10;
  for (let i = 0; i < treadCount; i++) {
    const angle = (i / treadCount) * Math.PI * 2;
    const treadGeo = new TorusGeometry(0.12 / 2, 0.04 / 2, 8, 8);
    const tread = new Mesh(treadGeo, tireMat);
    tread.name = `${name}_tread_${i}`;
    tread.position.set(Math.cos(angle) * 0.32, 0, Math.sin(angle) * 0.32);
    tread.rotation.x = Math.PI / 2;
    tread.rotation.z = angle;
    tread.scale.set(1, 0.5, 1);
    tire.add(tread);
  }

  // Hub cap ΓÇö shiny metal center
  const hubMat = createToyMetalMaterial(`${name}_hubMat`, new Color(0.75, 0.75, 0.8));
  const hubGeo = new CylinderGeometry(0.25 / 2, 0.25 / 2, 0.24, 12);
  const hub = new Mesh(hubGeo, hubMat);
  hub.name = `${name}_hub`;
  hub.rotation.x = Math.PI / 2;
  wheelParent.add(hub);

  scene.add(wheelParent);
  return wheelParent;
}

/** Builds the detailed monster truck mesh hierarchy with PBR materials. */
export function buildTruck(scene: Scene): TruckMeshes {
  // Body ΓÇö glossy painted red
  const bodyGeo = new BoxGeometry(1.5, 0.8, 1.0);
  const bodyMat = createGlossyPaintMaterial('truckBodyMat', new Color(0.9, 0.15, 0.1));
  const truckBody = new Mesh(bodyGeo, bodyMat);
  truckBody.name = 'truckBody';
  scene.add(truckBody);

  // Cab / roof ΓÇö slightly smaller box on top
  const cabGeo = new BoxGeometry(0.9, 0.5, 0.9);
  const cab = new Mesh(cabGeo, bodyMat);
  cab.name = 'truckCab';
  cab.position.set(-0.15, 0.6, 0);
  truckBody.add(cab);

  // Windshield ΓÇö translucent glass on the front of the cab
  const windshieldGeo = new PlaneGeometry(0.5, 0.4);
  const windshieldMat = createGlassMaterial('windshieldMat', new Color(0.6, 0.8, 1.0), 0.3);
  const windshield = new Mesh(windshieldGeo, windshieldMat);
  windshield.name = 'windshield';
  windshield.position.set(0.32, 0.6, 0);
  windshield.rotation.y = Math.PI / 2;
  truckBody.add(windshield);

  // Chrome-like metal bumper at the front
  const bumperGeo = new BoxGeometry(0.15, 0.25, 1.1);
  const bumperMat = createToyMetalMaterial('bumperMat', new Color(0.8, 0.8, 0.85));
  const bumper = new Mesh(bumperGeo, bumperMat);
  bumper.name = 'bumper';
  bumper.position.set(0.82, -0.15, 0);
  truckBody.add(bumper);

  // Headlights ΓÇö emissive spheres on the front
  for (const side of [-0.35, 0.35]) {
    const hlGeo = new SphereGeometry(0.15 / 2, 8, 8);
    const hlMat = createGlassMaterial(`headlightMat_${side}`, new Color(1.0, 0.95, 0.7), 0.8);
    hlMat.emissive = new Color(0.8, 0.75, 0.4);
    const headlight = new Mesh(hlGeo, hlMat);
    headlight.name = 'headlight';
    headlight.position.set(0.78, 0.05, side);
    truckBody.add(headlight);
  }

  // Exhaust pipes ΓÇö metal cylinders on the sides behind the cab
  for (const side of [-0.55, 0.55]) {
    const exhaustGeo = new CylinderGeometry(0.08 / 2, 0.08 / 2, 0.5, 10);
    const exhaustMat = createToyMetalMaterial(`exhaustMat_${side}`, new Color(0.5, 0.5, 0.55));
    const exhaust = new Mesh(exhaustGeo, exhaustMat);
    exhaust.name = 'exhaust';
    exhaust.position.set(-0.5, 0.55, side);
    truckBody.add(exhaust);
  }

  // Axles ΓÇö metal bars connecting left/right wheels
  for (const ax of [-0.5, 0.5]) {
    const axleGeo = new CylinderGeometry(0.06 / 2, 0.06 / 2, 1.1, 8);
    const axleMat = createToyMetalMaterial(`axleMat_${ax}`, new Color(0.55, 0.55, 0.6));
    const axle = new Mesh(axleGeo, axleMat);
    axle.name = 'axle';
    axle.rotation.x = Math.PI / 2;
    axle.position.set(ax, -0.4, 0);
    truckBody.add(axle);
  }

  // Wheels ΓÇö rubber tires with tread detail
  const tireMat = createRubberMaterial('tireMat', new Color(0.12, 0.12, 0.12));

  const wheelPositions = [
    new Vector3(-0.5, -0.4, 0.55),
    new Vector3(0.5, -0.4, 0.55),
    new Vector3(-0.5, -0.4, -0.55),
    new Vector3(0.5, -0.4, -0.55),
  ];

  const truckWheels: Mesh[] = [];
  for (const pos of wheelPositions) {
    const wheel = buildWheel(scene, 'wheel', tireMat);
    wheel.position.copy(pos);
    wheel.removeFromParent();
    truckBody.add(wheel);
    truckWheels.push(wheel);
  }

  // Friendly cartoon eyes on the windshield area
  const eyeWhiteMat = createCartoonEyeWhiteMaterial('eyeMat');
  const pupilMatPBR = createCartoonPupilMaterial('pupilMat');

  const truckEyes: Mesh[] = [];
  for (const side of [-0.15, 0.15]) {
    const eyeGeo = new SphereGeometry(0.2 / 2, 8, 8);
    const eye = new Mesh(eyeGeo, eyeWhiteMat);
    eye.name = 'eye';
    eye.position.set(0.76, 0.35, side);
    truckBody.add(eye);
    truckEyes.push(eye);

    const pupilGeo = new SphereGeometry(0.1 / 2, 6, 6);
    const pupil = new Mesh(pupilGeo, pupilMatPBR);
    pupil.name = 'pupil';
    pupil.position.set(0.05, 0, 0);
    eye.add(pupil);
  }

  return { body: truckBody, wheels: truckWheels, eyes: truckEyes };
}

/** Creates shared PBR materials used across the game. */
export function buildMaterials(): GameMaterials {
  const groundMat1 = createFeltMaterial('groundMat1', new Color(0.3, 0.6, 0.2));
  const groundMat2 = createSandMaterial('groundMat2', new Color(0.45, 0.35, 0.2));

  const starMat = createMetalMaterial('starMat', new Color(1.0, 0.84, 0.0));

  const crateMat = createPlasticMaterial('crateMat', new Color(0.55, 0.35, 0.15));
  const coneMat = createGlossyPaintMaterial('coneMat', new Color(1.0, 0.5, 0.0));

  const rampMat = createGlossyPaintMaterial('rampMat', new Color(0.6, 0.6, 0.2));

  return { groundMat1, groundMat2, starMat, crateMat, coneMat, rampMat };
}

import { type Scene, Color, Vector3, type Group } from 'three';
import { buildDetailedRock, buildDetailedCloud } from '@app/minigames/shared/meshBuilders';

/** Creates a background rock cluster using the shared detailed rock builder. */
export function createMountain(scene: Scene, x: number): Group {
  const scale = 3 + Math.random() * 4;
  const z = -8 - Math.random() * 5;
  const mountain = buildDetailedRock(new Vector3(x, scale * 0.2, z), scale, new Color(0.35, 0.5, 0.3));
  scene.add(mountain);
  return mountain;
}

/** Creates a fluffy background cloud using the shared detailed cloud builder. */
export function createCloud(scene: Scene, x: number): Group {
  const y = 6 + Math.random() * 3;
  const z = -5 - Math.random() * 3;
  const scale = 1.5 + Math.random() * 1.5;
  const cloud = buildDetailedCloud(new Vector3(x, y, z), scale);
  scene.add(cloud);
  return cloud;
}

import type { MiniGameContext } from '../../framework/types';
import { SPEED_TIERS, SEGMENT_WIDTH, GRAVITY } from './types';
import type { SegmentTemplate } from './types';

/** Returns current speed based on the player's score. */
export function getCurrentSpeed(context: MiniGameContext): number {
  const s = context.score.score;
  for (const [threshold, speed] of SPEED_TIERS) {
    if (s >= threshold) return speed;
  }
  return 2.5;
}

/** Calculates the initial jump velocity needed to reach a given height. */
export function velocityForHeight(height: number): number {
  return Math.sqrt(2 * GRAVITY * height);
}

/** Returns the x position of the left edge of a segment by index. */
export function segmentStartX(index: number): number {
  return index * SEGMENT_WIDTH;
}

/** Picks a random segment template, guaranteeing at least one ramp. */
export function pickTemplate(): SegmentTemplate {
  const templates: SegmentTemplate[] = ['flat', 'ramp', 'obstacle', 'mixed'];
  // Weighted towards having ramps
  const weights = [0.15, 0.35, 0.2, 0.3];
  const r = Math.random();
  let cumulative = 0;
  for (let i = 0; i < templates.length; i++) {
    cumulative += weights[i];
    if (r < cumulative) return templates[i];
  }
  return 'ramp';
}

import { Scene, Color, Vector3, Mesh, type Object3D, type MeshStandardMaterial } from 'three';
import type { IMiniGame, MiniGameContext, MiniGameTapEvent, ViewportInfo } from '../../framework/types';
import {
  createGameCamera,
  createGameLighting,
  disposeGameRig,
  type GameLightingRig,
} from '@app/minigames/shared/sceneSetup';
import { createDustPuff, createSparkleBurst, createConfettiBurst } from '@app/minigames/shared/particleFx';
import { buildSkyGradient } from '@app/minigames/shared/meshBuilders';
import { disposeMeshDeep } from '@app/minigames/shared/disposal';
import type { JumpState, SegmentData } from './types';
import {
  SEGMENT_WIDTH,
  SEGMENTS_AHEAD,
  SEGMENTS_ACTIVE,
  GRAVITY,
  GROUND_Y,
  STAR_COLLECT_RADIUS,
  OBSTACLE_HIT_RADIUS,
  BOUNCE_RECOVERY_TIME,
} from './types';
import { getCurrentSpeed, velocityForHeight } from './helpers';
import { buildTruck, buildMaterials, createSegment, disposeSegment } from './entities';

/**
 * Creates the Monster Truck auto-runner mini-game.
 * @param context - Shell-provided context with shared systems.
 * @returns An IMiniGame implementation for the monster truck gameplay.
 */
export function createGame(context: MiniGameContext): IMiniGame {
  const scene = context.scene as Scene;

  /* ΓöÇΓöÇ Mutable game state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
  let truckX = 0;
  let truckY = GROUND_Y;
  let jumpState: JumpState = 'grounded';
  let jumpVelocity = 0;
  let hasBoosted = false;
  let paused = false;
  let bounceTimer = 0;

  let segments: SegmentData[] = [];
  let nextSegmentIndex = 0;

  // Truck meshes
  let truckBody: Mesh | null = null;
  let truckWheels: Mesh[] = [];

  // Shared materials
  let groundMat1: MeshStandardMaterial | null = null;
  let groundMat2: MeshStandardMaterial | null = null;
  let starMat: MeshStandardMaterial | null = null;
  let crateMat: MeshStandardMaterial | null = null;
  let coneMat: MeshStandardMaterial | null = null;
  let rampMat: MeshStandardMaterial | null = null;

  // Environment meshes managed by the game
  let skyMesh: Object3D | null = null;

  // Timer for periodic dust puff emission behind wheels
  let dustTimer = 0;
  const DUST_INTERVAL = 0.15;

  let camera: ReturnType<typeof createGameCamera> | null = null;
  let lights: GameLightingRig | null = null;
  const cameraTarget = new Vector3(0, 2, 0);

  /* ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */

  /** Ensures the right segments are active around the truck's current position. */
  function manageSegments(): void {
    const currentSegIdx = Math.floor(truckX / SEGMENT_WIDTH);

    // Remove segments that are too far behind
    segments = segments.filter((seg) => {
      if (seg.index < currentSegIdx - 1) {
        disposeSegment(seg);
        return false;
      }
      return true;
    });

    // Create segments ahead
    const neededEnd = currentSegIdx + SEGMENTS_ACTIVE + SEGMENTS_AHEAD;
    while (nextSegmentIndex <= neededEnd) {
      segments.push(
        createSegment(scene, nextSegmentIndex, groundMat1, groundMat2, { starMat, crateMat, coneMat, rampMat }),
      );
      nextSegmentIndex++;
    }
  }

  /** Checks if truck is on a ramp and handles auto-launch. */
  function checkRamps(): boolean {
    for (const seg of segments) {
      for (const ramp of seg.ramps) {
        const rampLeft = ramp.worldX - ramp.width / 2;
        const rampRight = ramp.worldX + ramp.width / 2;
        if (truckX >= rampLeft && truckX <= rampRight && jumpState === 'grounded') {
          return true;
        }
      }
    }
    return false;
  }

  /** Collects stars near the truck. */
  function collectStars(): void {
    for (const seg of segments) {
      for (const star of seg.stars) {
        if (star.collected) continue;
        const dx = truckX - star.worldX;
        const dy = truckY - star.worldY;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < STAR_COLLECT_RADIUS) {
          star.collected = true;
          star.mesh.visible = false;
          context.score.addPoints(1);
          context.celebration.celebrationSound('chime');
          context.celebration.confetti(context.viewport.width / 2, context.viewport.height / 2, 'small');
          // Gold sparkle burst at the star's position
          createSparkleBurst(scene, new Vector3(star.worldX, star.worldY, 0), new Color(1.0, 0.85, 0.2), 12);
        }
      }
    }
  }

  /** Checks obstacle collisions. */
  function checkObstacles(): void {
    if (bounceTimer > 0) return;

    for (const seg of segments) {
      for (const obstacle of seg.obstacles) {
        if (obstacle.crushed) continue;
        const dx = truckX - obstacle.worldX;
        if (Math.abs(dx) > OBSTACLE_HIT_RADIUS) continue;

        if (jumpState !== 'grounded' && truckY > 1.2) {
          // Crush the obstacle from above
          obstacle.crushed = true;
          obstacle.mesh.scale.y = 0.1;
          obstacle.mesh.position.y = 0.05;
          context.score.addPoints(1);
          context.celebration.celebrationSound('pop');
          context.celebration.confetti(context.viewport.width / 2, context.viewport.height / 2, 'medium');
        } else if (jumpState === 'grounded') {
          // Soft bounce ΓÇö not a fail state
          bounceTimer = BOUNCE_RECOVERY_TIME;
          truckY = GROUND_Y + 0.5;
          jumpVelocity = 2;
          jumpState = 'jumping';
          hasBoosted = true; // prevent boost during recovery
        }
      }
    }
  }

  /** Awards a flip bonus when the truck reaches enough height. */
  function checkFlipBonus(): void {
    if (truckY >= 5.0 && jumpState === 'jumping' && jumpVelocity <= 0) {
      // High enough for a "flip" ΓÇö award bonus once on the way down
      context.score.addPoints(1);
      context.celebration.celebrationSound('whoosh');
    }
  }

  /* ΓöÇΓöÇ IMiniGame implementation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */

  const game: IMiniGame = {
    id: 'monster-truck' as const,

    async setup(): Promise<void> {
      // Camera
      camera = createGameCamera({
        name: 'truck',
        beta: 1.3,
        radius: 12.0,
        target: cameraTarget.clone(),
        fov: 0.9,
      });

      // Lights
      lights = createGameLighting({
        name: 'truck',
        direction: new Vector3(-0.5, -1, 0.5),
        directionalIntensity: 0.8,
        hemisphericIntensity: 0.5,
      });

      // Materials
      const mats = buildMaterials();
      groundMat1 = mats.groundMat1;
      groundMat2 = mats.groundMat2;
      starMat = mats.starMat;
      crateMat = mats.crateMat;
      coneMat = mats.coneMat;
      rampMat = mats.rampMat;

      // Sky gradient backdrop
      skyMesh = buildSkyGradient(new Color(0.35, 0.6, 0.95), new Color(1.0, 0.85, 0.6), 40);
      skyMesh.position.set(0, 5, -15);
      scene.add(skyMesh);
      scene.add(skyMesh);

      // Truck
      const truck = buildTruck(scene);
      truckBody = truck.body;
      truckWheels = truck.wheels;
    },

    start(): void {
      truckX = 0;
      truckY = GROUND_Y;
      jumpState = 'grounded';
      jumpVelocity = 0;
      hasBoosted = false;
      bounceTimer = 0;
      dustTimer = 0;
      paused = false;
      nextSegmentIndex = 0;

      // Dispose any existing segments
      for (const seg of segments) {
        disposeSegment(seg);
      }
      segments = [];

      context.score.reset();

      // Create initial segments
      manageSegments();

      // Position truck
      if (truckBody) {
        truckBody.position.set(truckX, truckY, 0);
      }
    },

    update(deltaTime: number): void {
      if (paused) return;

      const speed = getCurrentSpeed(context);

      // Bounce recovery
      if (bounceTimer > 0) {
        bounceTimer -= deltaTime;
      }

      // Move truck forward
      truckX += speed * deltaTime;

      // Check if on a ramp (auto-launch)
      const onRamp = checkRamps();
      if (onRamp && jumpState === 'grounded') {
        jumpState = 'jumping';
        jumpVelocity = velocityForHeight(3.0);
        hasBoosted = false;
      }

      // Jump physics
      if (jumpState === 'jumping' || jumpState === 'falling') {
        truckY += jumpVelocity * deltaTime;
        jumpVelocity -= GRAVITY * deltaTime;

        if (jumpVelocity < 0) {
          jumpState = 'falling';
        }

        // Check flip bonus at apex
        if (jumpState === 'falling' && truckY >= 5.0 && jumpVelocity > -1) {
          checkFlipBonus();
        }

        // Landing
        if (truckY <= GROUND_Y) {
          truckY = GROUND_Y;
          jumpState = 'grounded';
          jumpVelocity = 0;
          hasBoosted = false;
          // Sparkle burst on successful landing
          createSparkleBurst(scene, new Vector3(truckX, 0.2, 0), new Color(1.0, 0.9, 0.3), 15);
        }
      }

      // Update truck mesh position
      if (truckBody) {
        truckBody.position.x = truckX;
        truckBody.position.y = truckY;
      }

      // Spin wheels proportional to speed
      for (const wheel of truckWheels) {
        wheel.rotation.z -= speed * deltaTime * 3;
      }

      // Dust puff particles behind rear wheels while driving on the ground
      if (jumpState === 'grounded') {
        dustTimer += deltaTime;
        if (dustTimer >= DUST_INTERVAL) {
          dustTimer = 0;
          const dustColor = new Color(0.65, 0.55, 0.4);
          createDustPuff(scene, new Vector3(truckX - 0.6, 0.1, 0.5), dustColor, 8);
          createDustPuff(scene, new Vector3(truckX - 0.6, 0.1, -0.5), dustColor, 8);
        }
      } else {
        dustTimer = 0;
      }

      // Move the sky gradient to follow the truck horizontally
      if (skyMesh) {
        skyMesh.position.x = truckX;
      }

      // Update camera to follow truck
      if (camera) {
        const dx = truckX - cameraTarget.x;
        const dy = truckY - cameraTarget.y;
        cameraTarget.x = truckX;
        cameraTarget.y = truckY;
        camera.position.x += dx;
        camera.position.y += dy;
        camera.lookAt(cameraTarget);
      }

      // Collect stars
      collectStars();

      // Check obstacle collisions
      checkObstacles();

      // Spin star meshes
      for (const seg of segments) {
        for (const star of seg.stars) {
          if (!star.collected) {
            star.mesh.rotation.y += deltaTime * 2;
          }
        }
      }

      // Manage segments (recycle/create)
      manageSegments();
    },

    pause(): void {
      paused = true;
    },

    resume(): void {
      paused = false;
    },

    teardown(): void {
      // Dispose truck
      if (truckBody) {
        disposeMeshDeep(truckBody);
        truckBody = null;
      }
      truckWheels = [];

      // Dispose segments
      for (const seg of segments) {
        disposeSegment(seg);
      }
      segments = [];

      // Dispose materials
      const mats = [groundMat1, groundMat2, starMat, crateMat, coneMat, rampMat];
      for (const mat of mats) {
        mat?.dispose();
      }
      groundMat1 = null;
      groundMat2 = null;
      starMat = null;
      crateMat = null;
      coneMat = null;
      rampMat = null;

      // Dispose sky gradient
      if (skyMesh) {
        disposeMeshDeep(skyMesh);
        skyMesh = null;
      }

      // Dispose lights and camera
      disposeGameRig(camera, lights);
      camera = null;
      lights = null;
    },

    onResize(_viewport: ViewportInfo): void {
      // Camera is fixed; no responsive adjustments needed
    },

    onTap(_event: MiniGameTapEvent): void {
      if (paused) return;

      const onRamp = checkRamps();

      if (jumpState === 'grounded' && !onRamp) {
        // Regular hop-jump
        jumpState = 'jumping';
        jumpVelocity = velocityForHeight(3.0);
        hasBoosted = false;
        context.celebration.celebrationSound('whoosh');
      } else if (jumpState === 'grounded' && onRamp) {
        // Boosted jump from ramp
        jumpState = 'jumping';
        jumpVelocity = velocityForHeight(5.0);
        hasBoosted = false;
        context.celebration.celebrationSound('whoosh');
      } else if ((jumpState === 'jumping' || jumpState === 'falling') && !hasBoosted) {
        // Mid-air boost (once per jump)
        hasBoosted = true;
        jumpVelocity += velocityForHeight(1.5);
        context.celebration.celebrationSound('whoosh');
        // Confetti burst on boost activation
        createConfettiBurst(
          scene,
          new Vector3(truckX, truckY, 0),
          new Color(1.0, 0.4, 0.1),
          new Color(1.0, 0.85, 0.0),
          30,
        );
      }
    },
  };

  return game;
}

import { Scene, Mesh, type Object3D, SphereGeometry, Color, Vector3 } from 'three';
import { createRubberMaterial } from '@app/minigames/shared/materials';
import { buildPuppy as buildDetailedPuppy } from '@app/minigames/shared/animalBuilder';
import { createDustPuff, createSparkleBurst, createHeartBurst } from '@app/minigames/shared/particleFx';
import type { MiniGameContext } from '../../framework/types';
import { lerp, parabolicY } from './helpers';
import {
  BALL_RADIUS,
  BALL_READY_POS,
  PUPPY_ORIGIN,
  ARRIVAL_THRESHOLD,
  CHASE_SPEED,
  RETURN_SPEED,
  MIN_THROW_DISTANCE,
  MAX_THROW_DISTANCE,
  CHASE_DELAY,
  PICKUP_DURATION,
} from './types';
import type { BallState, PuppyState } from './types';

export interface PuppyMeshes {
  puppyRoot: Object3D;
  puppyBody: Mesh | null;
  puppyTail: Mesh | null;
  puppyPaw0: Mesh | null;
  puppyPaw1: Mesh | null;
  puppyPaw2: Mesh | null;
  puppyPaw3: Mesh | null;
}

/**
 * Builds the puppy using the shared animalBuilder and caches references to
 * animatable child meshes (body, head, tail, paws).
 */
export function buildPuppyMesh(scene: Scene): PuppyMeshes {
  const puppyRoot = buildDetailedPuppy('puppy', PUPPY_ORIGIN, new Color(0.82, 0.6, 0.3));
  scene.add(puppyRoot);

  let puppyBody: Mesh | null = null;
  let puppyTail: Mesh | null = null;
  let puppyPaw0: Mesh | null = null;
  let puppyPaw1: Mesh | null = null;
  let puppyPaw2: Mesh | null = null;
  let puppyPaw3: Mesh | null = null;

  // Cache references to child meshes for animation
  puppyRoot.traverse((child) => {
    if (child instanceof Mesh) {
      if (child.name === 'puppy_body') puppyBody = child;
      else if (child.name === 'puppy_tail') puppyTail = child;
      else if (child.name === 'puppy_paw_0') puppyPaw0 = child;
      else if (child.name === 'puppy_paw_1') puppyPaw1 = child;
      else if (child.name === 'puppy_paw_2') puppyPaw2 = child;
      else if (child.name === 'puppy_paw_3') puppyPaw3 = child;
    }
  });

  return { puppyRoot, puppyBody, puppyTail, puppyPaw0, puppyPaw1, puppyPaw2, puppyPaw3 };
}

/**
 * Builds the tennis ball mesh with a fuzzy yellow-green PBR rubber material.
 */
export function buildBall(scene: Scene): Mesh {
  const geo = new SphereGeometry(BALL_RADIUS, 12, 12);
  const mat = createRubberMaterial('ballMat', new Color(0.8, 0.9, 0.15));
  mat.roughness = 0.55; // slight fuzz for tennis ball feel
  const ballMesh = new Mesh(geo, mat);
  ballMesh.name = 'fetchBall';
  ballMesh.position.copy(BALL_READY_POS);
  scene.add(ballMesh);
  return ballMesh;
}

/**
 * Resets the ball to the ready position in front of the puppy.
 */
export function resetBall(ballMesh: Mesh | null, setBallState: (s: BallState) => void): void {
  if (!ballMesh) return;
  ballMesh.position.copy(BALL_READY_POS);
  setBallState('ready');
}

export interface BallFlightState {
  ballStartPos: Vector3;
  ballTargetPos: Vector3;
  ballFlightTime: number;
  ballFlightDuration: number;
}

/**
 * Launches the ball along a parabolic arc to the target distance.
 * @param distance - How far along the z-axis to throw the ball.
 */
export function throwBall(
  ballMesh: Mesh | null,
  distance: number,
  setBallState: (s: BallState) => void,
): BallFlightState | null {
  if (!ballMesh) return null;

  const clampedDistance = Math.max(MIN_THROW_DISTANCE, Math.min(MAX_THROW_DISTANCE, distance));

  setBallState('flying');
  const ballStartPos = ballMesh.position.clone();
  const ballTargetPos = new Vector3(0, BALL_RADIUS, ballStartPos.z + clampedDistance);
  const ballFlightTime = 0;
  // Duration scales with distance: roughly 0.3s base + 0.08s per unit
  const ballFlightDuration = 0.3 + clampedDistance * 0.08;

  return { ballStartPos, ballTargetPos, ballFlightTime, ballFlightDuration };
}

export interface BallBounceResult {
  ballLandedY: number;
  ballBounceTime: number;
  waitingToChase: boolean;
  chaseDelayTimer: number;
}

/**
 * Updates the ball's flying animation along the parabolic path.
 * @param deltaTime - Seconds since last frame.
 */
export function updateBallFlight(
  ballMesh: Mesh | null,
  ballState: BallState,
  flight: BallFlightState,
  deltaTime: number,
  scene: Scene,
  setBallState: (s: BallState) => void,
): { landed: boolean; bounceResult?: BallBounceResult; updatedFlight: BallFlightState } {
  if (!ballMesh || ballState !== 'flying') return { landed: false, updatedFlight: flight };

  const updatedFlight = { ...flight, ballFlightTime: flight.ballFlightTime + deltaTime };
  const t = Math.min(updatedFlight.ballFlightTime / updatedFlight.ballFlightDuration, 1);

  const distance = updatedFlight.ballTargetPos.z - updatedFlight.ballStartPos.z;
  ballMesh.position.x = lerp(updatedFlight.ballStartPos.x, updatedFlight.ballTargetPos.x, t);
  ballMesh.position.z = lerp(updatedFlight.ballStartPos.z, updatedFlight.ballTargetPos.z, t);
  ballMesh.position.y = BALL_RADIUS + parabolicY(t, distance);

  if (t >= 1) {
    setBallState('landed');

    // Dust puff particle effect on landing
    createDustPuff(scene, ballMesh.position.clone());

    return {
      landed: true,
      bounceResult: {
        ballLandedY: BALL_RADIUS,
        ballBounceTime: 0,
        waitingToChase: true,
        chaseDelayTimer: 0,
      },
      updatedFlight,
    };
  }

  return { landed: false, updatedFlight };
}

/**
 * Updates the ball's landing bounce animation.
 * @param deltaTime - Seconds since last frame.
 */
export function updateBallBounce(
  ballMesh: Mesh | null,
  ballState: BallState,
  ballBounceTime: number,
  ballLandedY: number,
  deltaTime: number,
): number {
  if (!ballMesh || ballState !== 'landed') return ballBounceTime;

  const newBounceTime = ballBounceTime + deltaTime;
  // Dampened bounce: decaying sine wave
  const bounceHeight = 0.3 * Math.exp(-newBounceTime * 5) * Math.abs(Math.sin(newBounceTime * 12));
  ballMesh.position.y = ballLandedY + bounceHeight;
  return newBounceTime;
}

/**
 * Updates the puppy's idle animation: tail wag and gentle body bob.
 */
export function updatePuppyIdle(
  puppyTail: Mesh | null,
  puppyBody: Mesh | null,
  puppyRoot: Object3D | null,
  elapsedTime: number,
): void {
  if (!puppyTail || !puppyBody || !puppyRoot) return;

  // Tail wag using sine wave
  puppyTail.rotation.y = Math.sin(elapsedTime * 8) * 0.4;

  // Gentle body bob
  puppyBody.position.y = Math.sin(elapsedTime * 2) * 0.02;
}

/**
 * Resets puppy paw positions to resting height.
 */
export function resetPawPositions(
  puppyPaw0: Mesh | null,
  puppyPaw1: Mesh | null,
  puppyPaw2: Mesh | null,
  puppyPaw3: Mesh | null,
): void {
  if (puppyPaw0) puppyPaw0.position.y = -0.35;
  if (puppyPaw1) puppyPaw1.position.y = -0.35;
  if (puppyPaw2) puppyPaw2.position.y = -0.35;
  if (puppyPaw3) puppyPaw3.position.y = -0.35;
}

/**
 * Moves the puppy toward a target position at the given speed.
 * @param target - The position to move toward.
 * @param speed - Movement speed in units per second.
 * @param deltaTime - Seconds since last frame.
 * @returns True if the puppy has arrived at the target.
 */
export function movePuppyToward(
  puppyRoot: Object3D | null,
  puppyPosition: Vector3,
  puppyTail: Mesh | null,
  puppyPaw0: Mesh | null,
  puppyPaw1: Mesh | null,
  puppyPaw2: Mesh | null,
  puppyPaw3: Mesh | null,
  elapsedTime: number,
  target: Vector3,
  speed: number,
  deltaTime: number,
): { arrived: boolean; newPosition: Vector3 } {
  if (!puppyRoot) return { arrived: true, newPosition: puppyPosition };

  const direction = target.clone().sub(puppyPosition);
  const distance = direction.length();

  if (distance < ARRIVAL_THRESHOLD) {
    const newPosition = target.clone();
    puppyRoot.position.x = newPosition.x;
    puppyRoot.position.z = newPosition.z;
    return { arrived: true, newPosition };
  }

  const step = Math.min(speed * deltaTime, distance);
  const normalized = direction.normalize();
  const newPosition = puppyPosition.clone().add(normalized.multiplyScalar(step));
  puppyRoot.position.x = newPosition.x;
  puppyRoot.position.z = newPosition.z;

  // Animate tail wagging faster during movement
  if (puppyTail) {
    puppyTail.rotation.y = Math.sin(elapsedTime * 14) * 0.6;
  }

  // Animate paw movement during running
  const legPhase = elapsedTime * 10;
  if (puppyPaw0) puppyPaw0.position.y = -0.35 + Math.sin(legPhase) * 0.05;
  if (puppyPaw1) puppyPaw1.position.y = -0.35 + Math.sin(legPhase + Math.PI) * 0.05;
  if (puppyPaw2) puppyPaw2.position.y = -0.35 + Math.sin(legPhase + Math.PI) * 0.05;
  if (puppyPaw3) puppyPaw3.position.y = -0.35 + Math.sin(legPhase) * 0.05;

  return { arrived: false, newPosition };
}

/**
 * Updates the puppy's chasing behavior.
 * @param deltaTime - Seconds since last frame.
 */
export function updatePuppyChase(
  puppyState: PuppyState,
  puppyRoot: Object3D | null,
  puppyPosition: Vector3,
  puppyTail: Mesh | null,
  puppyPaw0: Mesh | null,
  puppyPaw1: Mesh | null,
  puppyPaw2: Mesh | null,
  puppyPaw3: Mesh | null,
  elapsedTime: number,
  ballTargetPos: Vector3,
  deltaTime: number,
): { newPuppyState: PuppyState; newPosition: Vector3; pickupTimer: number } | null {
  if (puppyState !== 'chasing') return null;

  const targetOnGround = new Vector3(ballTargetPos.x, 0, ballTargetPos.z);
  const { arrived, newPosition } = movePuppyToward(
    puppyRoot,
    puppyPosition,
    puppyTail,
    puppyPaw0,
    puppyPaw1,
    puppyPaw2,
    puppyPaw3,
    elapsedTime,
    targetOnGround,
    CHASE_SPEED,
    deltaTime,
  );

  if (arrived) {
    // Pick up ball
    return { newPuppyState: 'dropping', newPosition, pickupTimer: 0 };
  }

  return { newPuppyState: 'chasing', newPosition, pickupTimer: 0 };
}

export interface PickupReturnResult {
  newPuppyState: PuppyState;
  newBallState: BallState;
  newPosition: Vector3;
  pickupTimer: number;
  fetchCount: number;
  resetBallNeeded: boolean;
}

/**
 * Updates the puppy's pickup and return behavior.
 * @param deltaTime - Seconds since last frame.
 */
export function updatePuppyPickupAndReturn(
  puppyState: PuppyState,
  ballState: BallState,
  puppyRoot: Object3D | null,
  puppyBody: Mesh | null,
  puppyTail: Mesh | null,
  puppyPaw0: Mesh | null,
  puppyPaw1: Mesh | null,
  puppyPaw2: Mesh | null,
  puppyPaw3: Mesh | null,
  puppyPosition: Vector3,
  ballMesh: Mesh | null,
  elapsedTime: number,
  pickupTimer: number,
  fetchCount: number,
  scene: Scene,
  context: MiniGameContext,
  deltaTime: number,
): PickupReturnResult {
  let currentPuppyState = puppyState;
  let currentBallState = ballState;
  let currentPickupTimer = pickupTimer;
  let currentPosition = puppyPosition;
  let currentFetchCount = fetchCount;
  let resetBallNeeded = false;

  if (currentPuppyState === 'dropping' && currentBallState === 'landed') {
    // Pickup phase
    currentPickupTimer += deltaTime;

    // Lower body slightly during pickup (sit effect)
    if (puppyBody) {
      puppyBody.position.y = -0.1 * Math.min(currentPickupTimer / PICKUP_DURATION, 1);
    }

    if (currentPickupTimer >= PICKUP_DURATION) {
      // Attach ball to puppy
      currentBallState = 'carried';
      if (puppyBody) puppyBody.position.y = 0;

      // Sparkle burst when puppy catches ball
      if (puppyRoot) {
        createSparkleBurst(scene, puppyRoot.position.clone().add(new Vector3(0, 0.5, 0.3)), new Color(1, 0.85, 0.2));
      }

      currentPuppyState = 'returning';
    }
  }

  if (currentPuppyState === 'returning') {
    // Ball follows puppy head
    if (ballMesh && puppyRoot) {
      ballMesh.position.set(puppyRoot.position.x, 0.6, puppyRoot.position.z + 0.45);
    }

    const { arrived, newPosition } = movePuppyToward(
      puppyRoot,
      currentPosition,
      puppyTail,
      puppyPaw0,
      puppyPaw1,
      puppyPaw2,
      puppyPaw3,
      elapsedTime,
      PUPPY_ORIGIN,
      RETURN_SPEED,
      deltaTime,
    );
    currentPosition = newPosition;

    if (arrived) {
      // Complete the fetch cycle
      currentPuppyState = 'dropping';
      currentBallState = 'carried';
      currentPickupTimer = 0;

      // Lower body for drop
      if (puppyBody) {
        puppyBody.position.y = -0.1;
      }

      // Score and celebrate
      currentFetchCount++;
      context.score.addPoints(1);
      context.combo.registerHit();
      context.celebration.confetti((context.viewport.width ?? 400) / 2, (context.viewport.height ?? 300) / 2, 'small');
      context.audio.playSound('sfx_shared_reward_star');

      // Heart burst on combo (fetchCount > 1 means consecutive fetches)
      if (currentFetchCount > 1 && puppyRoot) {
        createHeartBurst(scene, puppyRoot.position.clone().add(new Vector3(0, 0.8, 0)), new Color(1.0, 0.4, 0.5));
      }

      // Reset after a brief moment
      resetPawPositions(puppyPaw0, puppyPaw1, puppyPaw2, puppyPaw3);

      // Restore body height and reset ball
      if (puppyBody) puppyBody.position.y = 0;
      currentPuppyState = 'idle';
      resetBallNeeded = true;
    }
  }

  return {
    newPuppyState: currentPuppyState,
    newBallState: currentBallState,
    newPosition: currentPosition,
    pickupTimer: currentPickupTimer,
    fetchCount: currentFetchCount,
    resetBallNeeded,
  };
}

/**
 * Updates the chase delay timer after the ball lands.
 * @param deltaTime - Seconds since last frame.
 */
export function updateChaseDelay(
  waitingToChase: boolean,
  chaseDelayTimer: number,
  deltaTime: number,
): { waitingToChase: boolean; chaseDelayTimer: number; startChasing: boolean } {
  if (!waitingToChase) return { waitingToChase, chaseDelayTimer, startChasing: false };

  const newTimer = chaseDelayTimer + deltaTime;
  if (newTimer >= CHASE_DELAY) {
    return { waitingToChase: false, chaseDelayTimer: newTimer, startChasing: true };
  }

  return { waitingToChase: true, chaseDelayTimer: newTimer, startChasing: false };
}

import { Scene, Mesh, type Object3D, PlaneGeometry, BoxGeometry, Color, Vector3 } from 'three';
import { createFeltMaterial, createWoodMaterial } from '@app/minigames/shared/materials';
import {
  buildSkyGradient,
  buildDetailedTree,
  buildDetailedFence,
  buildGrassTuft,
  buildDetailedFlower,
} from '@app/minigames/shared/meshBuilders';

export interface EnvironmentMeshes {
  ground: Mesh;
  bench: Mesh;
  trees: Object3D[];
  fenceParts: Object3D[];
  skyMesh: Object3D;
  grassTufts: Object3D[];
  flowers: Object3D[];
}

/**
 * Builds the park environment with PBR materials, detailed trees, fence,
 * sky gradient, grass tufts, flowers, and a bench.
 */
export function buildEnvironment(scene: Scene): EnvironmentMeshes {
  const trees: Object3D[] = [];
  const fenceParts: Object3D[] = [];
  const grassTufts: Object3D[] = [];
  const flowers: Object3D[] = [];

  // Sky gradient backdrop
  const skyMesh = buildSkyGradient(new Color(0.4, 0.65, 0.95), new Color(0.7, 0.85, 0.98), 30);
  scene.add(skyMesh);

  // Ground with felt material for soft grass look
  const groundGeo = new PlaneGeometry(20, 20);
  groundGeo.rotateX(-Math.PI / 2);
  const ground = new Mesh(groundGeo, createFeltMaterial('groundMat', new Color(0.3, 0.65, 0.2)));
  ground.name = 'parkGround';
  scene.add(ground);

  // Detailed trees at sides
  const treePositions = [new Vector3(-5, 0, 3), new Vector3(-6, 0, -2), new Vector3(5, 0, 2), new Vector3(6, 0, -3)];
  for (const pos of treePositions) {
    const tree = buildDetailedTree(pos, 2.5);
    scene.add(tree);
    trees.push(tree);
  }

  // Detailed fence sections in background
  const fenceSectionWidth = 4.5;
  for (let i = -1; i <= 1; i++) {
    const fence = buildDetailedFence(new Vector3(i * fenceSectionWidth, 0, -7), fenceSectionWidth);
    scene.add(fence);
    fenceParts.push(fence);
  }

  // Grass tufts scattered across the ground
  const tuftPositions = [
    new Vector3(-2, 0, 2),
    new Vector3(1.5, 0, 3),
    new Vector3(-3, 0, -1),
    new Vector3(3, 0, 0.5),
    new Vector3(-1, 0, 4),
    new Vector3(2.5, 0, -2),
    new Vector3(-4, 0, 1),
    new Vector3(0.5, 0, -3),
  ];
  for (const pos of tuftPositions) {
    const tuft = buildGrassTuft(pos);
    scene.add(tuft);
    grassTufts.push(tuft);
  }

  // Flowers for colour accents
  const flowerConfigs: { pos: Vector3; color: Color }[] = [
    { pos: new Vector3(-3, 0, 3), color: new Color(0.95, 0.3, 0.35) },
    { pos: new Vector3(2, 0, 4), color: new Color(0.95, 0.85, 0.2) },
    { pos: new Vector3(-4.5, 0, -1.5), color: new Color(0.7, 0.3, 0.85) },
    { pos: new Vector3(3.5, 0, 1.5), color: new Color(0.95, 0.55, 0.2) },
  ];
  for (const cfg of flowerConfigs) {
    const flower = buildDetailedFlower(cfg.pos, cfg.color, 0.35);
    scene.add(flower);
    flowers.push(flower);
  }

  // Bench with wood PBR material
  const benchWoodMat = createWoodMaterial('benchMat', new Color(0.55, 0.35, 0.2));

  const benchSeatGeo = new BoxGeometry(2.0, 0.1, 0.6);
  const benchSeat = new Mesh(benchSeatGeo, benchWoodMat);
  benchSeat.name = 'benchSeat';
  benchSeat.position.set(4, 0.55, -3);
  scene.add(benchSeat);

  const benchBackGeo = new BoxGeometry(2.0, 0.6, 0.08);
  const benchBack = new Mesh(benchBackGeo, benchWoodMat);
  benchBack.name = 'benchBack';
  benchBack.position.set(4, 0.9, -3.27);
  scene.add(benchBack);

  const benchLeg1Geo = new BoxGeometry(0.1, 0.55, 0.1);
  const benchLeg1 = new Mesh(benchLeg1Geo, benchWoodMat);
  benchLeg1.name = 'benchLeg1';
  benchLeg1.position.set(3.2, 0.275, -3);
  scene.add(benchLeg1);

  const benchLeg2Geo = new BoxGeometry(0.1, 0.55, 0.1);
  const benchLeg2 = new Mesh(benchLeg2Geo, benchWoodMat);
  benchLeg2.name = 'benchLeg2';
  benchLeg2.position.set(4.8, 0.275, -3);
  scene.add(benchLeg2);

  trees.push(benchBack, benchLeg1, benchLeg2);

  return { ground, bench: benchSeat, trees, fenceParts, skyMesh, grassTufts, flowers };
}

import { type Scene, Mesh, type Object3D, BoxGeometry, CylinderGeometry, Color, Vector3 } from 'three';
import { createGameCamera, createGameLighting, type GameLightingRig } from '@app/minigames/shared/sceneSetup';
import { createPlasticMaterial, createGlossyPaintMaterial, createWoodMaterial } from '@app/minigames/shared/materials';
import { buildSkyGradient } from '@app/minigames/shared/meshBuilders';

export interface EnvironmentObjects {
  camera: ReturnType<typeof createGameCamera>;
  lights: GameLightingRig;
  craftTable: Mesh;
  crayonJar: Mesh;
  glueStick: Mesh;
  skyGradient: Object3D;
}

export function buildEnvironment(scene: Scene): EnvironmentObjects {
  // Camera ΓÇö top-down-ish view
  const camera = createGameCamera({
    name: 'shapeBuilder',
    beta: 1.1,
    radius: 9.0,
    target: new Vector3(0, 0.5, 0),
    fov: 0.85,
  });

  // Lights
  const lights = createGameLighting({
    name: 'shapeBuilder',
    direction: new Vector3(-1, -2, 1).normalize(),
    directionalIntensity: 0.7,
    hemisphericIntensity: 0.5,
  });

  // Craft table
  const tableGeo = new BoxGeometry(10, 0.1, 6);
  const craftTable = new Mesh(tableGeo, createWoodMaterial('tableMat', new Color(0.85, 0.75, 0.6)));
  craftTable.name = 'craftTable';
  craftTable.position.set(0, -0.05, 0);
  scene.add(craftTable);

  // Crayon jar decoration
  const jarGeo = new CylinderGeometry(0.5 / 2, 0.5 / 2, 0.8, 16);
  const crayonJar = new Mesh(jarGeo, createGlossyPaintMaterial('jarMat', new Color(0.3, 0.5, 0.8)));
  crayonJar.name = 'crayonJar';
  crayonJar.position.set(4.0, 0.4, 2.0);
  scene.add(crayonJar);

  // Glue stick decoration
  const glueGeo = new CylinderGeometry(0.2 / 2, 0.2 / 2, 0.6, 12);
  const glueStick = new Mesh(glueGeo, createPlasticMaterial('glueMat', new Color(0.95, 0.95, 0.9)));
  glueStick.name = 'glueStick';
  glueStick.position.set(4.3, 0.3, -1.8);
  glueStick.rotation.z = 0.3;
  scene.add(glueStick);

  // Sky gradient backdrop
  const skyGradient = buildSkyGradient(new Color(0.55, 0.7, 0.95), new Color(0.88, 0.85, 0.92), 20);
  skyGradient.position.set(0, 2, 0);
  scene.add(skyGradient);

  return { camera, lights, craftTable, crayonJar, glueStick, skyGradient };
}

/** Returns a random floating-point number in the range [min, max). */
export function randomRange(min: number, max: number): number {
  return min + Math.random() * (max - min);
}

/** Returns a random integer in the range [0, max). */
export function randomInt(max: number): number {
  return Math.floor(Math.random() * max);
}

/** Returns a random element from a non-empty readonly array. */
export function randomPick<T>(arr: readonly T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

/** Clamps a value to the inclusive range [lo, hi]. */
export function clamp(v: number, lo: number, hi: number): number {
  return v < lo ? lo : v > hi ? hi : v;
}

/** Linearly interpolates between a and b by factor t, clamped to [0, 1]. */
export function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * clamp(t, 0, 1);
}

/** Wraps an angle in radians to the range [-PI, PI]. */
export function wrapAngle(a: number): number {
  while (a > Math.PI) a -= Math.PI * 2;
  while (a < -Math.PI) a += Math.PI * 2;
  return a;
}

/** Applies a cubic ease-out curve to t in [0, 1]. */
export function easeOutCubic(t: number): number {
  return 1 - Math.pow(1 - t, 3);
}

/** Shuffles an array in-place using the Fisher-Yates algorithm. Returns the same array. */
export function shuffle<T>(arr: T[]): T[] {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

/** Computes the horizontal (XZ plane) distance between two 3D points. */
export function xzDistance(a: { x: number; z: number }, b: { x: number; z: number }): number {
  const dx = a.x - b.x;
  const dz = a.z - b.z;
  return Math.sqrt(dx * dx + dz * dz);
}

/** Computes the parabolic arc height for a projectile at progress t with given distance. */
export function parabolicY(t: number, distance: number): number {
  const peakHeight = distance * 0.3;
  return peakHeight * 4 * t * (1 - t);
}

import { Scene, Vector3, Color, Mesh, Group, SphereGeometry, CylinderGeometry, type Camera } from 'three';
import { createGlossyPaintMaterial } from '@app/utils/materialFactory';
import { createDustPuff } from '@app/utils/particles';
import { onTap } from '@app/utils/sceneHelpers';
import { idleWithInterrupt, type IdleInterruptHandle } from '@app/utils/idleInterruptible';

/**
 * Builds a procedural toy crab with body, eye stalks, and claws.
 * The crab plays an idle side-to-side sway that is interrupted on tap
 * with a side-scuttle reaction, then resumes automatically.
 *
 * @param scene - The Three.js Scene.
 * @param _shadowGen - Unused; shadow casting set via mesh.castShadow.
 * @param pos - World-space position for the crab.
 * @returns The root group of the crab hierarchy.
 */
export function buildCrab(scene: Scene, _shadowGen: unknown, pos: Vector3): Group {
  const root = new Group();
  root.name = 'crab_root';
  root.position.copy(pos);
  scene.add(root);

  // Body
  const bodyGeo = new SphereGeometry(0.5, 8, 8);
  const body = new Mesh(bodyGeo, createGlossyPaintMaterial('crabMat', new Color(0.9, 0.3, 0.15)));
  body.name = 'crabBody';
  body.scale.set(0.3, 0.12, 0.25);
  body.castShadow = true;
  root.add(body);

  // Eyes
  for (let s = -1; s <= 1; s += 2) {
    const stalk = new Mesh(new CylinderGeometry(0.03 / 2, 0.03 / 2, 0.08, 4), body.material);
    stalk.name = `crabEyeStalk_${s}`;
    stalk.position.set(s * 0.08, 0.08, 0.08);
    root.add(stalk);

    const eye = new Mesh(
      new SphereGeometry(0.04 / 2, 6, 6),
      createGlossyPaintMaterial(`crabEyeMat_${s}`, new Color(0.05, 0.05, 0.05)),
    );
    eye.name = `crabEye_${s}`;
    eye.position.y = 0.05;
    stalk.add(eye);
  }

  // Claws
  for (let s = -1; s <= 1; s += 2) {
    const clawGeo = new SphereGeometry(0.5, 6, 6);
    const claw = new Mesh(clawGeo, createGlossyPaintMaterial(`crabClawMat_${s}`, new Color(0.95, 0.35, 0.15)));
    claw.name = `crabClaw_${s}`;
    claw.scale.set(0.12, 0.08, 0.06);
    claw.position.set(s * 0.2, 0, 0.05);
    root.add(claw);
  }

  // Idle sway + side-scuttle reaction via shared utility
  const handle = idleWithInterrupt(root, {
    idleProperty: 'position',
    idleKeys: [
      { frame: 0, value: pos.clone() },
      { frame: 60, value: new Vector3(pos.x + 0.3, pos.y, pos.z) },
      { frame: 120, value: pos.clone() },
      { frame: 180, value: new Vector3(pos.x - 0.3, pos.y, pos.z) },
      { frame: 240, value: pos.clone() },
    ],
    reactionAnimations: () => {
      const p = root.position.clone();
      const dir = (Math.random() > 0.5 ? 1 : -1) * 0.6;
      return [
        {
          property: 'position',
          keys: [
            { frame: 0, value: p },
            { frame: 10, value: new Vector3(p.x + dir, p.y, p.z) },
            { frame: 30, value: p },
          ],
        },
      ];
    },
    particleFn: createDustPuff,
  });
  root.userData = { handle };

  return root;
}

/**
 * Registers a tap interaction on the crab that triggers the side-scuttle reaction.
 *
 * @param scene - The Three.js Scene.
 * @param canvas - The canvas element for event binding.
 * @param camera - The camera for raycasting.
 * @param crab - The crab root group from {@link buildCrab}.
 */
export function setupCrabTap(_scene: Scene, canvas: HTMLCanvasElement, camera: Camera, crab: Group): void {
  const body = crab.children.find((m) => m.name === 'crabBody');
  if (!body) return;
  const handle = crab.userData?.handle as IdleInterruptHandle | undefined;

  onTap(canvas, camera, body as Mesh, () => {
    handle?.trigger();
  });
}

