/**
 * Builds a procedural toy parrot with body, head, beak, and wing.
 * The parrot plays an idle bobbing animation that is interrupted on tap
 * with a wing-flap reaction, then resumes automatically.
 *
 * @param scene - The Three.js Scene.
 * @param _shadowGen - Unused; shadow casting set via mesh.castShadow.
 * @param pos - World-space position for the parrot.
 * @returns The root group of the parrot hierarchy.
 */
export function buildParrot(scene: Scene, _shadowGen: unknown, pos: Vector3): Group {
  const root = new Group();
  root.name = 'parrot_root';
  root.position.copy(pos);
  scene.add(root);

  // Body
  const bodyGeo = new SphereGeometry(0.5, 8, 8);
  const body = new Mesh(bodyGeo, createGlossyPaintMaterial('parrotBodyMat', new Color(0.2, 0.7, 0.3)));
