import {
  Scene,
  Vector3,
  Color,
  Mesh,
  Group,
  SphereGeometry,
  CylinderGeometry,
  CircleGeometry,
  type Material,
  type Camera,
} from 'three';
import { createGlossyPaintMaterial, createFeltMaterial } from '@app/utils/materialFactory';
import { createSparkleBurst } from '@app/utils/particles';
import { onTap } from '@app/utils/sceneHelpers';
import { idleWithInterrupt, type IdleInterruptHandle } from '@app/utils/idleInterruptible';

/** Builds species-specific features on an animal figurine. */
type FeatureBuilder = (scene: Scene, root: Group, head: Mesh, bodyMat: Material, color: Color) => void;

/** Species feature builders ΓÇö adding a new animal is an additive change (OCP). */
const ANIMAL_FEATURES: Record<string, FeatureBuilder> = {
  giraffe: (_scene, root, head, bodyMat) => {
    const neck = new Mesh(new CylinderGeometry(0.08 / 2, 0.08 / 2, 0.5, 6), bodyMat);
    neck.name = 'giraffeNeck';
    neck.position.set(0, 0.55, 0.1);
    neck.rotation.x = -0.3;
    root.add(neck);
    head.position.set(0, 0.75, 0.22);
  },
  elephant: (_scene, _root, head, bodyMat) => {
    const trunk = new Mesh(new CylinderGeometry(0.04 / 2, 0.06 / 2, 0.25, 6), bodyMat);
    trunk.name = 'elephantTrunk';
    trunk.position.set(0, -0.05, 0.1);
    trunk.rotation.x = 0.6;
    head.add(trunk);
    for (let s = -1; s <= 1; s += 2) {
      const earGeo = new CircleGeometry(0.12, 8);
      const ear = new Mesh(earGeo, bodyMat);
      ear.name = `elephantEar_${s}`;
      ear.position.set(s * 0.12, 0.02, 0);
      ear.rotation.y = s * 0.5;
      head.add(ear);
    }
  },
  bunny: (_scene, _root, head, bodyMat) => {
    for (let s = -1; s <= 1; s += 2) {
      const ear = new Mesh(new CylinderGeometry(0.03 / 2, 0.05 / 2, 0.25, 6), bodyMat);
      ear.name = `bunnyEar_${s}`;
      ear.position.set(s * 0.05, 0.12, 0);
      ear.rotation.z = s * -0.15;
      head.add(ear);
    }
  },
  puppy: (_scene, root, head, bodyMat, color) => {
    for (let s = -1; s <= 1; s += 2) {
      const earGeo = new SphereGeometry(0.5, 6, 6);
      const ear = new Mesh(earGeo, createGlossyPaintMaterial(`puppyEarMat_${s}`, color.clone().multiplyScalar(0.7)));
      ear.name = `puppyEar_${s}`;
      ear.scale.set(0.08, 0.12, 0.04);
      ear.position.set(s * 0.1, 0, 0);
      head.add(ear);
    }
    const tail = new Mesh(new CylinderGeometry(0.02 / 2, 0.04 / 2, 0.15, 4), bodyMat);
    tail.name = 'puppyTail';
    tail.position.set(0, 0.3, -0.2);
    tail.rotation.x = -0.8;
    root.add(tail);
  },
  lion: (_scene, _root, head) => {
    const mane = new Mesh(
      new SphereGeometry(0.32 / 2, 8, 8),
      createFeltMaterial('lionManeMat', new Color(0.7, 0.45, 0.1)),
    );
    mane.name = 'lionMane';
    mane.position.z = -0.02;
    head.add(mane);
  },
};

/**
 * Builds a toy animal figurine with body, head, eyes, legs, and species-specific features.
 * Species features are defined in ANIMAL_FEATURES ΓÇö adding a new animal is additive (OCP).
 * Includes idle sway + hop-and-wiggle tap reaction via the shared idleWithInterrupt utility.
 *
 * @param scene - The Three.js scene to add meshes to.
 * @param _shadowGen - Unused; shadow casting set via mesh.castShadow.
 * @param name - Animal species identifier (lion, giraffe, elephant, bunny, puppy).
 * @param pos - World-space position for the animal.
 * @param color - Base color for the animal's body material.
 * @returns The root group of the animal figurine.
 */
export function buildAnimal(scene: Scene, _shadowGen: unknown, name: string, pos: Vector3, color: Color): Group {
  const root = new Group();
  root.name = `animal_${name}_root`;
  root.position.copy(pos);
  scene.add(root);

  // Body
  const bodyGeo = new SphereGeometry(0.5, 10, 10);
  const bodyMat = createGlossyPaintMaterial(`animal_${name}_mat`, color);
  const body = new Mesh(bodyGeo, bodyMat);
  body.name = `animal_${name}_body`;
  body.scale.set(0.5, 0.35, 0.35);
  body.position.y = 0.25;
  body.castShadow = true;
  root.add(body);

  // Head
  const head = new Mesh(new SphereGeometry(0.22 / 2, 8, 8), bodyMat);
  head.name = `animal_${name}_head`;
  head.position.set(0, 0.42, 0.15);
  root.add(head);

  // Eyes
  const eyeMat = createGlossyPaintMaterial(`animal_${name}_eyeMat`, new Color(0.05, 0.05, 0.05));
  for (let s = -1; s <= 1; s += 2) {
    const eye = new Mesh(new SphereGeometry(0.04 / 2, 6, 6), eyeMat);
    eye.name = `eye_${s}`;
    eye.position.set(s * 0.06, 0.03, 0.09);
    head.add(eye);
  }

  // Legs
  for (let lx = -1; lx <= 1; lx += 2) {
    for (let lz = -1; lz <= 1; lz += 2) {
      const leg = new Mesh(new CylinderGeometry(0.08 / 2, 0.08 / 2, 0.2, 6), bodyMat);
      leg.name = `leg_${lx}_${lz}`;
      leg.position.set(lx * 0.12, 0.1, lz * 0.1);
      root.add(leg);
    }
  }

  // Species-specific features (OCP ΓÇö add to ANIMAL_FEATURES map)
  const featureBuilder = ANIMAL_FEATURES[name];
  if (featureBuilder) {
    featureBuilder(scene, root, head, bodyMat, color);
  }

  // Idle sway + hop-and-wiggle reaction via shared utility
  const baseY = pos.y;
  const handle = idleWithInterrupt(root, {
    idleProperty: 'rotation.z',
    idleKeys: [
      { frame: 0, value: 0 },
      { frame: 45, value: 0.04 },
      { frame: 90, value: -0.04 },
      { frame: 135, value: 0 },
    ],
    reactionAnimations: [
      {
        property: 'position.y',
        keys: [
          { frame: 0, value: baseY },
          { frame: 8, value: baseY + 0.4 },
          { frame: 16, value: baseY },
        ],
      },
      {
        property: 'rotation.z',
        keys: [
          { frame: 0, value: 0 },
          { frame: 4, value: 0.15 },
          { frame: 8, value: -0.15 },
          { frame: 12, value: 0.1 },
          { frame: 16, value: 0 },
        ],
      },
    ],
    particleFn: createSparkleBurst,
    particleOffset: new Vector3(0, 0.4, 0),
  });
  root.userData = { handle };

  return root;
}

/**
 * Registers a tap interaction on an animal figurine that triggers the
 * hop-and-wiggle reaction.
 *
 * @param scene - The Three.js scene.
 * @param canvas - The canvas element for event binding.
 * @param camera - The camera for raycasting.
 * @param animal - The root group of the animal figurine.
 */
export function setupAnimalTap(_scene: Scene, canvas: HTMLCanvasElement, camera: Camera, animal: Group): void {
  const body = animal.children.find((m) => m.name.endsWith('_body'));
  if (!body) return;
  const handle = animal.userData?.handle as IdleInterruptHandle | undefined;

  onTap(canvas, camera, body as Mesh, () => {
    handle?.trigger();
  });
}

