/**
 * Builds a toy tree with a cylindrical trunk and spherical canopy.
 *
 * @param scene - The Three.js scene.
 * @param _shadowGen - Unused; shadow casting set via mesh.castShadow.
 * @param pos - World-space position for the tree base.
 * @returns The trunk mesh (canopy is parented to it).
 */
export function buildTree(scene: Scene, _shadowGen: unknown, pos: Vector3): Mesh {
  const trunkGeo = new CylinderGeometry(0.3 / 2, 0.5 / 2, 2.5, 8);
  const trunkMat = getOrCreateMaterial('treeTrunkMat', () =>
    createWoodMaterial('treeTrunkMat', new Color(0.45, 0.3, 0.15)),
  );
  const trunk = new Mesh(trunkGeo, trunkMat);
  trunk.name = 'treeTrunk';
  trunk.position.set(pos.x, 1.25, pos.z);
  trunk.castShadow = true;
  scene.add(trunk);

  // Canopy
  const canopyMat = getOrCreateMaterial('canopyMat', () => createFeltMaterial('canopyMat', new Color(0.3, 0.6, 0.25)));
  const canopy = new Mesh(new SphereGeometry(2.5 / 2, 10, 10), canopyMat);
  canopy.name = 'canopy';
  canopy.position.y = 1.5;
  canopy.scale.y = 0.7;
  trunk.add(canopy);

  return trunk;
}

/**
 * Builds a wooden fence section with two posts.
 *
 * @param scene - The Three.js scene.
 * @param _shadowGen - Unused; shadow casting set via mesh.castShadow.
 * @param pos - World-space position for the fence.
 * @param rotY - Y-axis rotation in radians.
 * @returns The fence mesh.
 */
export function buildFence(scene: Scene, _shadowGen: unknown, pos: Vector3, rotY: number): Mesh {
  const fenceMat = getOrCreateMaterial('fenceMat', () => createWoodMaterial('fenceMat', new Color(0.75, 0.65, 0.5)));
  const fence = new Mesh(new BoxGeometry(1.5, 0.6, 0.08), fenceMat);
  fence.name = 'fence';
  fence.position.set(pos.x, 0.3, pos.z);
  fence.rotation.y = rotY;
  fence.castShadow = true;
  scene.add(fence);

  // Posts
  for (let p = -1; p <= 1; p += 2) {
    const post = new Mesh(new CylinderGeometry(0.06 / 2, 0.06 / 2, 0.7, 6), fenceMat);
    post.name = 'fencePost';
    post.position.set(p * 0.65, 0.05, 0);
    fence.add(post);
  }

  return fence;
}

/**
 * Builds a small cluster of three flowers with stems and coloured petals.
 *
 * @param scene - The Three.js scene.
 * @param pos - World-space position for the cluster.
 * @param stemMat - Material for flower stems.
 * @param petalMats - Array of materials cycled across the petals.
 * @returns The root group of the flower cluster.
 */
export function buildFlowerCluster(scene: Scene, pos: Vector3, stemMat: Material, petalMats: Material[]): Group {
  const root = new Group();
  root.name = 'flowerCluster';
  root.position.copy(pos);
