/**
 * Builds felt-lined toybox walls with wood rim and corner posts.
 * Omits the front wall (camera looks from that side). Uses animals blue theme.
 *
 * @param scene - The Three.js scene.
 * @param wallColor - Felt colour for the wall panels.
 * @param rimColor - Wood colour for rims and corner posts.
 * @param wallHeight - Height of the walls.
 * @param halfW - Half-width of the enclosure.
 * @param halfD - Half-depth of the enclosure.
 */
export function buildToyboxWalls(
  scene: Scene,
  wallColor: Color,
  rimColor: Color,
  wallHeight: number,
  halfW: number,
  halfD: number,
): void {
  const wallMat = createFeltMaterial('animalsToyboxWallMat', wallColor);
  const rimMat = createWoodMaterial('animalsToyboxRimMat', rimColor);

  // Wall definitions: [x, z, width, rotY, faceRotY]
  // Front wall omitted ΓÇö camera looks from that side
  const walls: [number, number, number, number, number][] = [
    [0, halfD, halfW * 2, 0, Math.PI], // back
    [-halfW, 0, halfD * 2, Math.PI / 2, Math.PI / 2], // left
    [halfW, 0, halfD * 2, Math.PI / 2, -Math.PI / 2], // right
  ];

  walls.forEach(([x, z, width, rotY, faceRotY], i) => {
    // Felt wall panel
    const panel = new Mesh(new PlaneGeometry(width, wallHeight), wallMat);
    panel.name = `animalsToyboxWall_${i}`;
    panel.position.set(x, wallHeight / 2, z);
    panel.rotation.y = faceRotY;
    panel.receiveShadow = true;
    scene.add(panel);

    // Wood rim along the top edge
    const rim = new Mesh(new CylinderGeometry(0.08, 0.08, width, 8), rimMat);
    rim.name = `animalsToyboxRim_${i}`;
    rim.position.set(x, wallHeight, z);
    rim.rotation.z = Math.PI / 2;
    rim.rotation.y = rotY;
    if (i === 0) rim.rotation.y = 0; // back wall rim runs along X
    scene.add(rim);
  });

  // Corner posts ΓÇö only back two corners
  const corners = [
    [-halfW, halfD],
    [halfW, halfD],
  ];
  corners.forEach(([cx, cz], ci) => {
    const post = new Mesh(new CylinderGeometry(0.12, 0.12, wallHeight + 0.1, 8), rimMat);
    post.name = `animalsToyboxCorner_${ci}`;
    post.position.set(cx, wallHeight / 2, cz);
    post.castShadow = true;
    scene.add(post);
  });
}

// ΓöÇΓöÇ Sky Backdrop ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Builds a cheerful sky backdrop with drifting clouds behind the scene.
 *
 * @param scene - The Three.js scene.
 * @param skyColor - Base colour for the sky plane.
 * @param skyEmissive - Emissive tint for the sky material.
 * @param cloudPositions - Cloud spawn positions and scales.
 */
export function buildSkyBackdrop(
  scene: Scene,
  skyColor: Color,
  skyEmissive: Color,
  cloudPositions: { x: number; y: number; z: number; s: number }[],
): Mesh {
  const skyMat = createPlasticMaterial('animalsSkyMat', skyColor);
  skyMat.emissive = skyEmissive.clone();
  const sky = new Mesh(new PlaneGeometry(28, 12), skyMat);
  sky.name = 'animalsSkyBackdrop';
  sky.position.set(0, 5, -6);
  scene.add(sky);

  // Soft clouds
  const cloudMat = createPlasticMaterial('animalsCloudMat', new Color(0.92, 0.94, 0.97));
  cloudMat.emissive = new Color(0.3, 0.32, 0.35);

  cloudPositions.forEach((cp, ci) => {
    const cloudGroup = new Group();
    cloudGroup.name = `animalsCloud_${ci}`;
    cloudGroup.position.set(cp.x, cp.y, cp.z);
    scene.add(cloudGroup);

    // Each cloud is 3-4 overlapping soft spheres
    const blobCount = 3 + Math.floor(Math.random() * 2);
    for (let b = 0; b < blobCount; b++) {
      const blob = new Mesh(new SphereGeometry(0.5 * cp.s, 8, 6), cloudMat);
      blob.name = `animalsCloudBlob_${ci}_${b}`;
      blob.position.set((b - blobCount / 2) * 0.4 * cp.s, (Math.random() - 0.5) * 0.2 * cp.s, 0);
      blob.scale.set(1.2, 0.6, 0.8);
      cloudGroup.add(blob);
    }

    // Gentle drift
    gsap.to(cloudGroup.position, {
      x: cp.x + 1.5,
      duration: 30 + ci * 8,
      repeat: -1,
      yoyo: true,
      ease: 'sine.inOut',
    });
  });

  return sky;
}

// ΓöÇΓöÇ Ground Cover ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
