// ΓöÇΓöÇ Barn ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Builds a toy barn with walls, peaked roof, and barn door.
 *
 * @param scene - The Three.js scene.
 * @param pos - World-space position for the barn.
 * @param barnColor - Base colour for the barn walls.
 * @param roofColor - Colour for the barn roof.
 * @param doorColor - Colour for the barn door.
 * @returns The barn root group.
 */
export function buildBarn(scene: Scene, pos: Vector3, barnColor: Color, roofColor: Color, doorColor: Color): Group {
  const root = new Group();
  root.name = 'barn_root';
  root.position.copy(pos);
  scene.add(root);

  const wallMat = createGlossyPaintMaterial('barnWallMat', barnColor);
  const roofMat = createWoodMaterial('barnRoofMat', roofColor);
  const doorMat = createWoodMaterial('barnDoorMat', doorColor);

  // Main barn body
  const body = new Mesh(new BoxGeometry(2.5, 1.8, 2.0), wallMat);
  body.name = 'barnBody';
  body.position.y = 0.9;
  body.castShadow = true;
  body.receiveShadow = true;
  root.add(body);

  // Roof ΓÇö two angled planes
  const roofW = 2.8;
  const roofD = 2.2;
  for (let side = -1; side <= 1; side += 2) {
    const roofPanel = new Mesh(new PlaneGeometry(roofW, roofD), roofMat);
    roofPanel.name = `barnRoof_${side}`;
    roofPanel.position.set(0, 2.1 + 0.3, side * 0.55);
    roofPanel.rotation.x = side * -0.5;
    roofPanel.castShadow = true;
    root.add(roofPanel);
  }

  // Roof ridge cap
  const ridge = new Mesh(new CylinderGeometry(0.06, 0.06, roofW, 6), roofMat);
  ridge.name = 'barnRidge';
  ridge.position.set(0, 2.55, 0);
  ridge.rotation.z = Math.PI / 2;
  root.add(ridge);

  // Barn door (front)
  const door = new Mesh(new BoxGeometry(0.8, 1.2, 0.05), doorMat);
  door.name = 'barnDoor';
  door.position.set(0, 0.6, -1.03);
  root.add(door);

  // Door cross-brace
  const brace1 = new Mesh(new BoxGeometry(0.7, 0.06, 0.06), doorMat);
  brace1.name = 'barnBrace1';
  brace1.position.set(0, 0.6, -1.06);
  brace1.rotation.z = 0.6;
  root.add(brace1);

  const brace2 = new Mesh(new BoxGeometry(0.7, 0.06, 0.06), doorMat);
  brace2.name = 'barnBrace2';
  brace2.position.set(0, 0.6, -1.06);
  brace2.rotation.z = -0.6;
  root.add(brace2);

  // White trim around door
  const trimMat = createGlossyPaintMaterial('barnTrimMat', new Color(0.95, 0.93, 0.88));
  const trimTop = new Mesh(new BoxGeometry(0.9, 0.06, 0.06), trimMat);
  trimTop.name = 'barnDoorTrimTop';
  trimTop.position.set(0, 1.23, -1.03);
  root.add(trimTop);

  for (let s = -1; s <= 1; s += 2) {
    const trimSide = new Mesh(new BoxGeometry(0.06, 1.25, 0.06), trimMat);
    trimSide.name = `barnDoorTrimSide_${s}`;
    trimSide.position.set(s * 0.43, 0.6, -1.03);
    root.add(trimSide);
  }

  return root;
}

// ΓöÇΓöÇ Water Trough ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Builds a wooden water trough with translucent water.
 *
 * @param scene - The Three.js scene.
 * @param pos - World-space position for the trough.
 * @returns The trough root group.
 */
export function buildWaterTrough(scene: Scene, pos: Vector3): Group {
  const root = new Group();
  root.name = 'waterTrough_root';
  root.position.copy(pos);
  scene.add(root);

  const woodMat = getOrCreateMaterial('troughWoodMat', () =>
    createWoodMaterial('troughWoodMat', new Color(0.55, 0.38, 0.2)),
  );

  // Trough body ΓÇö open-top box using five box faces
  const trough = new Mesh(new BoxGeometry(1.0, 0.35, 0.5), woodMat);
  trough.name = 'troughBody';
  trough.position.y = 0.3;
  trough.castShadow = true;
  root.add(trough);

  // Legs
  for (let lx = -1; lx <= 1; lx += 2) {
    for (let lz = -1; lz <= 1; lz += 2) {
      const leg = new Mesh(new CylinderGeometry(0.03, 0.04, 0.25, 6), woodMat);
      leg.name = `troughLeg_${lx}_${lz}`;
      leg.position.set(lx * 0.4, 0.12, lz * 0.18);
      root.add(leg);
    }
  }

  // Water surface
  const waterMat = createTranslucentMaterial('troughWaterMat', new Color(0.3, 0.55, 0.7), 0.5);
  const water = new Mesh(new PlaneGeometry(0.85, 0.4), waterMat);
  water.name = 'troughWater';
  water.rotation.x = -Math.PI / 2;
  water.position.y = 0.46;
  root.add(water);

  return root;
}

// ΓöÇΓöÇ Hay Bale ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Builds a cylindrical hay bale.
 *
 * @param scene - The Three.js scene.
 * @param pos - World-space position for the hay bale.
 * @returns The hay bale mesh.
 */
export function buildHayBale(scene: Scene, pos: Vector3): Mesh {
  const hayMat = getOrCreateMaterial('hayBaleMat', () => createFeltMaterial('hayBaleMat', new Color(0.78, 0.68, 0.38)));

  const bale = new Mesh(new CylinderGeometry(0.4, 0.4, 0.5, 12), hayMat);
  bale.name = 'hayBale';
  bale.position.set(pos.x, 0.25, pos.z);
  bale.rotation.z = Math.PI / 2;
  bale.rotation.y = Math.random() * 0.4;
  bale.castShadow = true;
  scene.add(bale);

  // Straw detail rings
  const strawMat = getOrCreateMaterial('strawRingMat', () =>
    createFeltMaterial('strawRingMat', new Color(0.7, 0.6, 0.3)),
  );
  for (let r = -1; r <= 1; r++) {
    const ring = new Mesh(new CylinderGeometry(0.42, 0.42, 0.02, 12), strawMat);
    ring.name = `strawRing_${r}`;
    ring.position.x = r * 0.15;
    bale.add(ring);
  }

  return bale;
}

import {
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  SpotLight,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial } from '@app/utils/materialFactory';
import { triggerSound } from '@app/assets/audio/sceneBridge';
import { BOOKSHELF_CENTER_X, BOOKSHELF_Z } from '../layout';
import gsap from 'gsap';

/** Scale multiplier ΓÇö 3x bigger than original. */
const S = 3;

/** Duration in seconds the lamp shines after being clicked. */
const SHINE_DURATION = 5;

/**
 * Creates a large desk lamp on the top shelf of the bookshelf.
 * When clicked, the lamp tilts forward and shines a spotlight toward
 * the front of the room for several seconds before returning to rest.
 */
export function createDeskLamp(scene: Scene, _keyLight: DirectionalLight): void {
  const redMat = createGlossyPaintMaterial('hub_lampRedMat', new Color(0.85, 0.12, 0.1));
  const metalMat = createPlasticMaterial('hub_lampMetalMat', new Color(0.3, 0.3, 0.32));

  const root = new Group();
  root.name = 'deskLamp_root';
  root.position.set(BOOKSHELF_CENTER_X + 1.1, 2.54, BOOKSHELF_Z - 0.1);
  scene.add(root);

  // Heavy circular base
  const base = new Mesh(new CylinderGeometry(0.07 * S, 0.08 * S, 0.02 * S, 14), redMat);
  base.name = 'lampBase';
  base.castShadow = true;
  root.add(base);

  // Pivot group for the arm + shade + bulb (tilts when shining)
  const armPivot = new Group();
  armPivot.name = 'lampArmPivot';
  armPivot.position.set(0, 0.01 * S, 0);
  root.add(armPivot);

  // Arm ΓÇö single pole angled slightly
  const arm = new Mesh(new CylinderGeometry(0.01 * S, 0.01 * S, 0.22 * S, 8), metalMat);
  arm.name = 'lampArm';
  arm.position.set(0.02 * S, 0.11 * S, 0);
  arm.rotation.z = 0.15;
  arm.castShadow = true;
  armPivot.add(arm);

  // Shade ΓÇö conical, wider at bottom
  const shadeGeo = new CylinderGeometry(0.015 * S, 0.06 * S, 0.06 * S, 12, 1, true);
  const shade = new Mesh(shadeGeo, redMat);
  shade.name = 'lampShade';
  shade.position.set(0.05 * S, 0.23 * S, 0);
  shade.rotation.z = 0.2;
  shade.castShadow = true;
  armPivot.add(shade);

  // Bulb glow inside the shade
  const bulbMat = createPlasticMaterial('hub_lampBulbMat', new Color(1.0, 0.95, 0.8));
  bulbMat.emissive = new Color(0.15, 0.12, 0.06);
  const bulb = new Mesh(new SphereGeometry(0.02 * S, 8, 8), bulbMat);
  bulb.name = 'lampBulb';
  bulb.position.set(0.05 * S, 0.21 * S, 0);
  armPivot.add(bulb);

  // ΓöÇΓöÇ SpotLight ΓÇö hidden until clicked ΓöÇΓöÇ
  const spotLight = new SpotLight(new Color(1.0, 0.95, 0.8), 0, 15, Math.PI / 6, 0.5, 1.5);
  spotLight.name = 'lampSpotLight';
  // Position at the bulb in world space (updated dynamically)
  const bulbWorldPos = new Vector3();
  bulb.getWorldPosition(bulbWorldPos);
  spotLight.position.copy(bulbWorldPos);
  // Target toward front of room (negative Z)
  spotLight.target.position.set(bulbWorldPos.x, 0, -5);
  scene.add(spotLight);
  scene.add(spotLight.target);

  // ΓöÇΓöÇ Click interaction ΓÇö tilt forward and shine ΓöÇΓöÇ
  let shining = false;

  base.userData.onClick = () => {
    if (shining) return;
    shining = true;

    triggerSound('sfx_shared_tap_fallback');

    // Tilt the arm pivot forward (toward camera / -Z) ΓÇö enough to fully expose the bulb
    gsap.to(armPivot.rotation, {
      x: 1.1,
      duration: 0.4,
      ease: 'power2.out',
      onUpdate: () => {
        // Keep spotlight following the bulb position
        bulb.getWorldPosition(bulbWorldPos);
        spotLight.position.copy(bulbWorldPos);
      },
      onComplete: () => {
        // Turn on the spotlight
        bulbMat.emissive = new Color(0.6, 0.5, 0.3);
        spotLight.intensity = 3;

        // Hold for SHINE_DURATION then return
        gsap.delayedCall(SHINE_DURATION, () => {
          // Fade out the light
          gsap.to(spotLight, {
            intensity: 0,
            duration: 0.5,
            ease: 'power2.in',
          });
          gsap.to(bulbMat.emissive, {
            r: 0.15,
            g: 0.12,
            b: 0.06,
            duration: 0.5,
            ease: 'power2.in',
          });

          // Tilt back to rest
          gsap.to(armPivot.rotation, {
            x: 0,
            duration: 0.6,
            ease: 'power2.inOut',
            onComplete: () => {
              shining = false;
            },
          });
        });
      },
    });
  };

  // Make the whole lamp clickable via raycasting (register pick meshes)
  [base, arm, shade, bulb].forEach((mesh) => {
    mesh.userData.onClick = base.userData.onClick;
  });
}

