  // ΓöÇΓöÇ Legs ΓÇö short and chubby, sticking forward ΓöÇΓöÇ
  [-1, 1].forEach((side, i) => {
    const leg = new Mesh(new CylinderGeometry(0.035, 0.04, 0.1, 8), brownMat);
