import {
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  TorusGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createWoodMaterial, createWovenMaterial } from '@app/utils/materialFactory';

/**
 * Creates two woven baskets with thick rims, tapered bodies, woven band details,
 * and small toys peeking out from inside.
 */
export function createBaskets(scene: Scene, _keyLight: DirectionalLight): void {
  const basketConfigs = [
    { pos: new Vector3(-5.0, 0, 3.0), rotY: 0.2 },
    { pos: new Vector3(4.8, 0, -1.5), rotY: -0.4 },
  ];

  const weaveColor = new Color(0.7, 0.55, 0.35);
  const rimColor = new Color(0.6, 0.45, 0.28);
  const darkWeaveColor = new Color(0.55, 0.4, 0.25);

  for (let i = 0; i < basketConfigs.length; i++) {
    const bc = basketConfigs[i];
    const basketMat = createWovenMaterial(`hub_basketMat${i}`, weaveColor);
    const darkMat = createWovenMaterial(`hub_basketDarkMat${i}`, darkWeaveColor);
    const rimMat = createWovenMaterial(`hub_basketRimMat${i}`, rimColor);

    const root = new Group();
    root.name = `basket${i}_root`;
    root.position.copy(bc.pos);
    root.rotation.y = bc.rotY;
    scene.add(root);

    // Main body ΓÇö open-top cylinder, wider at top than bottom
    const body = new Mesh(new CylinderGeometry(0.32, 0.22, 0.44, 16, 1, true), basketMat);
    body.name = `basket${i}_body`;
    body.position.y = 0.22;
    body.castShadow = true;
    root.add(body);

    // Floor inside the basket
    const floor = new Mesh(new CylinderGeometry(0.21, 0.21, 0.02, 12), darkMat);
    floor.name = `basket${i}_floor`;
    floor.position.y = 0.02;
    root.add(floor);

    // Thick rolled rim ΓÇö torus at the top edge
    const rim = new Mesh(new TorusGeometry(0.32, 0.03, 10, 20), rimMat);
    rim.name = `basket${i}_rim`;
    rim.position.y = 0.44;
    rim.rotation.x = Math.PI / 2;
    root.add(rim);

    // Woven band details ΓÇö two horizontal rings around the body
    [0.15, 0.32].forEach((bandY, bi) => {
      const band = new Mesh(new TorusGeometry(0.22 + bandY * 0.3, 0.012, 8, 20), darkMat);
      band.name = `basket${i}_band${bi}`;
      band.position.y = bandY;
      band.rotation.x = Math.PI / 2;
      root.add(band);
    });

    // Base ring ΓÇö slight foot at the bottom
    const baseRing = new Mesh(new TorusGeometry(0.22, 0.018, 8, 16), rimMat);
    baseRing.name = `basket${i}_base`;
    baseRing.position.y = 0.01;
    baseRing.rotation.x = Math.PI / 2;
    root.add(baseRing);

    // Handle arcs ΓÇö two small handles on opposite sides
    [-1, 1].forEach((side, hi) => {
      const handleGeo = new TorusGeometry(0.06, 0.012, 8, 12, Math.PI);
      const handle = new Mesh(handleGeo, rimMat);
      handle.name = `basket${i}_handle${hi}`;
      handle.position.set(side * 0.32, 0.42, 0);
      handle.rotation.y = (side * Math.PI) / 2;
      handle.rotation.z = Math.PI;
      root.add(handle);
    });

    // Peeking toys inside
    // Small colorful ball
    const ball = new Mesh(
      new SphereGeometry(0.055, 8, 8),
      createGlossyPaintMaterial(`hub_basketBallMat${i}`, new Color(0.9, 0.3, 0.3)),
    );
    ball.name = `basket${i}_peekBall`;
    ball.position.set(0.08, 0.46, 0.04);
    root.add(ball);

    // Wooden stick/rod poking up at an angle
    const stick = new Mesh(
      new CylinderGeometry(0.012, 0.012, 0.22, 6),
      createWoodMaterial(`hub_basketStickMat${i}`, new Color(0.55, 0.4, 0.25)),
    );
    stick.name = `basket${i}_peekStick`;
    stick.position.set(-0.1, 0.48, -0.05);
    stick.rotation.z = 0.35;
    stick.rotation.x = -0.15;
    root.add(stick);

    // Small star shape (another toy peeking out)
    const star = new Mesh(
      new SphereGeometry(0.035, 6, 6),
      createGlossyPaintMaterial(`hub_basketStarMat${i}`, new Color(0.95, 0.85, 0.2)),
    );
    star.name = `basket${i}_peekStar`;
    star.position.set(-0.04, 0.47, 0.1);
    root.add(star);
  }
}

import { Color, Group, Mesh, SphereGeometry, CircleGeometry, type DirectionalLight, type Scene } from 'three';
import { createFeltMaterial } from '@app/utils/materialFactory';

/**
 * Creates a soft pink beanbag chair ΓÇö a large, amorphous fabric sack that
 * slumps on the floor with a sunken seat area and a puffy backrest.
 * Built from many overlapping soft ellipsoids for an organic, lumpy look.
 */
export function createBeanbag(scene: Scene, _keyLight: DirectionalLight): void {
  const mat = createFeltMaterial('hub_beanbagMat', new Color(0.92, 0.6, 0.7));
  const shadeMat = createFeltMaterial('hub_beanbagShadeMat', new Color(0.84, 0.52, 0.62));
  const lightMat = createFeltMaterial('hub_beanbagLightMat', new Color(0.96, 0.68, 0.76));

  const root = new Group();
  root.name = 'beanbag_root';
  root.position.set(-4.5, 0, -3.5);
  root.rotation.y = 0.3;
  scene.add(root);

  // Ground shadow disc
  const shadowGeo = new CircleGeometry(0.7, 16);
  const shadowMat = createFeltMaterial('hub_beanbagShadow', new Color(0.15, 0.12, 0.1));
  shadowMat.opacity = 0.25;
  shadowMat.transparent = true;
  const shadow = new Mesh(shadowGeo, shadowMat);
  shadow.name = 'beanbag_shadow';
  shadow.rotation.x = -Math.PI / 2;
  shadow.position.y = 0.005;
  root.add(shadow);

  // Large base mass ΓÇö the heavy bottom that spreads on the floor
  const baseGeo = new SphereGeometry(1, 18, 14);
  baseGeo.scale(0.65, 0.28, 0.6);
  const base = new Mesh(baseGeo, mat);
  base.name = 'beanbag_base';
  base.position.y = 0.18;
  base.castShadow = true;
  base.receiveShadow = true;
  root.add(base);

  // Lower skirt ΓÇö wider, flatter ring that sits at floor level (the spread)
  const skirtGeo = new SphereGeometry(1, 14, 8, 0, Math.PI * 2, Math.PI * 0.3, Math.PI * 0.4);
  skirtGeo.scale(0.72, 0.18, 0.68);
  const skirt = new Mesh(skirtGeo, shadeMat);
  skirt.name = 'beanbag_skirt';
  skirt.position.y = 0.06;
  skirt.castShadow = true;
  root.add(skirt);

  // Seat depression ΓÇö slightly darker area where you sit, sinks in
  const seatGeo = new SphereGeometry(1, 12, 8);
  seatGeo.scale(0.38, 0.08, 0.34);
  const seat = new Mesh(seatGeo, shadeMat);
  seat.name = 'beanbag_seat';
  seat.position.set(0.04, 0.36, 0.08);
  root.add(seat);

  // Backrest ΓÇö the tall puff behind where you lean
  const backGeo = new SphereGeometry(1, 14, 12);
  backGeo.scale(0.44, 0.48, 0.32);
  const back = new Mesh(backGeo, mat);
  back.name = 'beanbag_back';
  back.position.set(0, 0.32, -0.2);
  back.rotation.x = 0.2;
  back.castShadow = true;
  root.add(back);

  // Backrest top ΓÇö lighter highlight on top of the backrest
  const backTopGeo = new SphereGeometry(1, 10, 8);
  backTopGeo.scale(0.32, 0.18, 0.22);
  const backTop = new Mesh(backTopGeo, lightMat);
  backTop.name = 'beanbag_backTop';
  backTop.position.set(0, 0.62, -0.22);
  backTop.rotation.x = 0.15;
  root.add(backTop);

  // Left arm bulge ΓÇö fabric bunching on the side
  const armLGeo = new SphereGeometry(1, 10, 8);
  armLGeo.scale(0.2, 0.28, 0.36);
  const armL = new Mesh(armLGeo, mat);
  armL.name = 'beanbag_armL';
  armL.position.set(-0.46, 0.22, -0.02);
  armL.rotation.z = 0.2;
  armL.castShadow = true;
  root.add(armL);

  // Right arm bulge
  const armRGeo = new SphereGeometry(1, 10, 8);
  armRGeo.scale(0.18, 0.26, 0.34);
  const armR = new Mesh(armRGeo, mat);
  armR.name = 'beanbag_armR';
  armR.position.set(0.44, 0.2, 0);
  armR.rotation.z = -0.18;
  armR.castShadow = true;
  root.add(armR);

  // Front sag ΓÇö the low front edge that droops forward
  const frontGeo = new SphereGeometry(1, 10, 8);
  frontGeo.scale(0.4, 0.15, 0.18);
  const front = new Mesh(frontGeo, mat);
  front.name = 'beanbag_front';
  front.position.set(0, 0.14, 0.45);
  front.rotation.x = -0.25;
  front.castShadow = true;
  root.add(front);

  // Wrinkle lumps ΓÇö small irregularities across the surface for organic feel
  const wrinklePositions = [
    { pos: [0.18, 0.38, 0.15], s: [0.1, 0.04, 0.08] },
    { pos: [-0.2, 0.36, 0.12], s: [0.09, 0.035, 0.07] },
    { pos: [0.3, 0.26, -0.08], s: [0.07, 0.04, 0.1] },
    { pos: [-0.32, 0.28, 0.1], s: [0.08, 0.035, 0.06] },
    { pos: [0.1, 0.42, -0.32], s: [0.12, 0.04, 0.08] },
    { pos: [-0.14, 0.44, -0.28], s: [0.1, 0.035, 0.09] },
  ];
  wrinklePositions.forEach((w, wi) => {
    const geo = new SphereGeometry(1, 6, 4);
    geo.scale(w.s[0], w.s[1], w.s[2]);
    const wrinkle = new Mesh(geo, wi % 2 === 0 ? lightMat : shadeMat);
    wrinkle.name = `beanbag_wrinkle${wi}`;
    wrinkle.position.set(w.pos[0], w.pos[1], w.pos[2]);
    root.add(wrinkle);
  });

  // Seam lines ΓÇö fabric panel edges visible on the surface
  const seamPositions = [
    { pos: [0, 0.5, -0.16], rot: [0, 0.5, 0], sx: 0.42 },
    { pos: [0, 0.48, -0.14], rot: [0, -0.5, 0], sx: 0.38 },
    { pos: [0.2, 0.34, 0.1], rot: [0, 0.8, Math.PI / 2], sx: 0.3 },
    { pos: [-0.2, 0.32, 0.08], rot: [0, -0.7, Math.PI / 2], sx: 0.28 },
  ];
  seamPositions.forEach((sp, si) => {
    const seamGeo = new SphereGeometry(1, 6, 4);
    seamGeo.scale(sp.sx, 0.006, 0.012);
    const seam = new Mesh(seamGeo, shadeMat);
    seam.name = `beanbag_seam${si}`;
    seam.position.set(sp.pos[0], sp.pos[1], sp.pos[2]);
    seam.rotation.set(sp.rot[0], sp.rot[1], sp.rot[2]);
    root.add(seam);
  });
}

import { BoxGeometry, Color, CylinderGeometry, Group, Mesh, type DirectionalLight, type Scene } from 'three';
import { createWoodMaterial, createPlasticMaterial } from '@app/utils/materialFactory';

/** Creates a chalkboard on a wooden easel in the front-right corner of the room. */
export function createChalkboardEasel(scene: Scene, _keyLight: DirectionalLight): void {
  const root = new Group();
  root.name = 'chalkboardEasel_root';
  root.position.set(-5.0, 0, -5.0);
  root.rotation.y = Math.PI / 4 + 0.2; // angled into the corner
  scene.add(root);

  const woodMat = createWoodMaterial('hub_easelWoodMat', new Color(0.6, 0.42, 0.22));
  const boardMat = createPlasticMaterial('hub_chalkboardMat', new Color(0.12, 0.22, 0.15));
  const frameMat = createWoodMaterial('hub_chalkFrameMat', new Color(0.45, 0.3, 0.15));
  const trayMat = createWoodMaterial('hub_chalkTrayMat', new Color(0.5, 0.35, 0.18));
  const chalkWhite = createPlasticMaterial('hub_chalkWhiteMat', new Color(0.92, 0.9, 0.86));
  const chalkYellow = createPlasticMaterial('hub_chalkYellowMat', new Color(0.95, 0.88, 0.3));
  const chalkPink = createPlasticMaterial('hub_chalkPinkMat', new Color(0.92, 0.5, 0.6));

  // ΓöÇΓöÇ Easel legs ΓöÇΓöÇ
  // Front two legs (A-frame)
  [-1, 1].forEach((side) => {
    const leg = new Mesh(new CylinderGeometry(0.025, 0.03, 1.8, 8), woodMat);
    leg.name = `easelFrontLeg${side}`;
    leg.position.set(0, 0.9, side * 0.35);
    leg.rotation.z = 0.08; // slight forward lean
    leg.castShadow = true;
    root.add(leg);
  });

  // Back support leg
  const backLeg = new Mesh(new CylinderGeometry(0.02, 0.025, 1.7, 8), woodMat);
  backLeg.name = 'easelBackLeg';
  backLeg.position.set(-0.5, 0.85, 0);
  backLeg.rotation.z = -0.35;
  backLeg.castShadow = true;
  root.add(backLeg);

  // Cross brace between front legs
  const brace = new Mesh(new CylinderGeometry(0.015, 0.015, 0.65, 6), woodMat);
  brace.name = 'easelBrace';
  brace.position.set(0, 0.45, 0);
  brace.rotation.x = Math.PI / 2;
  root.add(brace);

  // ΓöÇΓöÇ Chalkboard ΓöÇΓöÇ
  const boardGroup = new Group();
  boardGroup.name = 'chalkboard_group';
  boardGroup.position.set(0.04, 1.2, 0);
  boardGroup.rotation.z = 0.08; // leaning back slightly on easel
  root.add(boardGroup);

  // Board surface ΓÇö dark green
  const board = new Mesh(new BoxGeometry(0.04, 0.7, 0.9), boardMat);
  board.name = 'chalkboard_surface';
  board.castShadow = true;
  boardGroup.add(board);

  // Wooden frame
  // Top
  const frameTop = new Mesh(new BoxGeometry(0.05, 0.04, 0.94), frameMat);
  frameTop.name = 'chalkboard_frameTop';
  frameTop.position.y = 0.37;
  boardGroup.add(frameTop);

  // Bottom
  const frameBottom = new Mesh(new BoxGeometry(0.05, 0.04, 0.94), frameMat);
  frameBottom.name = 'chalkboard_frameBottom';
  frameBottom.position.y = -0.37;
  boardGroup.add(frameBottom);

  // Left
  const frameLeft = new Mesh(new BoxGeometry(0.05, 0.74, 0.04), frameMat);
  frameLeft.name = 'chalkboard_frameLeft';
  frameLeft.position.z = -0.47;
  boardGroup.add(frameLeft);

  // Right
  const frameRight = new Mesh(new BoxGeometry(0.05, 0.74, 0.04), frameMat);
  frameRight.name = 'chalkboard_frameRight';
  frameRight.position.z = 0.47;
  boardGroup.add(frameRight);

  // Chalk tray at bottom
  const tray = new Mesh(new BoxGeometry(0.08, 0.03, 0.7), trayMat);
  tray.name = 'chalkboard_tray';
  tray.position.set(0.04, -0.36, 0);
  boardGroup.add(tray);

  // Chalk pieces in tray
  const chalkPieces = [
    { mat: chalkWhite, z: -0.1 },
    { mat: chalkYellow, z: 0.05 },
    { mat: chalkPink, z: 0.18 },
  ];
  chalkPieces.forEach(({ mat, z }) => {
    const chalk = new Mesh(new CylinderGeometry(0.012, 0.012, 0.08, 6), mat);
    chalk.name = `chalk_${z}`;
    chalk.position.set(0.04, -0.33, z);
    chalk.rotation.x = Math.PI / 2;
    chalk.rotation.z = Math.random() * 0.3 - 0.15;
    boardGroup.add(chalk);
  });

  // Simple chalk drawings on the board ΓÇö a few lines to suggest doodles
  // Smiley face circle (simplified as a thin box ring)
  const smileMat = chalkWhite;
  const smileyRing = new Mesh(new BoxGeometry(0.006, 0.2, 0.2), smileMat);
  smileyRing.name = 'chalk_smileyRing';
  smileyRing.position.set(0.025, 0.08, -0.12);
  boardGroup.add(smileyRing);

  // Eyes (dots)
  [-1, 1].forEach((side) => {
    const eye = new Mesh(new BoxGeometry(0.006, 0.025, 0.025), smileMat);
    eye.name = `chalk_smileyEye${side}`;
    eye.position.set(0.025, 0.12, -0.12 + side * 0.05);
    boardGroup.add(eye);
  });

  // Smile (line)
  const smile = new Mesh(new BoxGeometry(0.006, 0.015, 0.1), smileMat);
  smile.name = 'chalk_smile';
  smile.position.set(0.025, 0.02, -0.12);
  boardGroup.add(smile);

  // Yellow star doodle (upper right)
  const starLine1 = new Mesh(new BoxGeometry(0.006, 0.12, 0.01), chalkYellow);
  starLine1.name = 'chalk_starLine1';
  starLine1.position.set(0.025, 0.15, 0.2);
  boardGroup.add(starLine1);

  const starLine2 = new Mesh(new BoxGeometry(0.006, 0.01, 0.12), chalkYellow);
  starLine2.name = 'chalk_starLine2';
  starLine2.position.set(0.025, 0.15, 0.2);
  boardGroup.add(starLine2);
}

import { Color, ConeGeometry, CylinderGeometry, Group, Mesh, SphereGeometry, TorusGeometry, type Scene } from 'three';
import {
  createFeltMaterial,
  createGlossyPaintMaterial,
  createPlasticMaterial,
  createWoodMaterial,
} from '@app/utils/materialFactory';
import { CEILING_Y } from '../layout';
import gsap from 'gsap';

/**
 * Creates a hanging mobile attached to the ceiling by a string.
 * Features a wooden cross-bar with a crescent moon, stars, a cloud,
 * and a heart dangling on strings. The entire assembly rotates slowly.
 */
export function createHangingMobile(scene: Scene): void {
  // ΓöÇΓöÇ Root pivot ΓÇö rotates the entire mobile ΓöÇΓöÇ
  const pivot = new Group();
  pivot.name = 'mobilePivot';
  pivot.position.set(3.0, CEILING_Y, 3.5);
  scene.add(pivot);

  const stringMat = createFeltMaterial('hub_mobileStringMat', new Color(0.7, 0.6, 0.5));
  const barMat = createWoodMaterial('hub_mobileBarMat', new Color(0.65, 0.5, 0.35));

  // ΓöÇΓöÇ Ceiling attachment string ΓöÇΓöÇ
  const attachLen = 0.6;
  const attachString = new Mesh(new CylinderGeometry(0.006, 0.006, attachLen, 4), stringMat);
  attachString.name = 'mobileAttachString';
  attachString.position.y = -attachLen / 2;
  pivot.add(attachString);

  // ΓöÇΓöÇ Cross-bar assembly ΓöÇΓöÇ
  const crossGroup = new Group();
  crossGroup.name = 'mobileCrossGroup';
  crossGroup.position.y = -attachLen;
  pivot.add(crossGroup);

  // Main bar
  const mainBar = new Mesh(new CylinderGeometry(0.02, 0.02, 1.4, 6), barMat);
  mainBar.name = 'mobileMainBar';
  mainBar.rotation.z = Math.PI / 2;
  crossGroup.add(mainBar);

  // Perpendicular bar
  const crossBar = new Mesh(new CylinderGeometry(0.02, 0.02, 1.0, 6), barMat);
  crossBar.name = 'mobileCrossBar';
  crossBar.rotation.x = Math.PI / 2;
  crossGroup.add(crossBar);

  // Centre knot
  const knot = new Mesh(new SphereGeometry(0.035, 8, 8), barMat);
  knot.name = 'mobileKnot';
  crossGroup.add(knot);

  // ΓöÇΓöÇ Hanging ornaments ΓöÇΓöÇ
  const hangPoints = [
    { x: -0.65, z: 0, len: 0.7 }, // left end of main bar
    { x: 0.65, z: 0, len: 0.55 }, // right end of main bar
    { x: 0, z: -0.45, len: 0.85 }, // front of cross bar
    { x: 0, z: 0.45, len: 0.6 }, // back of cross bar
    { x: -0.3, z: -0.2, len: 0.95 }, // diagonal
  ];

  // Moon ΓÇö crescent shape
  const moonMat = createPlasticMaterial('hub_mobileMoonMat', new Color(1.0, 0.95, 0.7));
  moonMat.emissive = new Color(0.1, 0.09, 0.05);
  addHangingString(crossGroup, hangPoints[0], stringMat);
  const moonGroup = new Group();
  moonGroup.name = 'mobileMoonGroup';
  moonGroup.position.set(hangPoints[0].x, -hangPoints[0].len, hangPoints[0].z);
  crossGroup.add(moonGroup);

  const moonOuter = new Mesh(new TorusGeometry(0.1, 0.04, 8, 16, Math.PI * 1.3), moonMat);
  moonOuter.name = 'mobileMoon';
  moonOuter.rotation.z = -0.3;
  moonGroup.add(moonOuter);

  // Stars ΓÇö 3D star shapes (cones facing each other)
  const starColors = [new Color(1.0, 0.9, 0.3), new Color(1.0, 0.6, 0.75), new Color(0.5, 0.8, 1.0)];

  for (let si = 0; si < 3; si++) {
    const hp = hangPoints[si + 1];
    addHangingString(crossGroup, hp, stringMat);

    const starMat = createGlossyPaintMaterial(`hub_mobileStarMat${si}`, starColors[si]);
    starMat.emissive = starColors[si].clone().multiplyScalar(0.08);
    const starGroup = new Group();
    starGroup.name = `mobileStar${si}`;
    starGroup.position.set(hp.x, -hp.len, hp.z);
    starGroup.rotation.z = si * 0.7 + 0.2;
    crossGroup.add(starGroup);

    // Star body ΓÇö two cones tip-to-tip
    const coneH = 0.06;
    const coneR = 0.05;
    const topCone = new Mesh(new ConeGeometry(coneR, coneH, 5), starMat);
    topCone.name = `mobileStarTop${si}`;
    topCone.position.y = coneH * 0.15;
    starGroup.add(topCone);

    const botCone = new Mesh(new ConeGeometry(coneR, coneH, 5), starMat);
    botCone.name = `mobileStarBot${si}`;
    botCone.position.y = -coneH * 0.15;
    botCone.rotation.z = Math.PI;
    botCone.rotation.y = Math.PI / 5; // offset points
    starGroup.add(botCone);
  }

  // Cloud ΓÇö cluster of spheres
  const cloudMat = createPlasticMaterial('hub_mobileCloudMat', new Color(0.95, 0.95, 0.98));
  cloudMat.emissive = new Color(0.05, 0.05, 0.06);
  const hp4 = hangPoints[4];
  addHangingString(crossGroup, hp4, stringMat);

  const cloudGroup = new Group();
  cloudGroup.name = 'mobileCloud';
  cloudGroup.position.set(hp4.x, -hp4.len, hp4.z);
  crossGroup.add(cloudGroup);

  const cloudPuffs = [
    { x: 0, y: 0, z: 0, r: 0.05 },
    { x: -0.04, y: -0.01, z: 0, r: 0.04 },
    { x: 0.04, y: -0.01, z: 0, r: 0.04 },
    { x: -0.02, y: 0.03, z: 0, r: 0.035 },
    { x: 0.02, y: 0.03, z: 0, r: 0.035 },
  ];
  cloudPuffs.forEach((cp, ci) => {
    const puff = new Mesh(new SphereGeometry(cp.r, 8, 8), cloudMat);
    puff.name = `mobileCloudPuff${ci}`;
    puff.position.set(cp.x, cp.y, cp.z);
    cloudGroup.add(puff);
  });

  // ΓöÇΓöÇ Slow rotation ΓöÇΓöÇ
  gsap.to(pivot.rotation, {
    y: Math.PI * 2,
    duration: 25,
    repeat: -1,
    ease: 'none',
  });

  // ΓöÇΓöÇ Gentle sway ΓöÇΓöÇ
  gsap.to(crossGroup.rotation, {
    x: 0.04,
    duration: 4,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut',
  });
  gsap.to(crossGroup.rotation, {
    z: 0.03,
    duration: 5.5,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut',
  });
}

/** Adds a thin string from the cross-bar to a hang point. */
function addHangingString(
  parent: Group,
  hp: { x: number; z: number; len: number },
  mat: ReturnType<typeof createFeltMaterial>,
): void {
  const str = new Mesh(new CylinderGeometry(0.005, 0.005, hp.len, 4), mat);
  str.name = 'mobileHangString';
  str.position.set(hp.x, -hp.len / 2, hp.z);
  parent.add(str);
}

import type { DirectionalLight, Scene } from 'three';
import { createPennantBanner } from './pennantBanner';
import { createPillowsAndBaskets } from './pillowsAndBaskets';
import { createPullToy } from './pullToy';
import { createSpinningTop } from './spinningTop';
import { createHangingMobile } from './hangingMobile';
import { createLamp } from './lamp';
import { createRaggedyDolls } from './raggedyDolls';
import { createToyDrum } from './toyDrum';
import { createBackpack } from './backpack';
import { createChalkboardEasel } from './chalkboardEasel';

/** Creates all decorative props in the hub scene. */
export function createDecor(scene: Scene, keyLight: DirectionalLight): void {
  createPennantBanner(scene);
  createPillowsAndBaskets(scene, keyLight);
  createPullToy(scene, keyLight);
  createSpinningTop(scene, keyLight);
  createHangingMobile(scene);
  createLamp(scene, keyLight);
  createRaggedyDolls(scene, keyLight);
  createToyDrum(scene, keyLight);
  createBackpack(scene, keyLight);
  createChalkboardEasel(scene, keyLight);
}

import {
  CircleGeometry,
  Color,
  CylinderGeometry,
  Mesh,
  PointLight,
  SphereGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial } from '@app/utils/materialFactory';

/** Creates a mushroom-shaped night-light lamp with spots and a warm point-light glow. */
export function createLamp(scene: Scene, _keyLight: DirectionalLight): void {
  const stem = new Mesh(
    new CylinderGeometry(0.04, 0.06, 0.2, 10),
    createPlasticMaterial('hub_mushroomStemMat', new Color(0.95, 0.92, 0.85)),
  );
  stem.name = 'mushroomStem';
  stem.position.set(-4.2, 0.1, 0.5);
  stem.castShadow = true;
  scene.add(stem);

  const capMat = createGlossyPaintMaterial('hub_mushroomCapMat', new Color(0.9, 0.35, 0.35));
  capMat.emissive = new Color(0.2, 0.05, 0.05);
  const cap = new Mesh(new SphereGeometry(0.5, 12, 12), capMat);
  cap.name = 'mushroomCap';
  cap.scale.set(0.35, 0.2, 0.35);
  cap.position.y = 0.14;
  stem.add(cap);

  // Spots
  const spotMat = createPlasticMaterial('hub_mushroomSpotMat', new Color(0.98, 0.97, 0.95));
  const spotPositions = [
    new Vector3(0.05, 0.08, 0.12),
    new Vector3(-0.08, 0.06, 0.1),
    new Vector3(0.1, 0.04, -0.05),
    new Vector3(-0.04, 0.09, -0.08),
  ];
  for (let si = 0; si < spotPositions.length; si++) {
    const spot = new Mesh(new CircleGeometry(0.03, 8), spotMat);
    spot.name = `mushroomSpot${si}`;
    spot.position.copy(spotPositions[si]);
    cap.add(spot);
  }

  // Warm glow
  const glow = new PointLight(new Color(1.0, 0.85, 0.65), 0.3, 3.5);
  glow.name = 'mushroomGlow';
  glow.position.set(-4.2, 0.35, 0.5);
  scene.add(glow);
}

import { CircleGeometry, Color, CylinderGeometry, Mesh, type Scene } from 'three';
import { createFeltMaterial } from '@app/utils/materialFactory';
import {
  wallY,
  BACK_WALL_FACE_Z,
  PENNANT_STRING_T,
  PENNANT_FLAG_T,
  PENNANT_STRING_LENGTH,
  PENNANT_COUNT,
  PENNANT_FLAG_RADIUS,
  PENNANT_SPACING,
  PENNANT_START_X,
  PENNANT_DROOP,
} from '../layout';

/** Creates a colourful pennant banner string with triangular felt flags along the back wall. */
export function createPennantBanner(scene: Scene): void {
  const pennantColors = [
    new Color(0.92, 0.4, 0.35),
    new Color(0.9, 0.75, 0.25),
    new Color(0.5, 0.82, 0.6),
    new Color(0.45, 0.7, 0.92),
    new Color(0.72, 0.58, 0.85),
    new Color(1.0, 0.78, 0.6),
    new Color(0.92, 0.4, 0.35),
    new Color(0.9, 0.75, 0.25),
    new Color(0.5, 0.82, 0.6),
    new Color(0.45, 0.7, 0.92),
  ];

  const bannerZ = BACK_WALL_FACE_Z + 0.01;
  const flagZ = BACK_WALL_FACE_Z + 0.02;

  const stringMat = createFeltMaterial('hub_bannerStringMat', new Color(0.6, 0.5, 0.4));
  const string = new Mesh(new CylinderGeometry(0.01, 0.01, PENNANT_STRING_LENGTH, 4), stringMat);
  string.name = 'bannerString';
  string.position.set(0.5, wallY(PENNANT_STRING_T), bannerZ);
  string.rotation.z = Math.PI / 2;
  string.rotation.x = 0.03;
  scene.add(string);

  for (let i = 0; i < PENNANT_COUNT; i++) {
    const flag = new Mesh(
      new CircleGeometry(PENNANT_FLAG_RADIUS, 3),
      createFeltMaterial(`hub_pennantMat${i}`, pennantColors[i]),
    );
    flag.name = `pennant${i}`;
    const xPos = PENNANT_START_X + i * PENNANT_SPACING;
    const droop = Math.sin((i / (PENNANT_COUNT - 1)) * Math.PI) * PENNANT_DROOP;
    flag.position.set(xPos, wallY(PENNANT_FLAG_T) - droop, flagZ);
    flag.rotation.z = Math.PI;
    scene.add(flag);
  }
}

import { Color, Group, Mesh, SphereGeometry, BoxGeometry, Vector3, type DirectionalLight, type Scene } from 'three';
import { createFeltMaterial } from '@app/utils/materialFactory';

/**
 * Creates two soft felt floor pillows with a puffy, cushion-like shape.
 * Each pillow has a flat base, rounded puffy top, pinched corners, and a center button dimple.
 */
export function createPillows(scene: Scene, _keyLight: DirectionalLight): void {
  const pillowConfigs = [
    { pos: new Vector3(4.2, 0, 3.5), color: new Color(0.6, 0.75, 0.9), rotY: -0.5, size: 0.85 },
    { pos: new Vector3(-4.5, 0, 4.0), color: new Color(0.85, 0.85, 0.5), rotY: 0.8, size: 0.7 },
  ];

  for (let i = 0; i < pillowConfigs.length; i++) {
    const cfg = pillowConfigs[i];
    const s = cfg.size;
    const mat = createFeltMaterial(`hub_pillowMat${i}`, cfg.color);
    const darkerMat = createFeltMaterial(`hub_pillowDarkMat${i}`, cfg.color.clone().multiplyScalar(0.8));

    const root = new Group();
    root.name = `pillow${i}_root`;
    root.position.copy(cfg.pos);
    root.rotation.y = cfg.rotY;
    scene.add(root);

    // Main body ΓÇö a wide, flat rounded box shape (squashed sphere for softness)
    const bodyGeo = new SphereGeometry(1, 12, 8);
    bodyGeo.scale(0.42 * s, 0.1 * s, 0.38 * s);
    const body = new Mesh(bodyGeo, mat);
    body.name = `pillow${i}_body`;
    body.position.y = 0.1 * s;
    body.castShadow = true;
    body.receiveShadow = true;
    root.add(body);

    // Top puff ΓÇö slightly smaller, gives a rounded cushion top
    const topGeo = new SphereGeometry(1, 10, 6);
    topGeo.scale(0.36 * s, 0.07 * s, 0.32 * s);
    const top = new Mesh(topGeo, mat);
    top.name = `pillow${i}_top`;
    top.position.y = 0.15 * s;
    root.add(top);

    // Bottom flat ΓÇö slight base that sits on the floor
    const bottomGeo = new BoxGeometry(0.7 * s, 0.03 * s, 0.6 * s);
    const bottom = new Mesh(bottomGeo, darkerMat);
    bottom.name = `pillow${i}_bottom`;
    bottom.position.y = 0.015 * s;
    bottom.receiveShadow = true;
    root.add(bottom);

    // Four puffy corners ΓÇö pillow corners that poke out
    const cornerOffsets = [
      new Vector3(-0.34, 0.08, -0.28),
      new Vector3(0.34, 0.08, -0.28),
      new Vector3(-0.34, 0.08, 0.28),
      new Vector3(0.34, 0.08, 0.28),
    ];
    cornerOffsets.forEach((off, ci) => {
      const cornerGeo = new SphereGeometry(1, 6, 6);
      cornerGeo.scale(0.08 * s, 0.06 * s, 0.08 * s);
      const corner = new Mesh(cornerGeo, mat);
      corner.name = `pillow${i}_corner${ci}`;
      corner.position.set(off.x * s, off.y * s, off.z * s);
      root.add(corner);
    });

    // Center button dimple ΓÇö small darker disc on top
    const buttonGeo = new SphereGeometry(1, 8, 6);
    buttonGeo.scale(0.04 * s, 0.015 * s, 0.04 * s);
    const button = new Mesh(buttonGeo, darkerMat);
    button.name = `pillow${i}_button`;
    button.position.y = 0.18 * s;
    root.add(button);

    // Edge piping ΓÇö four subtle ridges along the pillow edges
    const pipingPositions = [
      { pos: new Vector3(0, 0.1, 0.35), scaleX: 0.38, rotY: 0 },
      { pos: new Vector3(0, 0.1, -0.35), scaleX: 0.38, rotY: 0 },
      { pos: new Vector3(0.38, 0.1, 0), scaleX: 0.32, rotY: Math.PI / 2 },
      { pos: new Vector3(-0.38, 0.1, 0), scaleX: 0.32, rotY: Math.PI / 2 },
    ];
    pipingPositions.forEach((p, pi) => {
      const pipeGeo = new SphereGeometry(1, 6, 4);
      pipeGeo.scale(p.scaleX * s, 0.025 * s, 0.02 * s);
      const pipe = new Mesh(pipeGeo, darkerMat);
      pipe.name = `pillow${i}_piping${pi}`;
      pipe.position.set(p.pos.x * s, p.pos.y * s, p.pos.z * s);
      pipe.rotation.y = p.rotY;
      root.add(pipe);
    });
  }
}

