  createFeltMaterial,
  createGlossyPaintMaterial,
  createPlasticMaterial,
  createWoodMaterial,
} from '@app/utils/materialFactory';

/** Creates a wooden pull-along dog toy on wheels with a pull string. */
export function createPullToy(scene: Scene, _keyLight: DirectionalLight): void {
  const root = new Group();
  root.name = 'pullToy_root';
  root.position.set(-1.2, 0.06, -0.5); // to the left of the stacking rings
  root.rotation.y = 0.5;
  scene.add(root);

  const bodyMat = createGlossyPaintMaterial('hub_pullToyMat', new Color(0.9, 0.55, 0.2));

  // Wooden platform base
  const platform = new Mesh(
    new BoxGeometry(0.5, 0.04, 0.22),
    createWoodMaterial('hub_pullPlatformMat', new Color(0.55, 0.4, 0.25)),
  );
  platform.name = 'pullPlatform';
  platform.position.y = 0.08;
  platform.castShadow = true;
  root.add(platform);

  // Wheels ΓÇö red, on axles
  const wheelMat = createGlossyPaintMaterial('hub_pullWheelMat', new Color(0.85, 0.2, 0.2));
  const wPos = [
    new Vector3(-0.18, -0.03, 0.13),
    new Vector3(0.18, -0.03, 0.13),
    new Vector3(-0.18, -0.03, -0.13),
    new Vector3(0.18, -0.03, -0.13),
  ];
  for (let wi = 0; wi < wPos.length; wi++) {
    const wheel = new Mesh(new CylinderGeometry(0.04, 0.04, 0.03, 10), wheelMat);
    wheel.name = `pullWheel${wi}`;
    wheel.position.copy(wPos[wi]);
    wheel.rotation.x = Math.PI / 2;
    platform.add(wheel);
  }

  // Dog body ΓÇö use geometry scaling so children aren't compressed
  const dogBodyGeo = new SphereGeometry(1, 10, 8);
  dogBodyGeo.scale(0.13, 0.1, 0.08);
  const dogBody = new Mesh(dogBodyGeo, bodyMat);
  dogBody.name = 'pullDogBody';
  dogBody.position.set(0, 0.14, 0);
  dogBody.castShadow = true;
  platform.add(dogBody);

  // Dog head ΓÇö round, sits in front of the body
  const dogHead = new Mesh(new SphereGeometry(0.065, 10, 10), bodyMat);
  dogHead.name = 'pullDogHead';
  dogHead.position.set(0.14, 0.04, 0);
  dogHead.castShadow = true;
  dogBody.add(dogHead);

  // Snout ΓÇö lighter coloured bump
  const snoutGeo = new SphereGeometry(1, 8, 8);
  snoutGeo.scale(0.035, 0.025, 0.03);
  const snout = new Mesh(snoutGeo, createPlasticMaterial('hub_pullSnoutMat', new Color(0.95, 0.8, 0.6)));
  snout.name = 'pullDogSnout';
  snout.position.set(0.055, -0.01, 0);
  dogHead.add(snout);

  // Nose ΓÇö black dot at tip of snout
  const nose = new Mesh(
    new SphereGeometry(0.012, 6, 6),
    createGlossyPaintMaterial('hub_pullNoseMat', new Color(0.1, 0.1, 0.1)),
  );
  nose.name = 'pullDogNose';
  nose.position.set(0.03, 0.008, 0);
  snout.add(nose);

  // Eyes ΓÇö small black beads
  const eyeMat = createGlossyPaintMaterial('hub_pullEyeMat', new Color(0.08, 0.08, 0.08));
  [-1, 1].forEach((side) => {
    const eye = new Mesh(new SphereGeometry(0.012, 6, 6), eyeMat);
    eye.name = `pullDogEye${side}`;
    eye.position.set(0.04, 0.025, side * 0.035);
    dogHead.add(eye);
  });

  // Blush spots
  const blushMat = createPlasticMaterial('hub_pullBlushMat', new Color(1.0, 0.6, 0.55));
  [-1, 1].forEach((side) => {
    const blush = new Mesh(new CircleGeometry(0.012, 8), blushMat);
    blush.name = `pullDogBlush${side}`;
    blush.position.set(0.02, -0.01, side * 0.05);
    blush.rotation.y = side * 0.4;
    dogHead.add(blush);
  });

  // Floppy ears
  [-1, 1].forEach((side) => {
    const earGeo = new SphereGeometry(1, 8, 6);
    earGeo.scale(0.02, 0.04, 0.035);
    const ear = new Mesh(earGeo, createFeltMaterial(`hub_pullEarMat${side}`, new Color(0.75, 0.45, 0.15)));
    ear.name = `pullDogEar${side}`;
    ear.position.set(-0.01, 0.02, side * 0.055);
    ear.rotation.x = side * 0.4;
    dogHead.add(ear);
  });

  // Legs ΓÇö four short cylinders
  const legMat = createGlossyPaintMaterial('hub_pullLegMat', new Color(0.85, 0.5, 0.18));
  const legPositions = [
    new Vector3(0.06, -0.08, 0.05),
    new Vector3(0.06, -0.08, -0.05),
    new Vector3(-0.06, -0.08, 0.05),
    new Vector3(-0.06, -0.08, -0.05),
  ];
  legPositions.forEach((lp, li) => {
    const leg = new Mesh(new CylinderGeometry(0.015, 0.015, 0.06, 6), legMat);
    leg.name = `pullDogLeg${li}`;
    leg.position.copy(lp);
    dogBody.add(leg);
  });

  // Tail ΓÇö short, upright, wagging
  const tail = new Mesh(new CylinderGeometry(0.01, 0.01, 0.06, 4), bodyMat);
  tail.name = 'pullDogTail';
  tail.position.set(-0.12, 0.06, 0);
  tail.rotation.z = 0.5;
  dogBody.add(tail);

  // Pull string ΓÇö brown felt cord with a bead at the end
  const string = new Mesh(
    new CylinderGeometry(0.004, 0.004, 0.35, 4),
    createFeltMaterial('hub_pullStringMat', new Color(0.5, 0.35, 0.2)),
  );
  string.name = 'pullString';
  string.position.set(0.42, 0.02, 0);
  string.rotation.z = Math.PI / 2;
  platform.add(string);

  // String bead
  const bead = new Mesh(
    new SphereGeometry(0.018, 6, 6),
    createGlossyPaintMaterial('hub_pullBeadMat', new Color(0.85, 0.2, 0.2)),
  );
  bead.name = 'pullStringBead';
  bead.position.set(0.6, 0.02, 0);
  platform.add(bead);
}

import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createFeltMaterial, createPlasticMaterial } from '@app/utils/materialFactory';

/**
 * Creates Raggedy Ann and Raggedy Andy dolls sitting on top of
 * the green (creative) dresser toybox, backs near the wall.
 */
export function createRaggedyDolls(scene: Scene, _keyLight: DirectionalLight): void {
  // Dresser front edge Γëê Z 7.72. Sit them on the front edge so legs drape over.
  // After hovering fix, dresser top Γëê Y 1.02.
  const topY = 1.02;
  const frontEdgeZ = 7.78;

  createRaggedyAnn(scene, -2.7, topY, frontEdgeZ);
  createRaggedyAndy(scene, -3.6, topY, frontEdgeZ);
}

/** Raggedy Ann ΓÇö soft red yarn hair, blue dress with white apron, gentle face. */
function createRaggedyAnn(scene: Scene, x: number, y: number, z: number): void {
  const root = new Group();
  root.name = 'raggedyAnn_root';
  root.position.set(x, y, z);
  root.rotation.y = Math.PI + 0.1;
  root.scale.setScalar(3);
  scene.add(root);

  const skinMat = createFeltMaterial('hub_annSkinMat', new Color(0.96, 0.85, 0.76));
  const dressMat = createFeltMaterial('hub_annDressMat', new Color(0.35, 0.5, 0.82));
  const apronMat = createFeltMaterial('hub_annApronMat', new Color(0.97, 0.96, 0.93));
  const hairMat = createFeltMaterial('hub_annHairMat', new Color(0.82, 0.3, 0.18));
  const eyeMat = createFeltMaterial('hub_annEyeMat', new Color(0.2, 0.15, 0.12));
  const cheekMat = createPlasticMaterial('hub_annCheekMat', new Color(0.95, 0.7, 0.68));
  const noseMat = createFeltMaterial('hub_annNoseMat', new Color(0.85, 0.45, 0.4));
  const mouthMat = createFeltMaterial('hub_annMouthMat', new Color(0.8, 0.4, 0.38));
  const shoeMat = createFeltMaterial('hub_annShoeMat', new Color(0.15, 0.15, 0.15));
  const stockingMat = createFeltMaterial('hub_annStockingMat', new Color(0.95, 0.95, 0.92));

  // Body ΓÇö soft torso
  const body = new Mesh(new BoxGeometry(0.1, 0.18, 0.06), dressMat);
  body.name = 'annBody';
  body.position.y = 0.09;
  body.castShadow = true;
  root.add(body);

  // Apron
  const apron = new Mesh(new BoxGeometry(0.08, 0.13, 0.005), apronMat);
  apron.name = 'annApron';
  apron.position.set(0, 0.005, 0.033);
  body.add(apron);

  // Head ΓÇö round and friendly
  const head = new Mesh(new SphereGeometry(0.07, 12, 12), skinMat);
  head.name = 'annHead';
  head.position.y = 0.155;
  head.castShadow = true;
  body.add(head);

  // Yarn hair ΓÇö soft loops around the head
  const hairAngles = [0.6, 1.0, 1.4, 1.8, 2.2, 2.6, 3.0, 3.4, 3.8, 4.2, 4.6, 5.0, 5.4, 5.8];
  hairAngles.forEach((angle, i) => {
    // Skip the face area
    if (angle > 5.5 || angle < 0.8) return;
    const len = 0.05 + Math.random() * 0.025;
    const strand = new Mesh(new CylinderGeometry(0.007, 0.006, len, 4), hairMat);
    strand.name = `annHair${i}`;
    const r = 0.066;
    strand.position.set(Math.sin(angle) * r, 0.025 - len * 0.25, Math.cos(angle) * r);
    strand.rotation.x = Math.cos(angle) * 0.25;
    strand.rotation.z = Math.sin(angle) * 0.35;
    head.add(strand);
  });

  // Hair top ΓÇö soft cap of yarn
  for (let i = 0; i < 5; i++) {
    const puff = new Mesh(new SphereGeometry(0.022, 6, 6), hairMat);
    puff.name = `annHairTop${i}`;
    const a = (i / 5) * Math.PI * 2;
    puff.position.set(Math.sin(a) * 0.03, 0.055, Math.cos(a) * 0.025);
    head.add(puff);
  }

  // Pigtails ΓÇö soft yarn bundles
  [-1, 1].forEach((side) => {
    for (let j = 0; j < 4; j++) {
      const len = 0.08 + j * 0.01;
      const pigtail = new Mesh(new CylinderGeometry(0.007, 0.005, len, 4), hairMat);
      pigtail.name = `annPigtail${side}_${j}`;
      pigtail.position.set(side * (0.058 + j * 0.004), -0.01 - j * 0.004, -0.01);
      pigtail.rotation.z = side * 0.45;
      pigtail.rotation.x = 0.1;
      head.add(pigtail);
    }
  });

  // Eyes ΓÇö small soft dots, wider apart, warm brown
  [-1, 1].forEach((side) => {
    const eye = new Mesh(new SphereGeometry(0.008, 8, 8), eyeMat);
    eye.name = `annEye${side}`;
    eye.position.set(side * 0.028, 0.012, 0.062);
    head.add(eye);

    // Tiny white highlight
    const highlight = new Mesh(new SphereGeometry(0.003, 6, 6), apronMat);
    highlight.name = `annEyeHighlight${side}`;
    highlight.position.set(side * 0.003, 0.003, 0.004);
    eye.add(highlight);
  });

  // Nose ΓÇö soft round bump, not a triangle
  const nose = new Mesh(new SphereGeometry(0.01, 8, 8), noseMat);
  nose.name = 'annNose';
  nose.position.set(0, -0.002, 0.066);
  head.add(nose);

  // Cheeks ΓÇö soft pink, subtle
  [-1, 1].forEach((side) => {
    const cheek = new Mesh(new SphereGeometry(0.013, 8, 8), cheekMat);
    cheek.name = `annCheek${side}`;
    cheek.position.set(side * 0.033, -0.012, 0.055);
    head.add(cheek);
  });

  // Smile ΓÇö gentle upward curve
  const smile = new Mesh(new BoxGeometry(0.025, 0.003, 0.003), mouthMat);
  smile.name = 'annSmile';
  smile.position.set(0, -0.024, 0.06);
  head.add(smile);

  // Arms ΓÇö soft floppy
  [-1, 1].forEach((side) => {
    const upperArm = new Mesh(new CylinderGeometry(0.015, 0.013, 0.09, 6), dressMat);
    upperArm.name = `annUpperArm${side}`;
    upperArm.position.set(side * 0.065, 0.04, 0);
    upperArm.rotation.z = side * 0.7;
    body.add(upperArm);

    const lowerArm = new Mesh(new CylinderGeometry(0.013, 0.011, 0.07, 6), skinMat);
    lowerArm.name = `annLowerArm${side}`;
    lowerArm.position.y = -0.075;
    lowerArm.rotation.z = side * 0.2;
    upperArm.add(lowerArm);

    const hand = new Mesh(new SphereGeometry(0.012, 6, 6), skinMat);
    hand.name = `annHand${side}`;
    hand.position.y = -0.04;
    lowerArm.add(hand);
  });

  // Dress hem
  const hem = new Mesh(new BoxGeometry(0.12, 0.04, 0.065), dressMat);
  hem.name = 'annHem';
  hem.position.y = -0.1;
  body.add(hem);

  // Legs ΓÇö striped stockings, draped over edge, clearly visible
  [-1, 1].forEach((side) => {
    const upperLeg = new Mesh(new CylinderGeometry(0.016, 0.015, 0.08, 6), stockingMat);
    upperLeg.name = `annUpperLeg${side}`;
    upperLeg.position.set(side * 0.035, -0.12, 0.025);
    upperLeg.rotation.x = -1.2;
    upperLeg.rotation.z = side * 0.06;
    body.add(upperLeg);

    const lowerLeg = new Mesh(new CylinderGeometry(0.015, 0.013, 0.08, 6), stockingMat);
    lowerLeg.name = `annLowerLeg${side}`;
    lowerLeg.position.y = -0.075;
    lowerLeg.rotation.x = 0.3;
    upperLeg.add(lowerLeg);

    // Stripe rings
    for (let s = 0; s < 4; s++) {
      const parent = s < 2 ? upperLeg : lowerLeg;
      const yOff = s < 2 ? -0.02 + s * 0.03 : -0.02 + (s - 2) * 0.03;
      const stripe = new Mesh(new CylinderGeometry(0.017, 0.017, 0.006, 6), noseMat);
      stripe.name = `annStripe${side}_${s}`;
      stripe.position.y = yOff;
      parent.add(stripe);
    }

    const shoe = new Mesh(new BoxGeometry(0.026, 0.018, 0.038), shoeMat);
    shoe.name = `annShoe${side}`;
    shoe.position.set(0, -0.045, 0.01);
    lowerLeg.add(shoe);
  });
}

/** Raggedy Andy ΓÇö red yarn hair, blue cap, blue shirt, gentle face. */
function createRaggedyAndy(scene: Scene, x: number, y: number, z: number): void {
  const root = new Group();
  root.name = 'raggedyAndy_root';
  root.position.set(x, y, z);
  root.rotation.y = Math.PI - 0.1;
  root.scale.setScalar(3);
  scene.add(root);

  const skinMat = createFeltMaterial('hub_andySkinMat', new Color(0.96, 0.85, 0.76));
  const shirtMat = createFeltMaterial('hub_andyShirtMat', new Color(0.35, 0.55, 0.82));
  const pantsMat = createFeltMaterial('hub_andyPantsMat', new Color(0.3, 0.4, 0.68));
  const hairMat = createFeltMaterial('hub_andyHairMat', new Color(0.82, 0.3, 0.18));
  const capMat = createFeltMaterial('hub_andyCapMat', new Color(0.3, 0.5, 0.78));
  const eyeMat = createFeltMaterial('hub_andyEyeMat', new Color(0.2, 0.15, 0.12));
  const cheekMat = createPlasticMaterial('hub_andyCheekMat', new Color(0.95, 0.7, 0.68));
  const noseMat = createFeltMaterial('hub_andyNoseMat', new Color(0.85, 0.45, 0.4));
  const mouthMat = createFeltMaterial('hub_andyMouthMat', new Color(0.8, 0.4, 0.38));
  const shoeMat = createFeltMaterial('hub_andyShoeMat', new Color(0.35, 0.22, 0.14));
  const whiteMat = createFeltMaterial('hub_andyWhiteMat', new Color(0.97, 0.96, 0.93));

  // Body ΓÇö soft torso
  const body = new Mesh(new BoxGeometry(0.1, 0.16, 0.06), shirtMat);
  body.name = 'andyBody';
  body.position.y = 0.08;
  body.castShadow = true;
  root.add(body);

  // Head ΓÇö round and friendly
  const head = new Mesh(new SphereGeometry(0.07, 12, 12), skinMat);
  head.name = 'andyHead';
  head.position.y = 0.145;
  head.castShadow = true;
  body.add(head);

  // Yarn hair ΓÇö messy tufts poking from under cap
  const tuftAngles = [-2.2, -1.8, -1.4, 1.4, 1.8, 2.2, 2.8, -2.8];
  tuftAngles.forEach((angle, i) => {
    const len = 0.035 + Math.random() * 0.02;
    const strand = new Mesh(new CylinderGeometry(0.007, 0.005, len, 4), hairMat);
    strand.name = `andyHair${i}`;
    const r = 0.064;
    strand.position.set(Math.sin(angle) * r, -0.005, Math.cos(angle) * r);
    strand.rotation.z = Math.sin(angle) * 0.4;
    strand.rotation.x = Math.cos(angle) * 0.2;
    head.add(strand);
  });

  // Cap ΓÇö soft rounded
  const capBase = new Mesh(new CylinderGeometry(0.068, 0.072, 0.022, 12), capMat);
  capBase.name = 'andyCap';
  capBase.position.set(0, 0.05, 0.005);
  capBase.rotation.x = -0.08;
  head.add(capBase);

  const capDome = new Mesh(new SphereGeometry(0.058, 10, 6, 0, Math.PI * 2, 0, Math.PI / 2), capMat);
  capDome.name = 'andyCapDome';
  capDome.position.y = 0.01;
  capBase.add(capDome);

  const brim = new Mesh(new CylinderGeometry(0.074, 0.074, 0.004, 12), capMat);
  brim.name = 'andyCapBrim';
  brim.position.set(0, -0.01, 0.02);
  capBase.add(brim);

  // Eyes ΓÇö small soft dots, warm brown
  [-1, 1].forEach((side) => {
    const eye = new Mesh(new SphereGeometry(0.008, 8, 8), eyeMat);
    eye.name = `andyEye${side}`;
    eye.position.set(side * 0.028, 0.012, 0.062);
    head.add(eye);

    const highlight = new Mesh(new SphereGeometry(0.003, 6, 6), whiteMat);
    highlight.name = `andyEyeHighlight${side}`;
    highlight.position.set(side * 0.003, 0.003, 0.004);
    eye.add(highlight);
  });

  // Nose ΓÇö soft round bump
  const nose = new Mesh(new SphereGeometry(0.01, 8, 8), noseMat);
  nose.name = 'andyNose';
  nose.position.set(0, -0.002, 0.066);
  head.add(nose);

  // Cheeks ΓÇö soft pink
  [-1, 1].forEach((side) => {
    const cheek = new Mesh(new SphereGeometry(0.013, 8, 8), cheekMat);
    cheek.name = `andyCheek${side}`;
    cheek.position.set(side * 0.033, -0.012, 0.055);
    head.add(cheek);
  });

  // Smile
  const smile = new Mesh(new BoxGeometry(0.025, 0.003, 0.003), mouthMat);
  smile.name = 'andySmile';
  smile.position.set(0, -0.024, 0.06);
  head.add(smile);

  // Arms ΓÇö soft floppy
  [-1, 1].forEach((side) => {
    const upperArm = new Mesh(new CylinderGeometry(0.015, 0.013, 0.09, 6), shirtMat);
    upperArm.name = `andyUpperArm${side}`;
    upperArm.position.set(side * 0.065, 0.03, 0);
    upperArm.rotation.z = side * 0.6;
    body.add(upperArm);

    const lowerArm = new Mesh(new CylinderGeometry(0.013, 0.011, 0.07, 6), skinMat);
    lowerArm.name = `andyLowerArm${side}`;
    lowerArm.position.y = -0.075;
    lowerArm.rotation.z = side * 0.2;
    upperArm.add(lowerArm);

    const hand = new Mesh(new SphereGeometry(0.012, 6, 6), skinMat);
    hand.name = `andyHand${side}`;
    hand.position.y = -0.04;
    lowerArm.add(hand);
  });

  // Legs ΓÇö pants, draped over edge with bent knees, clearly visible
  [-1, 1].forEach((side) => {
    const upperLeg = new Mesh(new CylinderGeometry(0.017, 0.016, 0.08, 6), pantsMat);
    upperLeg.name = `andyUpperLeg${side}`;
    upperLeg.position.set(side * 0.035, -0.09, 0.025);
    upperLeg.rotation.x = -1.2;
    upperLeg.rotation.z = side * 0.06;
    body.add(upperLeg);

    const lowerLeg = new Mesh(new CylinderGeometry(0.016, 0.014, 0.08, 6), pantsMat);
    lowerLeg.name = `andyLowerLeg${side}`;
    lowerLeg.position.y = -0.075;
    lowerLeg.rotation.x = 0.3;
    upperLeg.add(lowerLeg);

    const shoe = new Mesh(new BoxGeometry(0.028, 0.02, 0.04), shoeMat);
    shoe.name = `andyShoe${side}`;
    shoe.position.set(0, -0.045, 0.01);
    lowerLeg.add(shoe);
  });
}

import { Color, CylinderGeometry, Mesh, SphereGeometry, TorusGeometry, type DirectionalLight, type Scene } from 'three';
import { createGlossyPaintMaterial, createToyMetalMaterial } from '@app/utils/materialFactory';
import gsap from 'gsap';

/** Creates a striped spinning top with a metal tip, knob handle, and wobble animation. */
export function createSpinningTop(scene: Scene, _keyLight: DirectionalLight): void {
  const topBody = new Mesh(
    new CylinderGeometry(0.02, 0.15, 0.2, 16),
    createGlossyPaintMaterial('hub_spinTopMat', new Color(0.2, 0.6, 0.85)),
  );
  topBody.name = 'spinTop';
  topBody.position.set(3.0, 0.14, -2.0);
  topBody.castShadow = true;
  scene.add(topBody);

  // Stripe bands
  const stripeColors = [new Color(1.0, 0.85, 0.2), new Color(0.9, 0.25, 0.25), new Color(0.3, 0.8, 0.4)];
  for (let si = 0; si < stripeColors.length; si++) {
    const stripe = new Mesh(
      new TorusGeometry((0.22 - si * 0.05) / 2, 0.01, 16, 16),
      createGlossyPaintMaterial(`hub_spinStripeMat${si}`, stripeColors[si]),
    );
    stripe.name = `spinStripe${si}`;
    stripe.position.y = -0.02 + si * 0.05;
    topBody.add(stripe);
  }

  // Tip
  const tip = new Mesh(
    new CylinderGeometry(0.02, 0, 0.08, 8),
    createToyMetalMaterial('hub_spinTipMat', new Color(0.7, 0.65, 0.5)),
  );
  tip.name = 'spinTip';
  tip.position.y = -0.14;
  topBody.add(tip);

  // Handle knob
  const knob = new Mesh(
    new SphereGeometry(0.03, 8, 8),
    createGlossyPaintMaterial('hub_spinKnobMat', new Color(0.85, 0.2, 0.2)),
  );
  knob.name = 'spinKnob';
  knob.position.y = 0.12;
  topBody.add(knob);

  // Wobble animation
  gsap.to(topBody.rotation, {
    z: -0.05,
    duration: 4,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut',
  });
  topBody.rotation.z = 0.05;
}

import { Color, CylinderGeometry, Group, Mesh, SphereGeometry, type DirectionalLight, type Scene } from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial, createWoodMaterial } from '@app/utils/materialFactory';

/**
 * Creates a toy drum with crossed drumsticks on the right side
 * of the blue (animals) toybox.
 */
export function createToyDrum(scene: Scene, _keyLight: DirectionalLight): void {
  // Green (creative) dresser toybox left side (as seen from front).
  // Dresser at (-2.8, 0.01, 8.25), rot PI, scale 0.75. Top Γëê Y 1.02.
  // Left edge in world Γëê x = -1.45.
  const root = new Group();
  root.name = 'toyDrum_root';
  root.position.set(-1.6, 1.02, 8.25);
  root.rotation.y = 0.4;
  scene.add(root);

  const shellMat = createGlossyPaintMaterial('hub_drumShellMat', new Color(0.92, 0.28, 0.28));
  const headMat = createPlasticMaterial('hub_drumHeadMat', new Color(0.95, 0.92, 0.85));
  const rimMat = createGlossyPaintMaterial('hub_drumRimMat', new Color(0.85, 0.75, 0.2));
  const stripeMat = createGlossyPaintMaterial('hub_drumStripeMat', new Color(0.95, 0.95, 0.92));
  const stickMat = createWoodMaterial('hub_drumStickMat', new Color(0.7, 0.55, 0.35));
  const tipMat = createPlasticMaterial('hub_drumTipMat', new Color(0.92, 0.92, 0.88));

  // Drum shell
  const shell = new Mesh(new CylinderGeometry(0.16, 0.16, 0.14, 16), shellMat);
  shell.name = 'drumShell';
  shell.position.y = 0.07;
  shell.castShadow = true;
  root.add(shell);

  // Decorative stripes around the shell
  for (let i = 0; i < 8; i++) {
    const angle = (i / 8) * Math.PI * 2;
    const stripe = new Mesh(new CylinderGeometry(0.005, 0.005, 0.12, 4), stripeMat);
    stripe.name = `drumStripe${i}`;
    stripe.position.set(Math.cos(angle) * 0.161, 0, Math.sin(angle) * 0.161);
    shell.add(stripe);
  }

  // Drum head (top)
  const drumTop = new Mesh(new CylinderGeometry(0.16, 0.16, 0.008, 16), headMat);
  drumTop.name = 'drumTop';
  drumTop.position.y = 0.074;
  shell.add(drumTop);

  // Drum bottom
  const drumBottom = new Mesh(new CylinderGeometry(0.16, 0.16, 0.008, 16), headMat);
  drumBottom.name = 'drumBottom';
  drumBottom.position.y = -0.074;
  shell.add(drumBottom);

  // Rims (top and bottom)
  const rimTop = new Mesh(new CylinderGeometry(0.165, 0.165, 0.015, 16), rimMat);
  rimTop.name = 'drumRimTop';
  rimTop.position.y = 0.068;
  shell.add(rimTop);

  const rimBottom = new Mesh(new CylinderGeometry(0.165, 0.165, 0.015, 16), rimMat);
  rimBottom.name = 'drumRimBottom';
  rimBottom.position.y = -0.068;
  shell.add(rimBottom);

  // Drumsticks ΓÇö crossed on top of the drum
  [-1, 1].forEach((side) => {
    const stick = new Mesh(new CylinderGeometry(0.008, 0.006, 0.24, 6), stickMat);
    stick.name = `drumStick${side}`;
    stick.position.set(side * 0.02, 0.09, 0);
    stick.rotation.z = side * 0.4;
    stick.rotation.x = Math.PI / 2 - 0.1;
    stick.castShadow = true;
    shell.add(stick);

    // Rounded tip
    const tip = new Mesh(new SphereGeometry(0.012, 6, 6), tipMat);
    tip.name = `drumStickTip${side}`;
    tip.position.y = 0.12;
    stick.add(tip);
  });
}

