import {
  CircleGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial } from '@app/utils/materialFactory';
import gsap from 'gsap';

/** Creates a yellow rubber duck on the floor with a bobbing animation. */
export function createRubberDuck(scene: Scene, _keyLight: DirectionalLight): void {
  const duckMat = createGlossyPaintMaterial('hub_duckMat', new Color(1.0, 0.88, 0.12));

  const root = new Group();
  root.name = 'floorDuck_root';
  root.position.set(1.5, 0, 2.5);
  root.rotation.y = Math.atan2(-1.5, -0.5); // face toward rug centre
  scene.add(root);

  // Body ΓÇö rounded using geometry scaling
  const bodyGeo = new SphereGeometry(1, 12, 10);
  bodyGeo.scale(0.14, 0.11, 0.12);
  const body = new Mesh(bodyGeo, duckMat);
  body.name = 'duckBody';
  body.position.y = 0.11;
  body.castShadow = true;
  root.add(body);

  // Head ΓÇö round, sits on top
  const head = new Mesh(new SphereGeometry(0.07, 10, 10), duckMat);
  head.name = 'duckHead';
  head.position.set(0, 0.12, 0.06);
  head.castShadow = true;
  body.add(head);

  // Beak ΓÇö orange, protruding forward
  const beakGeo = new SphereGeometry(1, 8, 8);
  beakGeo.scale(0.04, 0.015, 0.03);
  const beak = new Mesh(beakGeo, createGlossyPaintMaterial('hub_duckBeakMat', new Color(1.0, 0.58, 0.12)));
  beak.name = 'duckBeak';
  beak.position.set(0, -0.015, 0.065);
  head.add(beak);

  // Eyes
  const eyeMat = createGlossyPaintMaterial('hub_duckEyeMat', new Color(0.06, 0.05, 0.05));
  [-1, 1].forEach((side) => {
    const eye = new Mesh(new CylinderGeometry(0.012, 0.012, 0.008, 10), eyeMat);
    eye.name = `duckEye${side}`;
    eye.position.set(side * 0.04, 0.025, 0.06);
    eye.rotation.x = Math.PI / 2;
    head.add(eye);

    const glint = new Mesh(
      new SphereGeometry(0.004, 4, 4),
      createGlossyPaintMaterial(`hub_duckGlintMat${side}`, new Color(1, 1, 1)),
    );
    glint.name = `duckGlint${side}`;
    glint.position.set(0.004, 0.005, 0.003);
    eye.add(glint);
  });

  // Cheek blush
  const blushMat = createPlasticMaterial('hub_duckBlushMat', new Color(1.0, 0.6, 0.55));
  [-1, 1].forEach((side) => {
    const blush = new Mesh(new CircleGeometry(0.018, 10), blushMat);
    blush.name = `duckBlush${side}`;
    blush.position.set(side * 0.05, -0.01, 0.058);
    head.add(blush);
  });

  // Tail ΓÇö small upward point
  const tail = new Mesh(new CylinderGeometry(0, 0.02, 0.05, 6), duckMat);
  tail.name = 'duckTail';
  tail.position.set(0, 0.06, -0.1);
  tail.rotation.x = -0.4;
  body.add(tail);

  // Wings ΓÇö small bumps on each side
  [-1, 1].forEach((side) => {
    const wingGeo = new SphereGeometry(1, 8, 6);
    wingGeo.scale(0.03, 0.06, 0.05);
    const wing = new Mesh(wingGeo, duckMat);
    wing.name = `duckWing${side}`;
    wing.position.set(side * 0.1, 0, -0.01);
    body.add(wing);
  });

  // Bobbing animation
  gsap.to(root.position, {
    y: 0.03,
    duration: 200 / 60,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut',
  });
}

import { Color, CylinderGeometry, Mesh, SphereGeometry, TorusGeometry, type DirectionalLight, type Scene } from 'three';
import { createGlossyPaintMaterial, createWoodMaterial } from '@app/utils/materialFactory';

/** Creates a stacking ring toy with a wood base, peg, knob, and five graduated coloured rings. */
export function createStackingRings(scene: Scene, _keyLight: DirectionalLight): void {
  const baseMat = createWoodMaterial('hub_pegMat', new Color(0.65, 0.5, 0.32));

  const base = new Mesh(new CylinderGeometry(0.325, 0.325, 0.06, 24), baseMat);
  base.name = 'ringBase';
  base.position.set(-0.5, 0.03, -0.5);
  base.castShadow = true;
  scene.add(base);

  const peg = new Mesh(new CylinderGeometry(0.03, 0.035, 0.4, 12), baseMat);
  peg.name = 'ringPeg';
  peg.position.set(-0.5, 0.26, -0.5);
  peg.castShadow = true;
  scene.add(peg);

  const knob = new Mesh(
    new SphereGeometry(0.05, 10, 10),
    createGlossyPaintMaterial('hub_ringKnobMat', new Color(0.9, 0.2, 0.2)),
  );
  knob.name = 'ringKnob';
  knob.position.y = 0.22;
  peg.add(knob);

  const ringColors = [
    new Color(0.88, 0.15, 0.18),
    new Color(1.0, 0.55, 0.08),
    new Color(1.0, 0.85, 0.15),
    new Color(0.25, 0.75, 0.35),
    new Color(0.35, 0.55, 0.9),
  ];
  const ringSizes = [0.54, 0.46, 0.38, 0.3, 0.22];

  for (let i = 0; i < 5; i++) {
    const ring = new Mesh(
      new TorusGeometry(ringSizes[i] / 2, 0.05, 16, 24),
      createGlossyPaintMaterial(`hub_ringMat${i}`, ringColors[i]),
    );
    ring.name = `stackRing${i}`;
    ring.position.set(-0.5, 0.08 + i * 0.08, -0.5);
    // Torus defaults to XY plane ΓÇö rotate to lie flat on the floor
    ring.rotation.x = Math.PI / 2;
    ring.castShadow = true;
    scene.add(ring);

    // Top ring sits slightly askew for a playful look
    if (i === 4) {
      ring.rotation.z = 0.12;
      ring.position.x += 0.02;
    }
  }
}

