import {
  BoxGeometry,
  CircleGeometry,
  Color,
  Mesh,
  PlaneGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial } from '@app/utils/materialFactory';

/** Creates three scattered alphabet blocks (A, B, C) with coloured faces and letter decals. */
export function createToyBlocks(scene: Scene, _keyLight: DirectionalLight): void {
  const configs = [
    { pos: new Vector3(-1.8, 0.18, 1.0), color: new Color(0.88, 0.2, 0.2), rotY: 0.4, letter: 'A' },
    { pos: new Vector3(1.0, 0.18, -2.8), color: new Color(0.22, 0.5, 0.88), rotY: -0.3, letter: 'B' },
    { pos: new Vector3(-3.8, 0.18, -4.2), color: new Color(1.0, 0.82, 0.15), rotY: 0.7, letter: 'C' },
  ];

  for (let i = 0; i < configs.length; i++) {
    const c = configs[i];
    const block = new Mesh(new BoxGeometry(0.36, 0.36, 0.36), createGlossyPaintMaterial(`hub_blockMat${i}`, c.color));
    block.name = `toyBlock${i}`;
    block.position.copy(c.pos);
    block.rotation.y = c.rotY;
    block.castShadow = true;
    scene.add(block);

    const facePanel = new Mesh(
      new PlaneGeometry(0.28, 0.28),
      createPlasticMaterial(`hub_blockPanelMat${i}`, new Color(0.95, 0.92, 0.85)),
    );
    facePanel.name = `blockPanel${i}`;
    facePanel.position.z = 0.181;
    block.add(facePanel);

    const letterMat = createGlossyPaintMaterial(`hub_blockLetterMat${i}`, c.color.clone().multiplyScalar(0.65));
    if (c.letter === 'A') {
      const a = new Mesh(new CircleGeometry(0.08, 3), letterMat);
      a.name = `blockLetter${i}`;
      a.position.z = 0.182;
      block.add(a);
    } else if (c.letter === 'B') {
      [-1, 1].forEach((v) => {
        const b = new Mesh(new CircleGeometry(0.045, 10), letterMat);
        b.name = `blockLetter${i}_${v}`;
        b.position.set(0.015, v * 0.04, 0.182);
        block.add(b);
      });
      const bar = new Mesh(new PlaneGeometry(0.02, 0.12), letterMat);
      bar.name = `blockLetterBar${i}`;
      bar.position.set(-0.03, 0, 0.182);
      block.add(bar);
    } else {
      const cShape = new Mesh(new CircleGeometry(0.06, 10, 0, Math.PI * 1.5), letterMat);
      cShape.name = `blockLetter${i}`;
      cShape.position.z = 0.182;
      cShape.rotation.z = 0.4;
      block.add(cShape);
    }

    const sideMat = createGlossyPaintMaterial(`hub_blockSideMat${i}`, c.color.clone().multiplyScalar(0.85));
    const sidePanel = new Mesh(new PlaneGeometry(0.28, 0.28), sideMat);
    sidePanel.name = `blockSide${i}`;
    sidePanel.position.set(0.181, 0, 0);
    sidePanel.rotation.y = Math.PI / 2;
    block.add(sidePanel);
  }
}

import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  MeshBasicMaterial,
  SphereGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial } from '@app/utils/materialFactory';
import { triggerSound } from '@app/assets/audio/sceneBridge';
import gsap from 'gsap';

/** Track radius ΓÇö matches the train track. */
const TRACK_RADIUS = 3.95;
const TRACK_Y = 0.01;

/** Creates a red toy car on the floor. When clicked, it hops onto the train tracks and chases the train. */
export function createToyCar(scene: Scene, _keyLight: DirectionalLight): void {
  const root = new Group();
  root.name = 'toyCar_root';
  root.position.set(4.0, TRACK_Y + 0.04, -3.5);
  root.rotation.y = 0.6;
  scene.add(root);

  const carMat = createGlossyPaintMaterial('hub_carMat', new Color(0.88, 0.18, 0.15));
  const trimMat = createGlossyPaintMaterial('hub_carTrimMat', new Color(0.78, 0.12, 0.1));
  const windowMat = createPlasticMaterial('hub_carWindowMat', new Color(0.7, 0.85, 1.0));
  const wheelMat = createPlasticMaterial('hub_carWheelMat', new Color(0.15, 0.15, 0.18));
  const hubMat = createPlasticMaterial('hub_carHubMat', new Color(0.8, 0.78, 0.7));
  const bumperMat = createPlasticMaterial('hub_carBumperMat', new Color(0.7, 0.68, 0.6));
  const headlightMat = createPlasticMaterial('hub_carHeadlightMat', new Color(1.0, 0.95, 0.7));

  // Main body ΓÇö boxy sedan shape
  const body = new Mesh(new BoxGeometry(0.38, 0.1, 0.18), carMat);
  body.name = 'toyCarBody';
  body.position.y = 0.08;
  body.castShadow = true;
  root.add(body);

  // Cabin / roof section
  const cabin = new Mesh(new BoxGeometry(0.2, 0.09, 0.16), carMat);
  cabin.name = 'toyCarCabin';
  cabin.position.set(-0.02, 0.09, 0);
  body.add(cabin);

  // Windows ΓÇö front and back
  const frontWin = new Mesh(new BoxGeometry(0.005, 0.06, 0.13), windowMat);
  frontWin.name = 'toyCarFrontWindow';
  frontWin.position.set(0.1, 0.0, 0);
  cabin.add(frontWin);

  const rearWin = new Mesh(new BoxGeometry(0.005, 0.06, 0.13), windowMat);
  rearWin.name = 'toyCarRearWindow';
  rearWin.position.set(-0.1, 0.0, 0);
  cabin.add(rearWin);

  // Side windows
  [-1, 1].forEach((side) => {
    const sideWin = new Mesh(new BoxGeometry(0.14, 0.055, 0.005), windowMat);
    sideWin.name = `toyCarSideWindow${side}`;
    sideWin.position.set(0, 0.0, side * 0.081);
    cabin.add(sideWin);
  });

  // Hood scoop
  const hood = new Mesh(new BoxGeometry(0.06, 0.025, 0.08), trimMat);
  hood.name = 'toyCarHood';
  hood.position.set(0.12, 0.05, 0);
  body.add(hood);

  // Bumpers ΓÇö front and rear
  const frontBumper = new Mesh(new BoxGeometry(0.02, 0.04, 0.18), bumperMat);
  frontBumper.name = 'toyCarFrontBumper';
  frontBumper.position.set(0.2, -0.02, 0);
  body.add(frontBumper);

  const rearBumper = new Mesh(new BoxGeometry(0.02, 0.04, 0.18), bumperMat);
  rearBumper.name = 'toyCarRearBumper';
  rearBumper.position.set(-0.2, -0.02, 0);
  body.add(rearBumper);

  // Headlights
  headlightMat.emissive = new Color(0.12, 0.1, 0.04);
  [-1, 1].forEach((side) => {
    const hl = new Mesh(new CylinderGeometry(0.015, 0.015, 0.01, 8), headlightMat);
    hl.name = `toyCarHeadlight${side}`;
    hl.position.set(0.19, 0.01, side * 0.06);
    hl.rotation.z = Math.PI / 2;
    body.add(hl);
  });

  // Taillights
  const tailMat = createGlossyPaintMaterial('hub_carTailMat', new Color(0.9, 0.15, 0.1));
  [-1, 1].forEach((side) => {
    const tl = new Mesh(new CylinderGeometry(0.012, 0.012, 0.01, 8), tailMat);
    tl.name = `toyCarTaillight${side}`;
    tl.position.set(-0.19, 0.01, side * 0.06);
    tl.rotation.z = Math.PI / 2;
    body.add(tl);
  });

  // Wheels
  const wheelOffsets: [number, number, number][] = [
    [0.12, -0.04, 0.1],
    [0.12, -0.04, -0.1],
    [-0.12, -0.04, 0.1],
    [-0.12, -0.04, -0.1],
  ];
  wheelOffsets.forEach(([wx, wy, wz], i) => {
    const wheel = new Mesh(new CylinderGeometry(0.035, 0.035, 0.025, 12), wheelMat);
    wheel.name = `toyCarWheel${i}`;
    wheel.position.set(wx, wy, wz);
    wheel.rotation.x = Math.PI / 2;
    body.add(wheel);

    const hub = new Mesh(new CylinderGeometry(0.012, 0.012, 0.005, 8), hubMat);
    hub.name = `toyCarHub${i}`;
    hub.position.set(0, 0.013, 0);
    wheel.add(hub);
  });

  // Exhaust pipe
  const pipeMat = createPlasticMaterial('hub_carPipeMat', new Color(0.4, 0.4, 0.42));
  const pipe = new Mesh(new CylinderGeometry(0.012, 0.014, 0.04, 6), pipeMat);
  pipe.name = 'toyCarExhaustPipe';
  pipe.position.set(-0.2, -0.02, 0.06);
  pipe.rotation.z = Math.PI / 2;
  body.add(pipe);

  // Exhaust puff pool
  const smokeMat = createPlasticMaterial('hub_carSmokeMat', new Color(0.85, 0.85, 0.88));
  smokeMat.transparent = true;
  smokeMat.opacity = 0.5;
  const PUFF_COUNT = 5;
  const puffs: Mesh[] = [];
  for (let i = 0; i < PUFF_COUNT; i++) {
    const puff = new Mesh(new SphereGeometry(0.02, 6, 6), smokeMat.clone());
    puff.name = `toyCarPuff${i}`;
    puff.visible = false;
    scene.add(puff);
    puffs.push(puff);
  }

  let puffIndex = 0;
  let exhaustRunning = false;
  const pipeWorldPos = new Vector3();
  const emitPuff = () => {
    if (!exhaustRunning) return;
    const puff = puffs[puffIndex % PUFF_COUNT];
    puffIndex++;
    pipe.getWorldPosition(pipeWorldPos);
    puff.position.copy(pipeWorldPos);
    puff.scale.setScalar(0.8);
    puff.visible = true;
    const mat = puff.material as typeof smokeMat;
    mat.opacity = 0.5;
    gsap.to(puff.position, { y: pipeWorldPos.y + 0.4, duration: 1.0, ease: 'power1.out' });
    gsap.to(puff.scale, { x: 2, y: 2, z: 2, duration: 1.0, ease: 'power1.out' });
    gsap.to(mat, {
      opacity: 0,
      duration: 1.0,
      ease: 'power1.in',
      onComplete: () => {
        puff.visible = false;
      },
    });
  };

  const exhaustTimer = gsap.to({}, { duration: 0.5, repeat: -1, paused: true, onRepeat: emitPuff, onStart: emitPuff });

  // Invisible hitbox for easy clicking
  const hitbox = new Mesh(new BoxGeometry(0.45, 0.25, 0.25), new MeshBasicMaterial({ visible: false }));
  hitbox.name = 'toyCarHitbox';
  hitbox.position.y = 0.08;
  root.add(hitbox);

  // Rocking idle animation
  const rockTween = gsap.to(root.rotation, {
    z: 0.02,
    duration: 3.75,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut',
  });

  // ΓöÇΓöÇ Click interaction ΓÇö hop onto tracks and chase the train ΓöÇΓöÇ
  let driving = false;

  // Find the train's orbit pivot so the car can follow at an offset
  const findTrainPivot = (): Group | null => {
    const pivot = scene.getObjectByName('trainOrbitPivot');
    return pivot instanceof Group ? pivot : null;
  };

  const driveHandler = () => {
    if (driving) return;
    driving = true;

    triggerSound('sfx_shared_tap_fallback');

    // Stop idle rocking, start exhaust
    rockTween.pause();
    root.rotation.z = 0;
    exhaustRunning = true;
    exhaustTimer.play();

    // The train sits at angle 0 on the orbit pivot. We'll place the car ~120┬░ behind
    const trainPivot = findTrainPivot();
    if (!trainPivot) return;

    // Create an orbit pivot for the car, offset behind the train
    const carOrbitPivot = new Group();
    carOrbitPivot.name = 'carOrbitPivot';
    scene.add(carOrbitPivot);

    // Get the train's current rotation so we start offset from it
    const trainAngle = trainPivot.rotation.y;
    const offsetAngle = (2 * Math.PI) / 3; // 120┬░ behind
    carOrbitPivot.rotation.y = trainAngle + offsetAngle;

    // Animate car from current position to track position
    const targetX = TRACK_RADIUS;
    const targetY = TRACK_Y + 0.04;

    // First, reparent car into the orbit pivot at the track position
    const tl = gsap.timeline();

    // Drive to the nearest track point
    const entryAngle = carOrbitPivot.rotation.y;
    const trackX = Math.cos(-entryAngle) * TRACK_RADIUS;
    const trackZ = Math.sin(-entryAngle) * TRACK_RADIUS;

    tl.to(root.position, {
      x: trackX,
      y: targetY,
      z: trackZ,
      duration: 1.0,
      ease: 'power2.inOut',
    });

    // Face tangent direction
    tl.to(
      root.rotation,
      {
        y: -entryAngle - Math.PI / 2,
        duration: 0.3,
        ease: 'power2.out',
      },
      '<',
    );

    tl.call(() => {
      // Reparent car under the orbit pivot
      scene.remove(root);
      root.position.set(targetX, targetY, 0);
      root.rotation.set(0, -Math.PI / 2, 0);
      carOrbitPivot.add(root);

      // Chase the train ΓÇö orbit at slightly faster speed (28s vs train's 30s)
      gsap.to(carOrbitPivot.rotation, {
        y: carOrbitPivot.rotation.y - Math.PI * 2,
        duration: 28,
        repeat: -1,
        ease: 'none',
      });
    });
  };

  // Assign click handler to body, cabin, and hitbox
  [body, cabin, hitbox].forEach((mesh) => {
    mesh.userData.onClick = driveHandler;
  });

  // Auto-activate after 15 seconds if not clicked
  gsap.delayedCall(15, () => {
    if (!driving) driveHandler();
  });
}

import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  TorusGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import { createGlossyPaintMaterial, createPlasticMaterial, createWoodMaterial } from '@app/utils/materialFactory';
import { triggerSound } from '@app/assets/audio/sceneBridge';
import gsap from 'gsap';

/** Track radius ΓÇö hugs the rug edge (rug radius = 3.8). */
const TRACK_RADIUS = 3.95;
const TRACK_Y = 0.01;
const TIE_COUNT = 48;

/** Creates a toy train on circular tracks around the rug, animated with smoke puffs and horn. */
export function createToyTrain(scene: Scene, _keyLight: DirectionalLight): void {
  const woodMat = createWoodMaterial('hub_trainWoodMat', new Color(0.65, 0.5, 0.32));
  const redMat = createGlossyPaintMaterial('hub_trainRedMat', new Color(0.88, 0.18, 0.18));
  const blueMat = createGlossyPaintMaterial('hub_trainBlueMat', new Color(0.25, 0.5, 0.88));
  const greenMat = createGlossyPaintMaterial('hub_trainGreenMat', new Color(0.3, 0.72, 0.35));
  const yellowMat = createGlossyPaintMaterial('hub_trainYellowMat', new Color(1.0, 0.85, 0.2));
  const wheelMat = createWoodMaterial('hub_trainWheelMat', new Color(0.45, 0.32, 0.2));
  const railMat = createPlasticMaterial('hub_trainRailMat', new Color(0.08, 0.08, 0.08));
  const tieMat = createWoodMaterial('hub_trainTieMat', new Color(0.4, 0.28, 0.15));

  // ΓöÇΓöÇ Circular track ΓöÇΓöÇ

  // Two rails ΓÇö thin torus rings (black)
  const railTube = 0.015;
  [-0.08, 0.08].forEach((offset, ri) => {
    const railGeo = new TorusGeometry(TRACK_RADIUS + offset, railTube, 8, 64);
    railGeo.rotateX(Math.PI / 2);
    const rail = new Mesh(railGeo, railMat);
    rail.name = `trackRail${ri}`;
    rail.position.y = TRACK_Y + railTube;
    scene.add(rail);
  });

  // Cross-ties ΓÇö short planks arranged radially
  for (let i = 0; i < TIE_COUNT; i++) {
    const angle = (i / TIE_COUNT) * Math.PI * 2;
    const tie = new Mesh(new BoxGeometry(0.22, 0.015, 0.04), tieMat);
    tie.name = `trackTie${i}`;
    tie.position.set(Math.cos(angle) * TRACK_RADIUS, TRACK_Y, Math.sin(angle) * TRACK_RADIUS);
    tie.rotation.y = -angle + Math.PI / 2;
    scene.add(tie);
  }

  // ΓöÇΓöÇ Train assembly ΓÇö all cars in one group that orbits the track ΓöÇΓöÇ
  const trainRoot = new Group();
  trainRoot.name = 'trainRoot';
  scene.add(trainRoot);

  // Orbit pivot ΓÇö rotates around Y axis at origin
  const orbitPivot = new Group();
  orbitPivot.name = 'trainOrbitPivot';
  trainRoot.add(orbitPivot);

  // Train carriage group ΓÇö positioned at track radius, facing tangent
  const trainGroup = new Group();
  trainGroup.name = 'trainGroup';
  trainGroup.position.set(TRACK_RADIUS, TRACK_Y + 0.04, 0);
  trainGroup.rotation.y = -Math.PI / 2; // face tangent direction (engine leads)
  orbitPivot.add(trainGroup);

  // ΓöÇΓöÇ Locomotive ΓöÇΓöÇ
  const loco = new Mesh(new BoxGeometry(0.35, 0.18, 0.22), redMat);
  loco.name = 'trainLoco';
  loco.position.set(0, 0.09, 0);
  loco.castShadow = true;
  trainGroup.add(loco);

  // Boiler
  const boiler = new Mesh(new CylinderGeometry(0.08, 0.08, 0.22, 12), redMat);
  boiler.name = 'trainBoiler';
  boiler.position.set(0.12, 0.04, 0);
  boiler.rotation.z = Math.PI / 2;
  loco.add(boiler);

  // Smokestack
  const stack = new Mesh(new CylinderGeometry(0.035, 0.02, 0.12, 10), yellowMat);
  stack.name = 'trainStack';
  stack.position.set(0.15, 0.16, 0);
  loco.add(stack);

  // Cab
  const cab = new Mesh(new BoxGeometry(0.14, 0.16, 0.2), redMat);
  cab.name = 'trainCab';
  cab.position.set(-0.1, 0.15, 0);
  loco.add(cab);

  const roof = new Mesh(new BoxGeometry(0.18, 0.025, 0.24), blueMat);
  roof.name = 'trainRoof';
  roof.position.y = 0.09;
  cab.add(roof);

  // Wheels
  [
    [-0.12, 0.12],
    [-0.12, -0.12],
    [0.1, 0.12],
    [0.1, -0.12],
  ].forEach((wp, wi) => {
    const wheel = new Mesh(new CylinderGeometry(0.04, 0.04, 0.025, 12), wheelMat);
    wheel.name = `trainLocoWheel${wi}`;
    wheel.position.set(wp[0], -0.07, wp[1]);
    wheel.rotation.x = Math.PI / 2;
    loco.add(wheel);
  });

  // ΓöÇΓöÇ Cargo car 1 (blue with pegs) ΓöÇΓöÇ
  const car2 = new Mesh(new BoxGeometry(0.28, 0.14, 0.2), blueMat);
  car2.name = 'trainCar2';
  car2.position.set(-0.38, -0.02, 0);
  loco.add(car2);

  [0, 1, 2].forEach((ci) => {
    const peg = new Mesh(
      new CylinderGeometry(0.02, 0.02, 0.08, 8),
      ci === 0 ? yellowMat : ci === 1 ? greenMat : redMat,
    );
    peg.name = `trainPeg${ci}`;
    peg.position.set(-0.06 + ci * 0.06, 0.1, 0);
    car2.add(peg);
  });

  [
    [-0.08, 0.11],
    [-0.08, -0.11],
    [0.08, 0.11],
    [0.08, -0.11],
  ].forEach((wp, wi) => {
    const wheel = new Mesh(new CylinderGeometry(0.03, 0.03, 0.02, 10), wheelMat);
    wheel.name = `trainCar2Wheel${wi}`;
    wheel.position.set(wp[0], -0.06, wp[1]);
    wheel.rotation.x = Math.PI / 2;
    car2.add(wheel);
  });

  // ΓöÇΓöÇ Cargo car 2 (green flatbed) ΓöÇΓöÇ
  const car3 = new Mesh(new BoxGeometry(0.24, 0.1, 0.18), greenMat);
  car3.name = 'trainCar3';
  car3.position.set(-0.68, -0.04, 0);
  loco.add(car3);

  const cargo = new Mesh(new BoxGeometry(0.14, 0.1, 0.12), woodMat);
  cargo.name = 'trainCargo';
  cargo.position.y = 0.1;
  car3.add(cargo);

  [
    [-0.06, 0.1],
    [-0.06, -0.1],
    [0.06, 0.1],
    [0.06, -0.1],
  ].forEach((wp, wi) => {
    const wheel = new Mesh(new CylinderGeometry(0.03, 0.03, 0.02, 10), wheelMat);
    wheel.name = `trainCar3Wheel${wi}`;
    wheel.position.set(wp[0], -0.04, wp[1]);
    wheel.rotation.x = Math.PI / 2;
    car3.add(wheel);
  });

  // Connectors
  const connMat = createWoodMaterial('hub_trainConnMat', new Color(0.5, 0.38, 0.22));
  [-0.26, -0.54].forEach((cx, ci) => {
    const conn = new Mesh(new CylinderGeometry(0.0075, 0.0075, 0.08, 4), connMat);
    conn.name = `trainConn${ci}`;
    conn.position.set(cx, -0.02, 0);
    conn.rotation.z = Math.PI / 2;
    loco.add(conn);
  });

  // ΓöÇΓöÇ Orbit animation ΓÇö train goes around the track (clockwise when viewed from above) ΓöÇΓöÇ
  gsap.to(orbitPivot.rotation, {
    y: -Math.PI * 2,
    duration: 30,
    repeat: -1,
    ease: 'none',
  });

  // ΓöÇΓöÇ Smoke puffs ΓÇö recycling pool of small spheres ΓöÇΓöÇ
  const smokeMat = createPlasticMaterial('hub_trainSmokeMat', new Color(0.9, 0.9, 0.92));
  smokeMat.transparent = true;
  smokeMat.opacity = 0.6;

  const PUFF_COUNT = 6;
  const puffs: Mesh[] = [];
  for (let i = 0; i < PUFF_COUNT; i++) {
    const puff = new Mesh(new SphereGeometry(0.03, 6, 6), smokeMat.clone());
    puff.name = `smokePuff${i}`;
    puff.visible = false;
    scene.add(puff);
    puffs.push(puff);
  }

  // Emit a puff every ~0.8 seconds
  let puffIndex = 0;
  const stackWorldPos = new Vector3();
  const emitPuff = () => {
    const puff = puffs[puffIndex % PUFF_COUNT];
    puffIndex++;

    // Read the smokestack's actual world position from the scene graph
    stack.getWorldPosition(stackWorldPos);

    puff.position.copy(stackWorldPos);
    puff.scale.setScalar(0.8);
    puff.visible = true;
    const mat = puff.material as typeof smokeMat;
    mat.opacity = 0.6;

    gsap.to(puff.position, {
      y: 0.9,
      duration: 1.5,
      ease: 'power1.out',
    });
    gsap.to(puff.scale, {
      x: 2.5,
      y: 2.5,
      z: 2.5,
      duration: 1.5,
      ease: 'power1.out',
    });
    gsap.to(mat, {
      opacity: 0,
      duration: 1.5,
      ease: 'power1.in',
      onComplete: () => {
        puff.visible = false;
      },
    });
  };

  // Start emitting puffs on a repeating timer
  gsap.to(
    {},
    {
      duration: 0.8,
      repeat: -1,
      onRepeat: emitPuff,
      onStart: emitPuff,
    },
  );

  // ΓöÇΓöÇ Train horn ΓÇö plays periodically ΓöÇΓöÇ
  const hornInterval = () => {
    triggerSound('sfx_hub_train_horn');
    // Schedule next horn between 12 and 20 seconds
    const nextDelay = 12 + Math.random() * 8;
    gsap.delayedCall(nextDelay, hornInterval);
  };
  // First horn after 6 seconds
  gsap.delayedCall(6, hornInterval);
}

