/**
 * Populates the Playroom Hub with all room contents: structure, furnishings,
 * toyboxes, owl companion, and interaction wiring.
 *
 * @param scene - The Three.js scene (camera, lights, and shadows already configured).
 * @param canvas - Canvas element for event binding.
 * @param camera - Camera for raycasting.
 * @param keyLight - Directional light for shadow casting.
 * @param nav - Navigation actions for toybox world transitions.
 * @returns A cleanup function to remove event listeners and dispose resources.
 */
export function createRoom(
  scene: Scene,
  canvas: HTMLCanvasElement,
  camera: Camera,
  keyLight: DirectionalLight,
  nav: NavigationActions,
): () => void {
  const cleanups: (() => void)[] = [];

  // ΓöÇΓöÇ Structure ΓöÇΓöÇ
  createWalls(scene);
  createCeiling(scene);
  const { floor, rug } = createFloor(scene);
  createWainscoting(scene);
  createCloudWallpaper(scene);
  createDoor(scene);
  createWallArt(scene);
  const dustMotes = createDustMotes(scene);
  cleanups.push(() => dustMotes.dispose());

  // ΓöÇΓöÇ Furnishings ΓöÇΓöÇ
  createBookshelf(scene, keyLight);
  createFloorToys(scene, keyLight);
  createCritters(scene, keyLight);
  createDecor(scene, keyLight);

  // ΓöÇΓöÇ Owl companion ΓöÇΓöÇ
  const owl = createOwlCompanion(scene, new Vector3(0, 0.35, 1.5));

  // ΓöÇΓöÇ Toyboxes ΓöÇΓöÇ
  TOYBOXES.forEach((tb) => {
    const root = createToybox(scene, tb, keyLight);
    // Only the blue (animals) toybox is interactive ΓÇö opens the nature world
    if (tb.id !== 'animals') return;
    const runtime = getToyboxRuntime(root);
    if (runtime) {
      const cleanup = wireToyboxInteractions(scene, canvas, camera, root, runtime, 'nature', nav, owl);
      cleanups.push(cleanup);
    }
  });
  let firstTap = false;

  const floorRaycaster = new Raycaster();
  const floorPointer = new Vector2();

  const onFloorClick = (event: PointerEvent) => {
    const rect = canvas.getBoundingClientRect();
    floorPointer.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    floorPointer.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
    floorRaycaster.setFromCamera(floorPointer, camera);

    // General click: check if any mesh with userData.onClick was hit (any button)
    const allHits = floorRaycaster.intersectObjects(scene.children, true);
    for (const hit of allHits) {
      const obj = hit.object;
      if (obj.userData.onClick) {
        obj.userData.onClick();
        return;
      }
    }

    // Floor click: move owl ΓÇö guard shift+left-click (used for camera orbit)
    if (!(event.button === 0 && event.shiftKey)) {
      const intersects = floorRaycaster.intersectObjects([floor, rug].filter(Boolean) as Mesh[]);
      if (intersects.length > 0) {
        const point = intersects[0].point;
        if (!firstTap) {
          firstTap = true;
          triggerSound('sfx_shared_sparkle_burst');
          createSparkleBurst(scene, point);
        } else {
          triggerSound('sfx_shared_tap_fallback');
        }
        owl.flyTo(point);
      }
    }
  };

  canvas.addEventListener('pointerdown', onFloorClick);
  cleanups.push(() => canvas.removeEventListener('pointerdown', onFloorClick));
  cleanups.push(() => owl.dispose());

  // ΓöÇΓöÇ Ambient animal visitors ΓöÇΓöÇ
  const visitorsCleanup = spawnAnimalVisitors(scene);
  cleanups.push(visitorsCleanup);

  return () => {
    for (const cleanup of cleanups) {
      cleanup();
    }
  };
}

// ΓöÇΓöÇ Toybox interaction wiring ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Registers hover, lid-pop, tap-pulse, and navigation actions on a toybox's pick meshes.
 *
 * @returns A cleanup function to remove event listeners.
 */
function wireToyboxInteractions(
  _scene: Scene,
  canvas: HTMLCanvasElement,
  camera: Camera,
  root: Group | Mesh,
  runtime: HubToyboxRuntime,
  id: SceneId,
  nav: NavigationActions,
  owl: OwlCompanion,
): () => void {
  const raycaster = new Raycaster();
  const pointer = new Vector2();

  const setHoverState = (active: boolean) => {
    runtime.hoverMaterials.forEach((material: MeshStandardMaterial) => {
      material.emissive = active ? material.color.clone().multiplyScalar(0.14) : new Color(0, 0, 0);
    });
  };

  const playLidAnimations = () => {
    runtime.lidAnimations.forEach((part) => {
      const target = part.propertyPath === 'rotation.x' ? part.mesh.rotation : part.mesh.rotation;
      const prop = part.propertyPath.split('.').pop()!;
      gsap.killTweensOf(target);
      gsap.to(target, {
        [prop]: part.peakValue,
        duration: 10 / 60,
        ease: 'power2.out',
        onComplete: () => {
          gsap.to(target, {
            [prop]: part.settleValue,
            duration: 15 / 60,
            ease: 'power2.inOut',
          });
        },
      });
    });
  };

  let pendingNav = false;

  const onClick = (event: PointerEvent) => {
    if (pendingNav) return;
    const rect = canvas.getBoundingClientRect();
    pointer.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    pointer.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(pointer, camera);
    const intersects = raycaster.intersectObjects(runtime.pickMeshes, true);
    if (intersects.length > 0) {
      pendingNav = true;
      triggerSound('sfx_hub_toybox_tap');

      // Fly owl to the toybox, then open on landing
      const toyboxPos = new Vector3();
      if (root instanceof Group) {
        root.getWorldPosition(toyboxPos);
      } else {
        toyboxPos.copy(root.position);
      }

      owl.flyTo(toyboxPos, () => {
        // Owl has landed ΓÇö now play lid + pulse + navigate
        playLidAnimations();

        gsap.killTweensOf(root.scale);
        gsap.to(root.scale, {
          x: 1.05,
          y: 1.05,
          z: 1.05,
          duration: 6 / 60,
          ease: 'power2.out',
          onComplete: () => {
            gsap.to(root.scale, {
              x: 1,
              y: 1,
              z: 1,
              duration: 6 / 60,
              ease: 'power2.in',
              onComplete: () => {
                triggerSound('sfx_hub_toybox_open');
                nav.navigateTo(id);
                pendingNav = false;
              },
            });
          },
        });
      });
    }
  };

  const onPointerMove = (event: PointerEvent) => {
    const rect = canvas.getBoundingClientRect();
    pointer.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    pointer.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(pointer, camera);
    const intersects = raycaster.intersectObjects(runtime.pickMeshes, true);
    setHoverState(intersects.length > 0);
  };

  canvas.addEventListener('pointerdown', onClick);
  canvas.addEventListener('pointermove', onPointerMove);

  return () => {
    canvas.removeEventListener('pointerdown', onClick);
    canvas.removeEventListener('pointermove', onPointerMove);
  };
}

