import { CircleGeometry, Color, Mesh, type Scene } from 'three';
import { createPlasticMaterial } from '@app/utils/materialFactory';
import { CEILING_Y, BACK_WALL_FACE_Z, RIGHT_WALL_FACE_X, LEFT_WALL_FACE_X } from '@app/scenes/hub/layout';

/** Cloud wallpaper covers the upper third of all three walls. */
const CLOUD_ZONE_BOTTOM = CEILING_Y * (2 / 3); // Y=6.0
const CLOUD_ZONE_TOP = CEILING_Y - 0.3; // leave room for crown molding

/** Creates repeating cloud pattern on the upper third of all three walls. */
export function createCloudWallpaper(scene: Scene): void {
  const cloudMat = createPlasticMaterial('hub_wpCloudMat', new Color(0.95, 0.96, 1.0));
  cloudMat.emissive = new Color(0.04, 0.04, 0.05);

  // Cloud shape: cluster of 3-4 overlapping circles
  function addCloud(name: string, cx: number, cy: number, cz: number, scale: number, rotY: number): void {
    const puffs = [
      { dx: 0, dy: 0, r: 0.28 },
      { dx: -0.22, dy: -0.04, r: 0.2 },
      { dx: 0.2, dy: -0.02, r: 0.22 },
      { dx: 0.08, dy: 0.1, r: 0.16 },
    ];
    for (let pi = 0; pi < puffs.length; pi++) {
      const p = puffs[pi];
      const puff = new Mesh(new CircleGeometry(p.r * scale, 12), cloudMat);
      puff.name = `${name}_p${pi}`;
      if (Math.abs(rotY) < 0.01) {
        // Back wall ΓÇö face camera (-Z)
        puff.position.set(cx + p.dx * scale, cy + p.dy * scale, cz);
        puff.rotation.y = Math.PI;
      } else if (rotY > 0) {
        // Right wall ΓÇö facing +X
        puff.position.set(cz, cy + p.dy * scale, cx + p.dx * scale * -1);
        puff.rotation.y = Math.PI / 2;
      } else {
        // Left wall ΓÇö facing -X
        puff.position.set(cz, cy + p.dy * scale, cx + p.dx * scale);
        puff.rotation.y = -Math.PI / 2;
      }
      scene.add(puff);
    }
  }

  // ΓöÇΓöÇ Back wall clouds ΓöÇΓöÇ
  const backZ = BACK_WALL_FACE_Z - 0.02;
  const backCloudPositions = [
    { x: -4.5, y: 7.2, s: 1.0 },
    { x: -2.0, y: 6.8, s: 1.3 },
    { x: 0.5, y: 7.5, s: 0.9 },
    { x: 2.5, y: 6.5, s: 1.1 },
    { x: 4.8, y: 7.0, s: 0.8 },
    { x: -0.8, y: 8.0, s: 0.7 },
    { x: 3.5, y: 7.8, s: 0.9 },
    { x: -3.5, y: 8.2, s: 0.6 },
  ];
  for (let i = 0; i < backCloudPositions.length; i++) {
    const c = backCloudPositions[i];
    if (c.y >= CLOUD_ZONE_BOTTOM && c.y <= CLOUD_ZONE_TOP) {
      addCloud(`wpCloudBack${i}`, c.x, c.y, backZ, c.s, 0);
    }
  }

  // ΓöÇΓöÇ Right wall clouds ΓöÇΓöÇ
  const rightX = RIGHT_WALL_FACE_X + 0.02;
  const sideCloudPositions = [
    { z: -8, y: 7.0, s: 1.1 },
    { z: -4, y: 7.5, s: 0.9 },
    { z: -1, y: 6.8, s: 1.2 },
    { z: 2, y: 7.3, s: 0.8 },
    { z: 5, y: 7.8, s: 1.0 },
    { z: 7, y: 6.5, s: 0.7 },
    { z: -6, y: 8.0, s: 0.6 },
    { z: 3.5, y: 8.2, s: 0.8 },
  ];
  for (let i = 0; i < sideCloudPositions.length; i++) {
    const c = sideCloudPositions[i];
    if (c.y >= CLOUD_ZONE_BOTTOM && c.y <= CLOUD_ZONE_TOP) {
      addCloud(`wpCloudRight${i}`, c.z, c.y, rightX, c.s, 1);
    }
  }

  // ΓöÇΓöÇ Left wall clouds ΓöÇΓöÇ
  const leftX = LEFT_WALL_FACE_X - 0.02;
  for (let i = 0; i < sideCloudPositions.length; i++) {
    const c = sideCloudPositions[i];
    if (c.y >= CLOUD_ZONE_BOTTOM && c.y <= CLOUD_ZONE_TOP) {
      addCloud(`wpCloudLeft${i}`, c.z, c.y, leftX, c.s, -1);
    }
  }
}

import { BoxGeometry, Color, CylinderGeometry, Group, Mesh, PlaneGeometry, SphereGeometry, type Scene } from 'three';
import { createWoodMaterial, createToyMetalMaterial } from '@app/utils/materialFactory';
import { RIGHT_WALL_FACE_X } from '@app/scenes/hub/layout';

/** Door dimensions. */
const DOOR_WIDTH = 2.0;
const DOOR_HEIGHT = 3.8;
const DOOR_THICKNESS = 0.12;
const DOOR_CENTER_Z = 0;
const DOOR_OPEN_ANGLE = 0.12; // slightly ajar inward

/** Creates a slightly-open paneled door on the right wall with knob on the left side. */
export function createDoor(scene: Scene): void {
  const doorMat = createWoodMaterial('hub_doorMat', new Color(0.55, 0.38, 0.22));
  const frameMat = createWoodMaterial('hub_doorFrameMat', new Color(0.9, 0.88, 0.85));
  const knobMat = createToyMetalMaterial('hub_doorKnobMat', new Color(0.75, 0.65, 0.4));

  const wallX = RIGHT_WALL_FACE_X;

  // ΓöÇΓöÇ Door frame ΓÇö flush with wall, receding into wall thickness ΓöÇΓöÇ
  const frameBar = 0.12;
  const frameDepth = 0.18;

  const topBar = new Mesh(new BoxGeometry(frameDepth, frameBar, DOOR_WIDTH + 2 * frameBar), frameMat);
  topBar.name = 'doorFrameTop';
  topBar.position.set(wallX - frameDepth / 2, DOOR_HEIGHT + frameBar / 2, DOOR_CENTER_Z);
  scene.add(topBar);

  [-1, 1].forEach((side, i) => {
    const sideBar = new Mesh(new BoxGeometry(frameDepth, DOOR_HEIGHT + frameBar, frameBar), frameMat);
    sideBar.name = `doorFrameSide${i}`;
    sideBar.position.set(
      wallX - frameDepth / 2,
      (DOOR_HEIGHT + frameBar) / 2,
      DOOR_CENTER_Z + side * (DOOR_WIDTH / 2 + frameBar / 2),
    );
    scene.add(sideBar);
  });

  // ΓöÇΓöÇ Dark opening behind the door ΓöÇΓöÇ
  const gapMat = createWoodMaterial('hub_doorGapMat', new Color(0.08, 0.06, 0.05));
  const gap = new Mesh(new PlaneGeometry(DOOR_WIDTH, DOOR_HEIGHT), gapMat);
  gap.name = 'doorGap';
  gap.position.set(wallX - 0.02, DOOR_HEIGHT / 2, DOOR_CENTER_Z);
  gap.rotation.y = -Math.PI / 2;
  scene.add(gap);

  // ΓöÇΓöÇ Door panel ΓÇö hinge on -Z edge, swings slightly inward (toward room interior, +X) ΓöÇΓöÇ
  const doorPivot = new Group();
  doorPivot.name = 'doorPivot';
  doorPivot.position.set(wallX - frameDepth / 2, 0, DOOR_CENTER_Z - DOOR_WIDTH / 2);
  doorPivot.rotation.y = DOOR_OPEN_ANGLE;
  scene.add(doorPivot);

  const doorPanel = new Mesh(new BoxGeometry(DOOR_THICKNESS, DOOR_HEIGHT, DOOR_WIDTH), doorMat);
  doorPanel.name = 'doorPanel';
  doorPanel.position.set(0, DOOR_HEIGHT / 2, DOOR_WIDTH / 2);
  doorPanel.castShadow = true;
  doorPivot.add(doorPanel);

  // ΓöÇΓöÇ Classic 4-panel door ΓöÇΓöÇ
  // Panels are recessed grooves ΓÇö slightly darker inset rectangles
  const panelInsetMat = createWoodMaterial('hub_doorPanelInsetMat', new Color(0.48, 0.32, 0.18));
  const panelRailMat = createWoodMaterial('hub_doorPanelRailMat', new Color(0.52, 0.36, 0.2));

  const panelMarginZ = 0.2; // side margin from door edge
  const panelGapY = 0.12; // gap between panels
  const panelInsetW = DOOR_WIDTH - 2 * panelMarginZ; // panel width (Z)

  // Horizontal rails (stiles) ΓÇö the cross-pieces between panels
  const railThick = 0.1;
  const midRailY = DOOR_HEIGHT * 0.48; // middle rail position

  // Mid rail
  const midRail = new Mesh(new BoxGeometry(DOOR_THICKNESS + 0.01, railThick, panelInsetW + 0.04), panelRailMat);
  midRail.name = 'doorMidRail';
  midRail.position.set(0, midRailY - DOOR_HEIGHT / 2, 0);
  doorPanel.add(midRail);

  // Four recessed panels (2 top, 2 bottom of mid rail)
  const topPanelH = (DOOR_HEIGHT - midRailY - railThick / 2 - panelGapY * 2) / 2;
  const botPanelH = (midRailY - railThick / 2 - panelGapY * 2) / 2;
  const panelInsetDepth = 0.02;

  // Top two panels
  const topPanelCenterY = midRailY + railThick / 2 + panelGapY;
  [topPanelCenterY + topPanelH / 2, topPanelCenterY + topPanelH + panelGapY + topPanelH / 2].forEach((py, i) => {
    // Single wide panel per row for a classic look
    const panel = new Mesh(new BoxGeometry(panelInsetDepth, topPanelH - 0.04, panelInsetW - 0.08), panelInsetMat);
    panel.name = `doorTopPanel${i}`;
    panel.position.set(DOOR_THICKNESS / 2 - panelInsetDepth / 2 + 0.002, py - DOOR_HEIGHT / 2, 0);
    doorPanel.add(panel);

    // Matching panel on back side
    const panelBack = new Mesh(new BoxGeometry(panelInsetDepth, topPanelH - 0.04, panelInsetW - 0.08), panelInsetMat);
    panelBack.name = `doorTopPanelBack${i}`;
    panelBack.position.set(-DOOR_THICKNESS / 2 + panelInsetDepth / 2 - 0.002, py - DOOR_HEIGHT / 2, 0);
    doorPanel.add(panelBack);
  });

  // Bottom two panels (taller than top panels ΓÇö classic proportions)
  const botPanelCenterY = panelGapY;
  [botPanelCenterY + botPanelH / 2, botPanelCenterY + botPanelH + panelGapY + botPanelH / 2].forEach((py, i) => {
    const panel = new Mesh(new BoxGeometry(panelInsetDepth, botPanelH - 0.04, panelInsetW - 0.08), panelInsetMat);
    panel.name = `doorBotPanel${i}`;
    panel.position.set(DOOR_THICKNESS / 2 - panelInsetDepth / 2 + 0.002, py - DOOR_HEIGHT / 2, 0);
    doorPanel.add(panel);

    const panelBack = new Mesh(new BoxGeometry(panelInsetDepth, botPanelH - 0.04, panelInsetW - 0.08), panelInsetMat);
    panelBack.name = `doorBotPanelBack${i}`;
    panelBack.position.set(-DOOR_THICKNESS / 2 + panelInsetDepth / 2 - 0.002, py - DOOR_HEIGHT / 2, 0);
    doorPanel.add(panelBack);
  });

  // ΓöÇΓöÇ Door knob ΓÇö on the left side (+Z end, viewer's left) ΓöÇΓöÇ
  // Knob plate (escutcheon)
  const plateMat = createToyMetalMaterial('hub_doorPlateMat', new Color(0.7, 0.6, 0.38));
  const plate = new Mesh(new BoxGeometry(0.008, 0.18, 0.07), plateMat);
  plate.name = 'doorKnobPlate';
  plate.position.set(DOOR_THICKNESS / 2 + 0.004, midRailY - DOOR_HEIGHT / 2, DOOR_WIDTH * 0.35);
  doorPanel.add(plate);

  // Round knob
  const knob = new Mesh(new SphereGeometry(0.05, 10, 10), knobMat);
  knob.name = 'doorKnob';
  knob.position.set(DOOR_THICKNESS / 2 + 0.04, midRailY - DOOR_HEIGHT / 2, DOOR_WIDTH * 0.35);
  doorPanel.add(knob);

  // Knob stem
  const stem = new Mesh(new CylinderGeometry(0.015, 0.015, 0.04, 8), knobMat);
  stem.name = 'doorKnobStem';
  stem.position.set(-0.02, 0, 0);
  stem.rotation.z = Math.PI / 2;
  knob.add(stem);

  // Back side knob
  const knobBack = new Mesh(new SphereGeometry(0.05, 10, 10), knobMat);
  knobBack.name = 'doorKnobBack';
  knobBack.position.set(-DOOR_THICKNESS / 2 - 0.04, midRailY - DOOR_HEIGHT / 2, DOOR_WIDTH * 0.35);
  doorPanel.add(knobBack);

  const stemBack = new Mesh(new CylinderGeometry(0.015, 0.015, 0.04, 8), knobMat);
  stemBack.name = 'doorKnobStemBack';
  stemBack.position.set(0.02, 0, 0);
  stemBack.rotation.z = Math.PI / 2;
  knobBack.add(stemBack);
}

import { Color, CylinderGeometry, Mesh, PlaneGeometry, RingGeometry, type Scene } from 'three';
import { createWoodMaterial, createWovenMaterial } from '@app/utils/materialFactory';
import {
  FLOOR_WIDTH,
  FLOOR_DEPTH,
  PLANK_SPACING,
  PLANK_HALF_COUNT,
  RUG_DIAMETER,
  RUG_THICKNESS,
  RUG_BAND_DIAMETERS,
} from '@app/scenes/hub/layout';

/** Creates the wood floor, plank seams, and braided rug. Returns floor and rug meshes for click handling. */
export function createFloor(scene: Scene): { floor: Mesh; rug: Mesh } {
  const floorGeo = new PlaneGeometry(FLOOR_WIDTH, FLOOR_DEPTH);
  floorGeo.rotateX(-Math.PI / 2);
  const floor = new Mesh(floorGeo, createWoodMaterial('floorMat', new Color(0.72, 0.55, 0.35)));
  floor.name = 'floor';
  floor.receiveShadow = true;
  scene.add(floor);

  // Plank seams
  const seamMat = createWoodMaterial('hub_seamMat', new Color(0.58, 0.42, 0.26));
  for (let si = -PLANK_HALF_COUNT; si <= PLANK_HALF_COUNT; si++) {
    const seamGeo = new PlaneGeometry(FLOOR_DEPTH, 0.02);
    const seam = new Mesh(seamGeo, seamMat);
    seam.name = `floorSeam${si + PLANK_HALF_COUNT}`;
    seam.rotation.x = -Math.PI / 2;
    seam.position.set(si * PLANK_SPACING, 0.005, 0);
    seam.rotation.z = Math.PI / 2;
    scene.add(seam);
  }

  // Braided rug
  const rug = new Mesh(
    new CylinderGeometry(RUG_DIAMETER / 2, RUG_DIAMETER / 2, RUG_THICKNESS, 48),
    createWovenMaterial('rugMat', new Color(0.92, 0.85, 0.72)),
  );
  rug.name = 'rug';
  rug.position.y = RUG_THICKNESS / 2;
  rug.receiveShadow = true;
  scene.add(rug);

  const rugBandColors: Color[] = [
    new Color(0.6, 0.35, 0.2),
    new Color(0.85, 0.25, 0.25),
    new Color(1.0, 0.6, 0.15),
    new Color(1.0, 0.85, 0.25),
    new Color(0.4, 0.75, 0.35),
    new Color(0.4, 0.6, 0.9),
    new Color(0.65, 0.4, 0.75),
  ];
  const bandWidth = 0.18;
  for (let ri = 0; ri < RUG_BAND_DIAMETERS.length; ri++) {
    const outerR = RUG_BAND_DIAMETERS[ri] / 2;
    const innerR = outerR - bandWidth;
    const ringGeo = new RingGeometry(innerR, outerR, 48);
    ringGeo.rotateX(-Math.PI / 2);
    const band = new Mesh(ringGeo, createWovenMaterial(`hub_rugBandMat${ri}`, rugBandColors[ri]));
    band.name = `rugBand${ri}`;
    band.position.y = RUG_THICKNESS + 0.005;
    scene.add(band);
  }

  return { floor, rug };
}

import { BoxGeometry, Color, Mesh, type Scene } from 'three';
import { createWoodMaterial } from '@app/utils/materialFactory';
import {
  BACK_WALL_FACE_Z,
  RIGHT_WALL_FACE_X,
  LEFT_WALL_FACE_X,
  ROOM_DEPTH,
  ROOM_SPAN_X,
  CEILING_Y,
} from '@app/scenes/hub/layout';

/** Wainscoting height ΓÇö roughly lower quarter of the wall. */
const WAINSCOT_HEIGHT = CEILING_Y * 0.2; // 1.8
const WAINSCOT_DEPTH = 0.06;
const PANEL_INSET = 0.04;
const RAIL_HEIGHT = 0.1;
const RAIL_DEPTH = 0.08;

/** Door exclusion zone on the right wall (Z range to skip). */
const DOOR_Z_MIN = -1.2;
const DOOR_Z_MAX = 1.2;

/** Creates brown wainscoting panels with a top rail around all three walls, skipping the door opening. */
export function createWainscoting(scene: Scene): void {
  const wainscotMat = createWoodMaterial('hub_wainscotMat', new Color(0.62, 0.48, 0.32));
  const railMat = createWoodMaterial('hub_wainscotRailMat', new Color(0.65, 0.52, 0.36));
  const panelMat = createWoodMaterial('hub_wainscotPanelMat', new Color(0.58, 0.44, 0.28));

  // ΓöÇΓöÇ Back wall wainscoting ΓöÇΓöÇ
  const backBase = new Mesh(new BoxGeometry(ROOM_SPAN_X, WAINSCOT_HEIGHT, WAINSCOT_DEPTH), wainscotMat);
  backBase.name = 'wainscotBack';
  backBase.position.set(0, WAINSCOT_HEIGHT / 2, BACK_WALL_FACE_Z - WAINSCOT_DEPTH / 2);
  scene.add(backBase);

  const backRail = new Mesh(new BoxGeometry(ROOM_SPAN_X, RAIL_HEIGHT, RAIL_DEPTH), railMat);
  backRail.name = 'wainscotBackRail';
  backRail.position.set(0, WAINSCOT_HEIGHT + RAIL_HEIGHT / 2, BACK_WALL_FACE_Z - RAIL_DEPTH / 2);
  scene.add(backRail);

  const backPanelCount = 8;
  const backPanelWidth = (ROOM_SPAN_X - 0.6) / backPanelCount;
  for (let i = 0; i < backPanelCount; i++) {
    const px = -ROOM_SPAN_X / 2 + 0.3 + backPanelWidth * (i + 0.5);
    const panel = new Mesh(new BoxGeometry(backPanelWidth - 0.12, WAINSCOT_HEIGHT - 0.3, PANEL_INSET), panelMat);
    panel.name = `wainscotBackPanel${i}`;
    panel.position.set(px, WAINSCOT_HEIGHT / 2, BACK_WALL_FACE_Z - WAINSCOT_DEPTH - PANEL_INSET / 2 + 0.01);
    scene.add(panel);
  }

  // ΓöÇΓöÇ Right wall wainscoting ΓÇö split into two segments around the door ΓöÇΓöÇ
  const rightHalfDepth = ROOM_DEPTH / 2;

  // Segment before door (Z < DOOR_Z_MIN)
  const seg1Length = rightHalfDepth + DOOR_Z_MIN; // from -ROOM_DEPTH/2 to DOOR_Z_MIN
  const seg1CenterZ = -rightHalfDepth + seg1Length / 2;

  const rightBase1 = new Mesh(new BoxGeometry(WAINSCOT_DEPTH, WAINSCOT_HEIGHT, seg1Length), wainscotMat);
  rightBase1.name = 'wainscotRight1';
  rightBase1.position.set(RIGHT_WALL_FACE_X + WAINSCOT_DEPTH / 2, WAINSCOT_HEIGHT / 2, seg1CenterZ);
  scene.add(rightBase1);

  const rightRail1 = new Mesh(new BoxGeometry(RAIL_DEPTH, RAIL_HEIGHT, seg1Length), railMat);
  rightRail1.name = 'wainscotRightRail1';
  rightRail1.position.set(RIGHT_WALL_FACE_X + RAIL_DEPTH / 2, WAINSCOT_HEIGHT + RAIL_HEIGHT / 2, seg1CenterZ);
  scene.add(rightRail1);

  // Segment after door (Z > DOOR_Z_MAX)
  const seg2Length = rightHalfDepth - DOOR_Z_MAX; // from DOOR_Z_MAX to ROOM_DEPTH/2
  const seg2CenterZ = DOOR_Z_MAX + seg2Length / 2;

  const rightBase2 = new Mesh(new BoxGeometry(WAINSCOT_DEPTH, WAINSCOT_HEIGHT, seg2Length), wainscotMat);
  rightBase2.name = 'wainscotRight2';
  rightBase2.position.set(RIGHT_WALL_FACE_X + WAINSCOT_DEPTH / 2, WAINSCOT_HEIGHT / 2, seg2CenterZ);
  scene.add(rightBase2);

  const rightRail2 = new Mesh(new BoxGeometry(RAIL_DEPTH, RAIL_HEIGHT, seg2Length), railMat);
  rightRail2.name = 'wainscotRightRail2';
  rightRail2.position.set(RIGHT_WALL_FACE_X + RAIL_DEPTH / 2, WAINSCOT_HEIGHT + RAIL_HEIGHT / 2, seg2CenterZ);
  scene.add(rightRail2);

  // Panels on right wall ΓÇö skip panels that overlap the door
  const sidePanelCount = 10;
  const sidePanelDepth = (ROOM_DEPTH - 0.6) / sidePanelCount;
  for (let i = 0; i < sidePanelCount; i++) {
    const pz = -ROOM_DEPTH / 2 + 0.3 + sidePanelDepth * (i + 0.5);
    // Skip panels in the door zone
    if (pz > DOOR_Z_MIN && pz < DOOR_Z_MAX) continue;
    const panel = new Mesh(new BoxGeometry(PANEL_INSET, WAINSCOT_HEIGHT - 0.3, sidePanelDepth - 0.12), panelMat);
    panel.name = `wainscotRightPanel${i}`;
    panel.position.set(RIGHT_WALL_FACE_X + WAINSCOT_DEPTH + PANEL_INSET / 2 - 0.01, WAINSCOT_HEIGHT / 2, pz);
    scene.add(panel);
  }

  // ΓöÇΓöÇ Left wall wainscoting ΓöÇΓöÇ
  const leftBase = new Mesh(new BoxGeometry(WAINSCOT_DEPTH, WAINSCOT_HEIGHT, ROOM_DEPTH), wainscotMat);
  leftBase.name = 'wainscotLeft';
  leftBase.position.set(LEFT_WALL_FACE_X - WAINSCOT_DEPTH / 2, WAINSCOT_HEIGHT / 2, 0);
  scene.add(leftBase);

  const leftRail = new Mesh(new BoxGeometry(RAIL_DEPTH, RAIL_HEIGHT, ROOM_DEPTH), railMat);
  leftRail.name = 'wainscotLeftRail';
  leftRail.position.set(LEFT_WALL_FACE_X - RAIL_DEPTH / 2, WAINSCOT_HEIGHT + RAIL_HEIGHT / 2, 0);
  scene.add(leftRail);

  for (let i = 0; i < sidePanelCount; i++) {
    const pz = -ROOM_DEPTH / 2 + 0.3 + sidePanelDepth * (i + 0.5);
    const panel = new Mesh(new BoxGeometry(PANEL_INSET, WAINSCOT_HEIGHT - 0.3, sidePanelDepth - 0.12), panelMat);
    panel.name = `wainscotLeftPanel${i}`;
    panel.position.set(LEFT_WALL_FACE_X - WAINSCOT_DEPTH - PANEL_INSET / 2 + 0.01, WAINSCOT_HEIGHT / 2, pz);
    scene.add(panel);
  }
}

import {
  BoxGeometry,
  CircleGeometry,
  Color,
  CylinderGeometry,
  Mesh,
  PlaneGeometry,
  SphereGeometry,
  type Scene,
} from 'three';
import {
  createGlossyPaintMaterial,
  createPaperMaterial,
  createPlasticMaterial,
  createWoodMaterial,
} from '@app/utils/materialFactory';
import { BACK_WALL_FACE_Z, BOOKSHELF_CENTER_X, LEFT_WALL_FACE_X, CEILING_Y } from '@app/scenes/hub/layout';

/** Creates the framed picture above the bookshelf and Andy's art wall on the left. */
export function createWallArt(scene: Scene): void {
  createBookshelfPicture(scene);
  createAndysWall(scene);
}

// ΓöÇΓöÇ Framed picture above bookshelf ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Creates a framed picture centered above the bookshelf on the back wall. */
function createBookshelfPicture(scene: Scene): void {
  const wallZ = BACK_WALL_FACE_Z - 0.08; // in front of wall face
  const picY = CEILING_Y * 0.45 + 1.1; // moved up ~2 feet
  const picW = 1.8;
  const picH = 1.3;

  // Frame
  const frameMat = createWoodMaterial('hub_picFrameMat', new Color(0.55, 0.38, 0.22));
  const frameThick = 0.1;
  const frameDepth = 0.06;

  // Top/bottom bars
  [picH / 2, -picH / 2].forEach((yOff, i) => {
    const bar = new Mesh(new BoxGeometry(picW + frameThick * 2, frameThick, frameDepth), frameMat);
    bar.name = `picFrame${i === 0 ? 'Top' : 'Bot'}`;
    bar.position.set(BOOKSHELF_CENTER_X, picY + yOff, wallZ);
    scene.add(bar);
  });

  // Side bars
  [-1, 1].forEach((side, i) => {
    const bar = new Mesh(new BoxGeometry(frameThick, picH, frameDepth), frameMat);
    bar.name = `picFrameSide${i}`;
    bar.position.set(BOOKSHELF_CENTER_X + side * (picW / 2 + frameThick / 2), picY, wallZ);
    scene.add(bar);
  });

  // Canvas ΓÇö a simple landscape: green ground, blue sky, yellow sun
  // All flat meshes face +Z by default; rotate to face -Z (toward camera)
  const canvasMat = createPlasticMaterial('hub_picCanvasMat', new Color(0.55, 0.78, 0.95));
  const canvas = new Mesh(new PlaneGeometry(picW, picH), canvasMat);
  canvas.name = 'picCanvas';
  canvas.position.set(BOOKSHELF_CENTER_X, picY, wallZ - 0.01);
  canvas.rotation.y = Math.PI;
  scene.add(canvas);

  // Ground strip ΓÇö green hills
  const groundMat = createPlasticMaterial('hub_picGroundMat', new Color(0.35, 0.65, 0.25));
  const ground = new Mesh(new PlaneGeometry(picW, picH * 0.35), groundMat);
  ground.name = 'picGround';
  ground.position.set(BOOKSHELF_CENTER_X, picY - picH * 0.325, wallZ - 0.015);
  ground.rotation.y = Math.PI;
  scene.add(ground);

  // Sun ΓÇö yellow circle
  const sunMat = createGlossyPaintMaterial('hub_picSunMat', new Color(1.0, 0.9, 0.3));
  sunMat.emissive = new Color(0.15, 0.12, 0.02);
  const sun = new Mesh(new CircleGeometry(0.15, 12), sunMat);
  sun.name = 'picSun';
  sun.position.set(BOOKSHELF_CENTER_X + 0.5, picY + 0.35, wallZ - 0.02);
  sun.rotation.y = Math.PI;
  scene.add(sun);

  // Simple hill bumps
  const hillMat = createPlasticMaterial('hub_picHillMat', new Color(0.3, 0.55, 0.2));
  const hills = [
    { x: -0.4, r: 0.3 },
    { x: 0.2, r: 0.25 },
    { x: 0.6, r: 0.22 },
  ];
  for (let i = 0; i < hills.length; i++) {
    const hill = new Mesh(new CircleGeometry(hills[i].r, 12), hillMat);
    hill.name = `picHill${i}`;
    hill.position.set(BOOKSHELF_CENTER_X + hills[i].x, picY - picH * 0.15, wallZ - 0.018);
    hill.rotation.y = Math.PI;
    scene.add(hill);
  }
}

// ΓöÇΓöÇ Andy's art wall ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

