      color: new Color(0.9, 0.95, 0.88),
      frameColor: new Color(0, 0, 0),
    },
    {
      z: 1.5,
      y: 5.9 - DROP,
      w: 0.8,
      h: 0.6,
      rot: -0.15,
      color: new Color(1.0, 0.95, 0.85),
      frameColor: new Color(0, 0, 0),
    },
    {
      z: 4.5,
      y: 6.5 - DROP,
      w: 0.9,
      h: 0.7,
      rot: 0.2,
      color: new Color(0.92, 0.9, 0.98),
      frameColor: new Color(0, 0, 0),
    },
    {
      z: -0.5,
      y: 4.5 - DROP,
      w: 1.1,
      h: 0.8,
      rot: 0.0,
      color: new Color(0.95, 0.92, 0.85),
      frameColor: new Color(0, 0, 0),
    },
    {
      z: 2.8,
      y: 5.2 - DROP,
      w: 0.6,
