import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  TorusGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import type { SceneId } from '@app/types/scenes';
import { createWoodMaterial, createGlossyPaintMaterial, createToyMetalMaterial } from '@app/utils/materialFactory';
import { attachToyboxRuntime, applyBreathingAnimation } from './shared';
import { buildToyboxEmblem } from './emblem';

/** Creates a classic painted-chest toybox with lid, hinges, clasp, and emblem. */
export function createClassicToybox(
  scene: Scene,
  config: { id: SceneId; base: Color; accent: Color; pos: Vector3; rot: number },
  _keyLight: DirectionalLight,
): Group {
  const root = new Group();
  root.name = `toybox_${config.id}_root`;
  root.position.copy(config.pos);
  root.position.y += 0.7;
  root.rotation.y = config.rot;
  scene.add(root);

  const bodyMat = createGlossyPaintMaterial(`toybox_${config.id}_mat`, config.base);

  const body = new Mesh(new BoxGeometry(1.8, 1.2, 1.4), bodyMat);
  body.name = `toybox_${config.id}_body`;
  body.castShadow = true;
  root.add(body);

  const cornerMat = createGlossyPaintMaterial(`toybox_${config.id}_cornerMat`, config.base.clone().multiplyScalar(0.9));
  const cornerPositions = [
    new Vector3(-0.88, 0, 0.68),
    new Vector3(0.88, 0, 0.68),
    new Vector3(-0.88, 0, -0.68),
    new Vector3(0.88, 0, -0.68),
  ];
  for (let ci = 0; ci < cornerPositions.length; ci++) {
    const corner = new Mesh(new CylinderGeometry(0.06, 0.06, 1.18, 8), cornerMat);
    corner.name = `toybox_${config.id}_corner${ci}`;
    corner.position.copy(cornerPositions[ci]);
    root.add(corner);
  }

  const lid = new Mesh(
    new BoxGeometry(2.0, 0.3, 1.6),
    createGlossyPaintMaterial(`toybox_${config.id}_lidMat`, config.base.clone().multiplyScalar(0.85)),
  );
  lid.name = `toybox_${config.id}_lid`;
  lid.position.y = 0.75;
  lid.castShadow = true;
  root.add(lid);

  const ridge = new Mesh(
    new BoxGeometry(2.04, 0.06, 1.64),
    createGlossyPaintMaterial(`toybox_${config.id}_ridgeMat`, config.base.clone().multiplyScalar(0.7)),
  );
  ridge.name = `toybox_${config.id}_ridge`;
  ridge.position.y = 0.93;
  root.add(ridge);

  const trim = new Mesh(
    new BoxGeometry(1.85, 0.12, 1.45),
    createGlossyPaintMaterial(`toybox_${config.id}_trimMat`, config.accent),
  );
  trim.name = `toybox_${config.id}_trim`;
  trim.position.y = -0.56;
  root.add(trim);

  const footMat = createWoodMaterial(`toybox_${config.id}_footMat`, new Color(0.5, 0.35, 0.2));
  const footPositions = [
    new Vector3(-0.75, -0.68, 0.55),
    new Vector3(0.75, -0.68, 0.55),
    new Vector3(-0.75, -0.68, -0.55),
    new Vector3(0.75, -0.68, -0.55),
  ];
  for (let fi = 0; fi < footPositions.length; fi++) {
    const foot = new Mesh(new CylinderGeometry(0.07, 0.07, 0.1, 8), footMat);
    foot.name = `toybox_${config.id}_foot${fi}`;
    foot.position.copy(footPositions[fi]);
    root.add(foot);
  }

  const hingeMat = createToyMetalMaterial(`toybox_${config.id}_hingeMat`, new Color(0.7, 0.65, 0.5));
  [-0.5, 0.5].forEach((xOff, hi) => {
    const hinge = new Mesh(new CylinderGeometry(0.04, 0.04, 0.15, 8), hingeMat);
    hinge.name = `hinge_${config.id}_${hi}`;
    hinge.position.set(xOff, 0.6, -0.72);
    hinge.rotation.x = Math.PI / 2;
    root.add(hinge);

    const plate = new Mesh(new BoxGeometry(0.18, 0.22, 0.02), hingeMat);
    plate.name = `plate_${config.id}_${hi}`;
    plate.position.set(xOff, 0.55, -0.71);
    root.add(plate);
  });

  const clasp = new Mesh(new BoxGeometry(0.12, 0.18, 0.03), hingeMat);
  clasp.name = `clasp_${config.id}`;
  clasp.position.set(0, -0.05, 0.72);
  root.add(clasp);

  const claspRing = new Mesh(new TorusGeometry(0.05, 0.0075, 16, 12), hingeMat);
  claspRing.name = `claspRing_${config.id}`;
  claspRing.position.set(0, -0.12, 0.74);
  claspRing.rotation.x = Math.PI / 2;
  root.add(claspRing);

  const stripe = new Mesh(
    new BoxGeometry(1.82, 0.08, 0.02),
    createGlossyPaintMaterial(`toybox_${config.id}_stripeMat`, config.accent),
  );
  stripe.name = `toybox_${config.id}_stripe`;
  stripe.position.set(0, 0.0, 0.72);
  root.add(stripe);

  buildToyboxEmblem(scene, root, config.id, config.accent);
  applyBreathingAnimation(scene, root, config.id);
  attachToyboxRuntime(root, {
    hoverMaterials: [bodyMat],
    pickMeshes: [body],
    lidAnimations: [{ mesh: lid, propertyPath: 'rotation.x', peakValue: -0.6, settleValue: -0.5 }],
  });

  return root;
}

import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  Group,
  Mesh,
  SphereGeometry,
  Vector3,
  type DirectionalLight,
  type Scene,
} from 'three';
import type { SceneId } from '@app/types/scenes';
import { createWoodMaterial, createGlossyPaintMaterial, createToyMetalMaterial } from '@app/utils/materialFactory';
import { attachToyboxRuntime, applyBreathingAnimation } from './shared';
import { buildToyboxEmblem } from './emblem';

/** Dresser width ΓÇö twice a normal toybox. */
const BODY_W = 3.6;
const BODY_H = 1.2;
const BODY_D = 1.4;
const DRAWER_COUNT = 4;
const DRAWER_GAP = 0.04;

/** Creates a dresser-style toybox with 4 drawers and round knobs. */
export function createDresserToybox(
  scene: Scene,
  config: { id: SceneId; base: Color; accent: Color; pos: Vector3; rot: number },
  _keyLight: DirectionalLight,
): Group {
  const root = new Group();
  root.name = `toybox_${config.id}_root`;
  root.position.copy(config.pos);
  root.position.y += 0.7;
  root.rotation.y = config.rot;
  scene.add(root);

  const bodyMat = createGlossyPaintMaterial(`toybox_${config.id}_mat`, config.base);
  const darkerMat = createGlossyPaintMaterial(
    `toybox_${config.id}_darkerMat`,
    config.base.clone().multiplyScalar(0.85),
  );
  const knobMat = createToyMetalMaterial(`toybox_${config.id}_knobMat`, new Color(0.75, 0.65, 0.4));
  const footMat = createWoodMaterial(`toybox_${config.id}_footMat`, new Color(0.5, 0.35, 0.2));

  // ΓöÇΓöÇ Main body (frame) ΓöÇΓöÇ
  const body = new Mesh(new BoxGeometry(BODY_W, BODY_H, BODY_D), bodyMat);
  body.name = `toybox_${config.id}_body`;
  body.castShadow = true;
  root.add(body);

  // ΓöÇΓöÇ Top surface ΓöÇΓöÇ
  const top = new Mesh(
    new BoxGeometry(BODY_W + 0.1, 0.08, BODY_D + 0.1),
    createGlossyPaintMaterial(`toybox_${config.id}_topMat`, config.base.clone().multiplyScalar(0.9)),
  );
  top.name = `toybox_${config.id}_top`;
  top.position.y = BODY_H / 2 + 0.04;
  top.castShadow = true;
  root.add(top);

  // ΓöÇΓöÇ Bottom trim ΓöÇΓöÇ
  const trim = new Mesh(
    new BoxGeometry(BODY_W + 0.05, 0.1, BODY_D + 0.05),
    createGlossyPaintMaterial(`toybox_${config.id}_trimMat`, config.accent),
  );
  trim.name = `toybox_${config.id}_trim`;
  trim.position.y = -BODY_H / 2 - 0.02;
  root.add(trim);

  // ΓöÇΓöÇ Feet ΓöÇΓöÇ
  const footOffX = BODY_W / 2 - 0.15;
  const footOffZ = BODY_D / 2 - 0.15;
  const footY = -BODY_H / 2 - 0.12;
  [
    new Vector3(-footOffX, footY, footOffZ),
    new Vector3(footOffX, footY, footOffZ),
    new Vector3(-footOffX, footY, -footOffZ),
    new Vector3(footOffX, footY, -footOffZ),
  ].forEach((fp, fi) => {
    const foot = new Mesh(new CylinderGeometry(0.08, 0.06, 0.14, 8), footMat);
    foot.name = `toybox_${config.id}_foot${fi}`;
    foot.position.copy(fp);
    root.add(foot);
  });

  // ΓöÇΓöÇ 4 Drawers ΓÇö stacked vertically ΓöÇΓöÇ
  const totalGap = (DRAWER_COUNT + 1) * DRAWER_GAP;
  const drawerH = (BODY_H - totalGap) / DRAWER_COUNT;
  const drawerW = BODY_W - 0.12;
  const drawerD = 0.04;
  const drawerFrontZ = BODY_D / 2 + 0.005;

  const drawerMeshes: Mesh[] = [];

  for (let di = 0; di < DRAWER_COUNT; di++) {
    const drawerY = -BODY_H / 2 + DRAWER_GAP + drawerH / 2 + di * (drawerH + DRAWER_GAP);

    // Drawer face
    const drawer = new Mesh(new BoxGeometry(drawerW, drawerH - 0.02, drawerD), darkerMat);
    drawer.name = `toybox_${config.id}_drawer${di}`;
    drawer.position.set(0, drawerY, drawerFrontZ);
    root.add(drawer);
    drawerMeshes.push(drawer);

    // Round knobs ΓÇö two per drawer
    [-0.4, 0.4].forEach((kx, ki) => {
      const knob = new Mesh(new SphereGeometry(0.045, 8, 8), knobMat);
      knob.name = `toybox_${config.id}_knob${di}_${ki}`;
      knob.position.set(kx, 0, drawerD / 2 + 0.03);
      drawer.add(knob);
    });
  }

  // ΓöÇΓöÇ Side panels ΓÇö subtle accent stripe ΓöÇΓöÇ
  [-1, 1].forEach((side, si) => {
    const panel = new Mesh(
      new BoxGeometry(0.02, BODY_H - 0.1, BODY_D - 0.2),
      createGlossyPaintMaterial(`toybox_${config.id}_sidePanel${si}`, config.accent),
    );
    panel.name = `toybox_${config.id}_sidePanel${si}`;
    panel.position.set(side * (BODY_W / 2 + 0.005), 0, 0);
    root.add(panel);
  });

  buildToyboxEmblem(scene, root, config.id, config.accent);
  applyBreathingAnimation(scene, root, config.id);
  attachToyboxRuntime(root, {
    hoverMaterials: [bodyMat],
    pickMeshes: [body, ...drawerMeshes],
    lidAnimations: drawerMeshes.map((mesh, i) => ({
      mesh,
      propertyPath: 'position.z',
      peakValue: drawerFrontZ + 0.3 + i * 0.05,
      settleValue: drawerFrontZ + 0.15,
    })),
  });

  return root;
}

import { CircleGeometry, Color, Group, Mesh, PlaneGeometry, type Scene } from 'three';
import type { SceneId } from '@app/types/scenes';
import { createPlasticMaterial } from '@app/utils/materialFactory';

/** Builds a decorative front-face emblem on a toybox (stars, clover, or heart depending on world). */
export function buildToyboxEmblem(_scene: Scene, parent: Mesh | Group, id: SceneId, accent: Color): void {
  const emblemMat = createPlasticMaterial(`toybox_${id}_emblemMat`, accent);
  emblemMat.emissive = accent.clone().multiplyScalar(0.08);

  if (id === 'adventure') {
    const starMat = createPlasticMaterial(`toybox_${id}_starMat`, new Color(1.0, 0.95, 0.8));
    starMat.emissive = new Color(0.05, 0.04, 0.02);
    const starPositions = [
      { x: 0, y: 0.2, z: 0.72 },
      { x: -0.65, y: 0.35, z: 0.72 },
      { x: 0.65, y: 0.35, z: 0.72 },
      { x: -0.65, y: -0.25, z: 0.72 },
      { x: 0.65, y: -0.25, z: 0.72 },
    ];
    const starSizes = [0.18, 0.1, 0.1, 0.08, 0.08];
    for (let si = 0; si < starPositions.length; si++) {
      const star = new Mesh(new CircleGeometry(starSizes[si], 5), starMat);
      star.name = `toybox_${id}_star${si}`;
      star.position.set(starPositions[si].x, starPositions[si].y, starPositions[si].z);
      star.rotation.z = si * 0.4;
      parent.add(star);
    }
  } else if (id === 'creative') {
    const leafMat = createPlasticMaterial(`toybox_${id}_leafMat`, new Color(0.4, 0.7, 0.35));
    const cloverAngles = [0, (Math.PI * 2) / 3, (Math.PI * 4) / 3];
    for (let cli = 0; cli < cloverAngles.length; cli++) {
      const leaf = new Mesh(new CircleGeometry(0.08, 10), leafMat);
      leaf.name = `toybox_${id}_clover${cli}`;
      const cx = Math.sin(cloverAngles[cli]) * 0.08;
      const cy = Math.cos(cloverAngles[cli]) * 0.08 + 0.25;
      leaf.position.set(cx, cy, 0.72);
      parent.add(leaf);
    }

    const stemMat = createPlasticMaterial(`toybox_${id}_stemMat`, new Color(0.35, 0.6, 0.3));
    const stem = new Mesh(new PlaneGeometry(0.02, 0.15), stemMat);
    stem.name = `toybox_${id}_stem`;
    stem.position.set(0, 0.1, 0.72);
    parent.add(stem);

    const borderMat = createPlasticMaterial(`toybox_${id}_borderMat`, new Color(0.95, 0.92, 0.82));
    const borders = [
      { w: 1.6, h: 0.03, pos: { x: 0, y: 0.5, z: 0.72 } },
      { w: 1.6, h: 0.03, pos: { x: 0, y: -0.4, z: 0.72 } },
    ];
    for (let bi = 0; bi < borders.length; bi++) {
      const border = new Mesh(new PlaneGeometry(borders[bi].w, borders[bi].h), borderMat);
      border.name = `toybox_${id}_border${bi}`;
      border.position.set(borders[bi].pos.x, borders[bi].pos.y, borders[bi].pos.z);
      parent.add(border);
    }
  } else if (id === 'nature') {
    const heartMat = createPlasticMaterial(`toybox_${id}_heartMat`, new Color(0.9, 0.6, 0.7));
    const hl = new Mesh(new CircleGeometry(0.07, 10), heartMat);
    hl.name = `toybox_${id}_heartL`;
    hl.position.set(-0.05, 0.25, 0.72);
    parent.add(hl);

    const hr = new Mesh(new CircleGeometry(0.07, 10), heartMat);
    hr.name = `toybox_${id}_heartR`;
    hr.position.set(0.05, 0.25, 0.72);
    parent.add(hr);

    const hb = new Mesh(new CircleGeometry(0.08, 3), heartMat);
    hb.name = `toybox_${id}_heartBot`;
    hb.position.set(0, 0.16, 0.72);
    hb.rotation.z = Math.PI;
    parent.add(hb);

    const moonMat = createPlasticMaterial(`toybox_${id}_moonMat`, new Color(1.0, 0.95, 0.7));
    const moonFull = new Mesh(new CircleGeometry(0.08, 12), moonMat);
    moonFull.name = `toybox_${id}_moon`;
    moonFull.position.set(0, -0.05, 0.72);
    parent.add(moonFull);
  }
}

import type { Scene, DirectionalLight, Mesh } from 'three';
import type { SceneId } from '@app/types/scenes';
import { Color, Vector3, Group } from 'three';
import { TOYBOXES, type HubToyboxRuntime, type ToyboxLidAnimation } from './types';
import { createClassicToybox } from './classicToybox';
import { createAnimalsToybox } from './animalsToybox';
import { createDresserToybox } from './dresserToybox';

export { TOYBOXES, type HubToyboxRuntime, type ToyboxLidAnimation };

/**
 * Creates a themed toybox mesh for the Playroom Hub. Most toyboxes retain the
 * classic painted chest silhouette, while the Animals toybox becomes a toy-filled
 * open box inspired by the user-provided reference.
 */
export function createToybox(
  scene: Scene,
  config: { id: SceneId; base: Color; accent: Color; pos: Vector3; rot: number; scale?: number },
  keyLight: DirectionalLight,
): Group {
  let root: Group;
  if (config.id === 'animals') {
    root = createAnimalsToybox(scene, config, keyLight);
  } else if (config.id === 'creative') {
    root = createDresserToybox(scene, config, keyLight);
  } else {
    root = createClassicToybox(scene, config, keyLight);
  }

  if (config.scale && config.scale !== 1) {
    // The toybox creators set root.position.y = config.pos.y + offset.
    // Scaling shrinks the visual but not the position, causing floating.
    // Fix: scale the Y offset proportionally.
    const offset = root.position.y - config.pos.y;
    root.position.y = config.pos.y + offset * config.scale;
    root.scale.setScalar(config.scale);
  }

  return root;
}

/** Retrieves the runtime interaction data stored on a toybox root mesh. */
export function getToyboxRuntime(root: Mesh | Group): HubToyboxRuntime | undefined {
  return root.userData?.hubToyboxRuntime as HubToyboxRuntime | undefined;
}

