import { Scene, Vector3, Color, Mesh, Group, SphereGeometry, CylinderGeometry } from 'three';
import { createGlossyPaintMaterial, createTranslucentMaterial } from '@app/utils/materialFactory';
import { createSparkleBurst } from '@app/utils/particles';
import { startIdleLoop } from '@app/utils/animationHelpers';
import { idleWithInterrupt } from '@app/utils/idleInterruptible';
import type { EntityPlacement } from '../../../types';
import type { ButterflyBuildOptions } from './types';

/**
 * Builds a butterfly with a body, two translucent wings with flutter animation,
 * and an idle drift path. Tap triggers a flee-and-return reaction via the shared
 * idleWithInterrupt utility with lockDuringReaction to prevent re-triggering mid-flee.
 */
export function buildButterfly(scene: Scene, placement: EntityPlacement, options: ButterflyBuildOptions): Group {
  const { config } = options;
  const root = new Group();
  root.name = 'butterfly_root';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const body = new Mesh(new CylinderGeometry(0.02 / 2, 0.03 / 2, 0.15, 6), createGlossyPaintMaterial('bflyBodyMat', new Color(0.1, 0.1, 0.1)));
  body.name = 'bfly_body';
  body.rotation.x = Math.PI / 2;
  root.add(body);

  const wingMat = createTranslucentMaterial('bflyWingMat', config.wingColor, 0.7);
  const wingL = new Mesh(new SphereGeometry(0.5, 6, 6), wingMat);
  wingL.name = 'bfly_wingL';
  wingL.scale.set(0.2, 0.02, 0.15);
  wingL.position.set(-0.1, 0, 0);
  root.add(wingL);

  const wingR = new Mesh(new SphereGeometry(0.5, 6, 6), wingMat);
  wingR.name = 'bfly_wingR';
  wingR.scale.set(0.2, 0.02, 0.15);
  wingR.position.set(0.1, 0, 0);
  root.add(wingR);

  startIdleLoop(wingL, 'rotation.z', [
    { frame: 0, value: 0 },
    { frame: 5, value: 0.5 },
    { frame: 10, value: 0 },
  ]);

  startIdleLoop(wingR, 'rotation.z', [
    { frame: 0, value: 0 },
    { frame: 5, value: -0.5 },
    { frame: 10, value: 0 },
  ]);

  const homePos = placement.position.clone();
  const handle = idleWithInterrupt(root, {
    idleProperty: 'position',
    idleKeys: [
      { frame: 0, value: homePos.clone() },
      { frame: 90, value: new Vector3(homePos.x + 0.5, homePos.y + 0.2, homePos.z + 0.3) },
      { frame: 180, value: new Vector3(homePos.x - 0.3, homePos.y - 0.1, homePos.z - 0.2) },
      { frame: 270, value: homePos.clone() },
    ],
    reactionAnimations: () => {
      const p = root.position.clone();
      const fleePos = new Vector3(p.x + (Math.random() - 0.5) * 3, p.y + 1.5, p.z + (Math.random() - 0.5) * 3);
      return [
        {
          property: 'position',
          keys: [
            { frame: 0, value: p },
            { frame: 15, value: fleePos },
            { frame: 60, value: homePos.clone() },
          ],
        },
      ];
    },
    particleFn: createSparkleBurst,
    particleOffset: new Vector3(0, 0.1, 0),
    lockDuringReaction: true,
  });
  root.userData = { handle };

  return root;
}

import { Color } from 'three';
import type { ButterflyConfig } from './types';

export const ButterflyVariant = {
  BlueMorpho: 'blueMorpho',
  SunsetSkipper: 'sunsetSkipper',
