import { type Camera, Group, Mesh, Scene } from 'three';
import { onTap } from '@app/utils/sceneHelpers';
import type { IdleInterruptHandle } from '@app/utils/idleInterruptible';

/**
 * Registers a tap interaction on a butterfly that triggers the flee-and-return reaction.
 */
export function setupButterflyTap(_scene: Scene, canvas: HTMLCanvasElement, camera: Camera, butterfly: Group): void {
  const body = butterfly.children.find((m) => m.name === 'bfly_body');
  if (!body) return;
  const handle = butterfly.userData?.handle as IdleInterruptHandle | undefined;

  onTap(canvas, camera, body as Mesh, () => {
    handle?.trigger();
  });
}

import { Scene, Mesh, Group, PlaneGeometry, CylinderGeometry } from 'three';
import type { EntityPlacement } from '../../../types';
import type { FernBuildOptions } from './types';

/** Builds a detailed fern with serrated fronds that have individual leaflets. */
export function buildFern(scene: Scene, placement: EntityPlacement, options: FernBuildOptions): Group {
  const { materials } = options;
  const root = new Group();
  root.name = 'fern_root';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const frondCount = 5 + Math.floor(Math.random() * 3);
  for (let f = 0; f < frondCount; f++) {
    const frondGroup = new Group();
    frondGroup.name = `frond_${f}`;
    frondGroup.rotation.y = (f * Math.PI * 2) / frondCount + Math.random() * 0.3;
    frondGroup.rotation.x = -0.3 - Math.random() * 0.3;
    root.add(frondGroup);

    const stemLen = 0.4 + Math.random() * 0.2;
    const stem = new Mesh(new CylinderGeometry(0.008, 0.012, stemLen, 4), materials.frond);
    stem.name = `frondStem_${f}`;
    stem.position.y = stemLen / 2;
    frondGroup.add(stem);

    const leafletCount = 5 + Math.floor(Math.random() * 3);
    for (let l = 0; l < leafletCount; l++) {
      const t = (l + 1) / (leafletCount + 1);
      const leafSize = 0.06 * (1 - t * 0.4);
      [-1, 1].forEach((side) => {
        const leaflet = new Mesh(new PlaneGeometry(leafSize, leafSize * 2), materials.frond);
        leaflet.name = `leaflet_${f}_${l}_${side}`;
        leaflet.position.set(side * 0.04, t * stemLen - stemLen * 0.4, 0);
        leaflet.rotation.z = side * 0.5;
        leaflet.rotation.y = side * 0.3;
        stem.add(leaflet);
      });
    }
  }

  return root;
}

import { Scene, Color, Mesh, Group, SphereGeometry, CylinderGeometry } from 'three';
import { createGlossyPaintMaterial, createFeltMaterial, getOrCreateMaterial } from '@app/utils/materialFactory';
import type { EntityPlacement } from '../../../types';
import type { FlowerBuildOptions } from './types';

/**
 * Builds a flower with a stem, center, and five petals that start closed.
 */
export function buildFlower(scene: Scene, placement: EntityPlacement, options: FlowerBuildOptions): Group {
  const { config, materials } = options;
  const root = new Group();
  root.name = 'flower_root';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const stem = new Mesh(new CylinderGeometry(0.03 / 2, 0.04 / 2, 0.5, 6), materials.stem);
  stem.name = 'flower_stem';
  stem.position.y = 0.25;
  stem.castShadow = true;
  root.add(stem);

  const centerMat = getOrCreateMaterial('flowerCenterMat', () => createGlossyPaintMaterial('flowerCenterMat', new Color(1, 0.85, 0.2)));
  const center = new Mesh(new SphereGeometry(0.12 / 2, 8, 8), centerMat);
  center.name = 'flower_center';
  center.position.y = 0.52;
  root.add(center);

  const petalMatName = `petalMat_#${config.petalColor.getHexString()}`;
  const petalMat = getOrCreateMaterial(petalMatName, () => createFeltMaterial(petalMatName, config.petalColor));
  for (let p = 0; p < 5; p++) {
    const petal = new Mesh(new SphereGeometry(0.5, 6, 6), petalMat);
    petal.name = `petal_${p}`;
    petal.scale.set(0.15 * 0.5, 0.06 * 0.5, 0.08 * 0.5);
    const angle = (p * Math.PI * 2) / 5;
    petal.position.set(Math.cos(angle) * 0.1, 0.5, Math.sin(angle) * 0.1);
    petal.rotation.y = angle;
    root.add(petal);
  }

  return root;
}

