import { type Camera, Scene, Vector3, Mesh, Group } from 'three';
import { onTap } from '@app/utils/sceneHelpers';
import { playAnimation } from '@app/utils/animationHelpers';
import { createBurstEffect, POLLEN_BURST } from '@app/utils/particleFactory';

/**
 * Registers a tap interaction on a flower that blooms open the petals on first
 * tap and emits a pollen burst particle effect.
 */
export function setupFlowerTap(scene: Scene, canvas: HTMLCanvasElement, camera: Camera, flower: Group): void {
  const center = flower.children.find((m) => m.name === 'flower_center');
  if (!center) return;

  let isOpen = false;

  onTap(canvas, camera, center as Mesh, () => {
    const petals = flower.children.filter((m) => m.name.startsWith('petal_'));

    if (!isOpen) {
      petals.forEach((petal, i) => {
        playAnimation(petal, 'scale', [
          { frame: 0, value: petal.scale.clone() },
          { frame: 20 + i * 3, value: new Vector3(0.15, 0.06, 0.08) },
        ]);
      });
      isOpen = true;
    }

    createBurstEffect(scene, new Vector3(0, 0.55, 0).add(flower.position), POLLEN_BURST);
  });
}

import { ConeGeometry, Group, Mesh, type Scene } from 'three';
import type { EntityPlacement } from '../../../types';
