function seeded(seed: number): () => number {
  let s = Math.abs(seed * 9301 + 49297) % 233280;
  return () => {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

export function buildGrassPatch(scene: Scene, placement: EntityPlacement, options: GrassPatchBuildOptions): Group {
  const root = new Group();
  root.name = 'grass_patch';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const rand = seeded(placement.position.x * 71.3 + placement.position.z * 131.7);
  const tuftCount = 5 + Math.floor(rand() * 4);
  const radiusX = 0.34 + rand() * 0.14;
  const radiusZ = 0.24 + rand() * 0.12;

  for (let tuftIndex = 0; tuftIndex < tuftCount; tuftIndex++) {
    const tuft = new Group();
    tuft.name = `grass_tuft_${tuftIndex}`;
    const angle = rand() * Math.PI * 2;
    const dist = Math.sqrt(rand());
    tuft.position.set(Math.cos(angle) * radiusX * dist, 0, Math.sin(angle) * radiusZ * dist);
    tuft.rotation.y = rand() * Math.PI * 2;
    root.add(tuft);

    const bladeCount = 4 + Math.floor(rand() * 4);
    for (let bladeIndex = 0; bladeIndex < bladeCount; bladeIndex++) {
      const height = 0.12 + rand() * 0.18;
      const blade = new Mesh(new ConeGeometry(0.012, height, 3), options.materials.blade);
      blade.name = `blade_${bladeIndex}`;
      blade.position.set((rand() - 0.5) * 0.08, height / 2, (rand() - 0.5) * 0.08);
      blade.rotation.x = (rand() - 0.5) * 0.3;
      blade.rotation.z = (rand() - 0.5) * 0.3;
      tuft.add(blade);
    }
  }

  return root;
}

import { CircleGeometry, Color, Group, Mesh, type Scene } from 'three';
