] as const;

function seeded(seed: number): () => number {
  let s = Math.abs(seed * 9301 + 49297) % 233280;
  return () => {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

function getLeafMaterial(index: number) {
  const name = `leafLitterMat_${index}`;
  return getOrCreateMaterial(name, () => createFeltMaterial(name, LEAF_LITTER_COLORS[index]));
}

export function buildLeafLitter(scene: Scene, placement: EntityPlacement, options: LeafLitterBuildOptions = {}): Group {
  void options;

  const root = new Group();
  root.name = 'leaf_litter';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const rand = seeded(placement.position.x * 89.1 + placement.position.z * 43.7);
  const leafCount = 4 + Math.floor(rand() * 4);
  const radiusX = 0.32 + rand() * 0.12;
  const radiusZ = 0.2 + rand() * 0.12;

  for (let leafIndex = 0; leafIndex < leafCount; leafIndex++) {
    const size = 0.08 + rand() * 0.08;
    const leaf = new Mesh(new CircleGeometry(size, 6), getLeafMaterial(Math.floor(rand() * LEAF_LITTER_COLORS.length)));
    const angle = rand() * Math.PI * 2;
    const dist = Math.sqrt(rand());
    leaf.name = `fallen_leaf_${leafIndex}`;
    leaf.rotation.x = -Math.PI / 2;
    leaf.rotation.z = rand() * Math.PI * 2;
    leaf.position.set(Math.cos(angle) * radiusX * dist, rand() * 0.004, Math.sin(angle) * radiusZ * dist);
