function buildLadybug(bugMat: Material, bugSpotMat: Material): Mesh {
  const bug = new Mesh(new SphereGeometry(0.1 / 2, 8, 8), bugMat);
  bug.name = 'ladybug';

  for (let s = 0; s < 3; s++) {
    const spot = new Mesh(new SphereGeometry(0.025 / 2, 6, 6), bugSpotMat);
    spot.name = `bugSpot_${s}`;
    spot.position.set((s - 1) * 0.03, 0.04, 0);
    bug.add(spot);
  }

  return bug;
}

/**
 * Builds a flat leaf disc on the ground.
 */
export function buildLeaf(scene: Scene, placement: EntityPlacement, options: LeafBuildOptions): Mesh {
  const { materials } = options;
  const geo = new CircleGeometry(0.3, 8);
  geo.rotateX(-Math.PI / 2);
  const leaf = new Mesh(geo, materials.body);
  const revealHandle: LeafRevealHandle = {
    ladybug: buildLadybug(materials.ladybug, materials.ladybugSpot),
  };
  leaf.name = 'leaf';
  leaf.position.copy(placement.position);
  leaf.rotation.y = placement.rotY ?? 0;
  leaf.userData = { ...leaf.userData, revealHandle };
  scene.add(leaf);
  return leaf;
}

import { type Camera, Scene, Vector3, type Mesh } from 'three';
import { createSparkleBurst } from '@app/utils/particles';
import { createRevealInteraction } from '@app/utils/revealInteraction';
import type { LeafRevealHandle } from './types';

/**
 * Registers a tap interaction on a leaf that flips it over and reveals a ladybug.
 */
export function setupLeafTap(scene: Scene, canvas: HTMLCanvasElement, camera: Camera, leaf: Mesh): void {
  const revealHandle = leaf.userData?.revealHandle as LeafRevealHandle | undefined;
  if (!revealHandle) return;

  createRevealInteraction(scene, canvas, camera, {
    coverMesh: leaf,
    coverAnimation: {
      property: 'rotation.z',
      keys: [
        { frame: 0, value: leaf.rotation.z },
        { frame: 15, value: leaf.rotation.z + Math.PI },
      ],
    },
    creatureFactory: (pos: Vector3) => {
      revealHandle.ladybug.position.copy(pos);
      revealHandle.ladybug.position.y = 0.05;
      return revealHandle.ladybug;
    },
    escapeKeys: (pos: Vector3) => [
      { frame: 0, value: pos.clone() },
      { frame: 60, value: new Vector3(pos.x + 0.5, pos.y, pos.z + 0.3) },
    ],
    particleFn: createSparkleBurst,
    particleOffset: new Vector3(0, 0.1, 0),
    repeatOnTap: false,
  });
}

/**
 * Orchestrator: assembles the fallen log from its decomposed parts.
 *
 * Builds a richly detailed fallen log with layered bark, longitudinal
 * ridges, circumferential rings, knots, a hollow opening with a dark
 * interior, moss and lichen growth, shelf fungi, visible end-grain,
 * and a raccoon peeking out of the hollow facing the stream.
 */
import { Scene, Mesh, Group, SphereGeometry, type Material } from 'three';
import { createLogMaterials } from './materials';
import { buildLogBody } from './body';
import { addHollow } from './hollow';
import { addEndGrain } from './endGrain';
import { addFoliage } from './foliage';
import { addRaccoon } from './raccoon';
import type { EntityPlacement } from '../../../types';
import type { LogBuildOptions, LogRevealHandle } from './types';

function buildBeetle(mat: Material): Mesh {
  const beetle = new Mesh(new SphereGeometry(0.5, 8, 8), mat);
  beetle.name = 'beetle';
  beetle.scale.set(0.12, 0.06, 0.08);
  return beetle;
}

/**
 * Builds a complete fallen log and adds it to the scene.
 *
 * @param scene - The Three.js scene.
 * @param placement - World-space placement for the log.
 * @returns The body mesh (used as the tap target by setupLogTap).
 */
export function buildLog(scene: Scene, placement: EntityPlacement, options: LogBuildOptions): Mesh {
  const root = new Group();
  root.name = 'log_root';
  root.position.set(placement.position.x, placement.position.y + 0.26, placement.position.z);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const mats = createLogMaterials();
  const body = buildLogBody(root, mats);
  const revealHandle: LogRevealHandle = {
    beetle: buildBeetle(options.materials.beetle),
  };

  addHollow(body, mats);
  addEndGrain(body, mats);
  addFoliage(body, mats);
  addRaccoon(root);

  body.userData = { ...body.userData, revealHandle };

  return body;
}

import { CircleGeometry, Group, Mesh, type Scene } from 'three';
import type { EntityPlacement } from '../../../types';
import type { MossPatchBuildOptions } from './types';

function seeded(seed: number): () => number {
  let s = Math.abs(seed * 9301 + 49297) % 233280;
  return () => {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

export function buildMossPatch(scene: Scene, placement: EntityPlacement, options: MossPatchBuildOptions): Group {
  const root = new Group();
  root.name = 'moss_patch';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const rand = seeded(placement.position.x * 57.9 + placement.position.z * 117.3);
  const clumpCount = 3 + Math.floor(rand() * 3);
  const radiusX = 0.22 + rand() * 0.12;
  const radiusZ = 0.16 + rand() * 0.1;

  for (let clumpIndex = 0; clumpIndex < clumpCount; clumpIndex++) {
    const clumpRoot = new Group();
    const size = 0.18 + rand() * 0.16;
    const clump = new Mesh(new CircleGeometry(size, 8), options.materials.body);
    const angle = rand() * Math.PI * 2;
    const dist = Math.sqrt(rand());
    clumpRoot.name = `moss_clump_${clumpIndex}`;
    clumpRoot.position.set(Math.cos(angle) * radiusX * dist, rand() * 0.006, Math.sin(angle) * radiusZ * dist);
    root.add(clumpRoot);

    clump.name = `moss_disc_${clumpIndex}`;
    clump.rotation.x = -Math.PI / 2;
    clumpRoot.add(clump);

    const subClumpCount = 1 + Math.floor(rand() * 2);
    for (let subIndex = 0; subIndex < subClumpCount; subIndex++) {
      const subSize = size * (0.38 + rand() * 0.2);
      const subClump = new Mesh(new CircleGeometry(subSize, 6), options.materials.body);
      subClump.name = `moss_sub_clump_${clumpIndex}_${subIndex}`;
      subClump.rotation.x = -Math.PI / 2;
      subClump.position.set((rand() - 0.5) * size * 0.6, 0.005, (rand() - 0.5) * size * 0.6);
      clumpRoot.add(subClump);
    }
  }

  return root;
}

import { Scene, Color, Mesh, Group, SphereGeometry, CylinderGeometry } from 'three';
