/**
 * Builds a toy mushroom with a stem, cap, and optional white spots.
 */
export function buildMushroom(scene: Scene, placement: EntityPlacement, options: MushroomBuildOptions): Group {
  const { config, materials } = options;
  const root = new Group();
  root.name = 'mushroom_root';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const stem = new Mesh(new CylinderGeometry((0.12 * config.scale) / 2, (0.18 * config.scale) / 2, 0.5 * config.scale, 8), materials.stem);
  stem.name = 'mush_stem';
  stem.position.y = 0.25 * config.scale;
  stem.castShadow = true;
  root.add(stem);

  const capMatName = `mushCapMat_#${config.capColor.getHexString()}`;
  const capMat = getOrCreateMaterial(capMatName, () => createGlossyPaintMaterial(capMatName, config.capColor));
  const cap = new Mesh(new SphereGeometry(0.5, 10, 10), capMat);
  cap.name = 'mush_cap';
  cap.scale.set(0.6 * config.scale, 0.3 * config.scale, 0.6 * config.scale);
  cap.position.y = 0.5 * config.scale;
  cap.castShadow = true;
  root.add(cap);

  if (config.capColor.r > 0.7) {
    const spotMat = getOrCreateMaterial('mushSpotMat', () => createGlossyPaintMaterial('mushSpotMat', new Color(0.95, 0.95, 0.9)));
    for (let s = 0; s < 4; s++) {
      const spot = new Mesh(new SphereGeometry((0.06 * config.scale) / 2, 6, 6), spotMat);
      spot.name = `mush_spot_${s}`;
      const angle = (s * Math.PI) / 2 + 0.3;
      spot.position.set(Math.cos(angle) * 0.2 * config.scale, 0.1 * config.scale, Math.sin(angle) * 0.2 * config.scale);
      cap.add(spot);
    }
  }

  return root;
}

