import { type Camera, Scene, Vector3, Color, Mesh, Group } from 'three';
import { onTap } from '@app/utils/sceneHelpers';
import { createSparkleBurst } from '@app/utils/particles';
import { playAnimation } from '@app/utils/animationHelpers';

/**
 * Registers a tap interaction on a mushroom that plays a squash-and-stretch
 * bounce animation with an emissive glow pulse and sparkle particles.
 */
export function setupMushroomTap(scene: Scene, canvas: HTMLCanvasElement, camera: Camera, mushroom: Group): void {
  const cap = mushroom.children.find((m) => m.name === 'mush_cap');
  if (!cap) return;

  onTap(canvas, camera, cap as Mesh, () => {
    playAnimation(mushroom, 'scale', [
      { frame: 0, value: new Vector3(1, 1, 1) },
      { frame: 8, value: new Vector3(1.15, 0.8, 1.15) },
      { frame: 16, value: new Vector3(0.9, 1.2, 0.9) },
      { frame: 24, value: new Vector3(1, 1, 1) },
    ]);

    const glowColor = new Color(0.3, 0.5, 0.2);
    playAnimation(cap, 'material.emissiveColor', [
      { frame: 0, value: new Color(0, 0, 0) },
      { frame: 10, value: glowColor },
      { frame: 30, value: new Color(0, 0, 0) },
    ]);

    createSparkleBurst(scene, new Vector3(0, 0.4, 0).add(mushroom.position));
  });
}

import { Scene, Vector3, Color, Mesh, Group, CylinderGeometry, SphereGeometry, TorusGeometry } from 'three';
import { createGlossyPaintMaterial } from '@app/utils/materialFactory';
import { startIdleLoop } from '@app/utils/animationHelpers';
import gsap from 'gsap';
import type { EntityPlacement, NoBuildOptions } from '../../../types';

export type SnailBuildOptions = NoBuildOptions;

/** Builds a detailed snail with a coiled spiral shell, eye stalks, and a slimy trail. */
export function buildSnail(scene: Scene, placement: EntityPlacement, options: SnailBuildOptions = {}): Group {
  void options;
  const root = new Group();
  root.name = 'snail_root';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const homePosition = placement.position.clone();
  const crawlMidpoint = homePosition.clone().add(new Vector3(-1, 0, 0.2));

  const bodyMat = createGlossyPaintMaterial('snailBodyMat', new Color(0.8, 0.75, 0.5));
  const shellMat = createGlossyPaintMaterial('snailShellMat', new Color(0.65, 0.35, 0.2));
  const shellStripeMat = createGlossyPaintMaterial('snailStripeMat', new Color(0.75, 0.45, 0.25));

  const body = new Mesh(new SphereGeometry(0.5, 10, 8), bodyMat);
  body.name = 'snail_body';
  body.scale.set(0.24, 0.08, 0.1);
  body.castShadow = true;
  root.add(body);

  const shellGroup = new Group();
  shellGroup.name = 'snail_shellGroup';
  shellGroup.position.set(-0.02, 0.06, 0);
  root.add(shellGroup);

  const shellDome = new Mesh(new SphereGeometry(0.09, 10, 8), shellMat);
  shellDome.name = 'snail_shellDome';
  shellDome.scale.set(1, 0.9, 1);
  shellGroup.add(shellDome);

  for (let s = 0; s < 3; s++) {
    const ringRadius = 0.08 - s * 0.02;
    const ring = new Mesh(new TorusGeometry(ringRadius, 0.01, 6, 12), s % 2 === 0 ? shellStripeMat : shellMat);
    ring.name = `snailRing_${s}`;
    ring.position.y = s * 0.025;
    ring.rotation.x = Math.PI / 2;
    shellGroup.add(ring);
  }

  const apex = new Mesh(new SphereGeometry(0.02, 6, 6), shellStripeMat);
  apex.name = 'snail_apex';
  apex.position.y = 0.08;
  shellGroup.add(apex);

  [-1, 1].forEach((side) => {
    const stalkGroup = new Group();
    stalkGroup.name = `eyeStalk_${side}`;
    stalkGroup.position.set(0.1, 0.04, side * 0.035);
    stalkGroup.rotation.z = side * -0.25;
    root.add(stalkGroup);

    const stalk = new Mesh(new CylinderGeometry(0.006, 0.008, 0.12, 4), bodyMat);
    stalk.name = `stalk_${side}`;
    stalk.position.y = 0.06;
    stalkGroup.add(stalk);

    const eyeBall = new Mesh(new SphereGeometry(0.012, 6, 6), createGlossyPaintMaterial(`snailEyeMat_${side}`, new Color(0.1, 0.1, 0.1)));
    eyeBall.name = `snailEye_${side}`;
    eyeBall.position.y = 0.12;
    stalkGroup.add(eyeBall);

    gsap.to(stalkGroup.rotation, {
      x: 0.15,
      duration: 2 + side * 0.3,
      repeat: -1,
      yoyo: true,
      ease: 'sine.inOut',
    });
  });

  startIdleLoop(root, 'position', [
    { frame: 0, value: homePosition.clone() },
    { frame: 600, value: crawlMidpoint },
    { frame: 1200, value: homePosition.clone() },
  ]);

  return root;
}

import { Scene, Mesh, SphereGeometry, CylinderGeometry, type Material } from 'three';
import type { EntityPlacement } from '../../../types';
import type { StoneBuildOptions, StoneRevealHandle } from './types';

function buildGrub(mat: Material): Mesh {
  const grub = new Mesh(new CylinderGeometry(0.02 / 2, 0.03 / 2, 0.08, 6), mat);
  grub.name = 'grub';
  grub.rotation.z = Math.PI / 2;
  return grub;
}

/**
 * Builds a rounded stone on the ground.
 */
export function buildStone(scene: Scene, placement: EntityPlacement, options: StoneBuildOptions): Mesh {
  const { materials } = options;
  const stone = new Mesh(new SphereGeometry(0.5, 8, 8), materials.body);
  const revealHandle: StoneRevealHandle = {
    grub: buildGrub(materials.grub),
  };
  stone.name = 'stone';
  stone.scale.set(0.4, 0.25, 0.35);
  stone.position.set(placement.position.x, placement.position.y + 0.12, placement.position.z);
