}

import { Scene, Vector3, type Mesh, type Camera } from 'three';
import { createDustPuff } from '@app/utils/particles';
import { createRevealInteraction } from '@app/utils/revealInteraction';
import type { StoneRevealHandle } from './types';

/**
 * Registers a tap interaction on a stone that shifts it aside and reveals a grub.
 */
export function setupStoneTap(scene: Scene, canvas: HTMLCanvasElement, camera: Camera, stone: Mesh): void {
  const revealHandle = stone.userData?.revealHandle as StoneRevealHandle | undefined;
  if (!revealHandle) return;

  const dir = new Vector3((Math.random() - 0.5) * 0.6, 0, (Math.random() - 0.5) * 0.6);

  createRevealInteraction(scene, canvas, camera, {
    coverMesh: stone,
    coverAnimation: {
      property: 'position',
      keys: [
        { frame: 0, value: stone.position.clone() },
        { frame: 12, value: stone.position.clone().add(dir) },
      ],
    },
    creatureFactory: (pos: Vector3) => {
      revealHandle.grub.position.copy(pos);
      revealHandle.grub.position.x -= 0.15;
      revealHandle.grub.position.y = 0.02;
      return revealHandle.grub;
    },
    escapeKeys: (pos: Vector3) => [
      { frame: 0, value: pos.clone() },
      { frame: 40, value: new Vector3(pos.x - 0.4, pos.y, pos.z + 0.2) },
    ],
    particleFn: createDustPuff,
  });
}

