export type StreamBuildOptions = NoBuildOptions;

export function buildStream(scene: Scene, placement: EntityPlacement, options: StreamBuildOptions = {}): Mesh {
  void options;
  const root = new Group();
  root.name = 'streamRoot';
  root.position.copy(placement.position);
  root.rotation.y = placement.rotY ?? 0;
  scene.add(root);

  const context = createStreamContext();

  buildStreamBed(root, context);
  const water = buildWaterSurface(root, context);
  buildStreamBanks(root, context.getFrame);
  buildStreamRocks(root, context);

  return water;
}

