export function buildWaterSurface(parent: StreamParent, context: StreamContext): Mesh {
  const waterUniforms = {
    uTime: { value: 0.0 },
    uDeepColor: { value: new Color(0.05, 0.14, 0.17) },
    uShallowColor: { value: new Color(0.29, 0.44, 0.36) },
    uSpecularColor: { value: new Color(0.98, 0.96, 0.9) },
    uSkyColor: { value: new Color(0.5, 0.68, 0.76) },
    uSubsurfaceColor: { value: new Color(0.12, 0.18, 0.1) },
    uFlowSpeed: { value: 0.32 },
    uOpacity: { value: 0.84 },
  };

  const water = new Mesh(
    createRibbonGeometry(context, {
      lengthSegments: 96,
      widthSegments: 12,
      widthFor: context.getWaterWidth,
      edgeJitter: 0.08,
    }),
    new ShaderMaterial({
      name: 'streamWaterShader',
      uniforms: waterUniforms,
      vertexShader: waterVert,
      fragmentShader: waterFrag,
      transparent: true,
      side: DoubleSide,
      depthWrite: false,
    }),
  );

  water.name = 'stream';
  water.position.set(0, 0.038, 0);
  water.receiveShadow = true;
  parent.add(water);

  let animFrame = 0;
  const tick = () => {
    animFrame = requestAnimationFrame(tick);
    waterUniforms.uTime.value = performance.now() * 0.001;
  };
  tick();

  const waterGeometry = water.geometry;
  const origDispose = waterGeometry.dispose.bind(waterGeometry);
  waterGeometry.dispose = () => {
    cancelAnimationFrame(animFrame);
    origDispose();
  };

  return water;
}

