import { Scene, Color, Mesh, Group, CylinderGeometry, IcosahedronGeometry, ShaderMaterial, DoubleSide, FrontSide } from 'three';
import { simplex3, fbm3 } from '@app/utils/noise3d';
import type { EntityPlacement, NoBuildOptions } from '../../../types';

export type TreeBuildOptions = NoBuildOptions;

// ΓöÇΓöÇ Seeded RNG ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function seeded(seed: number): () => number {
  let s = Math.abs(seed * 9301 + 49297) % 233280;
  return () => {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

// ΓöÇΓöÇ Bark Shader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const BARK_VERT = /* glsl */ `
  varying vec3 vWorldPos;
  varying vec3 vNormal;
  varying vec2 vUv;

  void main() {
    vUv = uv;
    vec4 wp = modelMatrix * vec4(position, 1.0);
    vWorldPos = wp.xyz;
    vNormal = normalize(normalMatrix * normal);
    gl_Position = projectionMatrix * viewMatrix * wp;
  }
`;

const BARK_FRAG = /* glsl */ `
  uniform vec3 uBarkColor;
  uniform vec3 uBarkDark;
  uniform vec3 uMossColor;
  uniform float uSeed;

  varying vec3 vWorldPos;
  varying vec3 vNormal;
  varying vec2 vUv;

  // Simple 3D hash for procedural detail
  float hash(vec3 p) {
    p = fract(p * vec3(443.897, 441.423, 437.195));
    p += dot(p, p.yzx + 19.19);
    return fract((p.x + p.y) * p.z);
  }

  // Value noise
  float noise3(vec3 p) {
    vec3 i = floor(p);
    vec3 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float n = mix(
      mix(mix(hash(i), hash(i + vec3(1,0,0)), f.x),
          mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x), f.y),
      mix(mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),
          mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x), f.y),
      f.z);
    return n;
  }

  // fBm
  float fbm(vec3 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
      v += a * noise3(p);
      p *= 2.1;
      a *= 0.48;
    }
    return v;
  }

  void main() {
    vec3 p = vWorldPos * 3.0 + uSeed;

    // Vertical bark cracks ΓÇö stretch noise along Y
    float cracks = fbm(vec3(p.x * 2.0, p.y * 0.4, p.z * 2.0));

    // Fine grain detail
    float grain = fbm(p * 8.0) * 0.3;

    // Horizontal ring pattern (growth rings visible in cracks)
    float rings = sin(length(p.xz) * 12.0 + p.y * 0.5) * 0.1;

    // Combine
    float pattern = cracks + grain + rings;

    // Color: dark in crevices, lighter on ridges
    vec3 bark = mix(uBarkDark, uBarkColor, smoothstep(0.3, 0.7, pattern));

    // Moss on upward-facing and north-facing surfaces
    float upFacing = max(0.0, vNormal.y);
    float northFacing = max(0.0, -vNormal.z) * 0.5;
    float mossAmount = (upFacing + northFacing) * smoothstep(0.5, 0.8, fbm(p * 2.0 + 10.0));
    // More moss near base
    float heightFade = 1.0 - smoothstep(0.0, 3.0, vWorldPos.y);
    mossAmount *= heightFade * 0.7;

    vec3 color = mix(bark, uMossColor, mossAmount);

    // Simple lighting from normal
    vec3 lightDir = normalize(vec3(0.3, 1.0, 0.5));
    float diff = max(dot(vNormal, lightDir), 0.0) * 0.5 + 0.5;
    color *= diff;

    // Darken crevices (ambient occlusion fake)
    color *= smoothstep(0.15, 0.55, pattern) * 0.4 + 0.6;

    gl_FragColor = vec4(color, 1.0);
  }
`;

function createBarkMaterial(seed: number): ShaderMaterial {
  return new ShaderMaterial({
    vertexShader: BARK_VERT,
    fragmentShader: BARK_FRAG,
    uniforms: {
      uBarkColor: { value: new Color(0.35, 0.22, 0.13) },
      uBarkDark: { value: new Color(0.12, 0.07, 0.03) },
      uMossColor: { value: new Color(0.18, 0.32, 0.1) },
      uSeed: { value: seed },
    },
    side: FrontSide,
  });
}

// ΓöÇΓöÇ Canopy Shader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const CANOPY_VERT = /* glsl */ `
  varying vec3 vWorldPos;
  varying vec3 vNormal;

  void main() {
    vec4 wp = modelMatrix * vec4(position, 1.0);
    vWorldPos = wp.xyz;
    vNormal = normalize(normalMatrix * normal);
    gl_Position = projectionMatrix * viewMatrix * wp;
  }
`;

const CANOPY_FRAG = /* glsl */ `
  uniform vec3 uLeafLight;
  uniform vec3 uLeafMid;
  uniform vec3 uLeafDark;
  uniform float uSeed;

  varying vec3 vWorldPos;
  varying vec3 vNormal;

  float hash(vec3 p) {
    p = fract(p * vec3(443.897, 441.423, 437.195));
    p += dot(p, p.yzx + 19.19);
    return fract((p.x + p.y) * p.z);
  }

  float noise3(vec3 p) {
    vec3 i = floor(p);
    vec3 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(
      mix(mix(hash(i), hash(i + vec3(1,0,0)), f.x),
          mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x), f.y),
      mix(mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),
          mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x), f.y),
      f.z);
  }

  float fbm(vec3 p) {
    float v = 0.0, a = 0.5;
    for (int i = 0; i < 4; i++) { v += a * noise3(p); p *= 2.0; a *= 0.5; }
    return v;
  }

  void main() {
    vec3 p = vWorldPos * 4.0 + uSeed;

    // Leaf cluster pattern ΓÇö splotchy color variation
    float leafNoise = fbm(p);
    float detail = fbm(p * 3.0) * 0.5;

    // Three-tone leaf color
    vec3 color;
    float t = leafNoise + detail * 0.5;
    if (t < 0.4) {
      color = mix(uLeafDark, uLeafMid, t / 0.4);
    } else {
      color = mix(uLeafMid, uLeafLight, (t - 0.4) / 0.6);
    }

    // Dappled sunlight ΓÇö bright spots where light punches through
    float sun = smoothstep(0.65, 0.85, fbm(p * 1.5 + 50.0));
    color = mix(color, uLeafLight * 1.3, sun * 0.4);

    // Translucency ΓÇö backlit leaves glow warmly
    vec3 lightDir = normalize(vec3(0.3, 1.0, 0.5));
    float backlit = max(0.0, dot(-vNormal, lightDir));
    float translucentGlow = pow(backlit, 2.0) * 0.3;
    color += vec3(0.15, 0.2, 0.02) * translucentGlow;

    // Standard diffuse
    float diff = max(dot(vNormal, lightDir), 0.0) * 0.45 + 0.55;
    color *= diff;

    // Darken undersides
    float underside = max(0.0, -vNormal.y) * 0.25;
    color *= 1.0 - underside;

    gl_FragColor = vec4(color, 1.0);
  }
`;

function createCanopyMaterial(seed: number): ShaderMaterial {
  return new ShaderMaterial({
    vertexShader: CANOPY_VERT,
    fragmentShader: CANOPY_FRAG,
    uniforms: {
      uLeafLight: { value: new Color(0.35, 0.58, 0.22) },
      uLeafMid: { value: new Color(0.18, 0.42, 0.1) },
      uLeafDark: { value: new Color(0.08, 0.22, 0.04) },
      uSeed: { value: seed },
    },
    side: DoubleSide,
  });
}

// ΓöÇΓöÇ Vertex Deformation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Deforms a cylinder geometry's vertices using 3D noise to create an organic,
 * irregular trunk shape. Vertices near the base bulge outward, higher vertices
 * get more noise for knobby branch stubs.
 */
function deformTrunk(geo: CylinderGeometry, seed: number, baseRadius: number, topRadius: number): void {
  const pos = geo.attributes.position;
  const count = pos.count;

  for (let i = 0; i < count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const z = pos.getZ(i);

    // Normalized height 0..1
    const height = geo.parameters.height;
    const t = (y + height / 2) / height;

    // Current radius at this height
    const ringRadius = lerp(baseRadius, topRadius, t);
    if (ringRadius < 0.001) continue;

    // Direction from center
    const dx = x;
    const dz = z;
    const dist = Math.sqrt(dx * dx + dz * dz);
    if (dist < 0.001) continue;

    const nx = dx / dist;
    const nz = dz / dist;

    // Low frequency bulges
    const bulge = simplex3(x * 2 + seed, y * 1.5 + seed * 0.7, z * 2 + seed * 1.3) * 0.08;

    // Higher frequency knobs and irregularities ΓÇö more at top
    const knobs = fbm3(x * 6 + seed, y * 3, z * 6 + seed, 3) * 0.04 * (0.5 + t);

    // Vertical grooves (bark furrows)
    const angle = Math.atan2(dz, dx);
    const furrow = Math.sin(angle * 8 + seed) * 0.015 * (1 - t * 0.5);

    // Base flare
    const flare = Math.max(0, 1 - t * 4) * 0.06;

    const displacement = bulge + knobs + furrow + flare;

    pos.setX(i, x + nx * displacement);
    pos.setZ(i, z + nz * displacement);

    // Slight Y perturbation for organic feel
    const yNoise = simplex3(x * 4 + seed * 2, y * 2, z * 4 + seed * 2) * 0.02;
    pos.setY(i, y + yNoise);
  }

  pos.needsUpdate = true;
  geo.computeVertexNormals();
}

/**
 * Deforms an icosahedron into an organic leaf-cluster blob.
 * Creates an irregular, cloudlike silhouette instead of a sphere.
 */
function deformCanopy(geo: IcosahedronGeometry, seed: number, radius: number): void {
  const pos = geo.attributes.position;
  const count = pos.count;

  for (let i = 0; i < count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const z = pos.getZ(i);

    const dist = Math.sqrt(x * x + y * y + z * z);
    if (dist < 0.001) continue;

    const nx = x / dist;
    const ny = y / dist;
    const nz = z / dist;

    // Large lumps ΓÇö define the overall silhouette
    const lumps = simplex3(nx * 2.5 + seed, ny * 2.5 + seed * 0.6, nz * 2.5 + seed * 1.2) * 0.35;

    // Medium detail ΓÇö secondary bumps
    const bumps = fbm3(nx * 5 + seed, ny * 5, nz * 5, 3) * 0.15;

    // Fine leaf-edge roughness
    const rough = simplex3(nx * 12 + seed, ny * 12, nz * 12) * 0.06;

    // Flatten bottom slightly (tree canopies are wider than tall)
    const flattenBottom = ny < -0.3 ? (ny + 0.3) * 0.3 : 0;

    const newDist = radius * (1.0 + lumps + bumps + rough) + flattenBottom;

    pos.setX(i, nx * newDist);
    pos.setY(i, ny * newDist);
    pos.setZ(i, nz * newDist);
  }

  pos.needsUpdate = true;
  geo.computeVertexNormals();
}

// ΓöÇΓöÇ Root Generation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function buildRoots(parent: Group, barkMat: ShaderMaterial, rng: () => number, seed: number, baseRadius: number): void {
  const count = 4 + Math.floor(rng() * 4);

  for (let i = 0; i < count; i++) {
    const angle = (i / count) * Math.PI * 2 + (rng() - 0.5) * 0.5;
    const rootLen = lerp(0.6, 1.5, rng());
    const thick = baseRadius * lerp(0.2, 0.4, rng());
    const thin = thick * lerp(0.15, 0.3, rng());

    const geo = new CylinderGeometry(thin, thick, rootLen, 6, 4);
    deformTrunk(geo, seed + i * 17, thick, thin);

    const rootMesh = new Mesh(geo, barkMat);
    const dist = baseRadius * 0.7;
    rootMesh.position.set(Math.cos(angle) * dist, -rootLen * 0.15, Math.sin(angle) * dist);
    rootMesh.rotation.z = Math.cos(angle) * lerp(0.5, 0.8, rng());
    rootMesh.rotation.x = -Math.sin(angle) * lerp(0.5, 0.8, rng());
    rootMesh.castShadow = true;
    parent.add(rootMesh);
  }
}

// ΓöÇΓöÇ Public API ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Builds a realistic procedural tree with noise-deformed trunk geometry,
 * organic branching, procedural bark shader, and deformed canopy clusters
 * with a multi-tone leaf shader.
 *
 * @param scene - The Three.js scene.
 * @param placement - World-space placement for the tree base.
 * @returns The trunk mesh reference.
 */
export function buildTreeTrunk(scene: Scene, placement: EntityPlacement, options: TreeBuildOptions = {}): Mesh {
  void options;
  const { position, rotY = 0 } = placement;
  const rng = seeded(position.x * 73.7 + position.z * 137.3);
  const seed = position.x * 13.7 + position.z * 47.3;

  const trunkHeight = lerp(4.5, 6.0, rng());
  const baseRadius = lerp(0.35, 0.5, rng());
  const topRadius = baseRadius * lerp(0.35, 0.5, rng());

  const barkMat = createBarkMaterial(seed);
  const canopyMat = createCanopyMaterial(seed);

  const root = new Group();
  root.name = `tree_${position.x.toFixed(1)}_${position.z.toFixed(1)}`;
  root.position.copy(position);
  root.rotation.y = rotY;
  scene.add(root);

  // ΓöÇΓöÇ Trunk: high-poly cylinder with vertex deformation ΓöÇΓöÇ
  const trunkGeo = new CylinderGeometry(topRadius, baseRadius, trunkHeight, 16, 20);
  deformTrunk(trunkGeo, seed, baseRadius, topRadius);

  const trunk = new Mesh(trunkGeo, barkMat);
  trunk.name = 'treeTrunk';
  trunk.position.y = trunkHeight / 2;
  trunk.castShadow = true;
  root.add(trunk);

  // ΓöÇΓöÇ Roots ΓöÇΓöÇ
  buildRoots(root, barkMat, rng, seed, baseRadius);

  // ΓöÇΓöÇ Main canopy mass: 3-4 large deformed blobs ΓöÇΓöÇ
  const crownY = trunkHeight * 0.85;
  const mainClusterCount = 3 + Math.floor(rng() * 2);
  for (let i = 0; i < mainClusterCount; i++) {
    const r = lerp(1.2, 2.0, rng());
    const leafGeo = new IcosahedronGeometry(r, 3);
    deformCanopy(leafGeo, seed + i * 23, r);

    const cluster = new Mesh(leafGeo, canopyMat);
    const theta = (i / mainClusterCount) * Math.PI * 2 + rng();
    const spread = lerp(0.3, 1.0, rng());
    cluster.position.set(Math.cos(theta) * spread, crownY + lerp(-0.3, 0.8, rng()), Math.sin(theta) * spread);
    // Squash slightly ΓÇö canopies are wider than tall
    cluster.scale.y = lerp(0.55, 0.75, rng());
    cluster.castShadow = true;
    cluster.receiveShadow = true;
    root.add(cluster);
  }

  return trunk;
}

import { Scene, Color, Mesh, Group, PlaneGeometry, SphereGeometry } from 'three';
import { createPlasticMaterial } from '@app/utils/materialFactory';
import gsap from 'gsap';

// ΓöÇΓöÇ Sky Backdrop ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Builds a gentle sky gradient backdrop behind the scene. */
export function buildSkyBackdrop(scene: Scene): Mesh {
  const skyMat = createPlasticMaterial('natureSkyMat', new Color(0.35, 0.55, 0.7));
  skyMat.emissive = new Color(0.12, 0.2, 0.28);
  const sky = new Mesh(new PlaneGeometry(28, 12), skyMat);
  sky.name = 'skyBackdrop';
  sky.position.set(0, 5, -6);
  scene.add(sky);

  // Soft clouds
  const cloudMat = createPlasticMaterial('cloudMat', new Color(0.9, 0.92, 0.95));
  cloudMat.emissive = new Color(0.3, 0.32, 0.35);
  const cloudPositions = [
    { x: -4, y: 7.5, z: -5.5, s: 1.2 },
    { x: 2, y: 8, z: -5.8, s: 1.5 },
    { x: 6, y: 7.2, z: -5.3, s: 1.0 },
    { x: -1, y: 8.5, z: -5.6, s: 0.8 },
  ];
  cloudPositions.forEach((cp, ci) => {
    const cloudGroup = new Group();
    cloudGroup.name = `cloud_${ci}`;
    cloudGroup.position.set(cp.x, cp.y, cp.z);
    scene.add(cloudGroup);

    // Each cloud is 3-4 overlapping soft spheres
    const blobCount = 3 + Math.floor(Math.random() * 2);
    for (let b = 0; b < blobCount; b++) {
      const blob = new Mesh(new SphereGeometry(0.5 * cp.s, 8, 6), cloudMat);
      blob.name = `cloudBlob_${ci}_${b}`;
      blob.position.set((b - blobCount / 2) * 0.4 * cp.s, (Math.random() - 0.5) * 0.2 * cp.s, 0);
      blob.scale.set(1.2, 0.6, 0.8);
      cloudGroup.add(blob);
    }

    // Gentle drift
    gsap.to(cloudGroup.position, {
      x: cp.x + 1.5,
      duration: 30 + ci * 8,
      repeat: -1,
      yoyo: true,
      ease: 'sine.inOut',
    });
  });

  return sky;
}

import { Scene, Color, Mesh, PlaneGeometry, CylinderGeometry } from 'three';
import { createFeltMaterial, createWoodMaterial } from '@app/utils/materialFactory';

// ΓöÇΓöÇ Toybox Enclosure ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** Builds low felt-lined walls with a wood rim to create the toybox interior feel. */
export function buildToyboxWalls(scene: Scene): void {
  const wallMat = createFeltMaterial('toyboxWallMat', new Color(0.55, 0.38, 0.65));
  const rimMat = createWoodMaterial('toyboxRimMat', new Color(0.5, 0.32, 0.18));
  const wallHeight = 3.0;
  const halfW = 7.5;
  const halfD = 6.5;

  // Wall definitions: [x, z, width, rotY, faceRotY]
  // Front wall (i=0) omitted ΓÇö camera looks from that side
  const walls: [number, number, number, number, number][] = [
    [0, halfD, halfW * 2, 0, Math.PI], // back
    [-halfW, 0, halfD * 2, Math.PI / 2, Math.PI / 2], // left
    [halfW, 0, halfD * 2, Math.PI / 2, -Math.PI / 2], // right
  ];

  walls.forEach(([x, z, width, rotY, faceRotY], i) => {
    // Felt wall panel
    const panel = new Mesh(new PlaneGeometry(width, wallHeight), wallMat);
    panel.name = `toyboxWall_${i}`;
    panel.position.set(x, wallHeight / 2, z);
    panel.rotation.y = faceRotY;
    panel.receiveShadow = true;
    scene.add(panel);

    // Wood rim along the top edge
    const rim = new Mesh(new CylinderGeometry(0.08, 0.08, width, 8), rimMat);
    rim.name = `toyboxRim_${i}`;
    rim.position.set(x, wallHeight, z);
    rim.rotation.z = Math.PI / 2;
    rim.rotation.y = rotY;
    if (i === 0) rim.rotation.y = 0; // back wall rim runs along X
    scene.add(rim);
  });

  // Corner posts ΓÇö only back two corners (front corners omitted with front wall)
  const corners = [
    [-halfW, halfD],
    [halfW, halfD],
  ];
  corners.forEach(([cx, cz], ci) => {
    const post = new Mesh(new CylinderGeometry(0.12, 0.12, wallHeight + 0.1, 8), rimMat);
    post.name = `toyboxCorner_${ci}`;
    post.position.set(cx, wallHeight / 2, cz);
    post.castShadow = true;
    scene.add(post);
  });
}

import { Scene, Vector3, Mesh, SphereGeometry, PointLight, type MeshStandardMaterial } from 'three';
import { createTranslucentMaterial } from '@app/utils/materialFactory';
import gsap from 'gsap';
import type { FireflyConfig, FireflyTapHandle } from './types';

/**
 * Generates a random spawn position within the nature world bounds.
 * Fireflies hover between Y 0.6 and 2.4, spread across the scene.
 */
function randomSpawn(): Vector3 {
  return new Vector3((Math.random() - 0.5) * 10, 0.6 + Math.random() * 1.8, (Math.random() - 0.5) * 8);
}

/**
 * Generates a random drift destination near a home position.
 */
function randomDrift(home: Vector3, range: number): Vector3 {
  return new Vector3(
    home.x + (Math.random() - 0.5) * range,
    Math.max(0.4, home.y + (Math.random() - 0.5) * range * 0.6),
    home.z + (Math.random() - 0.5) * range,
  );
}

/**
 * Builds a group of fireflies with glow lights, drifting motion,
 * and pulsing emissive blink.
 *
 * Each firefly:
 * - Drifts lazily between random waypoints using GSAP
 * - Keeps a follow light parented to the mesh
 * - Pulses emissive brightness with organic timing
 * - Exposes a tap reaction handle for interaction wiring
 *
 * @returns An array of firefly meshes.
 */
export function buildFireflies(scene: Scene, config: FireflyConfig): Mesh[] {
  const fireflies: Mesh[] = [];

  for (let i = 0; i < config.count; i++) {
    const home = randomSpawn();

    const fly = new Mesh(new SphereGeometry(0.04, 6, 6), createTranslucentMaterial(`fireflyMat_${i}`, config.glowColor.clone(), 0.85));
    fly.name = `firefly_${i}`;
    fly.position.copy(home);
    const mat = fly.material as MeshStandardMaterial;
    mat.emissive = config.glowColor.clone();
    mat.emissiveIntensity = 1.0;
    scene.add(fly);

    const glow = new PointLight(config.lightColor.clone(), 0.15, 2.5);
    glow.name = `fireflyGlow_${i}`;
    fly.add(glow);

    const driftRange = 1.5 + Math.random() * 1.5;
    const driftToNext = () => {
      const dest = randomDrift(home, driftRange);
      const dist = fly.position.distanceTo(dest);
      const duration = 2.5 + dist * 1.2 + Math.random() * 2;

      gsap.to(fly.position, {
        x: dest.x,
        y: dest.y,
        z: dest.z,
        duration,
        ease: 'sine.inOut',
        onComplete: () => {
          gsap.delayedCall(0.3 + Math.random() * 1.5, driftToNext);
        },
      });
    };
    gsap.delayedCall(Math.random() * 3, driftToNext);

    const blinkCycle = () => {
      const onDuration = 1.0 + Math.random() * 2.5;
      const offDuration = 0.4 + Math.random() * 1.2;
      const fadeDuration = 0.3 + Math.random() * 0.5;

      gsap.to(mat.emissive, {
        r: config.dimColor.r,
        g: config.dimColor.g,
        b: config.dimColor.b,
        duration: fadeDuration,
        ease: 'power2.in',
        delay: onDuration,
        onComplete: () => {
          gsap.to(glow, { intensity: 0.02, duration: fadeDuration * 0.5 });
        },
      });

      gsap.delayedCall(onDuration + fadeDuration + offDuration, () => {
        gsap.to(mat.emissive, {
          r: config.glowColor.r,
          g: config.glowColor.g,
          b: config.glowColor.b,
          duration: fadeDuration,
          ease: 'power2.out',
        });
        gsap.to(glow, { intensity: 0.15, duration: fadeDuration });
        gsap.delayedCall(fadeDuration + 0.1, blinkCycle);
      });
    };
    gsap.delayedCall(Math.random() * 4, blinkCycle);

    const tapHandle: FireflyTapHandle = {
      trigger: () => {
        mat.emissive.copy(config.glowColor);
        glow.intensity = 0.4;
        gsap.to(glow, { intensity: 0.15, duration: 0.6, ease: 'power2.out' });
      },
    };
    fly.userData = { ...fly.userData, fireflyTapHandle: tapHandle };

    fireflies.push(fly);
  }

  return fireflies;
}

import { Vector3, type Camera, type Mesh, type Scene } from 'three';
import { createSparkleBurst } from '@app/utils/particles';
import { onTap } from '@app/utils/sceneHelpers';
import type { FireflyTapHandle } from './types';

export function setupFireflyTap(scene: Scene, canvas: HTMLCanvasElement, camera: Camera, fireflies: readonly Mesh[]): void {
  fireflies.forEach((firefly) => {
    const handle = firefly.userData?.fireflyTapHandle as FireflyTapHandle | undefined;

    onTap(canvas, camera, firefly, () => {
      createSparkleBurst(scene, firefly.getWorldPosition(new Vector3()));
      handle?.trigger();
    });
  });
}

import { type Camera, type Mesh, type Scene } from 'three';
import type { NavigationActions } from '@app/types/scenes';
import { createWorldScene } from '@app/utils/worldSceneFactory';
import { buildSceneBase, createDisposeCollector } from '@app/utils/sceneHelpers';
import { GLOW_SPORES, createContinuousEffect } from '@app/utils/particleFactory';
import { getLayoutPlacement } from './layout';
import { createNatureMaterials } from './materials';
import { ACORN_SCENE_PLAN } from './plans/acorns';
import { BUTTERFLY_SCENE_PLAN } from './plans/butterflies';
import { FERN_SCENE_PLAN } from './plans/ferns';
import { FLOWER_SCENE_PLAN } from './plans/flowers';
import { GRASS_PATCH_SCENE_PLAN } from './plans/grassPatch';
import { LEAF_LITTER_SCENE_PLAN } from './plans/leafLitter';
import { LEAF_SCENE_PLAN } from './plans/leaves';
import { LOG_SCENE_PLAN } from './plans/log';
import { MOSS_PATCH_SCENE_PLAN } from './plans/mossPatch';
import { MUSHROOM_SCENE_PLAN } from './plans/mushrooms';
import { SNAIL_SCENE_PLAN } from './plans/snail';
import { STONE_SCENE_PLAN } from './plans/stones';
import { STREAM_SCENE_PLAN } from './plans/stream';
import { TOADSTOOL_SCENE_PLAN } from './plans/toadstools';
import { TREE_SCENE_PLAN } from './plans/trees';
import { NATURE_SCAFFOLD } from './scaffold';
import { buildAcorn } from './builders/placed/acorns';
import { buildButterfly, getButterflyConfig, setupButterflyTap } from './builders/placed/butterflies';
import { buildFern } from './builders/placed/ferns';
import { buildFlower, getFlowerConfig, setupFlowerTap } from './builders/placed/flowers';
import { buildLeaf, setupLeafTap } from './builders/placed/leaves';
import { buildLog, setupLogTap } from './builders/placed/log';
import { buildMushroom, getMushroomConfig, setupMushroomTap } from './builders/placed/mushrooms';
import { buildSnail } from './builders/placed/snail';
import { buildStone, setupStoneTap } from './builders/placed/stones';
import { buildStream, setupStreamTap } from './builders/placed/stream';
import { buildToadstool } from './builders/placed/toadstools';
import { buildTreeTrunk } from './builders/placed/trees';
import { buildGrassPatch } from './builders/placed/grassPatch';
import { buildLeafLitter } from './builders/placed/leafLitter';
import { buildMossPatch } from './builders/placed/mossPatch';
import { buildSkyBackdrop } from './builders/scaffold/skyBackdrop';
import { buildToyboxWalls } from './builders/scaffold/toyboxWalls';
import { buildFireflies, FIREFLY_CONFIG, setupFireflyTap } from './builders/systems/fireflies';

/**
 * Creates the Nature toybox interior world scene: a forest-floor diorama
 * composed from layout anchors plus scene-local entity configuration.
 */
export function createScene(scene: Scene, canvas: HTMLCanvasElement, nav: NavigationActions) {
  const result = createWorldScene(scene, canvas, nav, {
    sceneId: 'nature',
    clearColor: NATURE_SCAFFOLD.clearColor,
    lighting: NATURE_SCAFFOLD.lighting,
    portals: NATURE_SCAFFOLD.portals,
    floorTap: NATURE_SCAFFOLD.floorTap,
    buildContents: (sc: Scene, cvs: HTMLCanvasElement, cam: Camera) => {
      const disposer = createDisposeCollector();
      const materials = createNatureMaterials();

      buildToyboxWalls(sc);
      buildSkyBackdrop(sc);

      const { ground: forestFloor } = buildSceneBase(sc, {
        groundMaterial: 'felt',
        groundColor: NATURE_SCAFFOLD.ground.color,
        groundWidth: NATURE_SCAFFOLD.ground.width,
        groundDepth: NATURE_SCAFFOLD.ground.depth,
      });

      let stream: Mesh | null = null;
      STREAM_SCENE_PLAN.forEach((plan) => {
        stream = buildStream(sc, getLayoutPlacement(plan.anchor));
      });

      TREE_SCENE_PLAN.forEach((plan) => {
        buildTreeTrunk(sc, getLayoutPlacement(plan.anchor));
      });

      const sporeSystem = createContinuousEffect(sc, GLOW_SPORES);
      disposer.add({
        dispose: () => {
          sporeSystem.stop();
          sporeSystem.dispose();
        },
      });

      GRASS_PATCH_SCENE_PLAN.forEach((plan) => {
        buildGrassPatch(sc, getLayoutPlacement(plan.anchor), {
          materials: { blade: materials.grass },
        });
      });

      LEAF_LITTER_SCENE_PLAN.forEach((plan) => {
        buildLeafLitter(sc, getLayoutPlacement(plan.anchor));
      });

      TOADSTOOL_SCENE_PLAN.forEach((plan) => {
        buildToadstool(sc, getLayoutPlacement(plan.anchor));
      });

      MUSHROOM_SCENE_PLAN.forEach((plan) => {
        const mushroom = buildMushroom(
          sc,
          getLayoutPlacement(plan.anchor),
          {
            config: getMushroomConfig(plan.variant),
            materials: { stem: materials.mushStem },
          },
        );
        setupMushroomTap(sc, cvs, cam, mushroom);
      });

      FLOWER_SCENE_PLAN.forEach((plan) => {
        const flower = buildFlower(sc, getLayoutPlacement(plan.anchor), {
          config: getFlowerConfig(plan.variant),
          materials: { stem: materials.flowerStem },
        });
        setupFlowerTap(sc, cvs, cam, flower);
      });

      LEAF_SCENE_PLAN.forEach((plan) => {
        const leaf = buildLeaf(sc, getLayoutPlacement(plan.anchor), {
          materials: {
            body: materials.leaf,
            ladybug: materials.ladybug,
            ladybugSpot: materials.ladybugSpot,
          },
        });
        setupLeafTap(sc, cvs, cam, leaf);
      });

      LOG_SCENE_PLAN.forEach((plan) => {
        const log = buildLog(sc, getLayoutPlacement(plan.anchor), {
          materials: { beetle: materials.beetle },
        });
        setupLogTap(sc, cvs, cam, log);
      });

      STONE_SCENE_PLAN.forEach((plan) => {
        const stone = buildStone(sc, getLayoutPlacement(plan.anchor), {
          materials: {
            body: materials.stone,
            grub: materials.grub,
          },
        });
        setupStoneTap(sc, cvs, cam, stone);
      });

      if (stream) {
        setupStreamTap(sc, cvs, cam, stream);
      }

      BUTTERFLY_SCENE_PLAN.forEach((plan) => {
        const butterfly = buildButterfly(sc, getLayoutPlacement(plan.anchor), {
          config: getButterflyConfig(plan.variant),
        });
        setupButterflyTap(sc, cvs, cam, butterfly);
      });

      const fireflies = buildFireflies(sc, FIREFLY_CONFIG);
      setupFireflyTap(sc, cvs, cam, fireflies);

      MOSS_PATCH_SCENE_PLAN.forEach((plan) => {
        buildMossPatch(sc, getLayoutPlacement(plan.anchor), {
          materials: { body: materials.moss },
        });
      });

      FERN_SCENE_PLAN.forEach((plan) => {
        buildFern(sc, getLayoutPlacement(plan.anchor), {
          materials: { frond: materials.fern },
        });
      });

      ACORN_SCENE_PLAN.forEach((plan) => {
        buildAcorn(sc, getLayoutPlacement(plan.anchor));
      });

      SNAIL_SCENE_PLAN.forEach((plan) => {
        buildSnail(sc, getLayoutPlacement(plan.anchor));
      });

      return forestFloor;
    },
  });

  return { cameraHandle: result.cameraHandle, dispose: result.dispose };
}

