import { PerspectiveCamera, Vector3, Spherical, MathUtils } from 'three';
import type { SceneId } from '@app/types/scenes';

/** Per-scene camera configuration using spherical coordinates around a target. */
interface CameraPreset {
  /** Azimuthal angle in radians (horizontal orbit). */
  azimuth: number;
  /** Polar angle in radians (vertical tilt from top). */
  polar: number;
  /** Distance from target. */
  distance: number;
  /** Look-at target position. */
  target: Vector3;
}

/** Spike-validated camera presets per scene. */
const PRESETS: Record<SceneId, CameraPreset> = {
  hub: { azimuth: 0, polar: 1.19, distance: 14, target: new Vector3(0, 0.5, 0) },
  adventure: { azimuth: 0, polar: 1.1, distance: 11, target: new Vector3(0, 0.3, 0) },
  animals: { azimuth: 0, polar: 1.15, distance: 11, target: new Vector3(0, 0.3, 0) },
  creative: { azimuth: 0, polar: 1.1, distance: 11, target: new Vector3(0, 0.3, 0) },
  nature: { azimuth: 0, polar: 1.2, distance: 10, target: new Vector3(0, 0.3, 0) },
};

/**
 * Handle returned by createSceneCamera for controlling the camera.
 */
export interface CameraHandle {
  /** The Three.js PerspectiveCamera. */
  camera: PerspectiveCamera;
  /** Call to clean up event listeners. */
  dispose: () => void;
  /** Resets camera to its original preset position. */
  recenter: () => void;
  /** Updates camera aspect ratio on resize. */
  resize: (width: number, height: number) => void;
}

/**
 * Creates a PerspectiveCamera with zoom, tilt, and pan controls.
 * Left-click drag pans, Shift+drag rotates/tilts, scroll wheel zooms.
 *
 * @param canvas - The canvas element for event binding.
 * @param sceneId - Identifies which preset to apply.
 * @returns A CameraHandle with the camera and control methods.
 */
export function createSceneCamera(canvas: HTMLCanvasElement, sceneId: SceneId): CameraHandle {
  const p = PRESETS[sceneId];

  // Widen distance on portrait viewports
  const aspect = canvas.clientWidth / canvas.clientHeight;
  const portraitMultiplier = aspect < 1 ? (1.0 / aspect) * 0.75 : 1;
  const baseDistance = p.distance * portraitMultiplier;

  const camera = new PerspectiveCamera(50, aspect, 0.1, 100);
  const target = p.target.clone();
  // Babylon azimuth 0 = front view; Three.js Spherical theta 0 = +Z (behind).
  // Offset by ╧Ç so preset azimuth values match the original Babylon conventions.
  const spherical = new Spherical(baseDistance, p.polar, p.azimuth + Math.PI);

  // Arc limits
  const maxAzimuthRange = 0.25;
  const maxPolarDown = 0.1;
  const maxPolarUp = 0.1;
  const minDistance = p.distance * 0.2;
  const maxDistance = baseDistance;

  // Pan clamp boundaries (at closest zoom)
  const panRangeX = 3.5;
  const minY = 0;
  const maxY = 2.0;

  /** Maximum camera Y ΓÇö keeps camera below ceiling with margin. */
  const ceilingY = 6.0;

  const updateCameraPosition = () => {
    const offset = new Vector3().setFromSpherical(spherical);
    camera.position.copy(target).add(offset);
    // Hard ceiling clamp ΓÇö camera must never go above ceiling
    if (camera.position.y > ceilingY) camera.position.y = ceilingY;
    camera.lookAt(target);
  };
  updateCameraPosition();

  let isDragging = false;
  let lastX = 0;
  let lastY = 0;
  let shiftHeld = false;

  // ΓöÇΓöÇ Pinch-zoom state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const activePointers = new Map<number, { x: number; y: number }>();
  let lastPinchDist = 0;
  const pinchSpeed = 0.015;

  const panSpeed = 0.015;
  const rotateSpeed = 0.004;
  const tiltSpeed = 0.005;

  const clampSpherical = () => {
    const baseTheta = p.azimuth + Math.PI;
    spherical.theta = MathUtils.clamp(spherical.theta, baseTheta - maxAzimuthRange, baseTheta + maxAzimuthRange);
    spherical.phi = MathUtils.clamp(
      spherical.phi,
      Math.max(0.9, p.polar - maxPolarDown),
      Math.min(1.35, p.polar + maxPolarUp),
    );
    spherical.radius = MathUtils.clamp(spherical.radius, minDistance, maxDistance);
  };

  /** Clamp target.y so camera never exceeds ceiling. */
  const clampTargetForCeiling = () => {
    // camera.y = target.y + radius * cos(phi)
    const cameraOffsetY = spherical.radius * Math.cos(spherical.phi);
    const maxTargetY = Math.min(maxY, ceilingY - cameraOffsetY);
    target.y = MathUtils.clamp(target.y, minY, Math.max(minY, maxTargetY));
  };

  /** Returns distance between two pointers, or 0 if fewer than 2. */
  const getPinchDist = (): number => {
    if (activePointers.size < 2) return 0;
    const pts = Array.from(activePointers.values());
    const dx = pts[0].x - pts[1].x;
    const dy = pts[0].y - pts[1].y;
    return Math.sqrt(dx * dx + dy * dy);
  };

  const onContextMenu = (e: Event) => e.preventDefault();

  const onPointerDown = (e: PointerEvent) => {
    activePointers.set(e.pointerId, { x: e.clientX, y: e.clientY });

    // Two-finger pinch start
    if (activePointers.size === 2) {
      isDragging = false;
      lastPinchDist = getPinchDist();
      return;
    }

    if (e.button !== 0) return;
    isDragging = true;
    shiftHeld = e.shiftKey;
    lastX = e.clientX;
    lastY = e.clientY;
  };

  const onPointerMove = (e: PointerEvent) => {
    activePointers.set(e.pointerId, { x: e.clientX, y: e.clientY });

    // Two-finger pinch zoom
    if (activePointers.size >= 2) {
      const dist = getPinchDist();
      if (lastPinchDist > 0 && dist > 0) {
        const delta = lastPinchDist - dist;
        spherical.radius += delta * pinchSpeed;
        clampSpherical();
        clampTargetForCeiling();
        updateCameraPosition();
      }
      lastPinchDist = dist;
      return;
    }

    if (!isDragging) return;
    const dx = e.clientX - lastX;
    const dy = e.clientY - lastY;
    lastX = e.clientX;
    lastY = e.clientY;

    if (shiftHeld) {
      // Shift + drag ΓåÆ orbit rotate + tilt
      spherical.theta -= dx * rotateSpeed;
      spherical.phi -= dy * tiltSpeed;
      clampSpherical();
    } else {
      // Left drag ΓåÆ pan target
      const scaleFactor = (spherical.radius / p.distance) * panSpeed;
      target.x -= dx * scaleFactor;
      target.y += dy * scaleFactor;

      // Tighten pan range when zoomed out so the view stays inside the room
      const zoomFraction = 1 - (spherical.radius - minDistance) / (maxDistance - minDistance);
      const effectiveRangeX = panRangeX * Math.max(0.1, zoomFraction);
      target.x = MathUtils.clamp(target.x, -effectiveRangeX, effectiveRangeX);
    }
    clampTargetForCeiling();
    updateCameraPosition();
  };

  const onPointerUp = (e: PointerEvent) => {
    activePointers.delete(e.pointerId);
    if (activePointers.size < 2) lastPinchDist = 0;
    if (activePointers.size === 0) {
      isDragging = false;
      shiftHeld = false;
    }
  };

  const onWheel = (e: WheelEvent) => {
    e.preventDefault();
    const zoomDelta = e.deltaY * 0.01;
    spherical.radius += zoomDelta;
    clampSpherical();
    clampTargetForCeiling();
    updateCameraPosition();
  };

  // Prevent browser default pinch-zoom on the canvas
  canvas.style.touchAction = 'none';

  canvas.addEventListener('contextmenu', onContextMenu);
  canvas.addEventListener('pointerdown', onPointerDown, true);
  canvas.addEventListener('pointermove', onPointerMove, true);
  canvas.addEventListener('pointerup', onPointerUp, true);
  canvas.addEventListener('pointerleave', onPointerUp, true);
  canvas.addEventListener('pointercancel', onPointerUp, true);
  canvas.addEventListener('wheel', onWheel, { passive: false });

  // Recenter on custom event
  const recenter = () => {
    target.copy(p.target);
    spherical.set(baseDistance, p.polar, p.azimuth + Math.PI);
    updateCameraPosition();
  };
  const onRecenter = () => recenter();
  window.addEventListener('camera:recenter', onRecenter);

  const dispose = () => {
    canvas.removeEventListener('contextmenu', onContextMenu);
    canvas.removeEventListener('pointerdown', onPointerDown, true);
    canvas.removeEventListener('pointermove', onPointerMove, true);
    canvas.removeEventListener('pointerup', onPointerUp, true);
    canvas.removeEventListener('pointerleave', onPointerUp, true);
    canvas.removeEventListener('pointercancel', onPointerUp, true);
    canvas.removeEventListener('wheel', onWheel);
    window.removeEventListener('camera:recenter', onRecenter);
  };

  const resize = (width: number, height: number) => {
    const newAspect = width / height;
    camera.aspect = newAspect;
    camera.updateProjectionMatrix();
    const newMult = newAspect < 1 ? (1.0 / newAspect) * 0.75 : 1;
    const newMaxDistance = p.distance * newMult;
    spherical.radius = MathUtils.clamp(spherical.radius, minDistance, newMaxDistance);
    updateCameraPosition();
  };

  return { camera, dispose, recenter, resize };
}

import {
  Points,
  BufferGeometry,
  Float32BufferAttribute,
  PointsMaterial,
